import { useState } from "react";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { CheckCircle, XCircle, Ban, Loader2, Trash2, RotateCcw } from "lucide-react";
import { useToast } from "@/hooks/use-toast";

interface CorretorActionsProps {
  corretor: {
    id: string;
    status: string;
    deleted_at?: string | null;
    profiles: {
      first_name: string;
      last_name: string;
    };
  };
}

export default function CorretorActions({ corretor }: CorretorActionsProps) {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [showApproveDialog, setShowApproveDialog] = useState(false);
  const [showRejectDialog, setShowRejectDialog] = useState(false);
  const [showSuspendDialog, setShowSuspendDialog] = useState(false);
  const [showDeleteDialog, setShowDeleteDialog] = useState(false);

  const updateStatusMutation = useMutation({
    mutationFn: async ({ status, data_avaliacao }: { status: string; data_avaliacao?: string }) => {
      const updateData: any = { status };
      if (data_avaliacao) {
        updateData.data_avaliacao = data_avaliacao;
      }

      const { error } = await supabase
        .from('corretores')
        .update(updateData)
        .eq('id', corretor.id);

      if (error) throw error;
    },
    onSuccess: (_, variables) => {
      queryClient.invalidateQueries({ queryKey: ['corretores'] });

      const statusMessages = {
        'ativo': 'Corretor aprovado com sucesso!',
        'inativo': 'Corretor rejeitado.',
        'bloqueado': 'Corretor suspenso.'
      };

      toast({
        title: "Status atualizado",
        description: statusMessages[variables.status as keyof typeof statusMessages],
      });
    },
    onError: () => {
      toast({
        title: "Erro",
        description: "Não foi possível atualizar o status do corretor.",
        variant: "destructive",
      });
    }
  });

  const handleApprove = () => {
    updateStatusMutation.mutate({ 
      status: 'ativo', 
      data_avaliacao: new Date().toISOString().split('T')[0] 
    });
    setShowApproveDialog(false);
  };

  const handleReject = () => {
    updateStatusMutation.mutate({ status: 'inativo' });
    setShowRejectDialog(false);
  };

  const handleSuspend = () => {
    updateStatusMutation.mutate({ status: 'bloqueado' });
    setShowSuspendDialog(false);
  };

  const handleReactivate = () => {
    updateStatusMutation.mutate({ status: 'ativo' });
  };

  // Mutation para soft delete
  const softDeleteMutation = useMutation({
    mutationFn: async () => {
      const { error } = await supabase
        .from('corretores')
        .update({ 
          deleted_at: new Date().toISOString(),
          status: 'inativo'
        })
        .eq('id', corretor.id);

      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['corretores'] });
      toast({
        title: "Corretor excluído",
        description: "O corretor foi movido para a lixeira.",
      });
    },
    onError: () => {
      toast({
        title: "Erro",
        description: "Não foi possível excluir o corretor.",
        variant: "destructive",
      });
    }
  });

  // Mutation para restaurar
  const restoreMutation = useMutation({
    mutationFn: async () => {
      const { error } = await supabase
        .from('corretores')
        .update({ 
          deleted_at: null,
          status: 'em_avaliacao'
        })
        .eq('id', corretor.id);

      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['corretores'] });
      toast({
        title: "Corretor restaurado",
        description: "O corretor foi restaurado com sucesso.",
      });
    },
    onError: () => {
      toast({
        title: "Erro",
        description: "Não foi possível restaurar o corretor.",
        variant: "destructive",
      });
    }
  });

  const handleDelete = () => {
    softDeleteMutation.mutate();
    setShowDeleteDialog(false);
  };

  const handleRestore = () => {
    restoreMutation.mutate();
  };

  // Se está na lixeira, mostrar apenas botão de restaurar
  if (corretor.deleted_at) {
    return (
      <Button
        variant="outline"
        size="sm"
        className="text-blue-600 border-blue-600 hover:bg-blue-50"
        onClick={handleRestore}
        disabled={restoreMutation.isPending}
      >
        {restoreMutation.isPending ? (
          <Loader2 className="w-3 h-3 mr-1 animate-spin" />
        ) : (
          <RotateCcw className="w-3 h-3 mr-1" />
        )}
        Restaurar
      </Button>
    );
  }

  if (corretor.status === 'em_avaliacao') {
    return (
      <>
        <div className="flex items-center gap-2">
          <Button
            variant="outline"
            size="sm"
            className="text-green-600 border-green-600 hover:bg-green-50"
            onClick={() => setShowApproveDialog(true)}
            disabled={updateStatusMutation.isPending}
          >
            {updateStatusMutation.isPending ? (
              <Loader2 className="w-3 h-3 mr-1 animate-spin" />
            ) : (
              <CheckCircle className="w-3 h-3 mr-1" />
            )}
            Aprovar
          </Button>

          <Button
            variant="outline"
            size="sm"
            className="text-red-600 border-red-600 hover:bg-red-50"
            onClick={() => setShowRejectDialog(true)}
            disabled={updateStatusMutation.isPending}
          >
            <XCircle className="w-3 h-3 mr-1" />
            Rejeitar
          </Button>
        </div>

        {/* Dialog de Aprovação */}
        <AlertDialog open={showApproveDialog} onOpenChange={setShowApproveDialog}>
          <AlertDialogContent>
            <AlertDialogHeader>
              <AlertDialogTitle>Aprovar Corretor</AlertDialogTitle>
              <AlertDialogDescription>
                Tem certeza que deseja aprovar {corretor.profiles.first_name} {corretor.profiles.last_name}?
                O corretor será ativado e poderá começar a receber leads.
              </AlertDialogDescription>
            </AlertDialogHeader>
            <AlertDialogFooter>
              <AlertDialogCancel>Cancelar</AlertDialogCancel>
              <AlertDialogAction onClick={handleApprove}>
                Aprovar Corretor
              </AlertDialogAction>
            </AlertDialogFooter>
          </AlertDialogContent>
        </AlertDialog>

        {/* Dialog de Rejeição */}
        <AlertDialog open={showRejectDialog} onOpenChange={setShowRejectDialog}>
          <AlertDialogContent>
            <AlertDialogHeader>
              <AlertDialogTitle>Rejeitar Corretor</AlertDialogTitle>
              <AlertDialogDescription>
                Tem certeza que deseja rejeitar {corretor.profiles.first_name} {corretor.profiles.last_name}?
                O corretor será marcado como inativo e não poderá receber leads.
              </AlertDialogDescription>
            </AlertDialogHeader>
            <AlertDialogFooter>
              <AlertDialogCancel>Cancelar</AlertDialogCancel>
              <AlertDialogAction onClick={handleReject} className="bg-red-600 hover:bg-red-700">
                Rejeitar Corretor
              </AlertDialogAction>
            </AlertDialogFooter>
          </AlertDialogContent>
        </AlertDialog>
      </>
    );
  }

  if (corretor.status === 'ativo') {
    return (
      <>
        <div className="flex items-center gap-2">
          <Button
            variant="outline"
            size="sm"
            className="text-orange-600 border-orange-600 hover:bg-orange-50"
            onClick={() => setShowSuspendDialog(true)}
            disabled={updateStatusMutation.isPending}
          >
            {updateStatusMutation.isPending ? (
              <Loader2 className="w-3 h-3 mr-1 animate-spin" />
            ) : (
              <Ban className="w-3 h-3 mr-1" />
            )}
            Suspender
          </Button>

          <Button
            variant="outline"
            size="sm"
            className="text-red-600 border-red-600 hover:bg-red-50"
            onClick={() => setShowDeleteDialog(true)}
            disabled={softDeleteMutation.isPending}
          >
            <Trash2 className="w-3 h-3 mr-1" />
            Excluir
          </Button>
        </div>

        {/* Dialog de Suspensão */}
        <AlertDialog open={showSuspendDialog} onOpenChange={setShowSuspendDialog}>
          <AlertDialogContent>
            <AlertDialogHeader>
              <AlertDialogTitle>Suspender Corretor</AlertDialogTitle>
              <AlertDialogDescription>
                Tem certeza que deseja suspender {corretor.profiles.first_name} {corretor.profiles.last_name}?
                O corretor será temporariamente bloqueado e não poderá receber novos leads.
              </AlertDialogDescription>
            </AlertDialogHeader>
            <AlertDialogFooter>
              <AlertDialogCancel>Cancelar</AlertDialogCancel>
              <AlertDialogAction onClick={handleSuspend} className="bg-orange-600 hover:bg-orange-700">
                Suspender Corretor
              </AlertDialogAction>
            </AlertDialogFooter>
          </AlertDialogContent>
        </AlertDialog>

        {/* Dialog de Exclusão */}
        <AlertDialog open={showDeleteDialog} onOpenChange={setShowDeleteDialog}>
          <AlertDialogContent>
            <AlertDialogHeader>
              <AlertDialogTitle>Excluir Corretor</AlertDialogTitle>
              <AlertDialogDescription>
                Tem certeza que deseja excluir {corretor.profiles.first_name} {corretor.profiles.last_name}?
                O corretor será movido para a lixeira e poderá ser restaurado posteriormente.
              </AlertDialogDescription>
            </AlertDialogHeader>
            <AlertDialogFooter>
              <AlertDialogCancel>Cancelar</AlertDialogCancel>
              <AlertDialogAction onClick={handleDelete} className="bg-red-600 hover:bg-red-700">
                Excluir Corretor
              </AlertDialogAction>
            </AlertDialogFooter>
          </AlertDialogContent>
        </AlertDialog>
      </>
    );
  }

  if (corretor.status === 'bloqueado' || corretor.status === 'inativo') {
    return (
      <Button
        variant="outline"
        size="sm"
        className="text-blue-600 border-blue-600 hover:bg-blue-50"
        onClick={handleReactivate}
        disabled={updateStatusMutation.isPending}
      >
        {updateStatusMutation.isPending ? (
          <Loader2 className="w-3 h-3 mr-1 animate-spin" />
        ) : (
          <CheckCircle className="w-3 h-3 mr-1" />
        )}
        Reativar
      </Button>
    );
  }

  return (
    <Badge variant="secondary">
      {corretor.status}
    </Badge>
  );
}

import { useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { 
  DropdownMenu, 
  DropdownMenuContent, 
  DropdownMenuItem, 
  DropdownMenuTrigger 
} from "@/components/ui/dropdown-menu";
import { Badge } from "@/components/ui/badge";
import { 
  ChevronDown, 
  Phone, 
  Calendar, 
  CheckCircle, 
  XCircle,
  MessageSquare,
  Clock,
  Loader2
} from "lucide-react";
import { useToast } from "@/hooks/use-toast";

interface LeadStatusActionsProps {
  lead: {
    id: string;
    status: string;
    nome: string;
  };
}

const statusConfig = {
  'novo': {
    label: 'Novo',
    variant: 'default' as const,
    icon: Clock,
    color: 'text-gray-600'
  },
  'buscando_corretor': {
    label: 'Em Contato',
    variant: 'secondary' as const,
    icon: Phone,
    color: 'text-blue-600'
  },
  'visita_agendada': {
    label: 'Agendado',
    variant: 'outline' as const,
    icon: Calendar,
    color: 'text-orange-600'
  },
  'visita_realizada': {
    label: 'Visitou',
    variant: 'success' as const,
    icon: CheckCircle,
    color: 'text-green-600'
  },
  'cancelado': {
    label: 'Perdido',
    variant: 'destructive' as const,
    icon: XCircle,
    color: 'text-red-600'
  },
  'follow_up': {
    label: 'Follow-up',
    variant: 'outline' as const,
    icon: MessageSquare,
    color: 'text-purple-600'
  }
};

export default function LeadStatusActions({ lead }: LeadStatusActionsProps) {
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const updateStatusMutation = useMutation({
    mutationFn: async (newStatus: string) => {
      const { error } = await supabase
        .from('leads')
        .update({ status: newStatus as any })
        .eq('id', lead.id);

      if (error) throw error;
    },
    onSuccess: (_, newStatus) => {
      queryClient.invalidateQueries({ queryKey: ['leads'] });
      queryClient.invalidateQueries({ queryKey: ['my-leads'] });

      const statusLabel = statusConfig[newStatus as keyof typeof statusConfig]?.label || newStatus;
      toast({
        title: "Status atualizado",
        description: `Lead ${lead.nome} marcado como: ${statusLabel}`,
      });
    },
    onError: () => {
      toast({
        title: "Erro",
        description: "Não foi possível atualizar o status do lead.",
        variant: "destructive",
      });
    }
  });

  const currentStatus = statusConfig[lead.status as keyof typeof statusConfig];
  const CurrentIcon = currentStatus?.icon || Clock;

  const getNextStatuses = (currentStatus: string) => {
    const statusFlow = {
      'novo': ['buscando_corretor', 'cancelado'],
      'buscando_corretor': ['visita_agendada', 'follow_up', 'cancelado'],
      'visita_agendada': ['visita_realizada', 'cancelado'],
      'visita_realizada': ['follow_up'],
      'cancelado': ['buscando_corretor', 'follow_up'],
      'follow_up': ['visita_agendada', 'visita_realizada', 'cancelado']
    };

    return statusFlow[currentStatus as keyof typeof statusFlow] || [];
  };

  const nextStatuses = getNextStatuses(lead.status);

  return (
    <div className="flex items-center gap-2">
      <Badge 
        variant={currentStatus?.variant || 'default'}
        className="flex items-center gap-1"
      >
        <CurrentIcon className="w-3 h-3" />
        {currentStatus?.label || lead.status}
      </Badge>

      {nextStatuses.length > 0 && (
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button 
              variant="outline" 
              size="sm"
              disabled={updateStatusMutation.isPending}
            >
              {updateStatusMutation.isPending ? (
                <Loader2 className="w-3 h-3 animate-spin" />
              ) : (
                <>
                  Alterar Status
                  <ChevronDown className="w-3 h-3 ml-1" />
                </>
              )}
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent align="end">
            {nextStatuses.map((status) => {
              const config = statusConfig[status as keyof typeof statusConfig];
              const Icon = config?.icon || Clock;

              return (
                <DropdownMenuItem
                  key={status}
                  onClick={() => updateStatusMutation.mutate(status)}
                  className="cursor-pointer"
                >
                  <Icon className={`w-4 h-4 mr-2 ${config?.color || 'text-gray-600'}`} />
                  {config?.label || status}
                </DropdownMenuItem>
              );
            })}
          </DropdownMenuContent>
        </DropdownMenu>
      )}
    </div>
  );
}

import { Switch } from "@/components/ui/switch";
import { Button } from "@/components/ui/button";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle, AlertDialogTrigger } from "@/components/ui/alert-dialog";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Star, CheckCircle, XCircle, MessageSquare, Calendar, Eye, Trash2, RotateCcw, Trash } from "lucide-react";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useToast } from "@/hooks/use-toast";
import { useState } from "react";
import { cn } from "@/lib/utils";

interface VisitaActionsProps {
  visitaId: string;
  status: string;
  leadId: string;
  onEdit: () => void;
  onView: () => void;
  isCorretor?: boolean;
  deletedAt?: string | null;
}

export function VisitaActions({
  visitaId,
  status,
  leadId,
  onEdit,
  onView,
  isCorretor = false,
  deletedAt = null
}: VisitaActionsProps) {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [rating, setRating] = useState(0);
  const [feedback, setFeedback] = useState("");
  const [leadComments, setLeadComments] = useState("");
  const [hasInterest, setHasInterest] = useState(false);

  // Status update mutation
  const updateStatusMutation = useMutation({
    mutationFn: async ({ newStatus, data }: { newStatus: string; data?: any }) => {
      const updateData: any = { status: newStatus };

      if (data) {
        Object.assign(updateData, data);
      }

      const { error } = await supabase
        .from('visitas')
        .update(updateData)
        .eq('id', visitaId);

      if (error) throw error;

      // Update lead status based on visit status
      let leadStatus = null;
      switch (newStatus) {
        case 'confirmada':
          leadStatus = 'visita_confirmada';
          break;
        case 'realizada':
          leadStatus = 'visita_realizada';
          break;
        case 'cancelada':
          leadStatus = 'cancelado';
          break;
      }

      if (leadStatus) {
        await supabase
          .from('leads')
          .update({ status: leadStatus })
          .eq('id', leadId);
      }

      // If interested, trigger CRM integration
      if (data?.interesse) {
        try {
          const { error: fnError } = await supabase.functions.invoke('send-lead-to-crm', {
            body: { visitaId }
          });

          if (fnError) {
            console.error('Error sending to CRM:', fnError);
            toast({
              title: "Atenção",
              description: "Status salvo, mas houve erro ao enviar para o CRM.",
              variant: "destructive",
            });
          } else {
            toast({
              title: "CRM Integrado",
              description: "Lead enviado para o CRM com sucesso!",
            });
          }
        } catch (err) {
          console.error('Failed to invoke CRM function:', err);
        }
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['visitas'] });
      queryClient.invalidateQueries({ queryKey: ['my-visitas'] });
      queryClient.invalidateQueries({ queryKey: ['leads'] });

      toast({
        title: "Sucesso",
        description: "Status da visita atualizado com sucesso!",
      });
    },
    onError: (error: any) => {
      toast({
        title: "Erro",
        description: error.message || "Erro ao atualizar status",
        variant: "destructive",
      });
    }
  });

  const handleConfirm = () => {
    updateStatusMutation.mutate({ newStatus: 'confirmada' });
  };

  const handleCancel = () => {
    updateStatusMutation.mutate({ newStatus: 'cancelada' });
  };

  const handleMarkCompleted = () => {
    updateStatusMutation.mutate({
      newStatus: 'realizada',
      data: {
        avaliacao_lead: rating > 0 ? rating : null,
        feedback_corretor: feedback.trim() || null,
        comentarios_lead: leadComments.trim() || null,
        interesse: hasInterest
      }
    });
  };

  // Soft delete mutation
  const softDeleteMutation = useMutation({
    mutationFn: async () => {
      const { error } = await supabase.rpc('soft_delete_visita', {
        visita_id: visitaId
      });
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['visitas'] });
      queryClient.invalidateQueries({ queryKey: ['my-visitas'] });
      queryClient.invalidateQueries({ queryKey: ['leads'] });
      toast({
        title: "Visita movida para lixeira",
        description: "A visita foi movida para a lixeira com sucesso.",
      });
    },
    onError: (error: any) => {
      toast({
        title: "Erro ao excluir",
        description: error.message,
        variant: "destructive",
      });
    }
  });

  // Restore mutation
  const restoreMutation = useMutation({
    mutationFn: async () => {
      const { error } = await supabase.rpc('restore_visita', {
        visita_id: visitaId
      });
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['visitas'] });
      queryClient.invalidateQueries({ queryKey: ['my-visitas'] });
      queryClient.invalidateQueries({ queryKey: ['leads'] });
      toast({
        title: "Visita restaurada",
        description: "A visita foi restaurada com sucesso.",
      });
    },
    onError: (error: any) => {
      toast({
        title: "Erro ao restaurar",
        description: error.message,
        variant: "destructive",
      });
    }
  });

  // Hard delete mutation
  const hardDeleteMutation = useMutation({
    mutationFn: async () => {
      const { error } = await supabase.rpc('hard_delete_visita', {
        visita_id: visitaId
      });
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['visitas'] });
      queryClient.invalidateQueries({ queryKey: ['my-visitas'] });
      toast({
        title: "Visita excluída permanentemente",
        description: "A visita foi excluída permanentemente do sistema.",
      });
    },
    onError: (error: any) => {
      toast({
        title: "Erro ao excluir permanentemente",
        description: error.message,
        variant: "destructive",
      });
    }
  });

  // Send reminder mutation
  const sendReminderMutation = useMutation({
    mutationFn: async () => {
      // Fetch visit details to compose the message
      const { data: visita, error: visitaError } = await supabase
        .from('visitas')
        .select(`
          id, data_visita, horario_visita,
          lead:leads!inner(nome, telefone),
          corretor:corretores(whatsapp, profiles(first_name)),
          empreendimento:empreendimentos(nome)
        `)
        .eq('id', visitaId)
        .single();

      if (visitaError || !visita) throw new Error('Dados da visita não encontrados');

      const lead = visita.lead as any;
      const corretor = visita.corretor as any;
      const empreendimento = visita.empreendimento as any;
      const dataVisita = new Date(visita.data_visita).toLocaleDateString('pt-BR');

      // Send to Lead
      if (lead?.telefone) {
        const msgLead = `⏰ *LEMBRETE DE VISITA*\n\nOlá ${lead.nome}, sua visita ao *${empreendimento?.nome}* é em breve.\n\n🕒 Data: ${dataVisita}\n⏰ Horário: ${visita.horario_visita}\n📍 Corretor: ${corretor?.profiles?.first_name || 'A definir'}\n\n⚠️ *Precisamos confirmar sua presença.*\nResponda *SIM* para confirmar ou *NÃO* para cancelar.`;

        const { error: leadError } = await supabase.functions.invoke('evolution-send-whatsapp-v2', {
          body: {
            phone_number: lead.telefone,
            message: msgLead,
            metadata: {
              visita_id: visitaId,
              type: 'manual_reminder',
              target: 'client',
              context: 'visit_reminder'
            }
          }
        });

        if (leadError) console.error('Erro ao enviar lembrete ao lead:', leadError);
      }

      // Send to Corretor
      if (corretor?.whatsapp) {
        const msgCorretor = `⏰ *LEMBRETE DE VISITA*\n\nCorretor(a) ${corretor.profiles?.first_name}, sua visita com *${lead.nome}* é em breve.\n\n🏢 ${empreendimento?.nome}\n🕒 Data: ${dataVisita}\n⏰ Horário: ${visita.horario_visita}\n\n⚠️ *Precisamos confirmar sua presença.*\nResponda *SIM* para confirmar ou *NÃO* se não puder comparecer.`;

        const { error: corretorError } = await supabase.functions.invoke('evolution-send-whatsapp-v2', {
          body: {
            phone_number: corretor.whatsapp,
            message: msgCorretor,
            metadata: {
              visita_id: visitaId,
              type: 'manual_reminder',
              target: 'corretor',
              context: 'visit_reminder'
            }
          }
        });

        if (corretorError) console.error('Erro ao enviar lembrete ao corretor:', corretorError);
      }
    },
    onSuccess: () => {
      toast({
        title: "Lembrete Enviado",
        description: "Lembrete enviado para o lead e corretor via WhatsApp.",
      });
    },
    onError: (error: any) => {
      toast({
        title: "Erro ao enviar lembrete",
        description: error.message,
        variant: "destructive",
      });
    }
  });

  const renderStars = () => {
    return Array.from({ length: 5 }, (_, i) => (
      <Star
        key={i}
        className={cn(
          "w-5 h-5 cursor-pointer transition-colors",
          i < rating ? "fill-yellow-400 text-yellow-400" : "text-muted-foreground hover:text-yellow-400"
        )}
        onClick={() => setRating(i + 1)}
      />
    ));
  };

  // If deleted, show different actions
  if (deletedAt) {
    return (
      <div className="flex items-center gap-2">
        {/* Restore */}
        <AlertDialog>
          <AlertDialogTrigger asChild>
            <Button
              variant="outline"
              size="sm"
              className="text-green-600 border-green-600 hover:bg-green-50"
            >
              <RotateCcw className="w-3 h-3 mr-1" />
              Restaurar
            </Button>
          </AlertDialogTrigger>
          <AlertDialogContent>
            <AlertDialogHeader>
              <AlertDialogTitle>Restaurar Visita</AlertDialogTitle>
              <AlertDialogDescription>
                Deseja restaurar esta visita? Ela voltará para a lista de visitas ativas.
              </AlertDialogDescription>
            </AlertDialogHeader>
            <AlertDialogFooter>
              <AlertDialogCancel>Cancelar</AlertDialogCancel>
              <AlertDialogAction
                onClick={() => restoreMutation.mutate()}
                disabled={restoreMutation.isPending}
              >
                {restoreMutation.isPending ? "Restaurando..." : "Restaurar"}
              </AlertDialogAction>
            </AlertDialogFooter>
          </AlertDialogContent>
        </AlertDialog>

        {/* Hard Delete */}
        {!isCorretor && (
          <AlertDialog>
            <AlertDialogTrigger asChild>
              <Button
                variant="outline"
                size="sm"
                className="text-red-600 border-red-600 hover:bg-red-50"
              >
                <Trash className="w-3 h-3 mr-1" />
                Excluir Permanentemente
              </Button>
            </AlertDialogTrigger>
            <AlertDialogContent>
              <AlertDialogHeader>
                <AlertDialogTitle>Excluir Permanentemente</AlertDialogTitle>
                <AlertDialogDescription className="text-red-600 font-medium">
                  ⚠️ ATENÇÃO: Esta ação é IRREVERSÍVEL! A visita será excluída permanentemente do sistema e não poderá ser recuperada.
                </AlertDialogDescription>
              </AlertDialogHeader>
              <AlertDialogFooter>
                <AlertDialogCancel>Cancelar</AlertDialogCancel>
                <AlertDialogAction
                  onClick={() => hardDeleteMutation.mutate()}
                  disabled={hardDeleteMutation.isPending}
                  className="bg-red-600 hover:bg-red-700"
                >
                  {hardDeleteMutation.isPending ? "Excluindo..." : "Sim, Excluir Permanentemente"}
                </AlertDialogAction>
              </AlertDialogFooter>
            </AlertDialogContent>
          </AlertDialog>
        )}

        {/* View Details */}
        <Button
          variant="outline"
          size="sm"
          onClick={onView}
        >
          <Eye className="w-3 h-3 mr-1" />
          Detalhes
        </Button>
      </div>
    );
  }

  return (
    <div className="flex items-center gap-2">
      {/* Confirm Visit */}
      {(status === 'agendada' || status === 'reagendada') && (
        <AlertDialog>
          <AlertDialogTrigger asChild>
            <Button
              variant="outline"
              size="sm"
              className="text-green-600 border-green-600 hover:bg-green-50"
            >
              <CheckCircle className="w-3 h-3 mr-1" />
              Confirmar
            </Button>
          </AlertDialogTrigger>
          <AlertDialogContent>
            <AlertDialogHeader>
              <AlertDialogTitle>Confirmar Visita</AlertDialogTitle>
              <AlertDialogDescription>
                Deseja confirmar esta visita? O lead será notificado sobre a confirmação.
              </AlertDialogDescription>
            </AlertDialogHeader>
            <AlertDialogFooter>
              <AlertDialogCancel>Cancelar</AlertDialogCancel>
              <AlertDialogAction
                onClick={handleConfirm}
                disabled={updateStatusMutation.isPending}
              >
                {updateStatusMutation.isPending ? "Confirmando..." : "Confirmar"}
              </AlertDialogAction>
            </AlertDialogFooter>
          </AlertDialogContent>
        </AlertDialog>
      )}

      {/* Mark as Completed */}
      {(status === 'confirmada' || ((status === 'agendada' || status === 'reagendada') && isCorretor)) && (
        <Dialog>
          <DialogTrigger asChild>
            <Button
              variant="outline"
              size="sm"
              className="text-blue-600 border-blue-600 hover:bg-blue-50"
            >
              <CheckCircle className="w-3 h-3 mr-1" />
              Marcar Realizada
            </Button>
          </DialogTrigger>
          <DialogContent className="max-w-md">
            <DialogHeader>
              <DialogTitle>Marcar Visita como Realizada</DialogTitle>
            </DialogHeader>
            <div className="space-y-4">
              <div className="space-y-2">
                <Label>Avaliação da Visita</Label>
                <div className="flex items-center gap-2">
                  <div className="flex gap-1">
                    {renderStars()}
                  </div>
                  <span className="text-sm text-muted-foreground">
                    {rating > 0 && `${rating}/5`}
                  </span>
                </div>
              </div>

              <div className="space-y-2">
                <Label htmlFor="leadComments">Comentários do Lead</Label>
                <Textarea
                  id="leadComments"
                  value={leadComments}
                  onChange={(e) => setLeadComments(e.target.value)}
                  placeholder="Comentários ou feedback do lead sobre a visita..."
                  className="min-h-[60px]"
                />
              </div>

              <div className="flex items-center space-x-2 py-2">
                <Switch
                  id="interest-mode"
                  checked={hasInterest}
                  onCheckedChange={setHasInterest}
                />
                <Label htmlFor="interest-mode" className="font-medium text-primary">
                  Cliente tem interesse na compra?
                </Label>
              </div>

              <div className="space-y-2">
                <Label htmlFor="feedback">Seu Feedback</Label>
                <Textarea
                  id="feedback"
                  value={feedback}
                  onChange={(e) => setFeedback(e.target.value)}
                  placeholder="Adicione seu feedback sobre esta visita..."
                  className="min-h-[60px]"
                />
              </div>

              <div className="flex justify-end gap-2">
                <Button
                  variant="outline"
                  onClick={() => {
                    setRating(0);
                    setFeedback("");
                    setLeadComments("");
                  }}
                >
                  Cancelar
                </Button>
                <Button
                  onClick={handleMarkCompleted}
                  disabled={updateStatusMutation.isPending}
                >
                  {updateStatusMutation.isPending ? "Salvando..." : "Marcar Realizada"}
                </Button>
              </div>
            </div>
          </DialogContent>
        </Dialog>
      )}

      {/* Cancel Visit */}
      {(status === 'agendada' || status === 'confirmada' || status === 'reagendada') && (
        <AlertDialog>
          <AlertDialogTrigger asChild>
            <Button
              variant="outline"
              size="sm"
              className="text-red-600 border-red-600 hover:bg-red-50"
            >
              <XCircle className="w-3 h-3 mr-1" />
              Cancelar
            </Button>
          </AlertDialogTrigger>
          <AlertDialogContent>
            <AlertDialogHeader>
              <AlertDialogTitle>Cancelar Visita</AlertDialogTitle>
              <AlertDialogDescription>
                Deseja cancelar esta visita? Esta ação irá alterar o status do lead.
              </AlertDialogDescription>
            </AlertDialogHeader>
            <AlertDialogFooter>
              <AlertDialogCancel>Não</AlertDialogCancel>
              <AlertDialogAction
                onClick={handleCancel}
                disabled={updateStatusMutation.isPending}
                className="bg-red-600 hover:bg-red-700"
              >
                {updateStatusMutation.isPending ? "Cancelando..." : "Sim, Cancelar"}
              </AlertDialogAction>
            </AlertDialogFooter>
          </AlertDialogContent>
        </AlertDialog>
      )}

      {/* Reschedule */}
      {status === 'cancelada' && (
        <Button
          variant="outline"
          size="sm"
          className="text-orange-600 border-orange-600 hover:bg-orange-50"
          onClick={onEdit}
        >
          <Calendar className="w-3 h-3 mr-1" />
          Reagendar
        </Button>
      )}

      {/* Send Reminder */}
      {(status === 'agendada' || status === 'confirmada' || status === 'reagendada') && (
        <Button
          variant="outline"
          size="sm"
          className="text-purple-600 border-purple-600 hover:bg-purple-50"
          onClick={() => sendReminderMutation.mutate()}
          disabled={sendReminderMutation.isPending}
        >
          <MessageSquare className="w-3 h-3 mr-1" />
          {sendReminderMutation.isPending ? "Enviando..." : "Lembrete"}
        </Button>
      )}

      {/* View Details */}
      <Button
        variant="outline"
        size="sm"
        onClick={onView}
      >
        <Eye className="w-3 h-3 mr-1" />
        Detalhes
      </Button>

      {/* Edit */}
      {!isCorretor && (
        <Button
          variant="outline"
          size="sm"
          onClick={onEdit}
        >
          Editar
        </Button>
      )}

      {/* Soft Delete */}
      {!isCorretor && (status === 'agendada' || status === 'cancelada' || status === 'reagendada') && (
        <AlertDialog>
          <AlertDialogTrigger asChild>
            <Button
              variant="outline"
              size="sm"
              className="text-red-600 border-red-600 hover:bg-red-50"
            >
              <Trash2 className="w-3 h-3 mr-1" />
              Excluir
            </Button>
          </AlertDialogTrigger>
          <AlertDialogContent>
            <AlertDialogHeader>
              <AlertDialogTitle>Excluir Visita</AlertDialogTitle>
              <AlertDialogDescription>
                Deseja mover esta visita para a lixeira? Você poderá restaurá-la posteriormente se necessário.
              </AlertDialogDescription>
            </AlertDialogHeader>
            <AlertDialogFooter>
              <AlertDialogCancel>Cancelar</AlertDialogCancel>
              <AlertDialogAction
                onClick={() => softDeleteMutation.mutate()}
                disabled={softDeleteMutation.isPending}
                className="bg-red-600 hover:bg-red-700"
              >
                {softDeleteMutation.isPending ? "Excluindo..." : "Sim, Excluir"}
              </AlertDialogAction>
            </AlertDialogFooter>
          </AlertDialogContent>
        </AlertDialog>
      )}
    </div>
  );
}

import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle, CardDescription, CardFooter } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger, DialogFooter, DialogDescription } from "@/components/ui/dialog";
import { Progress } from "@/components/ui/progress";
import { toast } from "sonner";
import {
    FlaskConical,
    Plus,
    Play,
    Pause,
    CheckCircle,
    XCircle,
    BarChart3,
    Users,
    TrendingUp
} from "lucide-react";

interface ABTestingManagerProps {
    agentId: string;
}

interface Experiment {
    id: string;
    agent_id: string;
    name: string;
    description: string | null;
    experiment_type: string;
    variants: {
        id: string;
        weight: number;
        config: Record<string, any>;
    }[];
    primary_metric: string;
    secondary_metrics: string[];
    status: "draft" | "running" | "paused" | "completed" | "cancelled";
    started_at: string | null;
    ended_at: string | null;
    target_sample_size: number;
    created_at: string;
}

interface ExperimentResult {
    variant_id: string;
    sample_size: number;
    conversions: number;
    conversion_rate: number;
    avg_metric_value: number;
    confidence_level: string;
}

const EXPERIMENT_TYPES = [
    { value: "prompt_variation", label: "Variação de Prompt" },
    { value: "greeting_message", label: "Mensagem de Saudação" },
    { value: "followup_timing", label: "Timing de Follow-up" },
    { value: "response_style", label: "Estilo de Resposta" },
    { value: "objection_handling", label: "Tratamento de Objeções" },
    { value: "qualification_order", label: "Ordem de Qualificação" }
];

const METRICS = [
    { value: "conversion_rate", label: "Taxa de Conversão" },
    { value: "qualification_rate", label: "Taxa de Qualificação" },
    { value: "avg_bant_score", label: "BANT Score Médio" },
    { value: "avg_messages", label: "Média de Mensagens" },
    { value: "visit_schedule_rate", label: "Taxa de Visita" },
    { value: "response_time", label: "Tempo de Resposta" }
];

export function ABTestingManager({ agentId }: ABTestingManagerProps) {
    const queryClient = useQueryClient();
    const [isCreateOpen, setIsCreateOpen] = useState(false);
    const [selectedExperiment, setSelectedExperiment] = useState<string | null>(null);

    // Form state
    const [newExperiment, setNewExperiment] = useState({
        name: "",
        description: "",
        experiment_type: "prompt_variation",
        primary_metric: "conversion_rate",
        target_sample_size: 100,
        variants: [
            { id: "control", weight: 50, config: { name: "Controle" } },
            { id: "variant_a", weight: 50, config: { name: "Variante A" } }
        ]
    });

    // Fetch experiments
    const { data: experiments, isLoading } = useQuery({
        queryKey: ["ab-experiments", agentId],
        queryFn: async () => {
            const { data, error } = await supabase
                .from("ab_experiments")
                .select("*")
                .eq("agent_id", agentId)
                .order("created_at", { ascending: false });

            if (error) throw error;
            return data as Experiment[];
        }
    });

    // Fetch results for selected experiment
    const { data: experimentResults } = useQuery({
        queryKey: ["ab-results", selectedExperiment],
        queryFn: async () => {
            if (!selectedExperiment) return null;
            const { data, error } = await supabase.rpc("get_ab_test_results", {
                p_experiment_id: selectedExperiment
            });
            if (error) throw error;
            return data as ExperimentResult[];
        },
        enabled: !!selectedExperiment
    });

    // Create experiment mutation
    const createMutation = useMutation({
        mutationFn: async (experiment: typeof newExperiment) => {
            const { data, error } = await supabase
                .from("ab_experiments")
                .insert({
                    agent_id: agentId,
                    name: experiment.name,
                    description: experiment.description || null,
                    experiment_type: experiment.experiment_type,
                    variants: experiment.variants,
                    primary_metric: experiment.primary_metric,
                    target_sample_size: experiment.target_sample_size,
                    status: "draft"
                })
                .select()
                .single();

            if (error) throw error;
            return data;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ["ab-experiments"] });
            setIsCreateOpen(false);
            setNewExperiment({
                name: "",
                description: "",
                experiment_type: "prompt_variation",
                primary_metric: "conversion_rate",
                target_sample_size: 100,
                variants: [
                    { id: "control", weight: 50, config: { name: "Controle" } },
                    { id: "variant_a", weight: 50, config: { name: "Variante A" } }
                ]
            });
            toast.success("Experimento criado com sucesso!");
        },
        onError: (error) => {
            toast.error("Erro ao criar experimento: " + error.message);
        }
    });

    // Update status mutation
    const statusMutation = useMutation({
        mutationFn: async ({ id, status }: { id: string; status: string }) => {
            const updates: Record<string, any> = { status };
            if (status === "running") {
                updates.started_at = new Date().toISOString();
            } else if (status === "completed" || status === "cancelled") {
                updates.ended_at = new Date().toISOString();
            }

            const { error } = await supabase
                .from("ab_experiments")
                .update(updates)
                .eq("id", id);

            if (error) throw error;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ["ab-experiments"] });
            toast.success("Status atualizado!");
        }
    });

    const getStatusBadge = (status: string) => {
        const configs: Record<string, { variant: "default" | "secondary" | "destructive" | "outline"; label: string }> = {
            draft: { variant: "outline", label: "Rascunho" },
            running: { variant: "default", label: "Em Execução" },
            paused: { variant: "secondary", label: "Pausado" },
            completed: { variant: "secondary", label: "Concluído" },
            cancelled: { variant: "destructive", label: "Cancelado" }
        };
        const config = configs[status] || configs.draft;
        return <Badge variant={config.variant}>{config.label}</Badge>;
    };

    const getTotalSamples = (results: ExperimentResult[] | null) => {
        if (!results) return 0;
        return results.reduce((sum, r) => sum + r.sample_size, 0);
    };

    if (isLoading) {
        return (
            <div className="flex items-center justify-center h-48">
                <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary" />
            </div>
        );
    }

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-2xl font-bold flex items-center gap-2">
                        <FlaskConical className="h-6 w-6" />
                        A/B Testing
                    </h2>
                    <p className="text-muted-foreground">
                        Gerencie experimentos para otimizar a performance do agente
                    </p>
                </div>

                <Dialog open={isCreateOpen} onOpenChange={setIsCreateOpen}>
                    <DialogTrigger asChild>
                        <Button>
                            <Plus className="h-4 w-4 mr-2" />
                            Novo Experimento
                        </Button>
                    </DialogTrigger>
                    <DialogContent className="max-w-2xl">
                        <DialogHeader>
                            <DialogTitle>Criar Novo Experimento</DialogTitle>
                            <DialogDescription>
                                Configure um novo teste A/B para o agente
                            </DialogDescription>
                        </DialogHeader>

                        <div className="grid gap-4 py-4">
                            <div className="grid gap-2">
                                <Label htmlFor="name">Nome do Experimento</Label>
                                <Input
                                    id="name"
                                    value={newExperiment.name}
                                    onChange={(e) => setNewExperiment({
                                        ...newExperiment,
                                        name: e.target.value
                                    })}
                                    placeholder="Ex: Teste de saudação personalizada"
                                />
                            </div>

                            <div className="grid gap-2">
                                <Label htmlFor="description">Descrição</Label>
                                <Textarea
                                    id="description"
                                    value={newExperiment.description}
                                    onChange={(e) => setNewExperiment({
                                        ...newExperiment,
                                        description: e.target.value
                                    })}
                                    placeholder="Descreva o objetivo do experimento..."
                                />
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <div className="grid gap-2">
                                    <Label>Tipo de Experimento</Label>
                                    <Select
                                        value={newExperiment.experiment_type}
                                        onValueChange={(v) => setNewExperiment({
                                            ...newExperiment,
                                            experiment_type: v
                                        })}
                                    >
                                        <SelectTrigger>
                                            <SelectValue />
                                        </SelectTrigger>
                                        <SelectContent>
                                            {EXPERIMENT_TYPES.map((type) => (
                                                <SelectItem key={type.value} value={type.value}>
                                                    {type.label}
                                                </SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                </div>

                                <div className="grid gap-2">
                                    <Label>Métrica Principal</Label>
                                    <Select
                                        value={newExperiment.primary_metric}
                                        onValueChange={(v) => setNewExperiment({
                                            ...newExperiment,
                                            primary_metric: v
                                        })}
                                    >
                                        <SelectTrigger>
                                            <SelectValue />
                                        </SelectTrigger>
                                        <SelectContent>
                                            {METRICS.map((metric) => (
                                                <SelectItem key={metric.value} value={metric.value}>
                                                    {metric.label}
                                                </SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                </div>
                            </div>

                            <div className="grid gap-2">
                                <Label>Tamanho da Amostra</Label>
                                <Input
                                    type="number"
                                    value={newExperiment.target_sample_size}
                                    onChange={(e) => setNewExperiment({
                                        ...newExperiment,
                                        target_sample_size: parseInt(e.target.value) || 100
                                    })}
                                />
                                <p className="text-xs text-muted-foreground">
                                    Número de conversas para cada variante
                                </p>
                            </div>
                        </div>

                        <DialogFooter>
                            <Button variant="outline" onClick={() => setIsCreateOpen(false)}>
                                Cancelar
                            </Button>
                            <Button
                                onClick={() => createMutation.mutate(newExperiment)}
                                disabled={!newExperiment.name || createMutation.isPending}
                            >
                                Criar Experimento
                            </Button>
                        </DialogFooter>
                    </DialogContent>
                </Dialog>
            </div>

            {/* Experiments Grid */}
            {experiments?.length === 0 ? (
                <Card className="p-8 text-center">
                    <FlaskConical className="h-12 w-12 mx-auto text-muted-foreground mb-4" />
                    <h3 className="text-lg font-medium mb-2">Nenhum experimento</h3>
                    <p className="text-muted-foreground mb-4">
                        Crie seu primeiro teste A/B para otimizar o agente
                    </p>
                    <Button onClick={() => setIsCreateOpen(true)}>
                        <Plus className="h-4 w-4 mr-2" />
                        Criar Experimento
                    </Button>
                </Card>
            ) : (
                <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
                    {experiments?.map((exp) => (
                        <Card
                            key={exp.id}
                            className={`cursor-pointer transition-shadow hover:shadow-md ${selectedExperiment === exp.id ? 'ring-2 ring-primary' : ''
                                }`}
                            onClick={() => setSelectedExperiment(
                                selectedExperiment === exp.id ? null : exp.id
                            )}
                        >
                            <CardHeader>
                                <div className="flex items-start justify-between">
                                    <div>
                                        <CardTitle className="text-base">{exp.name}</CardTitle>
                                        <CardDescription className="text-xs mt-1">
                                            {EXPERIMENT_TYPES.find(t => t.value === exp.experiment_type)?.label}
                                        </CardDescription>
                                    </div>
                                    {getStatusBadge(exp.status)}
                                </div>
                            </CardHeader>
                            <CardContent>
                                <div className="text-sm text-muted-foreground mb-4">
                                    {exp.description || "Sem descrição"}
                                </div>

                                <div className="grid grid-cols-2 gap-2 text-sm">
                                    <div className="flex items-center gap-1">
                                        <Users className="h-3 w-3" />
                                        <span>{exp.variants.length} variantes</span>
                                    </div>
                                    <div className="flex items-center gap-1">
                                        <BarChart3 className="h-3 w-3" />
                                        <span>{exp.target_sample_size} amostra</span>
                                    </div>
                                </div>
                            </CardContent>
                            <CardFooter className="flex gap-2">
                                {exp.status === "draft" && (
                                    <Button
                                        size="sm"
                                        onClick={(e) => {
                                            e.stopPropagation();
                                            statusMutation.mutate({ id: exp.id, status: "running" });
                                        }}
                                    >
                                        <Play className="h-3 w-3 mr-1" />
                                        Iniciar
                                    </Button>
                                )}
                                {exp.status === "running" && (
                                    <>
                                        <Button
                                            size="sm"
                                            variant="outline"
                                            onClick={(e) => {
                                                e.stopPropagation();
                                                statusMutation.mutate({ id: exp.id, status: "paused" });
                                            }}
                                        >
                                            <Pause className="h-3 w-3 mr-1" />
                                            Pausar
                                        </Button>
                                        <Button
                                            size="sm"
                                            onClick={(e) => {
                                                e.stopPropagation();
                                                statusMutation.mutate({ id: exp.id, status: "completed" });
                                            }}
                                        >
                                            <CheckCircle className="h-3 w-3 mr-1" />
                                            Concluir
                                        </Button>
                                    </>
                                )}
                                {exp.status === "paused" && (
                                    <Button
                                        size="sm"
                                        onClick={(e) => {
                                            e.stopPropagation();
                                            statusMutation.mutate({ id: exp.id, status: "running" });
                                        }}
                                    >
                                        <Play className="h-3 w-3 mr-1" />
                                        Retomar
                                    </Button>
                                )}
                            </CardFooter>
                        </Card>
                    ))}
                </div>
            )}

            {/* Results Detail */}
            {selectedExperiment && experimentResults && (
                <Card>
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <TrendingUp className="h-5 w-5" />
                            Resultados do Experimento
                        </CardTitle>
                        <CardDescription>
                            Total de amostras: {getTotalSamples(experimentResults)}
                        </CardDescription>
                    </CardHeader>
                    <CardContent>
                        <div className="space-y-4">
                            {experimentResults.map((result, index) => (
                                <div key={result.variant_id} className="space-y-2">
                                    <div className="flex items-center justify-between">
                                        <div className="flex items-center gap-2">
                                            <Badge variant={index === 0 ? "default" : "outline"}>
                                                {result.variant_id === "control" ? "Controle" : result.variant_id}
                                            </Badge>
                                            {index === 0 && (
                                                <Badge variant="secondary" className="text-xs">
                                                    Vencedor
                                                </Badge>
                                            )}
                                        </div>
                                        <div className="text-sm">
                                            <span className="font-bold text-lg">{result.conversion_rate}%</span>
                                            <span className="text-muted-foreground ml-2">
                                                ({result.conversions}/{result.sample_size})
                                            </span>
                                        </div>
                                    </div>
                                    <Progress value={result.conversion_rate} className="h-2" />
                                    <div className="flex justify-between text-xs text-muted-foreground">
                                        <span>Métrica média: {result.avg_metric_value}</span>
                                        <span>{result.confidence_level}</span>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </CardContent>
                </Card>
            )}
        </div>
    );
}

import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Progress } from "@/components/ui/progress";
import {
    TrendingUp,
    TrendingDown,
    MessageSquare,
    Users,
    Target,
    Calendar,
    Flame,
    Thermometer,
    Snowflake,
    Activity,
    Zap,
    BarChart3
} from "lucide-react";

interface AgentAnalyticsDashboardProps {
    agentId?: string;
}

interface DashboardStat {
    metric_name: string;
    current_value: number;
    previous_value: number;
    change_percentage: number;
}

interface FunnelEvent {
    event_type: string;
    count: number;
    percentage: number;
    avg_time_to_event_hours: number;
}

interface TemperatureStat {
    temperature: string;
    count: number;
    percentage: number;
}

export function AgentAnalyticsDashboard({ agentId }: AgentAnalyticsDashboardProps) {
    const [dateRange, setDateRange] = useState("7");

    // Fetch dashboard stats
    const { data: dashboardStats, isLoading: statsLoading } = useQuery({
        queryKey: ["agent-dashboard-stats", agentId, dateRange],
        queryFn: async () => {
            const { data, error } = await supabase.rpc("get_agent_dashboard_stats", {
                p_agent_id: agentId || null,
                p_days: parseInt(dateRange)
            });
            if (error) throw error;
            return data as DashboardStat[];
        }
    });

    // Fetch conversion funnel
    const { data: funnelData, isLoading: funnelLoading } = useQuery({
        queryKey: ["conversion-funnel", agentId, dateRange],
        queryFn: async () => {
            const { data, error } = await supabase.rpc("get_conversion_funnel", {
                p_agent_id: agentId || null,
                p_days: parseInt(dateRange)
            });
            if (error) throw error;
            return data as FunnelEvent[];
        }
    });

    // Fetch temperature distribution
    const { data: temperatureStats, isLoading: tempLoading } = useQuery({
        queryKey: ["temperature-stats", agentId, dateRange],
        queryFn: async () => {
            const { data, error } = await supabase.rpc("get_lead_temperature_stats", {
                p_agent_id: agentId || null,
                p_days: parseInt(dateRange)
            });
            if (error) throw error;
            return data as TemperatureStat[];
        }
    });

    // Fetch recent activity
    const { data: recentActivity } = useQuery({
        queryKey: ["recent-activity", agentId],
        queryFn: async () => {
            let query = supabase
                .from("agent_activity_log")
                .select("*")
                .order("created_at", { ascending: false })
                .limit(10);

            if (agentId) {
                query = query.eq("agent_id", agentId);
            }

            const { data, error } = await query;
            if (error) throw error;
            return data;
        }
    });

    const getStatIcon = (name: string) => {
        const icons: Record<string, React.ReactNode> = {
            "Conversas": <MessageSquare className="h-4 w-4" />,
            "Leads Qualificados": <Users className="h-4 w-4" />,
            "Leads Hot/Warm": <Flame className="h-4 w-4" />,
            "Visitas Agendadas": <Calendar className="h-4 w-4" />,
            "BANT Score Médio": <Target className="h-4 w-4" />
        };
        return icons[name] || <BarChart3 className="h-4 w-4" />;
    };

    const getTemperatureConfig = (temp: string) => {
        const configs: Record<string, { icon: React.ReactNode; color: string; bg: string }> = {
            hot: { icon: <Flame className="h-4 w-4" />, color: "text-red-500", bg: "bg-red-500" },
            warm: { icon: <Thermometer className="h-4 w-4" />, color: "text-orange-500", bg: "bg-orange-500" },
            cool: { icon: <Snowflake className="h-4 w-4" />, color: "text-blue-400", bg: "bg-blue-400" },
            cold: { icon: <Snowflake className="h-4 w-4" />, color: "text-gray-400", bg: "bg-gray-400" }
        };
        return configs[temp] || configs.cold;
    };

    const getFunnelEventLabel = (eventType: string) => {
        const labels: Record<string, string> = {
            conversation_started: "Conversa Iniciada",
            first_response: "Primeira Resposta",
            qualification_started: "Qualificação Iniciada",
            property_searched: "Busca de Imóveis",
            property_presented: "Imóveis Apresentados",
            interest_shown: "Interesse Demonstrado",
            visit_requested: "Visita Solicitada",
            visit_scheduled: "Visita Agendada",
            converted: "Convertido",
            lost: "Perdido"
        };
        return labels[eventType] || eventType;
    };

    const getActivityIcon = (type: string) => {
        const icons: Record<string, React.ReactNode> = {
            message_received: <MessageSquare className="h-3 w-3 text-blue-500" />,
            message_sent: <MessageSquare className="h-3 w-3 text-green-500" />,
            intent_detected: <Target className="h-3 w-3 text-purple-500" />,
            objection_detected: <Zap className="h-3 w-3 text-orange-500" />,
            action_executed: <Activity className="h-3 w-3 text-blue-600" />,
            handoff_triggered: <Users className="h-3 w-3 text-red-500" />,
            error_occurred: <Zap className="h-3 w-3 text-red-600" />
        };
        return icons[type] || <Activity className="h-3 w-3" />;
    };

    if (statsLoading) {
        return (
            <div className="flex items-center justify-center h-48">
                <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary" />
            </div>
        );
    }

    return (
        <div className="space-y-6">
            {/* Header with date range selector */}
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-2xl font-bold">Analytics Dashboard</h2>
                    <p className="text-muted-foreground">Métricas de performance do agente IA</p>
                </div>
                <Select value={dateRange} onValueChange={setDateRange}>
                    <SelectTrigger className="w-[180px]">
                        <SelectValue placeholder="Período" />
                    </SelectTrigger>
                    <SelectContent>
                        <SelectItem value="7">Últimos 7 dias</SelectItem>
                        <SelectItem value="14">Últimos 14 dias</SelectItem>
                        <SelectItem value="30">Últimos 30 dias</SelectItem>
                        <SelectItem value="90">Últimos 90 dias</SelectItem>
                    </SelectContent>
                </Select>
            </div>

            {/* KPI Cards */}
            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-5">
                {dashboardStats?.map((stat) => (
                    <Card key={stat.metric_name}>
                        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                            <CardTitle className="text-sm font-medium">
                                {stat.metric_name}
                            </CardTitle>
                            {getStatIcon(stat.metric_name)}
                        </CardHeader>
                        <CardContent>
                            <div className="text-2xl font-bold">
                                {stat.current_value?.toLocaleString("pt-BR") || "0"}
                            </div>
                            <div className="flex items-center text-xs text-muted-foreground">
                                {stat.change_percentage > 0 ? (
                                    <>
                                        <TrendingUp className="h-3 w-3 text-green-500 mr-1" />
                                        <span className="text-green-500">+{stat.change_percentage}%</span>
                                    </>
                                ) : stat.change_percentage < 0 ? (
                                    <>
                                        <TrendingDown className="h-3 w-3 text-red-500 mr-1" />
                                        <span className="text-red-500">{stat.change_percentage}%</span>
                                    </>
                                ) : (
                                    <span>Sem alteração</span>
                                )}
                                <span className="ml-1">vs período anterior</span>
                            </div>
                        </CardContent>
                    </Card>
                ))}
            </div>

            <Tabs defaultValue="funnel" className="w-full">
                <TabsList>
                    <TabsTrigger value="funnel">Funil de Conversão</TabsTrigger>
                    <TabsTrigger value="temperature">Temperatura de Leads</TabsTrigger>
                    <TabsTrigger value="activity">Atividade Recente</TabsTrigger>
                </TabsList>

                {/* Conversion Funnel */}
                <TabsContent value="funnel">
                    <Card>
                        <CardHeader>
                            <CardTitle>Funil de Conversão</CardTitle>
                            <CardDescription>
                                Progressão dos leads através do funil de vendas
                            </CardDescription>
                        </CardHeader>
                        <CardContent>
                            {funnelLoading ? (
                                <div className="animate-pulse space-y-2">
                                    {[1, 2, 3, 4, 5].map((i) => (
                                        <div key={i} className="h-10 bg-muted rounded" />
                                    ))}
                                </div>
                            ) : (
                                <div className="space-y-4">
                                    {funnelData?.map((event, index) => (
                                        <div key={event.event_type} className="space-y-2">
                                            <div className="flex items-center justify-between text-sm">
                                                <span className="font-medium">
                                                    {getFunnelEventLabel(event.event_type)}
                                                </span>
                                                <div className="flex items-center gap-4">
                                                    <Badge variant="outline">
                                                        {event.count} leads
                                                    </Badge>
                                                    <span className="text-muted-foreground w-16 text-right">
                                                        {event.percentage}%
                                                    </span>
                                                </div>
                                            </div>
                                            <Progress
                                                value={event.percentage}
                                                className="h-2"
                                                style={{
                                                    opacity: 1 - (index * 0.1)
                                                }}
                                            />
                                            {event.avg_time_to_event_hours > 0 && (
                                                <p className="text-xs text-muted-foreground">
                                                    Tempo médio: {event.avg_time_to_event_hours.toFixed(1)}h
                                                </p>
                                            )}
                                        </div>
                                    ))}
                                </div>
                            )}
                        </CardContent>
                    </Card>
                </TabsContent>

                {/* Temperature Distribution */}
                <TabsContent value="temperature">
                    <Card>
                        <CardHeader>
                            <CardTitle>Distribuição por Temperatura</CardTitle>
                            <CardDescription>
                                Classificação dos leads por nível de engajamento
                            </CardDescription>
                        </CardHeader>
                        <CardContent>
                            {tempLoading ? (
                                <div className="animate-pulse space-y-2">
                                    {[1, 2, 3, 4].map((i) => (
                                        <div key={i} className="h-16 bg-muted rounded" />
                                    ))}
                                </div>
                            ) : (
                                <div className="grid gap-4 md:grid-cols-4">
                                    {(["hot", "warm", "cool", "cold"] as const).map((temp) => {
                                        const stat = temperatureStats?.find(t => t.temperature === temp);
                                        const config = getTemperatureConfig(temp);
                                        return (
                                            <Card key={temp} className="border-l-4" style={{ borderLeftColor: `var(--${config.bg.replace('bg-', '')})` }}>
                                                <CardContent className="pt-4">
                                                    <div className="flex items-center gap-2">
                                                        <div className={config.color}>
                                                            {config.icon}
                                                        </div>
                                                        <span className="font-medium capitalize">{temp}</span>
                                                    </div>
                                                    <div className="text-3xl font-bold mt-2">
                                                        {stat?.count || 0}
                                                    </div>
                                                    <div className="text-sm text-muted-foreground">
                                                        {stat?.percentage || 0}% do total
                                                    </div>
                                                </CardContent>
                                            </Card>
                                        );
                                    })}
                                </div>
                            )}
                        </CardContent>
                    </Card>
                </TabsContent>

                {/* Recent Activity */}
                <TabsContent value="activity">
                    <Card>
                        <CardHeader>
                            <CardTitle>Atividade Recente</CardTitle>
                            <CardDescription>
                                Últimas ações do agente em tempo real
                            </CardDescription>
                        </CardHeader>
                        <CardContent>
                            <div className="space-y-3">
                                {recentActivity?.length === 0 ? (
                                    <p className="text-muted-foreground text-center py-8">
                                        Nenhuma atividade recente
                                    </p>
                                ) : (
                                    recentActivity?.map((activity: any) => (
                                        <div
                                            key={activity.id}
                                            className="flex items-center justify-between py-2 border-b last:border-0"
                                        >
                                            <div className="flex items-center gap-3">
                                                {getActivityIcon(activity.activity_type)}
                                                <div>
                                                    <p className="text-sm font-medium">
                                                        {activity.activity_type.replace(/_/g, " ")}
                                                    </p>
                                                    {activity.activity_data?.message && (
                                                        <p className="text-xs text-muted-foreground truncate max-w-md">
                                                            {activity.activity_data.message}
                                                        </p>
                                                    )}
                                                </div>
                                            </div>
                                            <div className="text-xs text-muted-foreground">
                                                {new Date(activity.created_at).toLocaleTimeString("pt-BR", {
                                                    hour: "2-digit",
                                                    minute: "2-digit"
                                                })}
                                                {activity.duration_ms && (
                                                    <span className="ml-2">
                                                        ({activity.duration_ms}ms)
                                                    </span>
                                                )}
                                            </div>
                                        </div>
                                    ))
                                )}
                            </div>
                        </CardContent>
                    </Card>
                </TabsContent>
            </Tabs>
        </div>
    );
}

import { useState, useEffect } from "react";
import { useMutation, useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Slider } from "@/components/ui/slider";
import { useToast } from "@/hooks/use-toast";
import { Save, Loader2, Bell } from "lucide-react";
import { FollowupEditor } from "./FollowupEditor";
import { EvolutionInstance } from "@/components/configuracoes/EvolutionInstances";

interface AIAgent {
    id?: string;
    name: string;
    description: string | null;
    is_active: boolean;
    persona_name: string;
    persona_role: string;
    tone: string;
    greeting_message: string | null;
    llm_provider: 'openai' | 'gemini';
    ai_model: string;
    max_tokens: number;
    temperature: number;
    system_prompt: string;
    enable_property_search: boolean;
    max_properties_to_show: number;
    max_messages_per_conversation: number;
    conversation_timeout_hours: number;
    trigger_keywords: string[];
    fallback_action: string;
    evolution_instance_id?: string | null;
}


const LLM_MODELS = {
    openai: [
        { value: 'gpt-4o-mini', label: 'GPT-4o Mini (Rápido, econômico)' },
        { value: 'gpt-4o', label: 'GPT-4o (Mais preciso)' },
        { value: 'gpt-3.5-turbo', label: 'GPT-3.5 Turbo (Mais barato)' },
    ],
    gemini: [
        { value: 'gemini-2.0-flash', label: 'Gemini 2.0 Flash (Mais recente)' },
        { value: 'gemini-1.5-flash', label: 'Gemini 1.5 Flash (Rápido)' },
        { value: 'gemini-1.5-pro', label: 'Gemini 1.5 Pro (Avançado)' },
    ]
};

interface AgentEditorProps {
    agent: AIAgent | null;
    onClose: () => void;
}

const DEFAULT_SYSTEM_PROMPT = `Você é uma consultora imobiliária virtual da MeMude Imóveis, especializada em lançamentos imobiliários em Fortaleza e região metropolitana.

## Seu Objetivo Principal
Qualificar leads interessados em comprar imóveis, descobrindo:
1. Tipo de imóvel desejado (apartamento, casa, terreno)
2. Faixa de preço/orçamento disponível
3. Localização preferida (bairros/regiões)
4. Prazo para compra
5. Se precisa de financiamento

## Comportamento
- Seja simpática, profissional e objetiva
- Use linguagem natural e amigável
- Faça uma pergunta por vez
- Quando identificar o perfil, apresente opções de imóveis compatíveis
- Quando o cliente demonstrar interesse em um imóvel, sugira agendar uma visita
- Nunca invente informações sobre imóveis
- Se não souber algo, diga que vai verificar

## Formato de Resposta
- Respostas curtas (máximo 3 parágrafos)
- Use emojis com moderação (1-2 por mensagem)
- Destaque informações importantes com *negrito*

## Ações Especiais
- [BUSCAR_IMOVEIS]: Quando precisar buscar imóveis compatíveis
- [AGENDAR_VISITA]: Quando cliente confirmar interesse em visitar
- [TRANSFERIR_HUMANO]: Quando não conseguir ajudar ou cliente solicitar`;

const DEFAULT_GREETING = `Olá! 👋 Sou a Ana, consultora virtual da MeMude Imóveis.

Estou aqui para ajudar você a encontrar o imóvel ideal! 🏠

Para começar, me conta: você está procurando um apartamento, casa ou terreno?`;

export function AgentEditor({ agent, onClose }: AgentEditorProps) {
    const { toast } = useToast();
    const [formData, setFormData] = useState<AIAgent>({
        name: '',
        description: '',
        is_active: false,
        persona_name: 'Ana',
        persona_role: 'Consultora de Imóveis',
        tone: 'professional_friendly',
        greeting_message: DEFAULT_GREETING,
        llm_provider: 'openai',
        ai_model: 'gpt-4o-mini',
        max_tokens: 500,
        temperature: 0.7,
        system_prompt: DEFAULT_SYSTEM_PROMPT,
        enable_property_search: true,
        max_properties_to_show: 3,
        max_messages_per_conversation: 50,
        conversation_timeout_hours: 24,
        trigger_keywords: ['comprar', 'apartamento', 'casa', 'imóvel', 'imovel'],
        fallback_action: 'notify_admin',
        evolution_instance_id: null
    });

    const { data: evolutionInstances = [] } = useQuery({
        queryKey: ['evolution-instances-select'],
        queryFn: async () => {
            const { data, error } = await supabase
                .from('evolution_instances')
                .select('id, name, instance_name')
                .eq('is_active', true)
                .order('name');
            if (error) throw error;
            return data as Partial<EvolutionInstance>[];
        }
    });

    useEffect(() => {
        if (agent) {
            setFormData({
                ...agent,
                trigger_keywords: agent.trigger_keywords || []
            });
        }
    }, [agent]);

    const saveMutation = useMutation({
        mutationFn: async (data: AIAgent) => {
            const payload = {
                name: data.name,
                description: data.description,
                is_active: data.is_active,
                persona_name: data.persona_name,
                persona_role: data.persona_role,
                tone: data.tone,
                greeting_message: data.greeting_message,
                llm_provider: data.llm_provider,
                ai_model: data.ai_model,
                max_tokens: data.max_tokens,
                temperature: data.temperature,
                system_prompt: data.system_prompt,
                enable_property_search: data.enable_property_search,
                max_properties_to_show: data.max_properties_to_show,
                max_messages_per_conversation: data.max_messages_per_conversation,
                conversation_timeout_hours: data.conversation_timeout_hours,
                trigger_keywords: data.trigger_keywords,
                fallback_action: data.fallback_action,
                evolution_instance_id: data.evolution_instance_id,
                updated_at: new Date().toISOString()
            };

            if (agent?.id) {
                const { error } = await supabase
                    .from('ai_agents')
                    .update(payload)
                    .eq('id', agent.id);
                if (error) throw error;
            } else {
                const { error } = await supabase
                    .from('ai_agents')
                    .insert(payload);
                if (error) throw error;
            }
        },
        onSuccess: () => {
            toast({
                title: "Salvo com sucesso",
                description: agent?.id ? "Agente atualizado." : "Agente criado."
            });
            onClose();
        },
        onError: (error: any) => {
            toast({
                title: "Erro",
                description: error.message,
                variant: "destructive"
            });
        }
    });

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.name.trim()) {
            toast({
                title: "Nome obrigatório",
                description: "Por favor, informe um nome para o agente.",
                variant: "destructive"
            });
            return;
        }
        if (!formData.system_prompt.trim()) {
            toast({
                title: "System prompt obrigatório",
                description: "Por favor, configure o prompt do sistema.",
                variant: "destructive"
            });
            return;
        }
        saveMutation.mutate(formData);
    };

    return (
        <form onSubmit={handleSubmit} className="space-y-6">
            <Tabs defaultValue="basic" className="w-full">
                <TabsList className="grid w-full grid-cols-5">
                    <TabsTrigger value="basic">Básico</TabsTrigger>
                    <TabsTrigger value="personality">Personalidade</TabsTrigger>
                    <TabsTrigger value="ai">IA</TabsTrigger>
                    <TabsTrigger value="behavior">Comportamento</TabsTrigger>
                    <TabsTrigger value="followups" disabled={!agent?.id}>
                        <Bell className="h-3 w-3 mr-1" />
                        Follow-ups
                    </TabsTrigger>
                </TabsList>

                {/* Basic Settings */}
                <TabsContent value="basic" className="space-y-4 mt-4">
                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-2">
                            <Label htmlFor="name">Nome do Agente *</Label>
                            <Input
                                id="name"
                                value={formData.name}
                                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                placeholder="Ex: Ana - Consultora Imobiliária"
                            />
                        </div>
                    </div>

                    <div className="space-y-2">
                        <Label htmlFor="evolution_instance">Instância Evolution API</Label>
                        <Select
                            value={formData.evolution_instance_id || "default"}
                            onValueChange={(value) => setFormData({
                                ...formData,
                                evolution_instance_id: value === "default" ? null : value
                            })}
                        >
                            <SelectTrigger>
                                <SelectValue placeholder="Selecione uma instância" />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="default">Padrão (System Settings)</SelectItem>
                                {evolutionInstances.map((instance) => (
                                    <SelectItem key={instance.id} value={instance.id || ""}>
                                        {instance.name}
                                    </SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                        <p className="text-xs text-muted-foreground">
                            Define qual conta do WhatsApp este agente usará.
                        </p>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-2">
                            <Label htmlFor="llm_provider">Provedor de IA</Label>
                            <Select
                                value={formData.llm_provider}
                                onValueChange={(value: 'openai' | 'gemini') => {
                                    const firstModel = LLM_MODELS[value][0].value;
                                    setFormData({ ...formData, llm_provider: value, ai_model: firstModel });
                                }}
                            >
                                <SelectTrigger>
                                    <SelectValue />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="openai">OpenAI (ChatGPT)</SelectItem>
                                    <SelectItem value="gemini">Google Gemini</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="ai_model">Modelo</Label>
                            <Select
                                value={formData.ai_model}
                                onValueChange={(value) => setFormData({ ...formData, ai_model: value })}
                            >
                                <SelectTrigger>
                                    <SelectValue />
                                </SelectTrigger>
                                <SelectContent>
                                    {LLM_MODELS[formData.llm_provider].map((model) => (
                                        <SelectItem key={model.value} value={model.value}>
                                            {model.label}
                                        </SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        </div>
                    </div>

                    <div className="space-y-2">
                        <Label htmlFor="description">Descrição</Label>
                        <Textarea
                            id="description"
                            value={formData.description || ''}
                            onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                            placeholder="Descrição do propósito do agente..."
                            rows={2}
                        />
                    </div>

                    <div className="flex items-center justify-between p-4 border rounded-lg">
                        <div>
                            <Label>Agente Ativo</Label>
                            <p className="text-sm text-muted-foreground">
                                Apenas um agente pode estar ativo por vez
                            </p>
                        </div>
                        <Switch
                            checked={formData.is_active}
                            onCheckedChange={(checked) => setFormData({ ...formData, is_active: checked })}
                        />
                    </div>
                </TabsContent>

                {/* Personality Settings */}
                <TabsContent value="personality" className="space-y-4 mt-4">
                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-2">
                            <Label htmlFor="persona_name">Nome do Personagem</Label>
                            <Input
                                id="persona_name"
                                value={formData.persona_name}
                                onChange={(e) => setFormData({ ...formData, persona_name: e.target.value })}
                                placeholder="Ana"
                            />
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="persona_role">Cargo/Papel</Label>
                            <Input
                                id="persona_role"
                                value={formData.persona_role}
                                onChange={(e) => setFormData({ ...formData, persona_role: e.target.value })}
                                placeholder="Consultora de Imóveis"
                            />
                        </div>
                    </div>

                    <div className="space-y-2">
                        <Label htmlFor="tone">Tom de Voz</Label>
                        <Select
                            value={formData.tone}
                            onValueChange={(value) => setFormData({ ...formData, tone: value })}
                        >
                            <SelectTrigger>
                                <SelectValue />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="professional">Profissional</SelectItem>
                                <SelectItem value="friendly">Amigável</SelectItem>
                                <SelectItem value="formal">Formal</SelectItem>
                                <SelectItem value="casual">Casual</SelectItem>
                                <SelectItem value="professional_friendly">Profissional e Amigável</SelectItem>
                            </SelectContent>
                        </Select>
                    </div>

                    <div className="space-y-2">
                        <Label htmlFor="greeting_message">Mensagem de Saudação</Label>
                        <Textarea
                            id="greeting_message"
                            value={formData.greeting_message || ''}
                            onChange={(e) => setFormData({ ...formData, greeting_message: e.target.value })}
                            placeholder="Olá! Como posso ajudar você hoje?"
                            rows={4}
                        />
                        <p className="text-xs text-muted-foreground">
                            Primeira mensagem enviada quando o cliente inicia uma conversa
                        </p>
                    </div>
                </TabsContent>

                {/* AI Settings */}
                <TabsContent value="ai" className="space-y-4 mt-4">
                    <div className="space-y-2">
                        <Label htmlFor="system_prompt">System Prompt * (Instruções para a IA)</Label>
                        <Textarea
                            id="system_prompt"
                            value={formData.system_prompt}
                            onChange={(e) => setFormData({ ...formData, system_prompt: e.target.value })}
                            rows={12}
                            className="font-mono text-sm"
                        />
                        <p className="text-xs text-muted-foreground">
                            Define o comportamento, personalidade e objetivos do agente.
                            Use [BUSCAR_IMOVEIS], [AGENDAR_VISITA], [TRANSFERIR_HUMANO] para ações especiais.
                        </p>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-2">
                            <Label>Temperatura: {formData.temperature}</Label>
                            <Slider
                                value={[formData.temperature]}
                                onValueChange={(value) => setFormData({ ...formData, temperature: value[0] })}
                                min={0}
                                max={1}
                                step={0.1}
                            />
                            <p className="text-xs text-muted-foreground">
                                Menor = mais focado, Maior = mais criativo
                            </p>
                        </div>
                        <div className="space-y-2">
                            <Label>Max Tokens: {formData.max_tokens}</Label>
                            <Slider
                                value={[formData.max_tokens]}
                                onValueChange={(value) => setFormData({ ...formData, max_tokens: value[0] })}
                                min={100}
                                max={2000}
                                step={100}
                            />
                            <p className="text-xs text-muted-foreground">
                                Limite de tamanho das respostas
                            </p>
                        </div>
                    </div>
                </TabsContent>

                {/* Behavior Settings */}
                <TabsContent value="behavior" className="space-y-4 mt-4">
                    <div className="flex items-center justify-between p-4 border rounded-lg">
                        <div>
                            <Label>Busca de Imóveis</Label>
                            <p className="text-sm text-muted-foreground">
                                Permite que o agente busque e apresente imóveis
                            </p>
                        </div>
                        <Switch
                            checked={formData.enable_property_search}
                            onCheckedChange={(checked) => setFormData({ ...formData, enable_property_search: checked })}
                        />
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-2">
                            <Label>Máximo de Imóveis por Busca</Label>
                            <Select
                                value={formData.max_properties_to_show.toString()}
                                onValueChange={(value) => setFormData({ ...formData, max_properties_to_show: parseInt(value) })}
                            >
                                <SelectTrigger>
                                    <SelectValue />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="3">3 imóveis</SelectItem>
                                    <SelectItem value="5">5 imóveis</SelectItem>
                                    <SelectItem value="10">10 imóveis</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                        <div className="space-y-2">
                            <Label>Ação de Fallback</Label>
                            <Select
                                value={formData.fallback_action}
                                onValueChange={(value) => setFormData({ ...formData, fallback_action: value })}
                            >
                                <SelectTrigger>
                                    <SelectValue />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="notify_admin">Notificar Administrador</SelectItem>
                                    <SelectItem value="transfer_human">Transferir para Humano</SelectItem>
                                    <SelectItem value="end_conversation">Encerrar Conversa</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                    </div>

                    <div className="space-y-2">
                        <Label>Keywords de Ativação</Label>
                        <Input
                            value={formData.trigger_keywords.join(', ')}
                            onChange={(e) => setFormData({
                                ...formData,
                                trigger_keywords: e.target.value.split(',').map(k => k.trim()).filter(Boolean)
                            })}
                            placeholder="comprar, apartamento, casa, imóvel"
                        />
                        <p className="text-xs text-muted-foreground">
                            Palavras que iniciam uma conversa com o agente (separadas por vírgula)
                        </p>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-2">
                            <Label>Limite de Mensagens</Label>
                            <Input
                                type="number"
                                value={formData.max_messages_per_conversation}
                                onChange={(e) => setFormData({ ...formData, max_messages_per_conversation: parseInt(e.target.value) })}
                            />
                            <p className="text-xs text-muted-foreground">
                                Máximo de mensagens por conversa
                            </p>
                        </div>
                        <div className="space-y-2">
                            <Label>Timeout da Conversa (horas)</Label>
                            <Input
                                type="number"
                                value={formData.conversation_timeout_hours}
                                onChange={(e) => setFormData({ ...formData, conversation_timeout_hours: parseInt(e.target.value) })}
                            />
                            <p className="text-xs text-muted-foreground">
                                Tempo de inatividade para expirar conversa
                            </p>
                        </div>
                    </div>
                </TabsContent>

                {/* Follow-ups Tab - Only available for existing agents */}
                <TabsContent value="followups" className="space-y-4 mt-4">
                    {agent?.id ? (
                        <FollowupEditor agentId={agent.id} />
                    ) : (
                        <div className="p-8 text-center text-muted-foreground">
                            <Bell className="h-12 w-12 mx-auto mb-4 opacity-50" />
                            <p>Salve o agente primeiro para configurar os follow-ups</p>
                        </div>
                    )}
                </TabsContent>
            </Tabs>

            {/* Submit Button */}
            <div className="flex justify-end gap-2 pt-4 border-t">
                <Button type="button" variant="outline" onClick={onClose}>
                    Cancelar
                </Button>
                <Button type="submit" disabled={saveMutation.isPending}>
                    {saveMutation.isPending ? (
                        <>
                            <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                            Salvando...
                        </>
                    ) : (
                        <>
                            <Save className="h-4 w-4 mr-2" />
                            Salvar Agente
                        </>
                    )}
                </Button>
            </div>
        </form>
    );
}

import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { ScrollArea } from "@/components/ui/scroll-area";
import {
    FileText,
    Search,
    Filter,
    Download,
    AlertCircle,
    MessageSquare,
    User,
    Settings,
    Shield,
    RefreshCw
} from "lucide-react";

interface AuditLogViewerProps {
    agentId?: string;
}

interface AuditLogEntry {
    id: string;
    user_id: string | null;
    agent_id: string | null;
    conversation_id: string | null;
    action: string;
    entity_type: string;
    entity_id: string | null;
    previous_value: Record<string, any> | null;
    new_value: Record<string, any> | null;
    metadata: Record<string, any>;
    created_at: string;
}

const ACTION_LABELS: Record<string, { label: string; color: string }> = {
    conversation_started: { label: "Conversa Iniciada", color: "bg-green-500" },
    conversation_ended: { label: "Conversa Encerrada", color: "bg-gray-500" },
    message_sent: { label: "Mensagem Enviada", color: "bg-blue-500" },
    message_received: { label: "Mensagem Recebida", color: "bg-blue-400" },
    lead_qualified: { label: "Lead Qualificado", color: "bg-purple-500" },
    lead_transferred: { label: "Lead Transferido", color: "bg-orange-500" },
    visit_scheduled: { label: "Visita Agendada", color: "bg-green-600" },
    property_searched: { label: "Busca de Imóveis", color: "bg-indigo-500" },
    agent_config_changed: { label: "Config Alterada", color: "bg-yellow-500" },
    prompt_modified: { label: "Prompt Modificado", color: "bg-yellow-600" },
    error_occurred: { label: "Erro Ocorrido", color: "bg-red-500" },
    rate_limited: { label: "Rate Limited", color: "bg-red-400" },
    api_called: { label: "API Chamada", color: "bg-gray-400" }
};

const ENTITY_ICONS: Record<string, React.ReactNode> = {
    conversation: <MessageSquare className="h-4 w-4" />,
    lead: <User className="h-4 w-4" />,
    agent: <Settings className="h-4 w-4" />,
    message: <MessageSquare className="h-4 w-4" />,
    system: <Shield className="h-4 w-4" />,
    config: <Settings className="h-4 w-4" />
};

export function AuditLogViewer({ agentId }: AuditLogViewerProps) {
    const [search, setSearch] = useState("");
    const [actionFilter, setActionFilter] = useState<string>("all");
    const [entityFilter, setEntityFilter] = useState<string>("all");
    const [limit, setLimit] = useState(50);

    // Fetch audit logs
    const { data: logs, isLoading, refetch } = useQuery({
        queryKey: ["audit-logs", agentId, actionFilter, entityFilter, limit],
        queryFn: async () => {
            let query = supabase
                .from("audit_logs")
                .select("*")
                .order("created_at", { ascending: false })
                .limit(limit);

            if (agentId) {
                query = query.eq("agent_id", agentId);
            }
            if (actionFilter && actionFilter !== "all") {
                query = query.eq("action", actionFilter);
            }
            if (entityFilter && entityFilter !== "all") {
                query = query.eq("entity_type", entityFilter);
            }

            const { data, error } = await query;
            if (error) throw error;
            return data as AuditLogEntry[];
        }
    });

    const filteredLogs = logs?.filter(log => {
        if (!search) return true;
        const searchLower = search.toLowerCase();
        return (
            log.action?.toLowerCase().includes(searchLower) ||
            log.entity_type?.toLowerCase().includes(searchLower) ||
            log.entity_id?.toLowerCase().includes(searchLower) ||
            JSON.stringify(log.metadata).toLowerCase().includes(searchLower)
        );
    });

    const getActionBadge = (action: string) => {
        const config = ACTION_LABELS[action] || { label: action, color: "bg-gray-400" };
        return (
            <Badge className={`${config.color} text-white text-xs`}>
                {config.label}
            </Badge>
        );
    };

    const exportLogs = () => {
        if (!filteredLogs) return;

        const csv = [
            ["Timestamp", "Action", "Entity Type", "Entity ID", "Metadata"].join(","),
            ...filteredLogs.map(log => [
                new Date(log.created_at).toISOString(),
                log.action,
                log.entity_type,
                log.entity_id || "",
                JSON.stringify(log.metadata).replace(/,/g, ";")
            ].join(","))
        ].join("\n");

        const blob = new Blob([csv], { type: "text/csv" });
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.href = url;
        a.download = `audit-logs-${new Date().toISOString().split("T")[0]}.csv`;
        a.click();
    };

    if (isLoading) {
        return (
            <div className="flex items-center justify-center h-48">
                <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary" />
            </div>
        );
    }

    return (
        <div className="space-y-4">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-2xl font-bold flex items-center gap-2">
                        <FileText className="h-6 w-6" />
                        Audit Logs
                    </h2>
                    <p className="text-muted-foreground">
                        Histórico de ações para compliance e segurança
                    </p>
                </div>
                <div className="flex gap-2">
                    <Button variant="outline" size="sm" onClick={() => refetch()}>
                        <RefreshCw className="h-4 w-4 mr-1" />
                        Atualizar
                    </Button>
                    <Button variant="outline" size="sm" onClick={exportLogs}>
                        <Download className="h-4 w-4 mr-1" />
                        Exportar
                    </Button>
                </div>
            </div>

            {/* Filters */}
            <Card>
                <CardContent className="pt-4">
                    <div className="flex gap-4 flex-wrap">
                        <div className="flex-1 min-w-[200px]">
                            <div className="relative">
                                <Search className="absolute left-2 top-2.5 h-4 w-4 text-muted-foreground" />
                                <Input
                                    placeholder="Buscar nos logs..."
                                    value={search}
                                    onChange={(e) => setSearch(e.target.value)}
                                    className="pl-8"
                                />
                            </div>
                        </div>

                        <Select value={actionFilter} onValueChange={setActionFilter}>
                            <SelectTrigger className="w-[180px]">
                                <Filter className="h-4 w-4 mr-2" />
                                <SelectValue placeholder="Ação" />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="all">Todas as Ações</SelectItem>
                                {Object.entries(ACTION_LABELS).map(([key, config]) => (
                                    <SelectItem key={key} value={key}>
                                        {config.label}
                                    </SelectItem>
                                ))}
                            </SelectContent>
                        </Select>

                        <Select value={entityFilter} onValueChange={setEntityFilter}>
                            <SelectTrigger className="w-[180px]">
                                <SelectValue placeholder="Entidade" />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="all">Todas as Entidades</SelectItem>
                                <SelectItem value="conversation">Conversas</SelectItem>
                                <SelectItem value="lead">Leads</SelectItem>
                                <SelectItem value="message">Mensagens</SelectItem>
                                <SelectItem value="agent">Agente</SelectItem>
                                <SelectItem value="system">Sistema</SelectItem>
                            </SelectContent>
                        </Select>

                        <Select value={String(limit)} onValueChange={(v) => setLimit(parseInt(v))}>
                            <SelectTrigger className="w-[120px]">
                                <SelectValue />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="50">50 logs</SelectItem>
                                <SelectItem value="100">100 logs</SelectItem>
                                <SelectItem value="200">200 logs</SelectItem>
                                <SelectItem value="500">500 logs</SelectItem>
                            </SelectContent>
                        </Select>
                    </div>
                </CardContent>
            </Card>

            {/* Logs List */}
            <Card>
                <CardHeader>
                    <CardTitle className="text-base">
                        {filteredLogs?.length || 0} registros encontrados
                    </CardTitle>
                </CardHeader>
                <CardContent>
                    <ScrollArea className="h-[500px]">
                        <div className="space-y-2">
                            {filteredLogs?.length === 0 ? (
                                <div className="text-center py-8 text-muted-foreground">
                                    <AlertCircle className="h-8 w-8 mx-auto mb-2" />
                                    Nenhum log encontrado
                                </div>
                            ) : (
                                filteredLogs?.map((log) => (
                                    <div
                                        key={log.id}
                                        className="flex items-start gap-3 p-3 rounded-lg border hover:bg-muted/50 transition-colors"
                                    >
                                        {/* Entity Icon */}
                                        <div className="mt-1 text-muted-foreground">
                                            {ENTITY_ICONS[log.entity_type] || <FileText className="h-4 w-4" />}
                                        </div>

                                        {/* Content */}
                                        <div className="flex-1 min-w-0">
                                            <div className="flex items-center gap-2 mb-1">
                                                {getActionBadge(log.action)}
                                                <span className="text-xs text-muted-foreground">
                                                    {log.entity_type}
                                                    {log.entity_id && ` • ${log.entity_id.substring(0, 8)}...`}
                                                </span>
                                            </div>

                                            {/* Metadata */}
                                            {log.metadata && Object.keys(log.metadata).length > 0 && (
                                                <div className="text-xs text-muted-foreground mt-1">
                                                    {Object.entries(log.metadata).slice(0, 3).map(([key, value]) => (
                                                        <span key={key} className="mr-2">
                                                            <span className="font-medium">{key}:</span>{" "}
                                                            {typeof value === "string"
                                                                ? value.substring(0, 30) + (value.length > 30 ? "..." : "")
                                                                : JSON.stringify(value).substring(0, 30)}
                                                        </span>
                                                    ))}
                                                </div>
                                            )}

                                            {/* Value changes */}
                                            {log.previous_value && log.new_value && (
                                                <div className="text-xs mt-1">
                                                    <span className="text-red-500">-</span>
                                                    <span className="text-green-500 ml-2">+</span>
                                                    <span className="text-muted-foreground ml-1">
                                                        Alteração detectada
                                                    </span>
                                                </div>
                                            )}
                                        </div>

                                        {/* Timestamp */}
                                        <div className="text-xs text-muted-foreground whitespace-nowrap">
                                            {new Date(log.created_at).toLocaleString("pt-BR", {
                                                day: "2-digit",
                                                month: "2-digit",
                                                hour: "2-digit",
                                                minute: "2-digit"
                                            })}
                                        </div>
                                    </div>
                                ))
                            )}
                        </div>
                    </ScrollArea>
                </CardContent>
            </Card>
        </div>
    );
}

import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Skeleton } from "@/components/ui/skeleton";
import { Input } from "@/components/ui/input";
import { MessageSquare, User, Bot, Calendar, Search, Phone, ChevronRight } from "lucide-react";

interface Conversation {
    id: string;
    agent_id: string;
    phone_number: string;
    status: string;
    current_stage: string;
    lead_score: number;
    total_messages: number;
    started_at: string;
    last_message_at: string;
    qualification_data: Record<string, any>;
    lead?: { nome: string } | null;
}

interface Message {
    id: string;
    role: string;
    content: string;
    created_at: string;
    intent_detected: string | null;
    action_taken: string | null;
    sentiment_log?: {
        sentiment: string;
        confidence: number;
    }[] | null;
}

interface ConversationMonitorProps {
    agentId?: string;
}

export function ConversationMonitor({ agentId }: ConversationMonitorProps) {
    const [selectedConversation, setSelectedConversation] = useState<Conversation | null>(null);
    const [searchTerm, setSearchTerm] = useState('');

    // Fetch conversations
    const { data: conversations, isLoading } = useQuery({
        queryKey: ['agent-conversations', agentId],
        queryFn: async () => {
            let query = supabase
                .from('agent_conversations')
                .select(`
          *,
          lead:leads(nome)
        `)
                .order('last_message_at', { ascending: false })
                .limit(50);

            if (agentId) {
                query = query.eq('agent_id', agentId);
            }

            const { data, error } = await query;
            if (error) throw error;
            return data as Conversation[];
        }
    });

    // Fetch messages for selected conversation
    const { data: messages, isLoading: messagesLoading } = useQuery({
        queryKey: ['agent-messages', selectedConversation?.id],
        queryFn: async () => {
            if (!selectedConversation) return [];

            const { data, error } = await supabase
                .from('agent_messages')
                .select(`
                    *,
                    sentiment_log:conversation_sentiment_log(sentiment, confidence)
                `)
                .eq('conversation_id', selectedConversation.id)
                .order('created_at', { ascending: true });

            if (error) throw error;
            return data as Message[];
        },
        enabled: !!selectedConversation
    });

    const filteredConversations = conversations?.filter(conv =>
        conv.phone_number.includes(searchTerm) ||
        conv.lead?.nome?.toLowerCase().includes(searchTerm.toLowerCase())
    );

    const getStatusBadge = (status: string) => {
        const variants: Record<string, { variant: 'default' | 'secondary' | 'destructive' | 'outline', label: string }> = {
            active: { variant: 'default', label: 'Ativa' },
            completed: { variant: 'secondary', label: 'Concluída' },
            transferred: { variant: 'outline', label: 'Transferida' },
            expired: { variant: 'destructive', label: 'Expirada' }
        };
        const config = variants[status] || { variant: 'outline', label: status };
        return <Badge variant={config.variant}>{config.label}</Badge>;
    };

    const getSentimentBadge = (message: Message) => {
        const log = message.sentiment_log?.[0];
        if (!log || message.role === 'assistant') return null;

        const sentimentConfig: Record<string, { emoji: string; className: string; label: string }> = {
            positive: { emoji: '😊', className: 'bg-green-500/20 text-green-700 border-green-300', label: 'Positivo' },
            neutral: { emoji: '😐', className: 'bg-gray-500/20 text-gray-700 border-gray-300', label: 'Neutro' },
            negative: { emoji: '😞', className: 'bg-red-500/20 text-red-700 border-red-300', label: 'Negativo' },
            urgent: { emoji: '⚡', className: 'bg-orange-500/20 text-orange-700 border-orange-300', label: 'Urgente' },
            frustrated: { emoji: '😤', className: 'bg-red-600/20 text-red-800 border-red-400', label: 'Frustrado' }
        };

        const config = sentimentConfig[log.sentiment] || sentimentConfig.neutral;
        return (
            <Badge variant="outline" className={`text-[10px] h-4 ${config.className}`}>
                {config.emoji} {config.label}
            </Badge>
        );
    };

    const formatDate = (date: string) => {
        return new Date(date).toLocaleString('pt-BR', {
            day: '2-digit',
            month: '2-digit',
            hour: '2-digit',
            minute: '2-digit'
        });
    };

    if (isLoading) {
        return (
            <div className="grid grid-cols-3 gap-4 h-[500px]">
                <div className="col-span-1 space-y-2">
                    {[1, 2, 3, 4, 5].map(i => (
                        <Skeleton key={i} className="h-20" />
                    ))}
                </div>
                <Skeleton className="col-span-2" />
            </div>
        );
    }

    return (
        <div className="grid grid-cols-3 gap-4 h-[600px]">
            {/* Conversations List */}
            <div className="col-span-1 border rounded-lg overflow-hidden">
                <div className="p-3 border-b bg-muted/50">
                    <div className="relative">
                        <Search className="absolute left-2 top-2.5 h-4 w-4 text-muted-foreground" />
                        <Input
                            placeholder="Buscar..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="pl-8 h-9"
                        />
                    </div>
                </div>

                <ScrollArea className="h-[540px]">
                    {filteredConversations?.length === 0 ? (
                        <div className="p-8 text-center text-muted-foreground">
                            <MessageSquare className="h-12 w-12 mx-auto mb-2 opacity-50" />
                            <p>Nenhuma conversa encontrada</p>
                        </div>
                    ) : (
                        <div className="divide-y">
                            {filteredConversations?.map(conv => (
                                <button
                                    key={conv.id}
                                    onClick={() => setSelectedConversation(conv)}
                                    className={`w-full p-3 text-left hover:bg-muted/50 transition-colors ${selectedConversation?.id === conv.id ? 'bg-muted' : ''
                                        }`}
                                >
                                    <div className="flex items-center justify-between mb-1">
                                        <span className="font-medium truncate">
                                            {conv.lead?.nome || conv.phone_number}
                                        </span>
                                        {getStatusBadge(conv.status)}
                                    </div>
                                    <div className="flex items-center gap-2 text-xs text-muted-foreground">
                                        <Phone className="h-3 w-3" />
                                        <span>{conv.phone_number}</span>
                                        <span>•</span>
                                        <span>{conv.total_messages} msgs</span>
                                    </div>
                                    <div className="flex items-center gap-1 text-xs text-muted-foreground mt-1">
                                        <Calendar className="h-3 w-3" />
                                        <span>{formatDate(conv.last_message_at)}</span>
                                    </div>
                                </button>
                            ))}
                        </div>
                    )}
                </ScrollArea>
            </div>

            {/* Messages Panel */}
            <div className="col-span-2 border rounded-lg overflow-hidden flex flex-col">
                {!selectedConversation ? (
                    <div className="flex-1 flex items-center justify-center text-muted-foreground">
                        <div className="text-center">
                            <ChevronRight className="h-12 w-12 mx-auto mb-2 opacity-50" />
                            <p>Selecione uma conversa para ver as mensagens</p>
                        </div>
                    </div>
                ) : (
                    <>
                        {/* Header */}
                        <div className="p-3 border-b bg-muted/50">
                            <div className="flex items-center justify-between">
                                <div>
                                    <h3 className="font-semibold">
                                        {selectedConversation.lead?.nome || selectedConversation.phone_number}
                                    </h3>
                                    <p className="text-xs text-muted-foreground">
                                        Score: {selectedConversation.lead_score} •
                                        Estágio: {selectedConversation.current_stage}
                                    </p>
                                </div>
                                {getStatusBadge(selectedConversation.status)}
                            </div>
                        </div>

                        {/* Messages */}
                        <ScrollArea className="flex-1 p-4">
                            {messagesLoading ? (
                                <div className="space-y-2">
                                    {[1, 2, 3].map(i => (
                                        <Skeleton key={i} className="h-16" />
                                    ))}
                                </div>
                            ) : (
                                <div className="space-y-4">
                                    {messages?.map(msg => (
                                        <div
                                            key={msg.id}
                                            className={`flex ${msg.role === 'assistant' ? 'justify-start' : 'justify-end'}`}
                                        >
                                            <div className={`max-w-[80%] ${msg.role === 'assistant'
                                                ? 'bg-muted rounded-lg rounded-tl-none'
                                                : 'bg-primary text-primary-foreground rounded-lg rounded-tr-none'
                                                } p-3`}>
                                                <div className="flex items-center gap-2 mb-1 text-xs opacity-70">
                                                    {msg.role === 'assistant' ? (
                                                        <Bot className="h-3 w-3" />
                                                    ) : (
                                                        <User className="h-3 w-3" />
                                                    )}
                                                    <span>{new Date(msg.created_at).toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })}</span>
                                                    {msg.intent_detected && (
                                                        <Badge variant="outline" className="text-[10px] h-4">
                                                            {msg.intent_detected}
                                                        </Badge>
                                                    )}
                                                    {getSentimentBadge(msg)}
                                                </div>
                                                <p className="text-sm whitespace-pre-wrap">{msg.content}</p>
                                                {msg.action_taken && msg.action_taken !== 'none' && (
                                                    <Badge variant="secondary" className="mt-2 text-xs">
                                                        Ação: {msg.action_taken}
                                                    </Badge>
                                                )}
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </ScrollArea>

                        {/* Qualification Data */}
                        {Object.keys(selectedConversation.qualification_data || {}).length > 0 && (
                            <div className="p-3 border-t bg-muted/30">
                                <h4 className="text-xs font-semibold mb-2 text-muted-foreground">
                                    Dados de Qualificação
                                </h4>
                                <div className="flex flex-wrap gap-2">
                                    {Object.entries(selectedConversation.qualification_data).map(([key, value]) => (
                                        <Badge key={key} variant="outline" className="text-xs">
                                            {key}: {typeof value === 'object' ? JSON.stringify(value) : String(value)}
                                        </Badge>
                                    ))}
                                </div>
                            </div>
                        )}
                    </>
                )}
            </div>
        </div>
    );
}

import { useState, useEffect } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Switch } from "@/components/ui/switch";
import { Badge } from "@/components/ui/badge";
import { useToast } from "@/hooks/use-toast";
import {
    Plus,
    Trash2,
    GripVertical,
    Clock,
    MessageSquare,
    ChevronUp,
    ChevronDown,
    Save
} from "lucide-react";

interface Followup {
    id?: string;
    agent_id: string;
    sequence_order: number;
    delay_hours: number;
    message_template: string;
    send_after_hour: number;
    send_before_hour: number;
    is_active: boolean;
    skip_if_qualified: boolean;
}

interface FollowupEditorProps {
    agentId: string;
}

const DEFAULT_FOLLOWUP: Omit<Followup, 'agent_id' | 'sequence_order'> = {
    delay_hours: 24,
    message_template: "Oi {{nome}}! 😊 Ainda está interessado nos imóveis que conversamos?",
    send_after_hour: 8,
    send_before_hour: 20,
    is_active: true,
    skip_if_qualified: false
};

const AVAILABLE_VARIABLES = [
    { var: '{{nome}}', desc: 'Nome do cliente' },
    { var: '{{bairro}}', desc: 'Bairro de preferência' },
    { var: '{{tipo_imovel}}', desc: 'Tipo de imóvel' },
    { var: '{{orcamento}}', desc: 'Orçamento' }
];

export function FollowupEditor({ agentId }: FollowupEditorProps) {
    const { toast } = useToast();
    const queryClient = useQueryClient();
    const [editingId, setEditingId] = useState<string | null>(null);

    const { data: followups, isLoading } = useQuery({
        queryKey: ['agent-followups', agentId],
        queryFn: async () => {
            const { data, error } = await supabase
                .from('agent_followups')
                .select('*')
                .eq('agent_id', agentId)
                .order('sequence_order', { ascending: true });
            if (error) throw error;
            return data as Followup[];
        },
        enabled: !!agentId
    });

    const saveMutation = useMutation({
        mutationFn: async (followup: Followup) => {
            if (followup.id) {
                const { error } = await supabase
                    .from('agent_followups')
                    .update({
                        delay_hours: followup.delay_hours,
                        message_template: followup.message_template,
                        send_after_hour: followup.send_after_hour,
                        send_before_hour: followup.send_before_hour,
                        is_active: followup.is_active,
                        skip_if_qualified: followup.skip_if_qualified
                    })
                    .eq('id', followup.id);
                if (error) throw error;
            } else {
                const { error } = await supabase
                    .from('agent_followups')
                    .insert(followup);
                if (error) throw error;
            }
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['agent-followups', agentId] });
            setEditingId(null);
            toast({ title: "Follow-up salvo", description: "Configuração atualizada com sucesso." });
        },
        onError: (error: any) => {
            toast({ title: "Erro", description: error.message, variant: "destructive" });
        }
    });

    const deleteMutation = useMutation({
        mutationFn: async (id: string) => {
            const { error } = await supabase
                .from('agent_followups')
                .delete()
                .eq('id', id);
            if (error) throw error;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['agent-followups', agentId] });
            toast({ title: "Follow-up excluído" });
        }
    });

    const addFollowup = () => {
        const newOrder = (followups?.length || 0) + 1;
        const newFollowup: Followup = {
            ...DEFAULT_FOLLOWUP,
            agent_id: agentId,
            sequence_order: newOrder
        };
        saveMutation.mutate(newFollowup);
    };

    const moveFollowup = async (index: number, direction: 'up' | 'down') => {
        if (!followups) return;
        const newIndex = direction === 'up' ? index - 1 : index + 1;
        if (newIndex < 0 || newIndex >= followups.length) return;

        const current = followups[index];
        const target = followups[newIndex];

        await supabase.from('agent_followups').update({ sequence_order: target.sequence_order }).eq('id', current.id);
        await supabase.from('agent_followups').update({ sequence_order: current.sequence_order }).eq('id', target.id);

        queryClient.invalidateQueries({ queryKey: ['agent-followups', agentId] });
    };

    if (isLoading) {
        return <div className="flex justify-center p-8"><div className="animate-spin rounded-full h-6 w-6 border-b-2 border-primary" /></div>;
    }

    return (
        <div className="space-y-4">
            <div className="flex items-center justify-between">
                <div>
                    <h3 className="text-lg font-semibold">Sequência de Follow-ups</h3>
                    <p className="text-sm text-muted-foreground">
                        Configure mensagens automáticas para reengajar leads inativos
                    </p>
                </div>
                <Button onClick={addFollowup} size="sm">
                    <Plus className="h-4 w-4 mr-1" />
                    Adicionar
                </Button>
            </div>

            <div className="flex flex-wrap gap-2 p-3 bg-muted rounded-lg">
                <span className="text-xs font-medium">Variáveis disponíveis:</span>
                {AVAILABLE_VARIABLES.map(v => (
                    <Badge key={v.var} variant="outline" className="text-xs cursor-help" title={v.desc}>
                        {v.var}
                    </Badge>
                ))}
            </div>

            {(!followups || followups.length === 0) ? (
                <Card className="p-8 text-center">
                    <MessageSquare className="h-12 w-12 mx-auto text-muted-foreground mb-4" />
                    <p className="text-muted-foreground mb-4">Nenhum follow-up configurado</p>
                    <Button onClick={addFollowup}>
                        <Plus className="h-4 w-4 mr-1" />
                        Criar Primeiro Follow-up
                    </Button>
                </Card>
            ) : (
                <div className="space-y-3">
                    {followups.map((followup, index) => (
                        <FollowupCard
                            key={followup.id}
                            followup={followup}
                            index={index}
                            total={followups.length}
                            isEditing={editingId === followup.id}
                            onEdit={() => setEditingId(followup.id || null)}
                            onSave={(updated) => saveMutation.mutate({ ...followup, ...updated })}
                            onDelete={() => deleteMutation.mutate(followup.id!)}
                            onMoveUp={() => moveFollowup(index, 'up')}
                            onMoveDown={() => moveFollowup(index, 'down')}
                            onCancel={() => setEditingId(null)}
                        />
                    ))}
                </div>
            )}
        </div>
    );
}

interface FollowupCardProps {
    followup: Followup;
    index: number;
    total: number;
    isEditing: boolean;
    onEdit: () => void;
    onSave: (updated: Partial<Followup>) => void;
    onDelete: () => void;
    onMoveUp: () => void;
    onMoveDown: () => void;
    onCancel: () => void;
}

function FollowupCard({ followup, index, total, isEditing, onEdit, onSave, onDelete, onMoveUp, onMoveDown, onCancel }: FollowupCardProps) {
    const [form, setForm] = useState(followup);

    useEffect(() => {
        setForm(followup);
    }, [followup]);

    if (!isEditing) {
        return (
            <Card className={`${!followup.is_active ? 'opacity-60' : ''}`}>
                <CardContent className="p-4">
                    <div className="flex items-start gap-3">
                        <div className="flex flex-col gap-1">
                            <Button variant="ghost" size="icon" className="h-6 w-6" onClick={onMoveUp} disabled={index === 0}>
                                <ChevronUp className="h-4 w-4" />
                            </Button>
                            <Button variant="ghost" size="icon" className="h-6 w-6" onClick={onMoveDown} disabled={index === total - 1}>
                                <ChevronDown className="h-4 w-4" />
                            </Button>
                        </div>

                        <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-2 mb-2">
                                <Badge variant={followup.is_active ? "default" : "secondary"}>
                                    #{followup.sequence_order}
                                </Badge>
                                <div className="flex items-center gap-1 text-sm text-muted-foreground">
                                    <Clock className="h-3 w-3" />
                                    Após {followup.delay_hours}h
                                </div>
                                <span className="text-xs text-muted-foreground">
                                    ({followup.send_after_hour}h - {followup.send_before_hour}h)
                                </span>
                            </div>
                            <p className="text-sm line-clamp-2">{followup.message_template}</p>
                        </div>

                        <div className="flex gap-1">
                            <Button variant="outline" size="sm" onClick={onEdit}>Editar</Button>
                            <Button variant="ghost" size="icon" className="text-destructive" onClick={onDelete}>
                                <Trash2 className="h-4 w-4" />
                            </Button>
                        </div>
                    </div>
                </CardContent>
            </Card>
        );
    }

    return (
        <Card className="border-primary">
            <CardHeader className="pb-3">
                <CardTitle className="text-base flex items-center gap-2">
                    <GripVertical className="h-4 w-4" />
                    Follow-up #{followup.sequence_order}
                </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
                <div className="grid grid-cols-3 gap-4">
                    <div className="space-y-2">
                        <Label>Delay (horas)</Label>
                        <Input
                            type="number"
                            min={1}
                            value={form.delay_hours}
                            onChange={(e) => setForm({ ...form, delay_hours: parseInt(e.target.value) || 1 })}
                        />
                    </div>
                    <div className="space-y-2">
                        <Label>Enviar após</Label>
                        <Input
                            type="number"
                            min={0}
                            max={23}
                            value={form.send_after_hour}
                            onChange={(e) => setForm({ ...form, send_after_hour: parseInt(e.target.value) || 8 })}
                        />
                    </div>
                    <div className="space-y-2">
                        <Label>Enviar até</Label>
                        <Input
                            type="number"
                            min={0}
                            max={23}
                            value={form.send_before_hour}
                            onChange={(e) => setForm({ ...form, send_before_hour: parseInt(e.target.value) || 20 })}
                        />
                    </div>
                </div>

                <div className="space-y-2">
                    <Label>Mensagem</Label>
                    <Textarea
                        value={form.message_template}
                        onChange={(e) => setForm({ ...form, message_template: e.target.value })}
                        rows={3}
                        placeholder="Use {{nome}}, {{bairro}}, etc."
                    />
                </div>

                <div className="flex items-center gap-6">
                    <div className="flex items-center gap-2">
                        <Switch
                            checked={form.is_active}
                            onCheckedChange={(checked) => setForm({ ...form, is_active: checked })}
                        />
                        <Label>Ativo</Label>
                    </div>
                    <div className="flex items-center gap-2">
                        <Switch
                            checked={form.skip_if_qualified}
                            onCheckedChange={(checked) => setForm({ ...form, skip_if_qualified: checked })}
                        />
                        <Label>Pular se já qualificado</Label>
                    </div>
                </div>

                <div className="flex justify-end gap-2">
                    <Button variant="outline" onClick={onCancel}>Cancelar</Button>
                    <Button onClick={() => onSave(form)}>
                        <Save className="h-4 w-4 mr-1" />
                        Salvar
                    </Button>
                </div>
            </CardContent>
        </Card>
    );
}

import { useState, useEffect } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Input } from "@/components/ui/input";
import {
    User,
    DollarSign,
    Home,
    MapPin,
    Calendar,
    CreditCard,
    Search,
    Star,
    CheckCircle,
    XCircle,
    Flame,
    Thermometer,
    Snowflake,
    Target
} from "lucide-react";
import { Progress } from "@/components/ui/progress";

interface LeadQualificationData {
    id: string;
    conversation_id: string;
    lead_id: string | null;
    property_type: string | null;
    min_price: number | null;
    max_price: number | null;
    min_bedrooms: number | null;
    max_bedrooms: number | null;
    preferred_neighborhoods: string[] | null;
    preferred_features: string[] | null;
    urgency: string | null;
    financing_needed: boolean | null;
    has_property_to_sell: boolean | null;
    decision_maker: boolean | null;
    qualification_score: number;
    is_qualified: boolean;
    disqualification_reason: string | null;
    // BANT fields
    bant_budget_score: number | null;
    bant_authority_score: number | null;
    bant_need_score: number | null;
    bant_timeline_score: number | null;
    bant_total_score: number | null;
    lead_temperature: string | null;
    created_at: string;
    updated_at: string;
    conversation?: {
        phone_number: string;
        total_messages: number;
        lead_score: number;
        qualification_data: Record<string, any>;
        agent?: {
            name: string;
        };
    };
}

interface LeadQualificationViewProps {
    agentId?: string;
}

export function LeadQualificationView({ agentId }: LeadQualificationViewProps) {
    const [searchTerm, setSearchTerm] = useState("");

    const { data: qualifications, isLoading } = useQuery({
        queryKey: ["lead-qualifications", agentId],
        queryFn: async () => {
            let query = supabase
                .from("ai_lead_qualification")
                .select(`
                    *,
                    conversation:agent_conversations(
                        phone_number,
                        total_messages,
                        lead_score,
                        qualification_data,
                        agent:ai_agents(name)
                    )
                `)
                .order("updated_at", { ascending: false })
                .limit(100);

            if (agentId) {
                query = query.eq("conversation.agent_id", agentId);
            }

            const { data, error } = await query;
            if (error) throw error;
            return data as LeadQualificationData[];
        }
    });

    const filteredQualifications = qualifications?.filter(q => {
        if (!searchTerm) return true;
        const search = searchTerm.toLowerCase();
        return (
            q.conversation?.phone_number?.includes(search) ||
            q.property_type?.toLowerCase().includes(search) ||
            q.preferred_neighborhoods?.some(n => n.toLowerCase().includes(search))
        );
    });

    const formatPrice = (value: number | null) => {
        if (!value) return "N/A";
        if (value >= 1000000) return `R$ ${(value / 1000000).toFixed(1)}M`;
        if (value >= 1000) return `R$ ${(value / 1000).toFixed(0)}k`;
        return `R$ ${value}`;
    };

    const getUrgencyLabel = (urgency: string | null) => {
        const labels: Record<string, { text: string; color: string }> = {
            immediate: { text: "Imediato", color: "bg-red-500" },
            "3_months": { text: "3 meses", color: "bg-orange-500" },
            "6_months": { text: "6 meses", color: "bg-yellow-500" },
            "1_year": { text: "1 ano", color: "bg-blue-500" },
            just_researching: { text: "Pesquisando", color: "bg-gray-500" }
        };
        return labels[urgency || ""] || { text: urgency || "N/A", color: "bg-gray-400" };
    };

    const getTemperatureBadge = (temperature: string | null, totalScore: number | null) => {
        const configs: Record<string, { icon: React.ReactNode; label: string; className: string }> = {
            hot: {
                icon: <Flame className="h-3 w-3" />,
                label: 'Hot Lead',
                className: 'bg-red-500 text-white'
            },
            warm: {
                icon: <Thermometer className="h-3 w-3" />,
                label: 'Warm Lead',
                className: 'bg-orange-500 text-white'
            },
            cool: {
                icon: <Snowflake className="h-3 w-3" />,
                label: 'Cool Lead',
                className: 'bg-blue-400 text-white'
            },
            cold: {
                icon: <Snowflake className="h-3 w-3" />,
                label: 'Cold Lead',
                className: 'bg-gray-400 text-white'
            }
        };
        const config = configs[temperature || 'cold'] || configs.cold;
        return (
            <Badge className={`${config.className} flex items-center gap-1`}>
                {config.icon}
                {totalScore !== null ? `${totalScore}` : config.label}
            </Badge>
        );
    };

    const BANTScoreBar = ({ label, score, max, color }: { label: string; score: number; max: number; color: string }) => (
        <div className="space-y-1">
            <div className="flex justify-between text-xs">
                <span className="text-muted-foreground">{label}</span>
                <span className="font-medium">{score}/{max}</span>
            </div>
            <Progress value={(score / max) * 100} className={`h-1.5 ${color}`} />
        </div>
    );

    if (isLoading) {
        return (
            <div className="flex items-center justify-center h-48">
                <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary" />
            </div>
        );
    }

    return (
        <div className="space-y-4">
            <div className="flex items-center gap-4">
                <div className="relative flex-1 max-w-md">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                    <Input
                        placeholder="Buscar por telefone, tipo ou bairro..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="pl-10"
                    />
                </div>
                <Badge variant="outline">
                    {filteredQualifications?.length || 0} qualificações
                </Badge>
            </div>

            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
                {filteredQualifications?.map((qual) => (
                    <Card key={qual.id} className="hover:shadow-md transition-shadow">
                        <CardHeader className="pb-2">
                            <div className="flex items-center justify-between">
                                <CardTitle className="text-sm font-medium flex items-center gap-2">
                                    <User className="h-4 w-4" />
                                    {qual.conversation?.phone_number || "N/A"}
                                </CardTitle>
                                <div className="flex items-center gap-1">
                                    {qual.lead_temperature ? (
                                        getTemperatureBadge(qual.lead_temperature, qual.bant_total_score)
                                    ) : qual.is_qualified ? (
                                        <Badge className="bg-green-500">
                                            <CheckCircle className="h-3 w-3 mr-1" />
                                            Qualificado
                                        </Badge>
                                    ) : (
                                        <Badge variant="secondary">
                                            <Star className="h-3 w-3 mr-1" />
                                            Score: {qual.qualification_score}
                                        </Badge>
                                    )}
                                </div>
                            </div>
                        </CardHeader>
                        <CardContent className="space-y-3">
                            {/* Property Type */}
                            {qual.property_type && (
                                <div className="flex items-center gap-2 text-sm">
                                    <Home className="h-4 w-4 text-muted-foreground" />
                                    <span className="capitalize">{qual.property_type}</span>
                                    {qual.min_bedrooms && (
                                        <span className="text-muted-foreground">
                                            ({qual.min_bedrooms}+ quartos)
                                        </span>
                                    )}
                                </div>
                            )}

                            {/* Price Range */}
                            {(qual.min_price || qual.max_price) && (
                                <div className="flex items-center gap-2 text-sm">
                                    <DollarSign className="h-4 w-4 text-muted-foreground" />
                                    <span>
                                        {formatPrice(qual.min_price)} - {formatPrice(qual.max_price)}
                                    </span>
                                </div>
                            )}

                            {/* Neighborhoods */}
                            {qual.preferred_neighborhoods && qual.preferred_neighborhoods.length > 0 && (
                                <div className="flex items-center gap-2 text-sm">
                                    <MapPin className="h-4 w-4 text-muted-foreground" />
                                    <span>{qual.preferred_neighborhoods.slice(0, 2).join(", ")}</span>
                                </div>
                            )}

                            {/* Urgency */}
                            {qual.urgency && (
                                <div className="flex items-center gap-2 text-sm">
                                    <Calendar className="h-4 w-4 text-muted-foreground" />
                                    <Badge className={`${getUrgencyLabel(qual.urgency).color} text-white text-xs`}>
                                        {getUrgencyLabel(qual.urgency).text}
                                    </Badge>
                                </div>
                            )}

                            {/* Financing */}
                            <div className="flex items-center gap-4 text-sm">
                                {qual.financing_needed !== null && (
                                    <div className="flex items-center gap-1">
                                        <CreditCard className="h-4 w-4 text-muted-foreground" />
                                        {qual.financing_needed ? (
                                            <span className="text-green-600">Precisa financiar</span>
                                        ) : (
                                            <span className="text-muted-foreground">À vista</span>
                                        )}
                                    </div>
                                )}
                                {qual.decision_maker !== null && (
                                    qual.decision_maker ? (
                                        <Badge variant="outline" className="text-xs">Decisor</Badge>
                                    ) : (
                                        <Badge variant="outline" className="text-xs text-muted-foreground">Não-decisor</Badge>
                                    )
                                )}
                            </div>

                            {/* Disqualification reason */}
                            {qual.disqualification_reason && (
                                <div className="flex items-center gap-2 text-sm text-red-500">
                                    <XCircle className="h-4 w-4" />
                                    <span>{qual.disqualification_reason}</span>
                                </div>
                            )}

                            {/* BANT Score Breakdown */}
                            {qual.bant_total_score !== null && qual.bant_total_score > 0 && (
                                <div className="space-y-2 pt-2 border-t">
                                    <div className="flex items-center gap-2 text-xs font-medium text-muted-foreground">
                                        <Target className="h-3 w-3" />
                                        BANT Score
                                    </div>
                                    <div className="grid gap-1.5">
                                        <BANTScoreBar
                                            label="Budget (Orçamento)"
                                            score={qual.bant_budget_score || 0}
                                            max={25}
                                            color="[&>div]:bg-green-500"
                                        />
                                        <BANTScoreBar
                                            label="Authority (Decisor)"
                                            score={qual.bant_authority_score || 0}
                                            max={20}
                                            color="[&>div]:bg-blue-500"
                                        />
                                        <BANTScoreBar
                                            label="Need (Necessidade)"
                                            score={qual.bant_need_score || 0}
                                            max={30}
                                            color="[&>div]:bg-purple-500"
                                        />
                                        <BANTScoreBar
                                            label="Timeline (Prazo)"
                                            score={qual.bant_timeline_score || 0}
                                            max={25}
                                            color="[&>div]:bg-orange-500"
                                        />
                                    </div>
                                </div>
                            )}

                            {/* Meta info */}
                            <div className="pt-2 border-t text-xs text-muted-foreground flex justify-between">
                                <span>{qual.conversation?.total_messages || 0} msgs</span>
                                <span>
                                    {new Date(qual.updated_at).toLocaleDateString("pt-BR")}
                                </span>
                            </div>
                        </CardContent>
                    </Card>
                ))}
            </div>

            {(!filteredQualifications || filteredQualifications.length === 0) && (
                <Card className="p-8 text-center text-muted-foreground">
                    <p>Nenhuma qualificação encontrada</p>
                    <p className="text-sm mt-1">
                        As qualificações aparecerão aqui conforme os leads conversam com os agentes
                    </p>
                </Card>
            )}
        </div>
    );
}

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Calendar } from "@/components/ui/calendar";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Checkbox } from "@/components/ui/checkbox";
import { Label } from "@/components/ui/label";
import { toast } from "@/hooks/use-toast";
import { supabase } from "@/integrations/supabase/client";
import { 
  Download, 
  FileText, 
  Calendar as CalendarIcon,
  Settings,
  Loader2
} from "lucide-react";
import { format, subDays, startOfDay, endOfDay } from "date-fns";
import { ptBR } from "date-fns/locale";
import { cn } from "@/lib/utils";
import * as XLSX from 'xlsx';

interface ExportOptions {
  startDate: Date;
  endDate: Date;
  format: 'excel' | 'csv' | 'pdf';
  includeAttempts: boolean;
  includeQueue: boolean;
  includeCommunications: boolean;
  includeMetrics: boolean;
  includeCorretorStats: boolean;
}

export const DistributionExporter = () => {
  const [options, setOptions] = useState<ExportOptions>({
    startDate: subDays(new Date(), 7),
    endDate: new Date(),
    format: 'excel',
    includeAttempts: true,
    includeQueue: true,
    includeCommunications: false,
    includeMetrics: true,
    includeCorretorStats: true
  });

  const [isExporting, setIsExporting] = useState(false);

  const fetchExportData = async () => {
    const start = startOfDay(options.startDate).toISOString();
    const end = endOfDay(options.endDate).toISOString();

    const data: any = {};

    // Distribution attempts
    if (options.includeAttempts) {
      const { data: attempts, error: attemptsError } = await supabase
        .from('distribution_attempts')
        .select(`
          *,
          leads!inner(nome, telefone, email),
          corretores!inner(
            profiles!inner(first_name, last_name),
            whatsapp,
            creci
          )
        `)
        .gte('created_at', start)
        .lte('created_at', end)
        .order('created_at', { ascending: false });

      if (attemptsError) throw attemptsError;
      data.attempts = attempts;
    }

    // Distribution queue
    if (options.includeQueue) {
      const { data: queue, error: queueError } = await supabase
        .from('distribution_queue')
        .select(`
          *,
          leads!inner(nome, telefone, email, empreendimento_id)
        `)
        .gte('created_at', start)
        .lte('created_at', end)
        .order('created_at', { ascending: false });

      if (queueError) throw queueError;
      data.queue = queue;
    }

    // Communications
    if (options.includeCommunications) {
      const { data: communications, error: commError } = await supabase
        .from('communication_log')
        .select('*')
        .gte('created_at', start)
        .lte('created_at', end)
        .order('created_at', { ascending: false });

      if (commError) throw commError;
      data.communications = communications;
    }

    // Corretor stats
    if (options.includeCorretorStats) {
      const { data: corretorStats, error: statsError } = await supabase
        .from('distribution_attempts')
        .select(`
          corretor_id,
          status,
          response_received_at,
          message_sent_at,
          corretores!inner(
            profiles!inner(first_name, last_name),
            whatsapp,
            creci,
            total_visitas,
            nota_media
          )
        `)
        .gte('created_at', start)
        .lte('created_at', end);

      if (statsError) throw statsError;

      // Agrupar por corretor
      const statsMap = new Map();
      corretorStats?.forEach(attempt => {
        const id = attempt.corretor_id;
        if (!statsMap.has(id)) {
          statsMap.set(id, {
            corretor_id: id,
            nome: `${attempt.corretores.profiles.first_name} ${attempt.corretores.profiles.last_name}`,
            whatsapp: attempt.corretores.whatsapp,
            creci: attempt.corretores.creci,
            total_visitas: attempt.corretores.total_visitas,
            nota_media: attempt.corretores.nota_media,
            total_attempts: 0,
            accepted: 0,
            rejected: 0,
            timeout: 0,
            response_times: []
          });
        }

        const stats = statsMap.get(id);
        stats.total_attempts++;

        if (attempt.status === 'accepted') stats.accepted++;
        else if (attempt.status === 'rejected') stats.rejected++;
        else if (attempt.status === 'timeout') stats.timeout++;

        if (attempt.response_received_at && attempt.message_sent_at) {
          const responseTime = (new Date(attempt.response_received_at).getTime() - 
                              new Date(attempt.message_sent_at).getTime()) / (1000 * 60);
          stats.response_times.push(responseTime);
        }
      });

      data.corretorStats = Array.from(statsMap.values()).map(stats => ({
        ...stats,
        acceptance_rate: stats.total_attempts > 0 ? (stats.accepted / stats.total_attempts) * 100 : 0,
        response_time_avg: stats.response_times.length > 0 
          ? stats.response_times.reduce((a: number, b: number) => a + b, 0) / stats.response_times.length 
          : 0
      }));
    }

    return data;
  };

  const exportToExcel = (data: any) => {
    const workbook = XLSX.utils.book_new();

    // Aba de tentativas de distribuição
    if (data.attempts) {
      const attemptsData = data.attempts.map((attempt: any) => ({
        'Data/Hora': format(new Date(attempt.created_at), 'dd/MM/yyyy HH:mm', { locale: ptBR }),
        'Lead': attempt.leads.nome,
        'Telefone': attempt.leads.telefone,
        'Corretor': `${attempt.corretores.profiles.first_name} ${attempt.corretores.profiles.last_name}`,
        'WhatsApp Corretor': attempt.corretores.whatsapp,
        'Ordem Tentativa': attempt.attempt_order,
        'Status': attempt.status,
        'Resposta': attempt.response_type || '',
        'Mensagem Resposta': attempt.response_message || '',
        'Enviado em': attempt.message_sent_at ? format(new Date(attempt.message_sent_at), 'dd/MM/yyyy HH:mm', { locale: ptBR }) : '',
        'Respondido em': attempt.response_received_at ? format(new Date(attempt.response_received_at), 'dd/MM/yyyy HH:mm', { locale: ptBR }) : '',
        'Timeout em': format(new Date(attempt.timeout_at), 'dd/MM/yyyy HH:mm', { locale: ptBR })
      }));

      const attemptsSheet = XLSX.utils.json_to_sheet(attemptsData);
      XLSX.utils.book_append_sheet(workbook, attemptsSheet, 'Tentativas de Distribuição');
    }

    // Aba da fila de distribuição
    if (data.queue) {
      const queueData = data.queue.map((item: any) => ({
        'Data Criação': format(new Date(item.created_at), 'dd/MM/yyyy HH:mm', { locale: ptBR }),
        'Lead': item.leads.nome,
        'Telefone': item.leads.telefone,
        'Status': item.status,
        'Tentativa Atual': item.current_attempt,
        'Iniciado em': format(new Date(item.started_at), 'dd/MM/yyyy HH:mm', { locale: ptBR }),
        'Completado em': item.completed_at ? format(new Date(item.completed_at), 'dd/MM/yyyy HH:mm', { locale: ptBR }) : '',
        'Motivo Falha': item.failure_reason || ''
      }));

      const queueSheet = XLSX.utils.json_to_sheet(queueData);
      XLSX.utils.book_append_sheet(workbook, queueSheet, 'Fila de Distribuição');
    }

    // Aba de comunicações
    if (data.communications) {
      const commData = data.communications.map((comm: any) => ({
        'Data/Hora': format(new Date(comm.created_at), 'dd/MM/yyyy HH:mm', { locale: ptBR }),
        'Tipo': comm.type,
        'Direção': comm.direction,
        'Telefone': comm.phone_number,
        'Status': comm.status,
        'Mensagem': comm.content.substring(0, 100) + (comm.content.length > 100 ? '...' : ''),
        'Message ID': comm.message_id || ''
      }));

      const commSheet = XLSX.utils.json_to_sheet(commData);
      XLSX.utils.book_append_sheet(workbook, commSheet, 'Comunicações');
    }

    // Aba de estatísticas dos corretores
    if (data.corretorStats) {
      const statsData = data.corretorStats.map((stats: any) => ({
        'Corretor': stats.nome,
        'WhatsApp': stats.whatsapp,
        'CRECI': stats.creci,
        'Total Tentativas': stats.total_attempts,
        'Aceitos': stats.accepted,
        'Rejeitados': stats.rejected,
        'Timeouts': stats.timeout,
        'Taxa Aceitação (%)': stats.acceptance_rate.toFixed(2),
        'Tempo Médio Resposta (min)': stats.response_time_avg.toFixed(2),
        'Total Visitas': stats.total_visitas,
        'Nota Média': stats.nota_media
      }));

      const statsSheet = XLSX.utils.json_to_sheet(statsData);
      XLSX.utils.book_append_sheet(workbook, statsSheet, 'Estatísticas Corretores');
    }

    // Salvar arquivo
    const fileName = `relatorio_distribuicao_${format(options.startDate, 'yyyy-MM-dd')}_${format(options.endDate, 'yyyy-MM-dd')}.xlsx`;
    XLSX.writeFile(workbook, fileName);
  };

  const exportToCSV = (data: any) => {
    if (data.attempts) {
      const attemptsData = data.attempts.map((attempt: any) => ({
        data_hora: format(new Date(attempt.created_at), 'dd/MM/yyyy HH:mm', { locale: ptBR }),
        lead: attempt.leads.nome,
        telefone: attempt.leads.telefone,
        corretor: `${attempt.corretores.profiles.first_name} ${attempt.corretores.profiles.last_name}`,
        status: attempt.status,
        ordem_tentativa: attempt.attempt_order
      }));

      const csv = XLSX.utils.json_to_sheet(attemptsData);
      const csvOutput = XLSX.utils.sheet_to_csv(csv);

      const blob = new Blob([csvOutput], { type: 'text/csv;charset=utf-8;' });
      const link = document.createElement('a');
      const url = URL.createObjectURL(blob);
      link.setAttribute('href', url);
      link.setAttribute('download', `tentativas_distribuicao_${format(options.startDate, 'yyyy-MM-dd')}_${format(options.endDate, 'yyyy-MM-dd')}.csv`);
      link.style.visibility = 'hidden';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
  };

  const handleExport = async () => {
    if (!options.includeAttempts && !options.includeQueue && !options.includeCommunications && !options.includeCorretorStats) {
      toast({
        title: "Erro",
        description: "Selecione pelo menos uma opção para exportar",
        variant: "destructive"
      });
      return;
    }

    setIsExporting(true);

    try {
      const data = await fetchExportData();

      if (options.format === 'excel') {
        exportToExcel(data);
      } else if (options.format === 'csv') {
        exportToCSV(data);
      }

      toast({
        title: "Sucesso",
        description: "Relatório exportado com sucesso!"
      });
    } catch (error) {
      console.error('Erro na exportação:', error);
      toast({
        title: "Erro",
        description: "Erro ao exportar relatório",
        variant: "destructive"
      });
    } finally {
      setIsExporting(false);
    }
  };

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Download className="h-5 w-5" />
          Exportar Relatórios
        </CardTitle>
      </CardHeader>
      <CardContent className="space-y-4">
        {/* Período */}
        <div className="grid grid-cols-2 gap-4">
          <div>
            <Label>Data Início</Label>
            <Popover>
              <PopoverTrigger asChild>
                <Button variant="outline" className="w-full justify-start text-left font-normal">
                  <CalendarIcon className="mr-2 h-4 w-4" />
                  {format(options.startDate, "dd/MM/yyyy")}
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-auto p-0" align="start">
                <Calendar
                  mode="single"
                  selected={options.startDate}
                  onSelect={(date) => date && setOptions(prev => ({ ...prev, startDate: date }))}
                  initialFocus
                  className={cn("p-3 pointer-events-auto")}
                />
              </PopoverContent>
            </Popover>
          </div>

          <div>
            <Label>Data Fim</Label>
            <Popover>
              <PopoverTrigger asChild>
                <Button variant="outline" className="w-full justify-start text-left font-normal">
                  <CalendarIcon className="mr-2 h-4 w-4" />
                  {format(options.endDate, "dd/MM/yyyy")}
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-auto p-0" align="start">
                <Calendar
                  mode="single"
                  selected={options.endDate}
                  onSelect={(date) => date && setOptions(prev => ({ ...prev, endDate: date }))}
                  initialFocus
                  className={cn("p-3 pointer-events-auto")}
                />
              </PopoverContent>
            </Popover>
          </div>
        </div>

        {/* Formato */}
        <div>
          <Label>Formato do Arquivo</Label>
          <Select 
            value={options.format} 
            onValueChange={(value: 'excel' | 'csv' | 'pdf') => 
              setOptions(prev => ({ ...prev, format: value }))
            }
          >
            <SelectTrigger>
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="excel">Excel (.xlsx)</SelectItem>
              <SelectItem value="csv">CSV (.csv)</SelectItem>
              <SelectItem value="pdf" disabled>PDF (em breve)</SelectItem>
            </SelectContent>
          </Select>
        </div>

        {/* Opções de Conteúdo */}
        <div>
          <Label className="text-base font-medium">Incluir nos Relatórios</Label>
          <div className="space-y-3 mt-2">
            <div className="flex items-center space-x-2">
              <Checkbox 
                id="attempts"
                checked={options.includeAttempts}
                onCheckedChange={(checked) => 
                  setOptions(prev => ({ ...prev, includeAttempts: !!checked }))
                }
              />
              <Label htmlFor="attempts">Tentativas de Distribuição</Label>
            </div>

            <div className="flex items-center space-x-2">
              <Checkbox 
                id="queue"
                checked={options.includeQueue}
                onCheckedChange={(checked) => 
                  setOptions(prev => ({ ...prev, includeQueue: !!checked }))
                }
              />
              <Label htmlFor="queue">Fila de Distribuição</Label>
            </div>

            <div className="flex items-center space-x-2">
              <Checkbox 
                id="communications"
                checked={options.includeCommunications}
                onCheckedChange={(checked) => 
                  setOptions(prev => ({ ...prev, includeCommunications: !!checked }))
                }
              />
              <Label htmlFor="communications">Log de Comunicações</Label>
            </div>

            <div className="flex items-center space-x-2">
              <Checkbox 
                id="corretor-stats"
                checked={options.includeCorretorStats}
                onCheckedChange={(checked) => 
                  setOptions(prev => ({ ...prev, includeCorretorStats: !!checked }))
                }
              />
              <Label htmlFor="corretor-stats">Estatísticas dos Corretores</Label>
            </div>
          </div>
        </div>

        {/* Botão de Exportação */}
        <Button 
          onClick={handleExport} 
          className="w-full" 
          disabled={isExporting}
        >
          {isExporting ? (
            <>
              <Loader2 className="mr-2 h-4 w-4 animate-spin" />
              Exportando...
            </>
          ) : (
            <>
              <FileText className="mr-2 h-4 w-4" />
              Exportar Relatório
            </>
          )}
        </Button>
      </CardContent>
    </Card>
  );
};

import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { RefreshCw, Clock, CheckCircle, XCircle, AlertTriangle } from "lucide-react";
import { DistributionTester } from "./DistributionTester";
import { AdvancedDistributionMetrics } from "./AdvancedDistributionMetrics";
import { DistributionExporter } from "./DistributionExporter";
import { Calendar } from "@/components/ui/calendar";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { CalendarIcon } from "lucide-react";
import { format, subDays, startOfDay, endOfDay } from "date-fns";
import { ptBR } from "date-fns/locale";
import { cn } from "@/lib/utils";
import { useState } from "react";
