import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Clock, CheckCircle2, XCircle, AlertCircle, User, Calendar } from "lucide-react";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";

interface VisitDistributionAttempt {
  id: string;
  visita_id: string;
  corretor_id: string;
  attempt_order: number;
  message_sent_at: string;
  timeout_at: string;
  response_received_at: string | null;
  status: string;
  response_message: string | null;
  response_type: string | null;
  corretores: {
    profiles: {
      first_name: string;
      last_name: string;
    };
  };
  visitas: {
    data_visita: string;
    horario_visita: string;
    leads: {
      nome: string;
    };
  };
}

export function VisitDistributionMonitor() {
  const { data: activeDistributions, isLoading } = useQuery({
    queryKey: ['active-visit-distributions'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('visit_distribution_queue')
        .select(`
          id,
          visita_id,
          status,
          current_attempt,
          started_at,
          assigned_corretor_id,
          visitas (
            data_visita,
            horario_visita,
            leads (nome)
          )
        `)
        .in('status', ['pending', 'in_progress'])
        .order('started_at', { ascending: false });

      if (error) throw error;
      return data;
    },
    refetchInterval: 5000, // Atualiza a cada 5 segundos
  });

  const { data: recentAttempts } = useQuery({
    queryKey: ['recent-visit-attempts'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('visit_distribution_attempts')
        .select(`
          id,
          visita_id,
          corretor_id,
          attempt_order,
          message_sent_at,
          timeout_at,
          response_received_at,
          status,
          response_message,
          response_type,
          corretores (
            profiles (
              first_name,
              last_name
            )
          ),
          visitas (
            data_visita,
            horario_visita,
            leads (nome)
          )
        `)
        .order('message_sent_at', { ascending: false })
        .limit(20);

      if (error) throw error;
      return data as unknown as VisitDistributionAttempt[];
    },
    refetchInterval: 5000,
  });

  const getStatusBadge = (status: string) => {
    const variants: Record<string, { variant: "default" | "secondary" | "destructive" | "outline", icon: any }> = {
      pending: { variant: "outline", icon: Clock },
      accepted: { variant: "default", icon: CheckCircle2 },
      rejected: { variant: "secondary", icon: XCircle },
      timeout: { variant: "destructive", icon: AlertCircle },
      error: { variant: "destructive", icon: XCircle },
    };

    const config = variants[status] || variants.pending;
    const Icon = config.icon;

    return (
      <Badge variant={config.variant} className="flex items-center gap-1">
        <Icon className="h-3 w-3" />
        {status === 'pending' ? 'Aguardando' : 
         status === 'accepted' ? 'Aceito' :
         status === 'rejected' ? 'Recusado' :
         status === 'timeout' ? 'Expirado' : 'Erro'}
      </Badge>
    );
  };

  const getQueueStatusBadge = (status: string) => {
    const variants: Record<string, "default" | "secondary" | "destructive" | "outline"> = {
      pending: "outline",
      in_progress: "default",
      completed: "secondary",
      failed: "destructive",
      cancelled: "secondary",
    };

    return (
      <Badge variant={variants[status] || "outline"}>
        {status === 'pending' ? 'Pendente' :
         status === 'in_progress' ? 'Em Andamento' :
         status === 'completed' ? 'Concluída' :
         status === 'failed' ? 'Falhou' : 'Cancelada'}
      </Badge>
    );
  };

  if (isLoading) {
    return (
      <Card>
        <CardHeader>
          <CardTitle>Monitor de Distribuição de Visitas</CardTitle>
        </CardHeader>
        <CardContent>
          <p className="text-muted-foreground">Carregando...</p>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-6">
      {/* Distribuições Ativas */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Clock className="h-5 w-5" />
            Distribuições Ativas
          </CardTitle>
        </CardHeader>
        <CardContent>
          {!activeDistributions || activeDistributions.length === 0 ? (
            <p className="text-muted-foreground">Nenhuma distribuição ativa no momento</p>
          ) : (
            <ScrollArea className="h-[200px]">
              <div className="space-y-3">
                {activeDistributions.map((dist: any) => (
                  <div key={dist.id} className="flex items-center justify-between p-3 border rounded-lg">
                    <div className="space-y-1">
                      <p className="font-medium">{dist.visitas?.leads?.nome || 'Lead sem nome'}</p>
                      <div className="flex items-center gap-2 text-sm text-muted-foreground">
                        <Calendar className="h-3 w-3" />
                        {format(new Date(dist.visitas?.data_visita || new Date()), 'dd/MM/yyyy', { locale: ptBR })}
                        {' às '}
                        {dist.visitas?.horario_visita}
                      </div>
                      <p className="text-xs text-muted-foreground">
                        Tentativa {dist.current_attempt}
                      </p>
                    </div>
                    <div className="text-right">
                      {getQueueStatusBadge(dist.status)}
                    </div>
                  </div>
                ))}
              </div>
            </ScrollArea>
          )}
        </CardContent>
      </Card>

      {/* Tentativas Recentes */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <User className="h-5 w-5" />
            Tentativas Recentes
          </CardTitle>
        </CardHeader>
        <CardContent>
          {!recentAttempts || recentAttempts.length === 0 ? (
            <p className="text-muted-foreground">Nenhuma tentativa registrada</p>
          ) : (
            <ScrollArea className="h-[400px]">
              <div className="space-y-3">
                {recentAttempts.map((attempt) => (
                  <div key={attempt.id} className="p-4 border rounded-lg space-y-2">
                    <div className="flex items-start justify-between">
                      <div className="space-y-1">
                        <p className="font-medium">
                          {attempt.corretores?.profiles?.first_name} {attempt.corretores?.profiles?.last_name}
                        </p>
                        <p className="text-sm text-muted-foreground">
                          Lead: {attempt.visitas?.leads?.nome || 'Sem nome'}
                        </p>
                        <div className="flex items-center gap-2 text-xs text-muted-foreground">
                          <Calendar className="h-3 w-3" />
                          {format(new Date(attempt.visitas?.data_visita || new Date()), 'dd/MM/yyyy', { locale: ptBR })}
                          {' às '}
                          {attempt.visitas?.horario_visita}
                        </div>
                      </div>
                      {getStatusBadge(attempt.status)}
                    </div>

                    <div className="flex items-center gap-4 text-xs text-muted-foreground">
                      <span>Tentativa #{attempt.attempt_order}</span>
                      <span>
                        Enviado: {format(new Date(attempt.message_sent_at), 'dd/MM HH:mm', { locale: ptBR })}
                      </span>
                      {attempt.response_received_at && (
                        <span>
                          Resposta: {format(new Date(attempt.response_received_at), 'dd/MM HH:mm', { locale: ptBR })}
                        </span>
                      )}
                    </div>

                    {attempt.response_message && (
                      <p className="text-sm p-2 bg-muted rounded">
                        "{attempt.response_message}"
                      </p>
                    )}
                  </div>
                ))}
              </div>
            </ScrollArea>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Switch } from "@/components/ui/switch";
import { Button } from "@/components/ui/button";
import { useToast } from "@/hooks/use-toast";
import { Settings, Save, Clock, Users, Bell } from "lucide-react";

export function VisitDistributionSettings() {
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const { data: settings, isLoading } = useQuery({
    queryKey: ['distribution-settings'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('distribution_settings')
        .select('*')
        .single();

      if (error) throw error;
      return data;
    },
  });

  const [formData, setFormData] = useState({
    max_attempts: settings?.max_attempts || 5,
    timeout_minutes: settings?.timeout_minutes || 15,
    auto_distribution_enabled: settings?.auto_distribution_enabled ?? true,
    fallback_to_admin: settings?.fallback_to_admin ?? true,
    notification_method: settings?.notification_method || 'whatsapp',
  });

  // Atualiza formData quando settings carrega
  useState(() => {
    if (settings) {
      setFormData({
        max_attempts: settings.max_attempts || 5,
        timeout_minutes: settings.timeout_minutes || 15,
        auto_distribution_enabled: settings.auto_distribution_enabled ?? true,
        fallback_to_admin: settings.fallback_to_admin ?? true,
        notification_method: settings.notification_method || 'whatsapp',
      });
    }
  });

  const updateMutation = useMutation({
    mutationFn: async (data: typeof formData) => {
      const { error } = await supabase
        .from('distribution_settings')
        .upsert({
          id: settings?.id || crypto.randomUUID(),
          ...data,
          updated_at: new Date().toISOString(),
        });

      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['distribution-settings'] });
      toast({
        title: "Configurações salvas",
        description: "As configurações de distribuição foram atualizadas com sucesso",
      });
    },
    onError: (error: any) => {
      toast({
        title: "Erro ao salvar",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  const handleSave = () => {
    updateMutation.mutate(formData);
  };

  if (isLoading) {
    return (
      <Card>
        <CardHeader>
          <CardTitle>Configurações de Distribuição</CardTitle>
        </CardHeader>
        <CardContent>
          <p className="text-muted-foreground">Carregando...</p>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Settings className="h-5 w-5" />
          Configurações de Distribuição de Visitas
        </CardTitle>
        <CardDescription>
          Configure como as visitas são distribuídas automaticamente para os corretores
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-6">
        {/* Distribuição Automática */}
        <div className="flex items-center justify-between">
          <div className="space-y-0.5">
            <Label htmlFor="auto-distribution" className="text-base">
              Distribuição Automática
            </Label>
            <p className="text-sm text-muted-foreground">
              Ativar distribuição automática de visitas para corretores
            </p>
          </div>
          <Switch
            id="auto-distribution"
            checked={formData.auto_distribution_enabled}
            onCheckedChange={(checked) =>
              setFormData({ ...formData, auto_distribution_enabled: checked })
            }
          />
        </div>

        {/* Número Máximo de Tentativas */}
        <div className="space-y-2">
          <Label htmlFor="max-attempts" className="flex items-center gap-2">
            <Users className="h-4 w-4" />
            Número Máximo de Tentativas
          </Label>
          <Input
            id="max-attempts"
            type="number"
            min="1"
            max="10"
            value={formData.max_attempts}
            onChange={(e) =>
              setFormData({ ...formData, max_attempts: parseInt(e.target.value) || 5 })
            }
          />
          <p className="text-xs text-muted-foreground">
            Quantos corretores serão contatados antes de notificar o administrador
          </p>
        </div>

        {/* Tempo Limite por Tentativa */}
        <div className="space-y-2">
          <Label htmlFor="timeout" className="flex items-center gap-2">
            <Clock className="h-4 w-4" />
            Tempo Limite por Tentativa (minutos)
          </Label>
          <Input
            id="timeout"
            type="number"
            min="5"
            max="60"
            value={formData.timeout_minutes}
            onChange={(e) =>
              setFormData({ ...formData, timeout_minutes: parseInt(e.target.value) || 15 })
            }
          />
          <p className="text-xs text-muted-foreground">
            Quanto tempo cada corretor tem para responder antes de passar para o próximo
          </p>
        </div>

        {/* Fallback para Admin */}
        <div className="flex items-center justify-between">
          <div className="space-y-0.5">
            <Label htmlFor="fallback-admin" className="text-base flex items-center gap-2">
              <Bell className="h-4 w-4" />
              Notificar Administrador
            </Label>
            <p className="text-sm text-muted-foreground">
              Notificar admin quando todas as tentativas falharem
            </p>
          </div>
          <Switch
            id="fallback-admin"
            checked={formData.fallback_to_admin}
            onCheckedChange={(checked) =>
              setFormData({ ...formData, fallback_to_admin: checked })
            }
          />
        </div>

        {/* Botão Salvar */}
        <Button
          onClick={handleSave}
          disabled={updateMutation.isPending}
          className="w-full"
        >
          <Save className="h-4 w-4 mr-2" />
          {updateMutation.isPending ? 'Salvando...' : 'Salvar Configurações'}
        </Button>
      </CardContent>
    </Card>
  );
}

import { useState, useEffect } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { 
  CheckCircle, 
  XCircle, 
  Clock, 
  Activity, 
  RefreshCw,
  ChevronDown,
  ChevronUp,
  Info,
  Zap
} from "lucide-react";
import { formatDistanceToNow } from "date-fns";
import { ptBR } from "date-fns/locale";

interface WebhookLog {
  id: string;
  event_type: string;
  instance_name: string;
  payload: any;
  processed_successfully: boolean;
  error_message: string | null;
  processing_time_ms: number | null;
  created_at: string;
}

export function WebhookMonitor() {
  const [expandedLog, setExpandedLog] = useState<string | null>(null);
  const [autoRefresh, setAutoRefresh] = useState(true);

  // Query para buscar logs de webhook
  const { data: logs = [], refetch, isLoading } = useQuery({
    queryKey: ['webhook-logs'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('webhook_logs')
        .select('*')
        .order('created_at', { ascending: false })
        .limit(20);

      if (error) throw error;
      return data as WebhookLog[];
    },
    refetchInterval: autoRefresh ? 10000 : false // Auto-refresh a cada 10 segundos
  });

  // Query para estatísticas
  const { data: stats } = useQuery({
    queryKey: ['webhook-stats'],
    queryFn: async () => {
      const twentyFourHoursAgo = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();

      const { data, error } = await supabase
        .from('webhook_logs')
        .select('processed_successfully, processing_time_ms')
        .gte('created_at', twentyFourHoursAgo);

      if (error) throw error;

      const total = data.length;
      const successful = data.filter(log => log.processed_successfully).length;
      const failed = total - successful;
      const successRate = total > 0 ? ((successful / total) * 100).toFixed(1) : '0';

      const processingTimes = data
        .filter(log => log.processing_time_ms !== null)
        .map(log => log.processing_time_ms!);

      const avgProcessingTime = processingTimes.length > 0
        ? Math.round(processingTimes.reduce((a, b) => a + b, 0) / processingTimes.length)
        : 0;

      return {
        total,
        successful,
        failed,
        successRate,
        avgProcessingTime
      };
    },
    refetchInterval: autoRefresh ? 10000 : false
  });

  // Verificar se webhook está ativo (recebeu evento nas últimas 24h)
  const isWebhookActive = logs.length > 0 && 
    (Date.now() - new Date(logs[0].created_at).getTime()) < 24 * 60 * 60 * 1000;

  const getEventBadge = (eventType: string) => {
    const eventMap: Record<string, { label: string; variant: "default" | "secondary" | "success" }> = {
      'messages.upsert': { label: 'Mensagem Recebida', variant: 'default' },
      'MESSAGES_UPSERT': { label: 'Mensagem Recebida', variant: 'default' },
      'messages.update': { label: 'Status Atualizado', variant: 'secondary' },
      'MESSAGES_UPDATE': { label: 'Status Atualizado', variant: 'secondary' },
      'connection.update': { label: 'Conexão', variant: 'secondary' },
      'CONNECTION_UPDATE': { label: 'Conexão', variant: 'secondary' },
      'TEST_CONNECTION': { label: 'Teste', variant: 'success' }
    };

    const config = eventMap[eventType] || { label: eventType, variant: 'secondary' };
    return <Badge variant={config.variant}>{config.label}</Badge>;
  };

  return (
    <div className="space-y-6">
      {/* Header com estatísticas */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">Total (24h)</p>
                <p className="text-2xl font-bold">{stats?.total || 0}</p>
              </div>
              <Activity className="w-8 h-8 text-muted-foreground" />
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">Taxa de Sucesso</p>
                <p className="text-2xl font-bold text-green-600">{stats?.successRate || 0}%</p>
              </div>
              <CheckCircle className="w-8 h-8 text-green-600" />
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">Tempo Médio</p>
                <p className="text-2xl font-bold">{stats?.avgProcessingTime || 0}ms</p>
              </div>
              <Clock className="w-8 h-8 text-muted-foreground" />
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">Status</p>
                <p className="text-sm font-medium">
                  {isWebhookActive ? (
                    <span className="text-green-600">Ativo</span>
                  ) : (
                    <span className="text-muted-foreground">Inativo</span>
                  )}
                </p>
              </div>
              {isWebhookActive ? (
                <Zap className="w-8 h-8 text-green-600" />
              ) : (
                <XCircle className="w-8 h-8 text-muted-foreground" />
              )}
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Lista de Webhooks */}
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <div>
              <CardTitle>Últimos Webhooks Recebidos</CardTitle>
              <CardDescription>
                Monitoramento em tempo real dos webhooks da Evolution API
              </CardDescription>
            </div>
            <div className="flex items-center gap-2">
              <Button
                variant="outline"
                size="sm"
                onClick={() => setAutoRefresh(!autoRefresh)}
              >
                {autoRefresh ? 'Pausar' : 'Ativar'} Auto-Refresh
              </Button>
              <Button
                variant="outline"
                size="sm"
                onClick={() => refetch()}
                disabled={isLoading}
              >
                <RefreshCw className={`w-4 h-4 ${isLoading ? 'animate-spin' : ''}`} />
              </Button>
            </div>
          </div>
        </CardHeader>
        <CardContent>
          {logs.length === 0 ? (
            <Alert>
              <Info className="h-4 w-4" />
              <AlertDescription>
                Nenhum webhook recebido ainda. Configure o webhook na Evolution API para começar a receber eventos.
              </AlertDescription>
            </Alert>
          ) : (
            <ScrollArea className="h-[500px] pr-4">
              <div className="space-y-2">
                {logs.map((log) => (
                  <Card key={log.id} className="border">
                    <CardContent className="p-4">
                      <div className="space-y-2">
                        {/* Header do log */}
                        <div className="flex items-center justify-between">
                          <div className="flex items-center gap-2">
                            {log.processed_successfully ? (
                              <CheckCircle className="w-4 h-4 text-green-600" />
                            ) : (
                              <XCircle className="w-4 h-4 text-red-600" />
                            )}
                            {getEventBadge(log.event_type)}
                            {log.instance_name && (
                              <Badge variant="outline">{log.instance_name}</Badge>
                            )}
                          </div>
                          <div className="flex items-center gap-2 text-sm text-muted-foreground">
                            {log.processing_time_ms && (
                              <span>{log.processing_time_ms}ms</span>
                            )}
                            <span>
                              {formatDistanceToNow(new Date(log.created_at), {
                                addSuffix: true,
                                locale: ptBR
                              })}
                            </span>
                            <Button
                              variant="ghost"
                              size="sm"
                              onClick={() => setExpandedLog(expandedLog === log.id ? null : log.id)}
                            >
                              {expandedLog === log.id ? (
                                <ChevronUp className="w-4 h-4" />
                              ) : (
                                <ChevronDown className="w-4 h-4" />
                              )}
                            </Button>
                          </div>
                        </div>

                        {/* Erro (se houver) */}
                        {log.error_message && (
                          <Alert variant="destructive" className="mt-2">
                            <AlertDescription className="text-sm">
                              {log.error_message}
                            </AlertDescription>
                          </Alert>
                        )}

                        {/* Payload expandido */}
                        {expandedLog === log.id && (
                          <div className="mt-2 p-3 bg-muted rounded-lg">
                            <p className="text-xs font-mono text-muted-foreground mb-2">
                              Payload completo:
                            </p>
                            <pre className="text-xs overflow-x-auto">
                              {JSON.stringify(log.payload, null, 2)}
                            </pre>
                          </div>
                        )}
                      </div>
                    </CardContent>
                  </Card>
                ))}
              </div>
            </ScrollArea>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
