interface Visita {
  id: string;
  data_visita: string;
  horario_visita: string;
  status: string;
  lead: {
    nome: string;
    telefone: string;
  };
  corretor: {
    first_name: string;
    last_name: string;
  };
  corretor_whatsapp: string | null;
  empreendimento: {
    nome: string;
  };
}

const statusVariants = {
  agendada: "secondary",
  confirmada: "default",
  realizada: "success",
  cancelada: "destructive",
  reagendada: "warning"
} as const;

const statusLabels = {
  agendada: "Agendada",
  confirmada: "Confirmada",
  realizada: "Realizada",
  cancelada: "Cancelada",
  reagendada: "Reagendada"
};

export default function VisitasCalendar() {
  const [selectedDate, setSelectedDate] = useState<Date>(new Date());

  const { data: visitas = [], isLoading } = useQuery({
    queryKey: ['visitas-calendar'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('visitas')
        .select(`
          id,
          data_visita,
          horario_visita,
          status,
          leads(nome, telefone),
          corretores(
            whatsapp,
            profiles(first_name, last_name)
          ),
          empreendimentos(nome)
        `)
        .is('deleted_at', null)
        .order('data_visita', { ascending: true })
        .order('horario_visita', { ascending: true });

      if (error) throw error;
      return data?.map(item => ({
        id: item.id,
        data_visita: item.data_visita,
        horario_visita: item.horario_visita,
        status: item.status,
        lead: item.leads,
        corretor: item.corretores?.profiles,
        corretor_whatsapp: (item.corretores as any)?.whatsapp || null,
        empreendimento: item.empreendimentos
      })) as Visita[] || [];
    }
  });

  const getVisitasForDate = (date: Date) => {
    return visitas.filter(visita =>
      isSameLocalDay(visita.data_visita, date)
    );
  };

  const modifiers = {
    hasVisitas: (date: Date) => getVisitasForDate(date).length > 0
  };

  // Estilo customizado para o indicador (bolinha)
  const modifiersStyles = {
    hasVisitas: {
      position: 'relative',
    } as React.CSSProperties
  };

  const selectedDateVisitas = getVisitasForDate(selectedDate);

  if (isLoading) {
    return <CalendarLoadingSkeleton />;
  }

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 animate-fade-in">
      <Card className="lg:col-span-2 hover-scale transition-all duration-200">
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <CalendarDays className="w-5 h-5" />
            Calendário de Visitas
          </CardTitle>
        </CardHeader>
        <CardContent className="p-2 md:p-6">
          <style>{`
              .rdp-day_hasVisitas::after {
                content: '';
                position: absolute;
                bottom: 2px;
                left: 50%;
                transform: translateX(-50%);
                width: 6px;
                height: 6px;
                border-radius: 50%;
                background-color: #ec4899; /* Pink-500 */
              }
            `}</style>
          <Calendar
            mode="single"
            selected={selectedDate}
            onSelect={(date) => date && setSelectedDate(date)}
            modifiers={modifiers}
            modifiersClassNames={{
              hasVisitas: 'rdp-day_hasVisitas'
            }}
            locale={ptBR}
            className="rounded-md border mx-auto w-full"
          />
        </CardContent>
      </Card>

      <Card className="hover-scale transition-all duration-200">
        <CardHeader>
          <CardTitle className="animate-fade-in">
            Visitas - {format(selectedDate, 'dd/MM/yyyy', { locale: ptBR })}
          </CardTitle>
        </CardHeader>
        <CardContent>
          {selectedDateVisitas.length === 0 ? (
            <div className="text-muted-foreground text-center py-8 animate-fade-in">
              <CalendarDays className="mx-auto h-12 w-12 mb-2 opacity-50" />
              <p>Nenhuma visita agendada para este dia</p>
            </div>
          ) : (
            <div className="space-y-3">
              {selectedDateVisitas.map((visita, index) => (
                <Popover key={visita.id}>
                  <PopoverTrigger asChild>
                    <Button
                      variant="outline"
                      className="w-full justify-start text-left h-auto p-3 hover-scale transition-all duration-200"
                      style={{ animationDelay: `${index * 100}ms` }}
                    >
                      <div className="flex flex-col gap-1 w-full">
                        <div className="flex items-center justify-between">
                          <span className="font-medium">
                            {visita.horario_visita.substring(0, 5)}
                          </span>
                          <Badge variant={statusVariants[visita.status as keyof typeof statusVariants]}>
                            {statusLabels[visita.status as keyof typeof statusLabels]}
                          </Badge>
                        </div>
                        <span className="text-sm text-muted-foreground">
                          {visita.lead.nome}
                        </span>
                      </div>
                    </Button>
                  </PopoverTrigger>
                  <PopoverContent className="w-80">
                    <div className="space-y-3">
                      {/* Horário e Empreendimento */}
                      <div className="flex items-center gap-2 animate-fade-in">
                        <Clock className="w-4 h-4 text-muted-foreground" />
                        <span className="font-medium">{visita.horario_visita.substring(0, 5)}</span>
                      </div>
                      <div className="flex items-center gap-2 animate-fade-in">
                        <MapPin className="w-4 h-4 text-muted-foreground" />
                        <span>{visita.empreendimento?.nome || 'Empreendimento não informado'}</span>
                      </div>

                      <hr className="border-border" />

                      {/* Lead */}
                      <div className="space-y-1 animate-fade-in">
                        <div className="flex items-center gap-2">
                          <User className="w-4 h-4 text-blue-500" />
                          <span className="font-medium text-sm">Lead: {visita.lead.nome}</span>
                        </div>
                        {visita.lead.telefone && (
                          <a
                            href={`https://wa.me/${visita.lead.telefone.replace(/\D/g, '')}`}
                            target="_blank"
                            rel="noopener noreferrer"
                            className="flex items-center gap-2 ml-6 text-sm text-green-600 hover:text-green-700 hover:underline transition-colors"
                          >
                            <Phone className="w-3.5 h-3.5" />
                            {visita.lead.telefone}
                          </a>
                        )}
                      </div>

                      {/* Corretor */}
                      <div className="space-y-1 animate-fade-in">
                        <div className="flex items-center gap-2">
                          <User className="w-4 h-4 text-purple-500" />
                          <span className="font-medium text-sm">
                            Corretor: {visita.corretor ? `${visita.corretor.first_name} ${visita.corretor.last_name}` : 'Não atribuído'}
                          </span>
                        </div>
                        {visita.corretor_whatsapp && (
                          <a
                            href={`https://wa.me/${visita.corretor_whatsapp.replace(/\D/g, '')}`}
                            target="_blank"
                            rel="noopener noreferrer"
                            className="flex items-center gap-2 ml-6 text-sm text-green-600 hover:text-green-700 hover:underline transition-colors"
                          >
                            <Phone className="w-3.5 h-3.5" />
                            {visita.corretor_whatsapp}
                          </a>
                        )}
                      </div>
                    </div>
                  </PopoverContent>
                </Popover>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Loader2, Plus, Pencil, Trash2, CheckCircle, XCircle, Zap, AlertTriangle, Info, RefreshCw, LogOut, QrCode, BarChart2 } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { EvolutionStatusDashboard } from "./EvolutionStatusDashboard";

export interface EvolutionInstance {
    id: string;
    name: string;
    instance_name: string;
    api_url: string;
    api_token: string;
    is_active: boolean;
    created_at: string;
}

export function EvolutionInstances() {
    const { toast } = useToast();
    const queryClient = useQueryClient();

    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [editingInstance, setEditingInstance] = useState<EvolutionInstance | null>(null);
    const [testingConnection, setTestingConnection] = useState<string | null>(null);
    const [selectedInstanceForStatus, setSelectedInstanceForStatus] = useState<EvolutionInstance | null>(null);
    const [qrCodeData, setQrCodeData] = useState<string | null>(null);
    const [showQrModal, setShowQrModal] = useState(false);

    // Fetch instances
    const { data: instances = [], isLoading } = useQuery({
        queryKey: ['evolution-instances'],
        queryFn: async () => {
            const { data, error } = await supabase
                .from('evolution_instances')
                .select('*')
                .order('created_at', { ascending: false });

            if (error) throw error;
            return data as EvolutionInstance[];
        }
    });

    // Generic Manager Mutation
    const managerMutation = useMutation({
        mutationFn: async (payload: any) => {
            const { data, error } = await supabase.functions.invoke('evolution-manager', {
                body: payload
            });

            if (error) throw error;
            if (!data.success) throw new Error(data.error || 'Erro na operação');
            return data.data;
        },
        onSuccess: (data, variables) => {
            queryClient.invalidateQueries({ queryKey: ['evolution-instances'] });

            let message = "Operação realizada com sucesso";
            if (variables.action === 'create') message = "Instância criada com sucesso";
            if (variables.action === 'delete') message = "Instância removida com sucesso";
            if (variables.action === 'restart') message = "Instância reiniciada";
            if (variables.action === 'logout') message = "Sessão desconectada";

            if (variables.action === 'connect') {
                // Handle QR Code from Evolution V2 (base64 or code)
                const base64 = data?.base64 || data?.qrcode?.base64;
                if (base64) {
                    setQrCodeData(base64.startsWith('data:') ? base64 : `data:image/png;base64,${base64}`);
                    setShowQrModal(true);
                } else if (data?.pairingCode) {
                    toast({ title: "Pairing Code", description: `Código: ${data.pairingCode}` });
                } else if (data?.instance?.state === 'open' || data?.state === 'open') {
                    toast({ title: "Já conectado", description: "Esta instância já está conectada." });
                }
            } else if (variables.action === 'connectionState') {
                const state = data?.instance?.state || data?.state || 'unknown';
                toast({
                    title: "Status da Conexão",
                    description: `Estado atual: ${state}`,
                    variant: state === 'open' ? 'default' : 'destructive'
                });
            } else {
                toast({ title: "Sucesso", description: message });
            }
        },
        onError: (error) => {
            toast({
                title: "Erro",
                description: error.message,
                variant: "destructive"
            });
        },
        onSettled: () => {
            setTestingConnection(null);
        }
    });

    // Delete Mutation
    const deleteMutation = useMutation({
        mutationFn: async (id: string) => {
            const { data, error } = await supabase.functions.invoke('evolution-manager', {
                body: { action: 'delete', instance_id: id }
            });
            if (error) throw error;
            if (!data.success) throw new Error(data.error);
            return data;
        },
        onSuccess: () => {
            toast({ title: "Sucesso", description: "Instância removida" });
            queryClient.invalidateQueries({ queryKey: ['evolution-instances'] });
        },
        onError: (error) => {
            toast({ title: "Erro ao excluir", description: error.message, variant: "destructive" });
        }
    });

    // Save (Create/Update based on DB only for update)
    const saveMutation = useMutation({
        mutationFn: async (formData: any) => {
            if (editingInstance) {
                // Update DB only
                const { error } = await supabase
                    .from('evolution_instances')
                    .update({
                        name: formData.name,
                        instance_name: formData.instance_name,
                        api_url: formData.api_url,
                        api_token: formData.api_token,
                        is_active: formData.is_active
                    })
                    .eq('id', editingInstance.id);
                if (error) throw error;
                return { action: 'update' };
            } else {
                // Create via Manager
                const payload = {
                    action: 'create',
                    payload: {
                        instanceName: formData.instance_name,
                        raw_url: formData.api_url,
                        raw_apikey: formData.api_token,
                        name: formData.name
                    }
                };
                const { data, error } = await supabase.functions.invoke('evolution-manager', {
                    body: payload
                });
                if (error) throw error;
                if (!data.success) throw new Error(data.error);
                return { action: 'create', ...data };
            }
        },
        onSuccess: (data) => {
            toast({ title: "Sucesso", description: data.action === 'create' ? "Instância criada" : "Instância atualizada" });
            setIsDialogOpen(false);
            setEditingInstance(null);
            queryClient.invalidateQueries({ queryKey: ['evolution-instances'] });
        },
        onError: (error) => {
            toast({ title: "Erro ao salvar", description: error.message, variant: "destructive" });
        }
    });

    const testConnection = (instance: EvolutionInstance) => {
        setTestingConnection(instance.id);
        managerMutation.mutate({
            action: 'connectionState',
            instance_id: instance.id
        });
    };

    return (
        <Card>
            <CardHeader>
                <div className="flex items-center justify-between">
                    <div className="space-y-1">
                        <CardTitle className="flex items-center gap-2">
                            <Zap className="w-5 h-5 text-yellow-500" />
                            Instâncias Evolution API
                        </CardTitle>
                        <CardDescription>
                            Gerencie suas conexões com a Evolution API V2
                        </CardDescription>
                    </div>
                    <Button onClick={() => { setEditingInstance(null); setIsDialogOpen(true); }}>
                        <Plus className="w-4 h-4 mr-2" />
                        Nova Instância
                    </Button>
                </div>
            </CardHeader>
            <CardContent>
                {isLoading ? (
                    <div className="flex justify-center p-4">
                        <Loader2 className="w-6 h-6 animate-spin" />
                    </div>
                ) : instances.length === 0 ? (
                    <div className="text-center p-6 border border-dashed rounded-lg text-muted-foreground">
                        Nenhuma instância configurada. Adicione uma para começar.
                    </div>
                ) : (
                    <div className="border rounded-md">
                        <Table>
                            <TableHeader>
                                <TableRow>
                                    <TableHead>Nome</TableHead>
                                    <TableHead>Instância (Evolution)</TableHead>
                                    <TableHead>URL</TableHead>
                                    <TableHead>Status</TableHead>
                                    <TableHead className="text-right">Ações</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {instances.map((instance) => (
                                    <TableRow key={instance.id}>
                                        <TableCell className="font-medium">{instance.name}</TableCell>
                                        <TableCell>{instance.instance_name}</TableCell>
                                        <TableCell className="text-muted-foreground text-xs truncate max-w-[200px]" title={instance.api_url}>
                                            {instance.api_url}
                                        </TableCell>
                                        <TableCell>
                                            {instance.is_active ?
                                                <Badge variant="default" className="bg-green-600">Ativo</Badge> :
                                                <Badge variant="secondary">Inativo</Badge>
                                            }
                                        </TableCell>
                                        <TableCell className="text-right space-x-2">
                                            <Button
                                                variant="ghost"
                                                size="icon"
                                                onClick={() => managerMutation.mutate({ action: 'connect', instance_id: instance.id })}
                                                title="Conectar (QR Code)"
                                            >
                                                <QrCode className="w-4 h-4 text-purple-500" />
                                            </Button>
                                            <Button
                                                variant="ghost"
                                                size="icon"
                                                onClick={() => setSelectedInstanceForStatus(instance)}
                                                title="Dashboard de Status"
                                            >
                                                <BarChart2 className="w-4 h-4 text-blue-600" />
                                            </Button>
                                            <Button
                                                variant="ghost"
                                                size="icon"
                                                onClick={() => testConnection(instance)}
                                                disabled={!!testingConnection}
                                                title="Verificar Conexão"
                                            >
                                                {testingConnection === instance.id ? (
                                                    <Loader2 className="w-4 h-4 animate-spin" />
                                                ) : (
                                                    <Zap className="w-4 h-4 text-blue-500" />
                                                )}
                                            </Button>
                                            <Button
                                                variant="ghost"
                                                size="icon"
                                                title="Reiniciar"
                                                onClick={() => {
                                                    if (confirm('Reiniciar instância?')) {
                                                        managerMutation.mutate({ action: 'restart', instance_id: instance.id });
                                                    }
                                                }}
                                            >
                                                <RefreshCw className="w-4 h-4 text-orange-500" />
                                            </Button>
                                            <Button
                                                variant="ghost"
                                                size="icon"
                                                title="Logout (Desconectar)"
                                                onClick={() => {
                                                    if (confirm('Desconectar e limpar sessão do WhatsApp?')) {
                                                        managerMutation.mutate({ action: 'logout', instance_id: instance.id });
                                                    }
                                                }}
                                            >
                                                <LogOut className="w-4 h-4 text-gray-500" />
                                            </Button>
                                            <Button
                                                variant="ghost"
                                                size="icon"
                                                onClick={() => { setEditingInstance(instance); setIsDialogOpen(true); }}
                                                title="Editar Configurações"
                                            >
                                                <Pencil className="w-4 h-4" />
                                            </Button>
                                            <Button
                                                variant="ghost"
                                                size="icon"
                                                onClick={() => {
                                                    if (confirm('Tem certeza que deseja excluir esta instância?')) {
                                                        deleteMutation.mutate(instance.id);
                                                    }
                                                }}
                                                title="Excluir Instância"
                                            >
                                                <Trash2 className="w-4 h-4 text-red-500" />
                                            </Button>
                                        </TableCell>
                                    </TableRow>
                                ))}
                            </TableBody>
                        </Table>
                    </div>
                )}

                {/* Dialog for Create/Edit */}
                <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
                    <DialogContent>
                        <DialogHeader>
                            <DialogTitle>{editingInstance ? 'Editar Instância' : 'Nova Instância'}</DialogTitle>
                            <DialogDescription>
                                Configure os dados de conexão da sua Evolution API V2.
                            </DialogDescription>
                        </DialogHeader>
                        <form onSubmit={(e) => {
                            e.preventDefault();
                            const formData = new FormData(e.currentTarget);
                            saveMutation.mutate({
                                name: formData.get('name') as string,
                                instance_name: formData.get('instance_name') as string,
                                api_url: formData.get('api_url') as string,
                                api_token: formData.get('api_token') as string,
                                is_active: formData.get('is_active') === 'on'
                            });
                        }}>
                            <div className="space-y-4 py-4">
                                <div className="space-y-2">
                                    <Label htmlFor="name">Nome Identificador</Label>
                                    <Input id="name" name="name" placeholder="Ex: Produção Principal" defaultValue={editingInstance?.name} required />
                                </div>
                                <div className="space-y-2">
                                    <Label htmlFor="instance_name">Nome da Instância (Evolution)</Label>
                                    <Input id="instance_name" name="instance_name" placeholder="Ex: my-instance" defaultValue={editingInstance?.instance_name} required />
                                </div>
                                <div className="space-y-2">
                                    <Label htmlFor="api_url">URL da API</Label>
                                    <Input id="api_url" name="api_url" placeholder="https://api.evolution.com" defaultValue={editingInstance?.api_url} required />
                                </div>
                                <div className="space-y-2">
                                    <Label htmlFor="api_token">API Key (Global ou da Instância)</Label>
                                    <Input id="api_token" name="api_token" type="password" defaultValue={editingInstance?.api_token} required />
                                </div>
                                <div className="flex items-center space-x-2">
                                    <Switch id="is_active" name="is_active" defaultChecked={editingInstance ? editingInstance.is_active : true} />
                                    <Label htmlFor="is_active">Ativo</Label>
                                </div>
                            </div>
                            <DialogFooter>
                                <Button type="button" variant="outline" onClick={() => setIsDialogOpen(false)}>Cancelar</Button>
                                <Button type="submit" disabled={saveMutation.isPending}>
                                    {saveMutation.isPending && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
                                    Salvar
                                </Button>
                            </DialogFooter>
                        </form>
                    </DialogContent>
                </Dialog>

                {/* Dialog for QR Code */}
                <Dialog open={showQrModal} onOpenChange={setShowQrModal}>
                    <DialogContent className="sm:max-w-md">
                        <DialogHeader>
                            <DialogTitle>Conectar WhatsApp</DialogTitle>
                            <DialogDescription>
                                Escaneie o QR Code abaixo com o seu WhatsApp para conectar.
                            </DialogDescription>
                        </DialogHeader>
                        <div className="flex items-center justify-center p-6">
                            {qrCodeData ? (
                                <img src={qrCodeData} alt="QR Code" className="w-64 h-64 border rounded" />
                            ) : (
                                <div className="flex flex-col items-center gap-2">
                                    <Loader2 className="w-8 h-8 animate-spin text-primary" />
                                    <span className="text-sm text-muted-foreground">Carregando QR Code...</span>
                                </div>
                            )}
                        </div>
                        <DialogFooter>
                            <Button type="button" variant="secondary" onClick={() => setShowQrModal(false)}>
                                Fechar
                            </Button>
                        </DialogFooter>
                    </DialogContent>
                </Dialog>

            </CardContent>

            {/* Dialog for Status Dashboard */}
            <Dialog open={!!selectedInstanceForStatus} onOpenChange={(open) => !open && setSelectedInstanceForStatus(null)}>
                <DialogContent className="max-w-3xl h-[80vh] flex flex-col">
                    <DialogHeader>
                        <DialogTitle>Status da Instância: {selectedInstanceForStatus?.name}</DialogTitle>
                        <DialogDescription>
                            Monitoramento em tempo real e logs de integração.
                        </DialogDescription>
                    </DialogHeader>
                    <div className="flex-1 overflow-y-auto pr-2">
                        {selectedInstanceForStatus && (
                            <EvolutionStatusDashboard instanceId={selectedInstanceForStatus.id} />
                        )}
                    </div>
                    <DialogFooter>
                        <Button type="button" variant="secondary" onClick={() => setSelectedInstanceForStatus(null)}>
                            Fechar
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </Card>
    );
}

import { useState, useMemo, useCallback } from 'react';
import {
    DndContext,
    DragOverlay,
    closestCorners,
    KeyboardSensor,
    PointerSensor,
    useSensor,
    useSensors,
    type DragStartEvent,
    type DragEndEvent,
    type DragOverEvent,
} from '@dnd-kit/core';
import { sortableKeyboardCoordinates } from '@dnd-kit/sortable';
import KanbanColumn from './KanbanColumn';
import KanbanCard from './KanbanCard';
import type { CrmStage, CrmLead } from '@/hooks/useCrmPipeline';

interface KanbanBoardProps {
    stages: CrmStage[];
    leads: CrmLead[];
    onMoveLead: (crmLeadId: string, newStageId: string, newPosition: number) => void;
    onCardClick?: (crmLead: CrmLead) => void;
    onRemoveLead?: (crmLeadId: string) => void;
    onConfigureClick?: () => void;
}

export default function KanbanBoard({
    stages,
    leads,
    onMoveLead,
    onCardClick,
    onRemoveLead,
    onConfigureClick,
}: KanbanBoardProps) {
    const [activeId, setActiveId] = useState<string | null>(null);

    const sensors = useSensors(
        useSensor(PointerSensor, { activationConstraint: { distance: 8 } }),
        useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates })
    );

    const leadsByStage = useMemo(() => {
        const map: Record<string, CrmLead[]> = {};
        for (const stage of stages) {
            map[stage.id] = [];
        }
        for (const lead of leads) {
            const stageId = lead.stage_id;
            if (stageId && map[stageId]) {
                map[stageId].push(lead);
            }
        }
        // Sort by posicao within each stage
        for (const stageId of Object.keys(map)) {
            map[stageId].sort((a, b) => a.posicao - b.posicao);
        }
        return map;
    }, [stages, leads]);

    const activeLead = useMemo(
        () => leads.find((l) => l.id === activeId) ?? null,
        [leads, activeId]
    );

    const findStageForLead = useCallback(
        (leadId: string): string | null => {
            const lead = leads.find((l) => l.id === leadId);
            return lead?.stage_id ?? null;
        },
        [leads]
    );

    const handleDragStart = (event: DragStartEvent) => {
        setActiveId(event.active.id as string);
    };

    const handleDragOver = (_event: DragOverEvent) => {
        // Visual feedback handled by useDroppable isOver
    };

    const handleDragEnd = (event: DragEndEvent) => {
        const { active, over } = event;
        setActiveId(null);

        if (!over) return;

        const activeCrmLeadId = active.id as string;
        const overData = over.data.current;

        let targetStageId: string;
        let targetPosition = 0;

        if (overData?.type === 'column') {
            // Dropped on an empty column
            targetStageId = over.id as string;
            targetPosition = 0;
        } else if (overData?.type === 'card') {
            // Dropped on another card — find its stage
            const overCrmLead = overData.crmLead as CrmLead;
            targetStageId = overCrmLead.stage_id!;

            // Calculate position
            const stageLeads = leadsByStage[targetStageId] ?? [];
            const overIndex = stageLeads.findIndex((l) => l.id === over.id);
            targetPosition = overIndex >= 0 ? overIndex : stageLeads.length;
        } else {
            // Dropped on a column (via id match)
            targetStageId = over.id as string;
            targetPosition = (leadsByStage[targetStageId] ?? []).length;
        }

        // Only update if stage changed or position changed
        const currentStageId = findStageForLead(activeCrmLeadId);
        if (currentStageId !== targetStageId || true) {
            onMoveLead(activeCrmLeadId, targetStageId, targetPosition);
        }
    };

    return (
        <DndContext
            sensors={sensors}
            collisionDetection={closestCorners}
            onDragStart={handleDragStart}
            onDragOver={handleDragOver}
            onDragEnd={handleDragEnd}
        >
            <div className="flex gap-4 overflow-x-auto pb-4 min-h-[400px]">
                {stages.map((stage) => (
                    <KanbanColumn
                        key={stage.id}
                        stage={stage}
                        leads={leadsByStage[stage.id] ?? []}
                        onCardClick={onCardClick}
                        onRemoveLead={onRemoveLead}
                    />
                ))}

                {/* Botão Configurar dentro do Kanban */}
                {onConfigureClick && (
                    <div className="flex-shrink-0 w-[300px] flex flex-col">
                        <button
                            onClick={onConfigureClick}
                            className="flex items-center justify-center gap-2 p-4 h-[56px] bg-gray-50/50 border-2 border-dashed border-gray-300 rounded-xl text-muted-foreground hover:text-primary hover:border-primary/50 hover:bg-primary/5 transition-colors"
                        >
                            <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12.22 2h-.44a2 2 0 0 0-2 2v.18a2 2 0 0 1-1 1.73l-.43.25a2 2 0 0 1-2 0l-.15-.08a2 2 0 0 0-2.73.73l-.22.38a2 2 0 0 0 .73 2.73l.15.1a2 2 0 0 1 1 1.72v.51a2 2 0 0 1-1 1.74l-.15.09a2 2 0 0 0-.73 2.73l.22.38a2 2 0 0 0 2.73.73l.15-.08a2 2 0 0 1 2 0l.43.25a2 2 0 0 1 1 1.73V20a2 2 0 0 0 2 2h.44a2 2 0 0 0 2-2v-.18a2 2 0 0 1 1-1.73l.43-.25a2 2 0 0 1 2 0l.15.08a2 2 0 0 0 2.73-.73l.22-.39a2 2 0 0 0-.73-2.73l-.15-.08a2 2 0 0 1-1-1.74v-.5a2 2 0 0 1 1-1.74l.15-.09a2 2 0 0 0 .73-2.73l-.22-.38a2 2 0 0 0-2.73-.73l-.15.08a2 2 0 0 1-2 0l-.43-.25a2 2 0 0 1-1-1.73V4a2 2 0 0 0-2-2z" /><circle cx="12" cy="12" r="3" /></svg>
                            <span className="font-medium text-sm">Configurar Funil</span>
                        </button>
                    </div>
                )}
            </div>

            <DragOverlay>
                {activeLead ? (
                    <div className="rotate-3 opacity-90">
                        <KanbanCard crmLead={activeLead} />
                    </div>
                ) : null}
            </DragOverlay>
        </DndContext>
    );
}

import { useEffect, useState } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useNavigate } from 'react-router-dom';
import StatsCard from './StatsCard';
import VisitsChart from './VisitsChart';
import LeadModal from '@/components/modals/LeadModal';
import CorretorModal from '@/components/modals/CorretorModal';
import EmpreendimentoModal from '@/components/modals/EmpreendimentoModal';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip";
import {
  Users,
  UserCheck,
  Calendar,
  TrendingUp,
  AlertCircle,
  CheckCircle,
  Building2,
  Loader2
} from 'lucide-react';
import { useToast } from '@/hooks/use-toast';

interface DashboardStats {
  totalLeads: number;
  leadsHoje: number;
  totalCorretores: number;
  corretoresAtivos: number;
  visitasHoje: number;
  visitasSemana: number;
  taxaConversao: number;
}



const AdminDashboard = () => {
  const [stats, setStats] = useState<DashboardStats>({
    totalLeads: 0,
    leadsHoje: 0,
    totalCorretores: 0,
    corretoresAtivos: 0,
    visitasHoje: 0,
    visitasSemana: 0,
    taxaConversao: 0,
  });

  const [loading, setLoading] = useState(true);
  const [isLeadModalOpen, setIsLeadModalOpen] = useState(false);
  const [isCorretorModalOpen, setIsCorretorModalOpen] = useState(false);
  const [isEmpreendimentoModalOpen, setIsEmpreendimentoModalOpen] = useState(false);
  const { toast } = useToast();
  const navigate = useNavigate();

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      // Fetch leads stats
      const today = new Date().toISOString().split('T')[0];
      const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];

      const [
        totalLeadsResult,
        leadsHojeResult,
        totalCorretoresResult,
        corretoresAtivosResult,
        visitasHojeResult,
        visitasSemanaResult,
      ] = await Promise.all([
        supabase.from('leads').select('*', { count: 'exact' }),
        supabase.from('leads').select('*', { count: 'exact' }).gte('created_at', today),
        supabase.from('corretores').select('*', { count: 'exact' }),
        supabase.from('corretores').select('*', { count: 'exact' }).eq('status', 'ativo'),
        supabase.from('visitas').select('*', { count: 'exact' }).eq('data_visita', today),
        supabase.from('visitas').select('*', { count: 'exact' }).gte('data_visita', weekAgo),
      ]);

      // Calculate conversion rate
      const visitasRealizadas = await supabase
        .from('visitas')
        .select('*', { count: 'exact' })
        .eq('status', 'realizada');

      const taxaConversao = totalLeadsResult.count && visitasRealizadas.count
        ? Math.round((visitasRealizadas.count / totalLeadsResult.count) * 100)
        : 0;

      setStats({
        totalLeads: totalLeadsResult.count || 0,
        leadsHoje: leadsHojeResult.count || 0,
        totalCorretores: totalCorretoresResult.count || 0,
        corretoresAtivos: corretoresAtivosResult.count || 0,
        visitasHoje: visitasHojeResult.count || 0,
        visitasSemana: visitasSemanaResult.count || 0,
        taxaConversao,
      });

    } catch (error) {
      console.error('Error fetching dashboard data:', error);
      toast({
        title: "Erro ao carregar dados",
        description: "Não foi possível carregar os dados do dashboard.",
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };



  if (loading) {
    return (
      <div className="p-6">
        <div className="animate-pulse space-y-4">
          <div className="h-8 bg-gray-200 rounded w-1/4"></div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            {[1, 2, 3, 4].map((i) => (
              <div key={i} className="h-32 bg-gray-200 rounded"></div>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div>
        <h1 className="text-3xl font-bold tracking-tight text-foreground">
          Dashboard Administrativo
        </h1>
        <p className="text-muted-foreground">
          Visão geral da operação MeMude Connect
        </p>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatsCard
          title="Total de Leads"
          value={stats.totalLeads}
          icon={Users}
          description="Leads cadastrados"
          trend={{
            value: stats.leadsHoje,
            isPositive: stats.leadsHoje > 0
          }}
        />

        <StatsCard
          title="Corretores Ativos"
          value={`${stats.corretoresAtivos}/${stats.totalCorretores}`}
          icon={UserCheck}
          description="Corretores disponíveis"
        />

        <StatsCard
          title="Visitas Hoje"
          value={stats.visitasHoje}
          icon={Calendar}
          description="Agendadas para hoje"
        />

        <StatsCard
          title="Taxa de Conversão"
          value={`${stats.taxaConversao}%`}
          icon={TrendingUp}
          description="Leads → Visitas"
          trend={{
            value: stats.taxaConversao,
            isPositive: stats.taxaConversao > 50
          }}
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Visits Chart */}
        <VisitsChart />

        {/* Quick Actions */}
        <Card className="glass-card">
          <CardHeader>
            <CardTitle className="flex items-center">
              <AlertCircle className="mr-2 h-5 w-5" />
              Ações Rápidas
            </CardTitle>
            <CardDescription>
              Acesso rápido às principais funcionalidades
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <TooltipProvider>
              <Tooltip>
                <TooltipTrigger asChild>
                  <Button
                    className="w-full justify-start hover-scale transition-all duration-200"
                    variant="outline"
                    onClick={() => setIsLeadModalOpen(true)}
                    disabled={isLeadModalOpen}
                  >
                    {isLeadModalOpen ? (
                      <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                    ) : (
                      <Users className="mr-2 h-4 w-4" />
                    )}
                    Adicionar Lead Manualmente
                  </Button>
                </TooltipTrigger>
