import { useEffect, useState } from 'react';
import { useAuth } from '@/hooks/useAuth';
import { supabase } from '@/integrations/supabase/client';
import StatsCard from './StatsCard';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { 
  Users, 
  Calendar, 
  Star, 
  TrendingUp, 
  Clock,
  MapPin,
  Phone
} from 'lucide-react';
import { useToast } from '@/hooks/use-toast';
import { parseLocalDate } from '@/utils/dateHelpers';

interface CorretorStats {
  totalLeads: number;
  leadsAtivos: number;
  visitasAgendadas: number;
  visitasRealizadas: number;
  notaMedia: number;
  totalVisitas: number;
}

interface VisitaProxima {
  id: string;
  data_visita: string;
  horario_visita: string;
  leads: {
    nome: string;
    telefone: string;
  };
  empreendimentos: {
    nome: string;
    endereco?: string;
  };
}

const CorretorDashboard = () => {
  const { profile } = useAuth();
  const [stats, setStats] = useState<CorretorStats>({
    totalLeads: 0,
    leadsAtivos: 0,
    visitasAgendadas: 0,
    visitasRealizadas: 0,
    notaMedia: 0,
    totalVisitas: 0,
  });
  const [proximasVisitas, setProximasVisitas] = useState<VisitaProxima[]>([]);
  const [loading, setLoading] = useState(true);
  const { toast } = useToast();

  useEffect(() => {
    if (profile) {
      fetchCorretorData();
    }
  }, [profile]);

  const fetchCorretorData = async () => {
    try {
      // First get corretor info
      const { data: corretor } = await supabase
        .from('corretores')
        .select('*')
        .eq('profile_id', profile!.id)
        .single();

      if (!corretor) {
        toast({
          title: "Perfil não encontrado",
          description: "Seu perfil de corretor não foi encontrado. Entre em contato com o administrador.",
          variant: "destructive",
        });
        return;
      }

      // Get leads assigned to this corretor
      const { data: leads } = await supabase
        .from('leads')
        .select('*')
        .eq('corretor_designado_id', corretor.id);

      // Get visitas for this corretor
      const { data: visitas } = await supabase
        .from('visitas')
        .select(`
          *,
          leads (nome, telefone),
          empreendimentos (nome, endereco)
        `)
        .eq('corretor_id', corretor.id)
        .order('data_visita', { ascending: true });

      // Get upcoming visitas
      const today = new Date().toISOString().split('T')[0];
      const proximasVisitas = visitas?.filter(v => 
        v.data_visita >= today && ['agendada', 'confirmada'].includes(v.status)
      ).slice(0, 5) || [];

      // Calculate stats
      const leadsAtivos = leads?.filter(l => 
        !['cancelado', 'visita_realizada'].includes(l.status)
      ).length || 0;

      const visitasAgendadas = visitas?.filter(v => 
        ['agendada', 'confirmada'].includes(v.status)
      ).length || 0;

      const visitasRealizadas = visitas?.filter(v => 
        v.status === 'realizada'
      ).length || 0;

      setStats({
        totalLeads: leads?.length || 0,
        leadsAtivos,
        visitasAgendadas,
        visitasRealizadas,
        notaMedia: corretor.nota_media || 0,
        totalVisitas: corretor.total_visitas || 0,
      });

      setProximasVisitas(proximasVisitas);
    } catch (error) {
      console.error('Error fetching corretor data:', error);
      toast({
        title: "Erro ao carregar dados",
        description: "Não foi possível carregar seus dados.",
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="p-6">
        <div className="animate-pulse space-y-4">
          <div className="h-8 bg-gray-200 rounded w-1/4"></div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            {[1, 2, 3, 4].map((i) => (
              <div key={i} className="h-32 bg-gray-200 rounded"></div>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="p-6 space-y-6">
      {/* Header */}
      <div>
        <h1 className="text-3xl font-bold tracking-tight text-foreground">
          Bem-vindo, {profile?.first_name}!
        </h1>
        <p className="text-muted-foreground">
          Aqui está um resumo da sua performance e próximas atividades
        </p>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatsCard
          title="Meus Leads"
          value={stats.totalLeads}
          icon={Users}
          description={`${stats.leadsAtivos} ativos`}
        />

        <StatsCard
          title="Visitas Agendadas"
          value={stats.visitasAgendadas}
          icon={Calendar}
          description="Próximas visitas"
        />

        <StatsCard
          title="Minha Nota"
          value={stats.notaMedia.toFixed(1)}
          icon={Star}
          description="Avaliação média"
          trend={{
            value: stats.notaMedia * 20, // Convert to percentage
            isPositive: stats.notaMedia >= 4.0
          }}
        />

        <StatsCard
          title="Total de Visitas"
          value={stats.totalVisitas}
          icon={TrendingUp}
          description={`${stats.visitasRealizadas} realizadas`}
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Próximas Visitas */}
        <Card className="glass-card">
          <CardHeader>
            <CardTitle className="flex items-center">
              <Clock className="mr-2 h-5 w-5" />
              Próximas Visitas
            </CardTitle>
            <CardDescription>
              Suas visitas agendadas para os próximos dias
            </CardDescription>
          </CardHeader>
          <CardContent>
            <div className="space-y-4">
              {proximasVisitas.length > 0 ? (
                proximasVisitas.map((visita) => (
                  <div
                    key={visita.id}
                    className="flex items-center justify-between p-4 bg-white/50 rounded-lg border border-white/20"
                  >
                    <div className="flex-1">
                      <div className="flex items-center space-x-2 mb-2">
                        <Badge variant="outline" className="bg-primary/10">
                          {parseLocalDate(visita.data_visita).toLocaleDateString('pt-BR')} às {visita.horario_visita}
                        </Badge>
                      </div>

                      <h4 className="font-medium text-sm flex items-center">
                        <Users className="mr-1 h-3 w-3" />
                        {visita.leads?.nome}
                      </h4>

                      <p className="text-xs text-muted-foreground flex items-center mt-1">
                        <Phone className="mr-1 h-3 w-3" />
                        {visita.leads?.telefone}
                      </p>

                      <p className="text-xs text-primary font-medium flex items-center mt-1">
                        <MapPin className="mr-1 h-3 w-3" />
                        {visita.empreendimentos?.nome}
                      </p>

                      {visita.empreendimentos?.endereco && (
                        <p className="text-xs text-muted-foreground mt-1">
                          {visita.empreendimentos.endereco}
                        </p>
                      )}
                    </div>
                  </div>
                ))
              ) : (
                <div className="text-center py-8 text-muted-foreground">
                  <Calendar className="mx-auto h-12 w-12 mb-2 opacity-50" />
                  <p>Nenhuma visita agendada</p>
                  <p className="text-sm">Aguarde novos leads serem direcionados para você</p>
                </div>
              )}
            </div>
          </CardContent>
        </Card>

        {/* Performance */}
        <Card className="glass-card">
          <CardHeader>
            <CardTitle className="flex items-center">
              <TrendingUp className="mr-2 h-5 w-5" />
              Minha Performance
            </CardTitle>
            <CardDescription>
              Estatísticas do seu desempenho
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-6">
            <div className="text-center">
              <div className="text-4xl font-bold text-primary mb-2">
                {stats.notaMedia.toFixed(1)}
              </div>
              <div className="flex justify-center mb-2">
                {[1, 2, 3, 4, 5].map((star) => (
                  <Star
                    key={star}
                    className={`h-5 w-5 ${
                      star <= Math.round(stats.notaMedia)
                        ? 'text-yellow-400 fill-current'
                        : 'text-gray-300'
                    }`}
                  />
                ))}
              </div>
              <p className="text-sm text-muted-foreground">Avaliação dos clientes</p>
            </div>

            <div className="grid grid-cols-2 gap-4 text-center">
              <div>
                <div className="text-2xl font-bold text-secondary">{stats.visitasRealizadas}</div>
                <div className="text-sm text-muted-foreground">Visitas Realizadas</div>
              </div>
              <div>
                <div className="text-2xl font-bold text-success">{stats.leadsAtivos}</div>
                <div className="text-sm text-muted-foreground">Leads Ativos</div>
              </div>
            </div>

            <Button className="w-full" variant="outline">
              Ver Histórico Completo
            </Button>
          </CardContent>
        </Card>
      </div>
    </div>
  );
};

export default CorretorDashboard;

import { useEffect, useState, useMemo } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Calendar } from '@/components/ui/calendar';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { ChartContainer, ChartTooltip, ChartTooltipContent } from '@/components/ui/chart';
import { ToggleGroup, ToggleGroupItem } from '@/components/ui/toggle-group';
import { TrendingUp, CalendarIcon, Loader2 } from 'lucide-react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Area, AreaChart, ResponsiveContainer } from 'recharts';
import { format, subDays, startOfDay, endOfDay } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { DateRange } from 'react-day-picker';
import { cn } from '@/lib/utils';

interface VisitDataPoint {
    date: string;
    visitas: number;
    fullDate: string;
}

type FilterPeriod = '7d' | '30d' | 'custom';

const chartConfig = {
    visitas: {
        label: 'Visitas',
        color: 'hsl(var(--primary))',
    },
};

const VisitsChart = () => {
    const [data, setData] = useState<VisitDataPoint[]>([]);
    const [loading, setLoading] = useState(true);
    const [period, setPeriod] = useState<FilterPeriod>('7d');
    const [dateRange, setDateRange] = useState<DateRange | undefined>({
        from: subDays(new Date(), 7),
        to: new Date(),
    });
    const [isCalendarOpen, setIsCalendarOpen] = useState(false);

    const dateFilter = useMemo(() => {
        if (period === '7d') {
            return { from: subDays(new Date(), 7), to: new Date() };
        } else if (period === '30d') {
            return { from: subDays(new Date(), 30), to: new Date() };
        } else {
            return dateRange || { from: subDays(new Date(), 7), to: new Date() };
        }
    }, [period, dateRange]);

    useEffect(() => {
        fetchVisitsData();
    }, [dateFilter]);

    const fetchVisitsData = async () => {
        setLoading(true);
        try {
            const fromDate = format(startOfDay(dateFilter.from!), 'yyyy-MM-dd');
            const toDate = format(endOfDay(dateFilter.to!), 'yyyy-MM-dd');

            const { data: visitas, error } = await supabase
                .from('visitas')
                .select('data_visita')
                .gte('data_visita', fromDate)
                .lte('data_visita', toDate)
                .is('deleted_at', null);

            if (error) throw error;

            // Aggregate by date
            const countByDate: Record<string, number> = {};

            // Initialize all dates in range with 0
            let currentDate = new Date(dateFilter.from!);
            while (currentDate <= dateFilter.to!) {
                const dateKey = format(currentDate, 'yyyy-MM-dd');
                countByDate[dateKey] = 0;
                currentDate = new Date(currentDate.getTime() + 24 * 60 * 60 * 1000);
            }

            // Count visits per date
            visitas?.forEach((visita) => {
                const dateKey = visita.data_visita;
                if (countByDate[dateKey] !== undefined) {
                    countByDate[dateKey]++;
                }
            });

            // Convert to chart data
            const chartData: VisitDataPoint[] = Object.entries(countByDate)
                .sort(([a], [b]) => a.localeCompare(b))
                .map(([fullDate, count]) => ({
                    date: format(new Date(fullDate + 'T12:00:00'), 'dd/MM', { locale: ptBR }),
                    visitas: count,
                    fullDate,
                }));

            setData(chartData);
        } catch (error) {
            console.error('Error fetching visits data:', error);
        } finally {
            setLoading(false);
        }
    };

    const handlePeriodChange = (value: string) => {
        if (value) {
            setPeriod(value as FilterPeriod);
            if (value !== 'custom') {
                setIsCalendarOpen(false);
            }
        }
    };

    const handleDateRangeSelect = (range: DateRange | undefined) => {
        setDateRange(range);
        if (range?.from && range?.to) {
            setPeriod('custom');
            setIsCalendarOpen(false);
        }
    };

    const totalVisitas = data.reduce((acc, d) => acc + d.visitas, 0);

    return (
        <Card className="glass-card">
            <CardHeader className="pb-2">
                <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
                    <div>
                        <CardTitle className="flex items-center">
                            <TrendingUp className="mr-2 h-5 w-5" />
                            Visitas Recentes
                        </CardTitle>
                        <CardDescription>
                            {totalVisitas} visitas no período selecionado
                        </CardDescription>
                    </div>
                    <div className="flex items-center gap-2">
                        <ToggleGroup
                            type="single"
                            value={period}
                            onValueChange={handlePeriodChange}
                            className="bg-muted/50 rounded-lg p-1"
                        >
                            <ToggleGroupItem
                                value="7d"
                                className="text-xs px-3 data-[state=on]:bg-background data-[state=on]:shadow-sm"
                            >
                                7 dias
                            </ToggleGroupItem>
                            <ToggleGroupItem
                                value="30d"
                                className="text-xs px-3 data-[state=on]:bg-background data-[state=on]:shadow-sm"
                            >
                                30 dias
                            </ToggleGroupItem>
                        </ToggleGroup>
                        <Popover open={isCalendarOpen} onOpenChange={setIsCalendarOpen}>
                            <PopoverTrigger asChild>
                                <Button
                                    variant={period === 'custom' ? 'default' : 'outline'}
                                    size="sm"
                                    className={cn(
                                        "h-8 px-3",
                                        period === 'custom' && "bg-primary text-primary-foreground"
                                    )}
                                >
                                    <CalendarIcon className="h-4 w-4" />
                                </Button>
                            </PopoverTrigger>
                            <PopoverContent className="w-auto p-0" align="end">
                                <Calendar
                                    initialFocus
                                    mode="range"
                                    defaultMonth={dateRange?.from}
                                    selected={dateRange}
                                    onSelect={handleDateRangeSelect}
                                    numberOfMonths={2}
                                    locale={ptBR}
                                />
                            </PopoverContent>
                        </Popover>
                    </div>
                </div>
            </CardHeader>
            <CardContent>
                {loading ? (
                    <div className="flex items-center justify-center h-[250px]">
                        <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
                    </div>
                ) : data.length === 0 ? (
                    <div className="flex flex-col items-center justify-center h-[250px] text-muted-foreground">
                        <TrendingUp className="h-12 w-12 mb-2 opacity-50" />
                        <p>Nenhuma visita no período</p>
                    </div>
                ) : (
                    <ChartContainer config={chartConfig} className="h-[250px] w-full">
                        <AreaChart data={data} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                            <defs>
                                <linearGradient id="visitasGradient" x1="0" y1="0" x2="0" y2="1">
                                    <stop offset="5%" stopColor="hsl(var(--primary))" stopOpacity={0.3} />
                                    <stop offset="95%" stopColor="hsl(var(--primary))" stopOpacity={0} />
                                </linearGradient>
                            </defs>
                            <CartesianGrid strokeDasharray="3 3" className="stroke-muted" />
                            <XAxis
                                dataKey="date"
                                tickLine={false}
                                axisLine={false}
                                tick={{ fontSize: 12 }}
                                tickMargin={8}
                            />
                            <YAxis
                                tickLine={false}
                                axisLine={false}
                                tick={{ fontSize: 12 }}
                                tickMargin={8}
                                allowDecimals={false}
                            />
                            <ChartTooltip
                                content={
                                    <ChartTooltipContent
                                        labelFormatter={(value, payload) => {
                                            if (payload?.[0]?.payload?.fullDate) {
                                                return format(
                                                    new Date(payload[0].payload.fullDate + 'T12:00:00'),
                                                    "dd 'de' MMMM",
                                                    { locale: ptBR }
                                                );
                                            }
                                            return value;
                                        }}
                                    />
                                }
                            />
                            <Area
                                type="monotone"
                                dataKey="visitas"
                                stroke="hsl(var(--primary))"
                                strokeWidth={2}
                                fill="url(#visitasGradient)"
                                dot={{ fill: 'hsl(var(--primary))', strokeWidth: 2, r: 3 }}
                                activeDot={{ r: 5, strokeWidth: 0 }}
                            />
                        </AreaChart>
                    </ChartContainer>
                )}
            </CardContent>
        </Card>
    );
};

export default VisitsChart;

import { useForm } from "react-hook-form";
