}

import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import LeadForm from "@/components/forms/LeadForm";

interface LeadModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  initialData?: any;
  title: string;
  onLeadCreated?: (leadId: string) => void;
}

export default function LeadModal({ 
  open, 
  onOpenChange, 
  initialData, 
  title,
  onLeadCreated 
}: LeadModalProps) {
  const handleSuccess = (leadId?: string) => {
    if (leadId && onLeadCreated) {
      onLeadCreated(leadId);
    }
    onOpenChange(false);
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>{title}</DialogTitle>
        </DialogHeader>
        <LeadForm
          initialData={initialData}
          onSuccess={handleSuccess}
          onCancel={() => onOpenChange(false)}
        />
      </DialogContent>
    </Dialog>
  );
}

import React, { useState, useEffect } from "react";
import { X, Plus, Trash2, AlertTriangle, Image, FileText, List } from "lucide-react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Switch } from "@/components/ui/switch";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Card, CardContent } from "@/components/ui/card";
import { MessageTemplate, useCreateTemplate, useUpdateTemplate } from "@/hooks/useTemplates";
import { VariableSelector } from "../templates/VariableSelector";

interface TemplateModalProps {
  isOpen: boolean;
  onClose: () => void;
  template?: MessageTemplate;
  categoryLabels: Record<string, string>;
  typeLabels: Record<string, string>;
}

export const TemplateModal: React.FC<TemplateModalProps> = ({
  isOpen,
  onClose,
  template,
  categoryLabels,
  typeLabels
}) => {
  const [formData, setFormData] = useState({
    name: "",
    category: "",
    type: "",
    subject: "",
    content: "",
    variables: [] as string[],
    is_active: true
  });

  const [showVariableSelector, setShowVariableSelector] = useState(false);

  // Fase 5: Estados para novos tipos de mensagem
  const [messageType, setMessageType] = useState<'text' | 'buttons' | 'media' | 'list'>('text');
  const [buttons, setButtons] = useState<Array<{ id: string; text: string }>>([]);
  const [mediaType, setMediaType] = useState<'image' | 'video' | 'document' | 'audio'>('image');
  const [mediaUrl, setMediaUrl] = useState("");
  const [mediaCaption, setMediaCaption] = useState("");
  const [listTitle, setListTitle] = useState("");
  const [listDescription, setListDescription] = useState("");
  const [listButtonText, setListButtonText] = useState("Ver opções");
  const [listSections, setListSections] = useState<Array<{
    title: string;
    rows: Array<{ id: string; title: string; description?: string }>;
  }>>([]);

  const createTemplate = useCreateTemplate();
  const updateTemplate = useUpdateTemplate();

  const isEditing = !!template;

  useEffect(() => {
    if (template) {
      setFormData({
        name: template.name,
        category: template.category,
        type: template.type,
        subject: template.subject || "",
        content: template.content,
        variables: template.variables || [],
        is_active: template.is_active
      });

      // Carregar configurações de botões/mídia/lista
      if (template.button_config && template.button_config.length > 0) {
        setMessageType('buttons');
        setButtons(template.button_config);
      } else if (template.media_config) {
        setMessageType('media');
        setMediaType(template.media_config.type || 'image');
        setMediaUrl(template.media_config.url || '');
        setMediaCaption(template.media_config.caption || '');
      } else if (template.list_config) {
        setMessageType('list');
        setListTitle(template.list_config.title || '');
        setListDescription(template.list_config.description || '');
        setListButtonText(template.list_config.buttonText || 'Ver opções');
        setListSections(template.list_config.sections || []);
      }
    } else {
      setFormData({
        name: "",
        category: "",
        type: "",
        subject: "",
        content: "",
        variables: [],
        is_active: true
      });
      setMessageType('text');
      setButtons([]);
      setMediaUrl("");
      setMediaCaption("");
      setListSections([]);
    }
  }, [template, isOpen]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    try {
      const templateData: any = { ...formData };

      // Adicionar configurações específicas baseadas no tipo de mensagem
      if (formData.type === 'whatsapp') {
        if (messageType === 'buttons' && buttons.length > 0) {
          templateData.button_config = buttons;
        } else if (messageType === 'media' && mediaUrl) {
          templateData.media_config = {
            type: mediaType,
            url: mediaUrl,
            caption: mediaCaption || null,
          };
        } else if (messageType === 'list' && listSections.length > 0) {
          templateData.list_config = {
            title: listTitle,
            description: listDescription || null,
            buttonText: listButtonText,
            sections: listSections,
          };
        }
      }

      if (isEditing && template) {
        await updateTemplate.mutateAsync({
          id: template.id,
          ...templateData
        } as any);
      } else {
        await createTemplate.mutateAsync(templateData as any);
      }
      onClose();
    } catch (error) {
      console.error('Erro ao salvar template:', error);
    }
  };

  const addButton = () => {
    setButtons([...buttons, { id: `btn_${Date.now()}`, text: "" }]);
  };

  const removeButton = (index: number) => {
    setButtons(buttons.filter((_, i) => i !== index));
  };

  const updateButton = (index: number, field: 'id' | 'text', value: string) => {
    const newButtons = [...buttons];
    newButtons[index][field] = value;
    setButtons(newButtons);
  };

  const addListSection = () => {
    setListSections([...listSections, { title: "", rows: [{ id: `row_${Date.now()}`, title: "" }] }]);
  };

  const addListRow = (sectionIndex: number) => {
    const newSections = [...listSections];
    newSections[sectionIndex].rows.push({ id: `row_${Date.now()}`, title: "" });
    setListSections(newSections);
  };

  const handleVariableInsert = (variableName: string) => {
    const cursorPosition = document.querySelector('textarea')?.selectionStart || 0;
    const textBefore = formData.content.substring(0, cursorPosition);
    const textAfter = formData.content.substring(cursorPosition);

    const newContent = textBefore + `{${variableName}}` + textAfter;
    setFormData(prev => ({ ...prev, content: newContent }));

    // Adicionar variável à lista se não existir
    if (!formData.variables.includes(variableName)) {
      setFormData(prev => ({
        ...prev,
        variables: [...prev.variables, variableName]
      }));
    }
  };

  const removeVariable = (variableName: string) => {
    setFormData(prev => ({
      ...prev,
      variables: prev.variables.filter(v => v !== variableName)
    }));
  };

  const isLoading = createTemplate.isPending || updateTemplate.isPending;

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <div className="flex items-center justify-between">
            <DialogTitle>
              {isEditing ? 'Editar Template' : 'Novo Template'}
              {template?.is_system && (
                <span className="text-sm font-normal text-muted-foreground ml-2">
                  (Template do Sistema)
                </span>
              )}
            </DialogTitle>
            <Button variant="ghost" size="sm" onClick={onClose}>
              <X className="w-4 h-4" />
            </Button>
          </div>
          {template?.is_system && (
            <div className="bg-blue-50 border border-blue-200 rounded-lg p-3 mt-2">
              <div className="flex items-start gap-2">
                <AlertTriangle className="w-4 h-4 text-blue-600 mt-0.5" />
                <div className="text-sm text-blue-800">
                  <p className="font-medium">Atenção: Template do Sistema</p>
                  <p className="text-blue-700">
                    Este é um template do sistema. Alterações podem afetar funcionalidades automáticas. 
                    Certifique-se de manter as variáveis essenciais para o funcionamento correto.
                  </p>
                </div>
              </div>
            </div>
          )}
        </DialogHeader>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {/* Nome */}
            <div className="space-y-2">
              <Label htmlFor="name">Nome do Template *</Label>
              <Input
                id="name"
                value={formData.name}
                onChange={(e) => setFormData(prev => ({ ...prev, name: e.target.value }))}
                placeholder="Ex: Distribuição de Lead - Bairro"
                required
              />
            </div>

            {/* Status */}
            <div className="space-y-2">
              <Label htmlFor="is_active">Status</Label>
              <div className="flex items-center space-x-2">
                <Switch
                  id="is_active"
                  checked={formData.is_active}
                  onCheckedChange={(checked) => setFormData(prev => ({ ...prev, is_active: checked }))}
                />
                <Label htmlFor="is_active">
                  {formData.is_active ? 'Ativo' : 'Inativo'}
                </Label>
              </div>
            </div>

            {/* Categoria */}
            <div className="space-y-2">
              <Label htmlFor="category">Categoria *</Label>
              <Select value={formData.category} onValueChange={(value) => setFormData(prev => ({ ...prev, category: value }))}>
                <SelectTrigger>
                  <SelectValue placeholder="Selecione a categoria" />
                </SelectTrigger>
                <SelectContent>
                  {Object.entries(categoryLabels).map(([value, label]) => (
                    <SelectItem key={value} value={value}>{label}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {/* Tipo */}
            <div className="space-y-2">
              <Label htmlFor="type">Tipo de Comunicação *</Label>
              <Select value={formData.type} onValueChange={(value) => setFormData(prev => ({ ...prev, type: value }))}>
                <SelectTrigger>
                  <SelectValue placeholder="Selecione o tipo" />
                </SelectTrigger>
                <SelectContent>
                  {Object.entries(typeLabels).map(([value, label]) => (
                    <SelectItem key={value} value={value}>{label}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          </div>

          {/* Assunto (apenas para emails) */}
          {formData.type === 'email' && (
            <div className="space-y-2">
              <Label htmlFor="subject">Assunto do E-mail</Label>
              <Input
                id="subject"
                value={formData.subject}
                onChange={(e) => setFormData(prev => ({ ...prev, subject: e.target.value }))}
                placeholder="Ex: Confirmação de Visita - {nome_empreendimento}"
              />
            </div>
          )}

          {/* Conteúdo - Fase 5: Com suporte a diferentes tipos */}
          {formData.type === 'whatsapp' ? (
            <Tabs value={messageType} onValueChange={(v) => setMessageType(v as any)}>
              <TabsList className="grid w-full grid-cols-4">
                <TabsTrigger value="text">Texto</TabsTrigger>
                <TabsTrigger value="buttons">Botões</TabsTrigger>
                <TabsTrigger value="media">Mídia</TabsTrigger>
                <TabsTrigger value="list">Lista</TabsTrigger>
              </TabsList>

              <TabsContent value="text" className="space-y-4 mt-4">
                <div className="space-y-2">
                  <div className="flex items-center justify-between">
                    <Label htmlFor="content">Conteúdo *</Label>
                    <Button
                      type="button"
                      variant="outline"
                      size="sm"
                      onClick={() => setShowVariableSelector(!showVariableSelector)}
                    >
                      <Plus className="w-4 h-4 mr-2" />
                      Inserir Variável
                    </Button>
                  </div>
                  <Textarea
                    id="content"
                    value={formData.content}
                    onChange={(e) => setFormData(prev => ({ ...prev, content: e.target.value }))}
                    placeholder="Use {variavel} para inserir variáveis dinâmicas"
                    rows={6}
                    required
                  />
                </div>
              </TabsContent>

              <TabsContent value="buttons" className="space-y-4 mt-4">
                <div className="space-y-2">
                  <Label>Mensagem</Label>
                  <Textarea
                    value={formData.content}
                    onChange={(e) => setFormData(prev => ({ ...prev, content: e.target.value }))}
                    placeholder="Texto da mensagem"
                    rows={4}
                  />
                </div>

                <div className="space-y-2">
                  <div className="flex items-center justify-between">
                    <Label>Botões</Label>
                    <Button type="button" size="sm" onClick={addButton}>
                      <Plus className="w-4 h-4 mr-2" />
                      Adicionar Botão
                    </Button>
                  </div>
                  {buttons.map((button, index) => (
                    <Card key={index}>
                      <CardContent className="flex gap-2 items-center pt-4">
                        <Input
                          placeholder="ID do botão"
                          value={button.id}
                          onChange={(e) => updateButton(index, 'id', e.target.value)}
                        />
                        <Input
                          placeholder="Texto do botão"
                          value={button.text}
                          onChange={(e) => updateButton(index, 'text', e.target.value)}
                        />
                        <Button
                          type="button"
                          variant="ghost"
                          size="icon"
                          onClick={() => removeButton(index)}
                        >
                          <X className="w-4 h-4" />
                        </Button>
                      </CardContent>
                    </Card>
                  ))}
                </div>
              </TabsContent>

              <TabsContent value="media" className="space-y-4 mt-4">
                <div className="space-y-2">
                  <Label>Tipo de Mídia</Label>
                  <Select value={mediaType} onValueChange={(v) => setMediaType(v as any)}>
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="image"><Image className="w-4 h-4 inline mr-2" />Imagem</SelectItem>
                      <SelectItem value="video">Vídeo</SelectItem>
                      <SelectItem value="document"><FileText className="w-4 h-4 inline mr-2" />Documento</SelectItem>
                      <SelectItem value="audio">Áudio</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                <div className="space-y-2">
                  <Label>URL da Mídia *</Label>
                  <Input
                    value={mediaUrl}
                    onChange={(e) => setMediaUrl(e.target.value)}
                    placeholder="https://..."
                  />
                </div>

                <div className="space-y-2">
                  <Label>Legenda (opcional)</Label>
                  <Textarea
                    value={mediaCaption}
                    onChange={(e) => setMediaCaption(e.target.value)}
                    placeholder="Legenda da mídia"
                    rows={3}
                  />
                </div>
              </TabsContent>

              <TabsContent value="list" className="space-y-4 mt-4">
                <div className="space-y-2">
                  <Label>Título da Lista *</Label>
                  <Input
                    value={listTitle}
                    onChange={(e) => setListTitle(e.target.value)}
                    placeholder="Título principal"
                  />
                </div>

                <div className="space-y-2">
                  <Label>Descrição (opcional)</Label>
                  <Textarea
                    value={listDescription}
                    onChange={(e) => setListDescription(e.target.value)}
                    rows={2}
                  />
                </div>

                <div className="space-y-2">
                  <Label>Texto do Botão</Label>
                  <Input
                    value={listButtonText}
                    onChange={(e) => setListButtonText(e.target.value)}
                    placeholder="Ver opções"
                  />
                </div>

                <div className="space-y-2">
                  <div className="flex items-center justify-between">
                    <Label>Seções</Label>
                    <Button type="button" size="sm" onClick={addListSection}>
                      <Plus className="w-4 h-4 mr-2" />
                      Adicionar Seção
                    </Button>
                  </div>
                  {listSections.map((section, sectionIndex) => (
                    <Card key={sectionIndex}>
                      <CardContent className="space-y-2 pt-4">
                        <Input
                          placeholder="Título da seção"
                          value={section.title}
                          onChange={(e) => {
                            const newSections = [...listSections];
                            newSections[sectionIndex].title = e.target.value;
                            setListSections(newSections);
                          }}
                        />
                        <Button
                          type="button"
                          size="sm"
                          variant="outline"
                          onClick={() => addListRow(sectionIndex)}
                        >
                          <Plus className="w-4 h-4 mr-2" />
                          Adicionar Item
                        </Button>
                      </CardContent>
                    </Card>
                  ))}
                </div>
              </TabsContent>
            </Tabs>
          ) : (
            <div className="space-y-2">
              <div className="flex items-center justify-between">
                <Label htmlFor="content">Conteúdo da Mensagem *</Label>
                <Button
                  type="button"
                  variant="outline"
                  size="sm"
                  onClick={() => setShowVariableSelector(!showVariableSelector)}
                >
                  <Plus className="w-4 h-4 mr-2" />
                  Inserir Variável
                </Button>
              </div>
              <Textarea
                id="content"
                value={formData.content}
                onChange={(e) => setFormData(prev => ({ ...prev, content: e.target.value }))}
                placeholder="Digite o conteúdo da mensagem. Use {variavel} para inserir dados dinâmicos."
                className="min-h-40"
                required
              />
            </div>
          )}

          {/* Seletor de Variáveis */}
          {showVariableSelector && (
            <div className="border rounded-lg p-4 bg-muted/50">
              <VariableSelector onVariableSelect={handleVariableInsert} />
            </div>
          )}

          {/* Variáveis Utilizadas */}
          {formData.variables.length > 0 && (
            <div className="space-y-3">
              <Label>Variáveis Utilizadas</Label>
              <div className="flex flex-wrap gap-2">
                {formData.variables.map((variable) => (
                  <Badge key={variable} variant="secondary" className="text-xs">
                    {variable}
                    <Button
                      type="button"
                      variant="ghost"
                      size="sm"
                      className="h-auto p-0 ml-2"
                      onClick={() => removeVariable(variable)}
                    >
                      <Trash2 className="w-3 h-3" />
                    </Button>
                  </Badge>
                ))}
              </div>
            </div>
          )}

          <Separator />

          {/* Botões */}
          <div className="flex justify-end gap-3">
            <Button type="button" variant="outline" onClick={onClose}>
              Cancelar
            </Button>
            <Button type="submit" disabled={isLoading}>
              {isLoading ? 'Salvando...' : (isEditing ? 'Atualizar' : 'Criar Template')}
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
};

import { useState, useEffect } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { VisitaForm, VisitaFormData } from "@/components/forms/VisitaForm";
import { useMutation, useQueryClient, useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useToast } from "@/hooks/use-toast";
import { Skeleton } from "@/components/ui/skeleton";
import { normalizeTime } from '@/utils/dateHelpers';
import LeadModal from "./LeadModal";

interface VisitaModalProps {
  isOpen: boolean;
  onClose: () => void;
  visitaId?: string;
  leadId?: string;
  corretorId?: string;
}

export function VisitaModal({ isOpen, onClose, visitaId, leadId, corretorId }: VisitaModalProps) {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [isLeadModalOpen, setIsLeadModalOpen] = useState(false);
  const [newlyCreatedLeadId, setNewlyCreatedLeadId] = useState<string | null>(null);

  const handleLeadCreated = (leadId: string) => {
    setNewlyCreatedLeadId(leadId);
    setIsLeadModalOpen(false);
    queryClient.invalidateQueries({ queryKey: ['leads'] });
  };

  // Fetch visita data if editing
  const { data: visita, isLoading: isLoadingVisita } = useQuery({
    queryKey: ['visita', visitaId],
    queryFn: async () => {
      if (!visitaId) return null;

      const { data, error } = await supabase
        .from('visitas')
        .select('*')
        .eq('id', visitaId)
        .single();

      if (error) throw error;
      return data;
    },
    enabled: !!visitaId
  });

  // Debug log for data flow
  useEffect(() => {
    console.log('🔍 [VisitaModal] Estado atual:', {
      visitaId,
      visitaData: visita,
      isLoadingVisita,
      isOpen
    });
  }, [visitaId, visita, isLoadingVisita, isOpen]);

  // Fetch leads for dropdown
  const { data: leads = [] } = useQuery({
    queryKey: ['leads'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('leads')
        .select('id, nome, telefone')
        .order('nome');

      if (error) throw error;
      return data;
    }
  });

  // Check for existing active visits for the selected lead (pre-submission validation)
  const selectedLeadId = newlyCreatedLeadId || leadId;
  const { data: existingVisitas = [] } = useQuery({
    queryKey: ['visitas-by-lead', selectedLeadId],
    queryFn: async () => {
      if (!selectedLeadId || visitaId) return [];

      const { data, error } = await supabase
        .from('visitas')
        .select('id, status, data_visita, horario_visita')
        .eq('lead_id', selectedLeadId)
        .in('status', ['agendada', 'confirmada']);

      if (error) throw error;
      return data || [];
    },
    enabled: !!selectedLeadId && !visitaId
  });

  // Fetch corretores for dropdown
  const { data: corretores = [] } = useQuery({
    queryKey: ['corretores'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('corretores')
        .select(`
          id,
          profiles(first_name, last_name)
        `)
        .eq('status', 'ativo')
        .order('profiles(first_name)');

      if (error) throw error;
      return data;
    }
  });

  // Fetch empreendimentos for dropdown
  const { data: empreendimentos = [] } = useQuery({
    queryKey: ['empreendimentos'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('empreendimentos')
        .select('id, nome')
        .eq('ativo', true)
        .order('nome');

      if (error) throw error;
      return data;
    }
  });

  // Create/Update mutation
  const mutation = useMutation({
    mutationFn: async (data: VisitaFormData) => {
      const visitaData = {
        lead_id: data.lead_id,
        corretor_id: data.auto_assign_corretor ? null : (data.corretor_id || null),
        empreendimento_id: data.empreendimento_id || null,
        data_visita: data.data_visita.toISOString().split('T')[0],
        horario_visita: data.horario_visita,
        status: data.status,
        avaliacao_lead: data.avaliacao_lead || null,
        comentarios_lead: data.comentarios_lead || null,
        feedback_corretor: data.feedback_corretor || null,
      };

      if (visitaId) {
        // Update existing visita
        const { data: result, error } = await supabase
          .from('visitas')
          .update(visitaData)
          .eq('id', visitaId)
          .select()
          .single();

        if (error) throw error;
        return { visita: result, autoAssign: data.auto_assign_corretor || false };
      } else {
        // Create new visita
        const { data: result, error } = await supabase
          .from('visitas')
          .insert(visitaData)
          .select()
          .single();

        if (error) throw error;
        return { visita: result, autoAssign: data.auto_assign_corretor || false };
      }
    },
    onSuccess: async (responseData) => {
      const { visita, autoAssign } = responseData;

      queryClient.invalidateQueries({ queryKey: ['visitas'] });
      queryClient.invalidateQueries({ queryKey: ['my-visitas'] });

      // Update lead status if visit was scheduled
      if (visita.status === 'agendada') {
        supabase
          .from('leads')
          .update({ status: 'visita_agendada' })
          .eq('id', visita.lead_id)
          .then(() => {
            queryClient.invalidateQueries({ queryKey: ['leads'] });
          });
      }

      // If auto-assign is enabled, trigger distribution
      // Works for both new visits and rescheduled visits (edits with auto_assign)
      const shouldDistribute = autoAssign && visita.id &&
        (visita.status === 'agendada' || visita.status === 'reagendada');

      if (shouldDistribute) {
        console.log('Iniciando distribuição automática para visita:', visita.id);

        toast({
          title: visitaId ? "Visita reagendada!" : "Visita criada!",
          description: "Buscando corretor disponível automaticamente...",
        });

        try {
          const { data: distributionResult, error: distributionError } = await supabase.functions.invoke(
            'distribute-visit',
            {
              body: { visita_id: visita.id }
            }
          );

          if (distributionError) {
            console.error('Erro na distribuição automática:', distributionError);

            // Mensagens de erro específicas e acionáveis
            let errorMessage = "Visita salva, mas houve erro na distribuição automática.";

            if (distributionError.message?.includes('cleanPhone') ||
              distributionError.message?.includes('not defined')) {
              errorMessage = "Erro técnico no sistema de distribuição. Nossa equipe foi notificada.";
            } else if (distributionError.message?.includes('telefone') ||
              distributionError.message?.includes('phone')) {
              errorMessage = "Corretor sem telefone válido cadastrado. Atribua manualmente.";
            } else if (distributionError.message?.includes('WhatsApp')) {
              errorMessage = "Erro ao enviar mensagem WhatsApp. Verifique as configurações da Evolution API.";
            }

            toast({
              title: "Aviso",
              description: errorMessage,
              variant: "destructive",
            });
          } else {
            console.log('Distribuição iniciada com sucesso:', distributionResult);
            toast({
              title: "Distribuição iniciada!",
              description: `Consultando ${distributionResult.total_eligible || 'vários'} corretores disponíveis...`,
            });
          }
        } catch (error) {
          console.error('Erro ao invocar distribute-visit:', error);
          toast({
            title: "Aviso",
            description: "Visita salva, mas erro ao iniciar distribuição. Atribua manualmente.",
            variant: "destructive",
          });
        }
      } else {
        toast({
          title: "Sucesso",
          description: visitaId ? "Visita atualizada com sucesso!" : "Visita agendada com sucesso!",
        });
      }

      onClose();
    },
    onError: (error: any) => {
      console.error('Erro ao salvar visita:', error);

      let errorMessage = "Erro ao salvar visita";
      let errorTitle = "Erro ao salvar visita";
      let actionLink = null;

      // FASE 2: Mensagens de erro específicas e acionáveis
      if (error.message?.includes('webhook') || error.message?.includes('Webhook não configurado')) {
        errorTitle = "⚙️ Webhook não configurado";
        errorMessage = "O webhook da Evolution API não está configurado. Configure para receber respostas dos corretores.";
        actionLink = { text: "Ir para Configurações", url: "/configuracoes" };
      } else if (error.message?.includes('WhatsApp') || error.message?.includes('whatsapp')) {
        errorTitle = "📱 Erro ao enviar WhatsApp";
        errorMessage = "Não foi possível enviar mensagem WhatsApp. Verifique se a API Evolution está configurada corretamente.";
        actionLink = { text: "Testar Conexão", url: "/configuracoes" };
      } else if (error.message?.includes('telefone') || error.message?.includes('phone')) {
        errorTitle = "📞 Corretor sem contato válido";
        errorMessage = "O corretor selecionado não possui WhatsApp ou telefone cadastrado. Atualize os dados do corretor.";
        actionLink = { text: "Ver Corretores", url: "/corretores" };
      } else if (error.message?.includes('pending') || error.message?.includes('aguardando')) {
        errorTitle = "✅ Mensagem enviada";
        errorMessage = "A mensagem foi enviada ao corretor. Aguardando resposta...";
        errorTitle = "Sucesso"; // Change to success
      } else if (error.message?.includes('duplicate key') || error.message?.includes('visitas_lead_id_key')) {
        errorMessage = "Já existe uma visita registrada com estes dados. Verifique os campos e tente novamente.";
      } else if (error.message?.includes('validation') || error.message?.includes('required')) {
        errorMessage = "Dados inválidos. Verifique todos os campos obrigatórios.";
      } else if (error.message?.includes('foreign key') || error.message?.includes('não existe')) {
        errorMessage = "Erro de referência. Verifique se o lead e corretor selecionados existem.";
      } else if (error.message) {
        errorMessage = error.message;
      }

      toast({
        title: errorTitle,
        description: actionLink
          ? `${errorMessage}\n\n👉 ${actionLink.text}`
          : errorMessage,
        variant: errorTitle === "Sucesso" ? "default" : "destructive",
      });
    }
  });

  const handleSubmit = (data: VisitaFormData) => {
    mutation.mutate(data);
  };

  const initialData = visitaId && visita ? {
    lead_id: visita.lead_id,
    corretor_id: visita.corretor_id || undefined,
    empreendimento_id: visita.empreendimento_id || undefined,
    data_visita: new Date(visita.data_visita),
    horario_visita: normalizeTime(visita.horario_visita),
    status: visita.status as 'agendada' | 'confirmada' | 'realizada' | 'cancelada' | 'reagendada',
    avaliacao_lead: visita.avaliacao_lead || undefined,
    comentarios_lead: visita.comentarios_lead || '',
    feedback_corretor: visita.feedback_corretor || '',
    auto_assign_corretor: false,
  } : {
    lead_id: newlyCreatedLeadId || leadId,
    corretor_id: corretorId,
    status: 'agendada' as const,
    auto_assign_corretor: false,
  };

  return (
    <>
      <Dialog open={isOpen} onOpenChange={onClose}>
        <DialogContent
          key={visitaId || 'new'}
          className="max-w-4xl max-h-[90vh] overflow-y-auto"
        >
          <DialogHeader>
            <DialogTitle>
              {visitaId ? 'Editar Visita' : 'Nova Visita'}
            </DialogTitle>
          </DialogHeader>

          {visitaId && isLoadingVisita ? (
            <div className="space-y-4">
              <Skeleton className="h-12 w-full" />
              <Skeleton className="h-12 w-full" />
              <Skeleton className="h-12 w-full" />
              <Skeleton className="h-32 w-full" />
              <div className="flex gap-4 justify-end">
                <Skeleton className="h-10 w-24" />
                <Skeleton className="h-10 w-32" />
              </div>
            </div>
          ) : (
            <>
              {existingVisitas.length > 0 && !visitaId && (
                <div className="mb-4 p-4 bg-warning/10 border border-warning rounded-lg">
                  <p className="text-sm text-warning-foreground font-medium">
                    ⚠️ Atenção: Este lead já possui {existingVisitas.length} visita(s) ativa(s):
                  </p>
                  <ul className="mt-2 text-sm text-muted-foreground space-y-1">
                    {existingVisitas.map((v) => (
                      <li key={v.id}>
                        • {v.status} - {new Date(v.data_visita).toLocaleDateString('pt-BR')} às {v.horario_visita}
                      </li>
                    ))}
                  </ul>
                </div>
              )}

              <VisitaForm
                initialData={initialData}
                onSubmit={handleSubmit}
                isLoading={mutation.isPending}
                leads={leads}
                corretores={corretores}
                empreendimentos={empreendimentos}
                onAddNewLead={() => setIsLeadModalOpen(true)}
              />
            </>
          )}
        </DialogContent>
      </Dialog>

      <LeadModal
        open={isLeadModalOpen}
        onOpenChange={setIsLeadModalOpen}
        title="Novo Lead"
        initialData={null}
        onLeadCreated={handleLeadCreated}
      />
    </>
  );
}

import { useState, useEffect } from "react";
import { Bell, CheckCircle, AlertCircle, Info, X, Calendar, UserPlus, Clock, XCircle } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { toast } from "@/hooks/use-toast";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useNavigate } from "react-router-dom";
import { formatDistanceToNow } from "date-fns";
import { ptBR } from "date-fns/locale";

interface Notification {
  id: string;
  user_id: string;
  type: string;
  title: string;
  message: string;
  read: boolean;
  metadata: any;
  related_lead_id?: string | null;
  related_visit_id?: string | null;
  related_corretor_id?: string | null;
  created_at: string;
  read_at?: string | null;
}

export function NotificationSystem() {
  const [open, setOpen] = useState(false);
  const queryClient = useQueryClient();
  const navigate = useNavigate();

  // Fetch real notifications from database
  const { data: notifications = [], isLoading } = useQuery<Notification[]>({
    queryKey: ['notifications'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('notifications')
        .select('*')
        .order('created_at', { ascending: false })
        .limit(50);

      if (error) throw error;
      return (data || []) as Notification[];
    },
  });

  // Real-time subscription for new notifications
  useEffect(() => {
    const channel = supabase
      .channel('notifications-changes')
      .on(
        'postgres_changes',
        {
          event: 'INSERT',
          schema: 'public',
          table: 'notifications',
        },
        (payload) => {
          console.log('New notification received:', payload);
          queryClient.invalidateQueries({ queryKey: ['notifications'] });

          // Show browser notification
          const notification = payload.new as Notification;
          if ('Notification' in window && Notification.permission === 'granted') {
            new Notification(notification.title, {
              body: notification.message,
              icon: '/favicon.ico',
            });
          }

          // Show toast
          toast({
            title: notification.title,
            description: notification.message,
          });
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [queryClient]);

  // Request notification permission on mount
  useEffect(() => {
    if ('Notification' in window && Notification.permission === 'default') {
      Notification.requestPermission();
    }
  }, []);

  const markAsReadMutation = useMutation({
    mutationFn: async (notificationId: string) => {
      const { error } = await supabase
        .from('notifications')
        .update({ read: true, read_at: new Date().toISOString() })
        .eq('id', notificationId);

      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['notifications'] });
    },
  });

  const markAllAsReadMutation = useMutation({
    mutationFn: async () => {
      const unreadIds = (notifications as Notification[]).filter(n => !n.read).map(n => n.id);

      if (unreadIds.length === 0) return;

      const { error } = await supabase
        .from('notifications')
        .update({ read: true, read_at: new Date().toISOString() })
        .in('id', unreadIds);

      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['notifications'] });
      toast({
        title: "Todas as notificações marcadas como lidas",
      });
    },
  });

  const handleNotificationClick = (notification: Notification) => {
    // Mark as read
    if (!notification.read) {
      markAsReadMutation.mutate(notification.id);
    }

    // Navigate based on type
    if (notification.related_lead_id) {
      navigate('/leads');
    } else if (notification.related_visit_id) {
      navigate('/visitas');
    }

    setOpen(false);
  };

  const getNotificationIcon = (type: string) => {
    switch (type) {
      case 'new_lead':
      case 'lead_distributed':
        return <UserPlus className="h-4 w-4 text-blue-500" />;
      case 'lead_accepted':
        return <CheckCircle className="h-4 w-4 text-green-500" />;
      case 'lead_rejected':
      case 'lead_timeout':
        return <XCircle className="h-4 w-4 text-red-500" />;
      case 'new_visit':
      case 'visit_confirmed':
        return <Calendar className="h-4 w-4 text-purple-500" />;
      case 'visit_completed':
        return <CheckCircle className="h-4 w-4 text-green-500" />;
      case 'visit_cancelled':
        return <XCircle className="h-4 w-4 text-red-500" />;
      case 'distribution_timeout':
        return <Clock className="h-4 w-4 text-orange-500" />;
      case 'system_alert':
        return <AlertCircle className="h-4 w-4 text-yellow-500" />;
      case 'info':
      default:
        return <Info className="h-4 w-4 text-blue-500" />;
    }
  };

  const notificationList = notifications as Notification[];
  const unreadCount = notificationList.filter(n => !n.read).length;

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>
        <Button variant="ghost" size="icon" className="relative">
          <Bell className="h-5 w-5" />
          {unreadCount > 0 && (
            <Badge 
              variant="destructive" 
              className="absolute -top-1 -right-1 h-5 w-5 rounded-full p-0 flex items-center justify-center text-xs"
            >
              {unreadCount}
            </Badge>
          )}
        </Button>
      </PopoverTrigger>

      <PopoverContent className="w-96 p-0" align="end">
        <div className="flex items-center justify-between p-4 border-b">
          <h3 className="font-semibold text-lg">Notificações</h3>
          {unreadCount > 0 && (
            <Button
              variant="ghost"
              size="sm"
              onClick={() => markAllAsReadMutation.mutate()}
              disabled={markAllAsReadMutation.isPending}
            >
              Marcar todas como lidas
            </Button>
          )}
        </div>

        <ScrollArea className="h-[400px]">
          {isLoading ? (
            <div className="flex items-center justify-center py-8">
              <p className="text-sm text-muted-foreground">Carregando...</p>
            </div>
          ) : notificationList.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-8 text-center">
              <Bell className="h-12 w-12 text-muted-foreground mb-2" />
              <p className="text-sm text-muted-foreground">
                Nenhuma notificação
              </p>
            </div>
          ) : (
            <div className="space-y-2">
              {notificationList.map((notification) => (
                <div
                  key={notification.id}
                  className={`p-3 rounded-lg border transition-colors cursor-pointer hover:bg-accent/30 ${
                    notification.read
                      ? 'bg-background'
                      : 'bg-accent/50'
                  }`}
                  onClick={() => handleNotificationClick(notification)}
                >
                  <div className="flex items-start gap-3">
                    <div className="mt-0.5">
                      {getNotificationIcon(notification.type)}
                    </div>
                    <div className="flex-1 space-y-1">
                      <div className="flex items-center justify-between">
                        <p className="text-sm font-medium leading-none">
                          {notification.title}
                        </p>
                      </div>
                      <p className="text-sm text-muted-foreground">
                        {notification.message}
                      </p>
                      <p className="text-xs text-muted-foreground">
                        {formatDistanceToNow(new Date(notification.created_at), {
                          addSuffix: true,
                          locale: ptBR,
                        })}
                      </p>
                    </div>
                    {!notification.read && (
                      <Button
                        variant="ghost"
                        size="icon"
                        className="h-8 w-8 shrink-0"
                        onClick={(e) => {
                          e.stopPropagation();
                          markAsReadMutation.mutate(notification.id);
                        }}
                      >
                        <X className="h-4 w-4" />
                      </Button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </ScrollArea>
      </PopoverContent>
    </Popover>
  );
}

/**
 * Hook to programmatically create notifications
 */
export const useNotification = () => {
  const createNotification = async (notification: {
    user_id: string;
    type: string;
    title: string;
    message: string;
    metadata?: Record<string, any>;
    related_lead_id?: string;
    related_visit_id?: string;
    related_corretor_id?: string;
  }) => {
    try {
      const { error } = await supabase.functions.invoke('create-notification', {
        body: notification,
      });

      if (error) throw error;

      toast({
        title: notification.title,
        description: notification.message,
      });
    } catch (error) {
      console.error('Error creating notification:', error);
      toast({
        title: 'Erro',
        description: 'Não foi possível criar a notificação',
        variant: 'destructive',
      });
    }
  };

  return { createNotification };
};

