      charts: prev.charts.includes(chartId)
        ? prev.charts.filter((id: string) => id !== chartId)
        : [...prev.charts, chartId]
    }));
  };

  const handleMetricToggle = (metricId: string) => {
    setConfig(prev => ({
      ...prev,
      metrics: prev.metrics.includes(metricId)
        ? prev.metrics.filter((id: string) => id !== metricId)
        : [...prev.metrics, metricId]
    }));
  };

  const handleSave = () => {
    const templateData: ReportTemplate = {
      id: template?.id,
      name: config.name,
      description: config.description,
      category: config.category,
      is_public: false,
      template_config: {
        period: config.period,
        charts: config.charts,
        metrics: config.metrics,
        filters: config.filters
      }
    };
    onSave(templateData);
  };

  const handleGenerate = () => {
    onGenerate(config);
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold">Construtor de Relatórios</h2>
          <p className="text-muted-foreground">
            Configure seu relatório personalizado
          </p>
        </div>
        <div className="flex gap-2">
          <Button variant="outline" onClick={handleSave}>
            <Save className="mr-2 h-4 w-4" />
            Salvar Template
          </Button>
          <Button onClick={handleGenerate}>
            <Play className="mr-2 h-4 w-4" />
            Gerar Relatório
          </Button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Configuration Panel */}
        <div className="lg:col-span-1 space-y-6">
          {/* Basic Info */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Settings className="w-5 h-5" />
                Configurações Básicas
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="name">Nome do Relatório</Label>
                <Input
                  id="name"
                  placeholder="Ex: Relatório Mensal de Performance"
                  value={config.name}
                  onChange={(e) => setConfig(prev => ({ ...prev, name: e.target.value }))}
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="description">Descrição</Label>
                <Textarea
                  id="description"
                  placeholder="Descreva o objetivo deste relatório..."
                  value={config.description}
                  onChange={(e) => setConfig(prev => ({ ...prev, description: e.target.value }))}
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="period">Período</Label>
                <Select value={config.period} onValueChange={(value) => setConfig(prev => ({ ...prev, period: value }))}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="daily">Diário</SelectItem>
                    <SelectItem value="weekly">Semanal</SelectItem>
                    <SelectItem value="monthly">Mensal</SelectItem>
                    <SelectItem value="quarterly">Trimestral</SelectItem>
                    <SelectItem value="yearly">Anual</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </CardContent>
          </Card>

          {/* Charts Selection */}
          <Card>
            <CardHeader>
              <CardTitle>Gráficos</CardTitle>
              <CardDescription>
                Selecione os gráficos que deseja incluir no relatório
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-3">
              {AVAILABLE_CHARTS.map(chart => (
                <div key={chart.id} className="flex items-center space-x-2">
                  <Checkbox
                    id={chart.id}
                    checked={config.charts.includes(chart.id)}
                    onCheckedChange={() => handleChartToggle(chart.id)}
                  />
                  <div className="flex items-center gap-2 flex-1">
                    <chart.icon className="w-4 h-4" />
                    <Label htmlFor={chart.id} className="text-sm cursor-pointer">
                      {chart.name}
                    </Label>
                  </div>
                  <Badge variant="outline" className="text-xs">
                    {chart.type}
                  </Badge>
                </div>
              ))}
            </CardContent>
          </Card>

          {/* Metrics Selection */}
          <Card>
            <CardHeader>
              <CardTitle>Métricas</CardTitle>
              <CardDescription>
                Escolha as métricas principais para destacar
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-3">
              {AVAILABLE_METRICS.map(metric => (
                <div key={metric.id} className="flex items-center space-x-2">
                  <Checkbox
                    id={metric.id}
                    checked={config.metrics.includes(metric.id)}
                    onCheckedChange={() => handleMetricToggle(metric.id)}
                  />
                  <div className="flex items-center gap-2">
                    <metric.icon className="w-4 h-4" />
                    <Label htmlFor={metric.id} className="text-sm cursor-pointer">
                      {metric.name}
                    </Label>
                  </div>
                </div>
              ))}
            </CardContent>
          </Card>
        </div>

        {/* Preview Panel */}
        <div className="lg:col-span-2">
          <Card>
            <CardHeader>
              <CardTitle>Preview do Relatório</CardTitle>
              <CardDescription>
                Visualize como seu relatório ficará
              </CardDescription>
            </CardHeader>
            <CardContent>
              {config.charts.length > 0 ? (
                <AdvancedCharts
                  leadsOverTime={previewData.leadsOverTime}
                  leadsByStatus={previewData.leadsByStatus}
                  conversionFunnel={previewData.conversionFunnel}
                  corretorPerformance={previewData.corretorPerformance}
                  visitsByMonth={previewData.visitsByMonth}
                  leadSources={previewData.leadSources}
                />
              ) : (
                <div className="flex flex-col items-center justify-center py-12 text-muted-foreground">
                  <BarChart3 className="w-12 h-12 mb-4" />
                  <h3 className="text-lg font-semibold mb-2">Selecione gráficos para visualizar</h3>
                  <p className="text-center">
                    Escolha os gráficos na configuração à esquerda para ver o preview aqui.
                  </p>
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Input } from '@/components/ui/input';
import { 
  FileText, 
  Plus, 
  Search, 
  Edit, 
  Trash2, 
  Copy, 
  Calendar,
  BarChart3,
  TrendingUp,
  Users,
  DollarSign,
  Star
} from 'lucide-react';
import { useToast } from '@/hooks/use-toast';
import { useAuth } from '@/hooks/useAuth';

interface ReportTemplate {
  id: string;
  name: string;
  description: string;
  template_config: any;
  category: string;
  is_public: boolean;
  created_at: string;
  created_by: string;
}

interface ReportTemplateManagerProps {
  onSelectTemplate: (template: ReportTemplate) => void;
}

export function ReportTemplateManager({ onSelectTemplate }: ReportTemplateManagerProps) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<string>('all');
  const { profile } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const { data: templates = [], isLoading } = useQuery({
    queryKey: ['report-templates'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('report_templates')
        .select('*')
        .order('created_at', { ascending: false });

      if (error) throw error;
      return data as ReportTemplate[];
    }
  });

  const deleteTemplateMutation = useMutation({
    mutationFn: async (templateId: string) => {
      const { error } = await supabase
        .from('report_templates')
        .delete()
        .eq('id', templateId);

      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['report-templates'] });
      toast({
        title: 'Template removido',
        description: 'O template foi removido com sucesso.',
      });
    },
    onError: (error: any) => {
      toast({
        title: 'Erro ao remover template',
        description: error.message,
        variant: 'destructive',
      });
    }
  });

  const duplicateTemplateMutation = useMutation({
    mutationFn: async (template: ReportTemplate) => {
      const { error } = await supabase
        .from('report_templates')
        .insert({
          name: `${template.name} (Cópia)`,
          description: template.description,
          template_config: template.template_config,
          category: 'custom',
          is_public: false,
          created_by: profile?.id
        });

      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['report-templates'] });
      toast({
        title: 'Template duplicado',
        description: 'O template foi duplicado com sucesso.',
      });
    },
    onError: (error: any) => {
      toast({
        title: 'Erro ao duplicar template',
        description: error.message,
        variant: 'destructive',
      });
    }
  });

  const filteredTemplates = templates.filter(template => {
    const matchesSearch = template.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         template.description?.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesCategory = selectedCategory === 'all' || template.category === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  const getCategoryIcon = (category: string) => {
    switch (category) {
      case 'performance': return <TrendingUp className="w-4 h-4" />;
      case 'leads': return <Users className="w-4 h-4" />;
      case 'financial': return <DollarSign className="w-4 h-4" />;
      case 'marketing': return <BarChart3 className="w-4 h-4" />;
      case 'satisfaction': return <Star className="w-4 h-4" />;
      default: return <FileText className="w-4 h-4" />;
    }
  };

  const getCategoryLabel = (category: string) => {
    switch (category) {
      case 'performance': return 'Performance';
      case 'leads': return 'Leads';
      case 'financial': return 'Financeiro';
      case 'marketing': return 'Marketing';
      case 'satisfaction': return 'Satisfação';
      default: return 'Personalizado';
    }
  };

  if (isLoading) {
    return (
      <div className="space-y-4">
        {[...Array(3)].map((_, i) => (
          <Card key={i} className="animate-pulse">
            <CardHeader>
              <div className="h-4 bg-muted rounded w-1/3"></div>
              <div className="h-3 bg-muted rounded w-2/3"></div>
            </CardHeader>
          </Card>
        ))}
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col space-y-4 md:flex-row md:items-center md:justify-between md:space-y-0">
        <div>
          <h2 className="text-2xl font-bold">Templates de Relatórios</h2>
          <p className="text-muted-foreground">
            Selecione um template para gerar seu relatório
          </p>
        </div>
        <Button className="md:w-auto">
          <Plus className="mr-2 h-4 w-4" />
          Novo Template
        </Button>
      </div>

      {/* Search and Filters */}
      <div className="flex flex-col space-y-4 md:flex-row md:items-center md:space-x-4 md:space-y-0">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-muted-foreground" />
          <Input
            placeholder="Buscar templates..."
            className="pl-10"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <div className="flex gap-2 flex-wrap">
          <Button
            variant={selectedCategory === 'all' ? 'default' : 'outline'}
            size="sm"
            onClick={() => setSelectedCategory('all')}
          >
            Todos
          </Button>
          {['performance', 'leads', 'financial', 'marketing', 'satisfaction'].map(category => (
            <Button
              key={category}
              variant={selectedCategory === category ? 'default' : 'outline'}
              size="sm"
              onClick={() => setSelectedCategory(category)}
              className="flex items-center gap-1"
            >
              {getCategoryIcon(category)}
              {getCategoryLabel(category)}
            </Button>
          ))}
        </div>
      </div>

      {/* Templates Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredTemplates.map((template) => (
          <Card 
            key={template.id} 
            className="hover:shadow-md transition-shadow cursor-pointer hover-scale"
            onClick={() => onSelectTemplate(template)}
          >
            <CardHeader>
              <div className="flex items-start justify-between">
                <div className="flex items-center gap-2">
                  {getCategoryIcon(template.category)}
                  <CardTitle className="text-lg">{template.name}</CardTitle>
                </div>
                <div className="flex gap-1">
                  {template.is_public && (
                    <Badge variant="secondary" className="text-xs">
                      Público
                    </Badge>
                  )}
                  <Badge variant="outline" className="text-xs">
                    {getCategoryLabel(template.category)}
                  </Badge>
                </div>
              </div>
              <CardDescription className="line-clamp-2">
                {template.description}
              </CardDescription>
            </CardHeader>
            <CardContent>
              <div className="flex items-center justify-between">
                <div className="text-sm text-muted-foreground">
                  {new Date(template.created_at).toLocaleDateString('pt-BR')}
                </div>
                <div className="flex gap-1" onClick={(e) => e.stopPropagation()}>
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => duplicateTemplateMutation.mutate(template)}
                  >
                    <Copy className="h-4 w-4" />
                  </Button>
                  <Button
                    variant="ghost"
                    size="sm"
                  >
                    <Edit className="h-4 w-4" />
                  </Button>
                  {!template.is_public && (
                    <Button
                      variant="ghost"
                      size="sm"
                      className="text-destructive hover:text-destructive"
                      onClick={() => deleteTemplateMutation.mutate(template.id)}
                    >
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  )}
                </div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {filteredTemplates.length === 0 && (
        <Card>
          <CardContent className="flex flex-col items-center justify-center py-12">
            <FileText className="w-12 h-12 text-muted-foreground mb-4" />
            <h3 className="text-lg font-semibold mb-2">Nenhum template encontrado</h3>
            <p className="text-muted-foreground text-center">
              {searchTerm ? 'Tente ajustar sua busca' : 'Crie seu primeiro template de relatório'}
            </p>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

import { useState } from 'react';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Badge } from '@/components/ui/badge';
import { useToast } from '@/hooks/use-toast';
import { useAuth } from '@/hooks/useAuth';
import { Calendar, Clock, Mail, X } from 'lucide-react';

interface ReportTemplate {
  id: string;
  name: string;
  description: string;
}

interface ScheduleReportModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  template: ReportTemplate | null;
}

export function ScheduleReportModal({ open, onOpenChange, template }: ScheduleReportModalProps) {
  const [formData, setFormData] = useState({
    schedule_type: 'monthly' as 'daily' | 'weekly' | 'monthly' | 'quarterly',
    recipients: [''],
    email_subject: '',
    email_message: '',
  });

  const { toast } = useToast();
  const { profile } = useAuth();
  const queryClient = useQueryClient();

  const scheduleReportMutation = useMutation({
    mutationFn: async (scheduleData: any) => {
      if (!template || !profile) throw new Error('Template ou perfil não encontrado');

      // Calculate next run date based on schedule type
      const now = new Date();
      let nextRun = new Date();

      switch (scheduleData.schedule_type) {
        case 'daily':
          nextRun.setDate(now.getDate() + 1);
          break;
        case 'weekly':
          nextRun.setDate(now.getDate() + 7);
          break;
        case 'monthly':
          nextRun.setMonth(now.getMonth() + 1);
          break;
        case 'quarterly':
          nextRun.setMonth(now.getMonth() + 3);
          break;
      }

      const { error } = await supabase
        .from('scheduled_reports')
        .insert({
          report_template_id: template.id,
          schedule_type: scheduleData.schedule_type,
          recipients: scheduleData.recipients.filter((email: string) => email.trim()),
          email_subject: scheduleData.email_subject || `Relatório ${template.name}`,
          email_message: scheduleData.email_message,
          next_run: nextRun.toISOString(),
          created_by: profile.id,
        });

      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['scheduled-reports'] });
      toast({
        title: 'Relatório agendado',
        description: 'O relatório foi agendado com sucesso.',
      });
      onOpenChange(false);
      resetForm();
    },
    onError: (error: any) => {
      toast({
        title: 'Erro ao agendar relatório',
        description: error.message || 'Não foi possível agendar o relatório.',
        variant: 'destructive',
      });
    }
  });

  const resetForm = () => {
    setFormData({
      schedule_type: 'monthly',
      recipients: [''],
      email_subject: '',
      email_message: '',
    });
  };

  const addRecipient = () => {
    setFormData(prev => ({
      ...prev,
      recipients: [...prev.recipients, '']
    }));
  };

  const updateRecipient = (index: number, email: string) => {
    setFormData(prev => ({
      ...prev,
      recipients: prev.recipients.map((recipient, i) => i === index ? email : recipient)
    }));
  };

  const removeRecipient = (index: number) => {
    if (formData.recipients.length > 1) {
      setFormData(prev => ({
        ...prev,
        recipients: prev.recipients.filter((_, i) => i !== index)
      }));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    const validRecipients = formData.recipients.filter(email => email.trim() && email.includes('@'));
    if (validRecipients.length === 0) {
      toast({
        title: 'Destinatários obrigatórios',
        description: 'Adicione pelo menos um email válido.',
        variant: 'destructive',
      });
      return;
    }

    scheduleReportMutation.mutate({
      ...formData,
      recipients: validRecipients
    });
  };

  const getScheduleLabel = (type: string) => {
    switch (type) {
      case 'daily': return 'Diário';
      case 'weekly': return 'Semanal';
      case 'monthly': return 'Mensal';
      case 'quarterly': return 'Trimestral';
      default: return type;
    }
  };

  if (!template) return null;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[600px]">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Calendar className="w-5 h-5" />
            Agendar Relatório
          </DialogTitle>
          <DialogDescription>
            Configure o envio automático do relatório "{template.name}"
          </DialogDescription>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="space-y-6">
          {/* Schedule Type */}
          <div className="space-y-2">
            <Label htmlFor="schedule_type">Frequência de Envio</Label>
            <Select 
              value={formData.schedule_type} 
              onValueChange={(value: typeof formData.schedule_type) => 
                setFormData(prev => ({ ...prev, schedule_type: value }))
              }
            >
              <SelectTrigger>
                <SelectValue placeholder="Selecione a frequência" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="daily">
                  <div className="flex items-center gap-2">
                    <Clock className="w-4 h-4" />
                    Diário
                  </div>
                </SelectItem>
                <SelectItem value="weekly">
                  <div className="flex items-center gap-2">
                    <Calendar className="w-4 h-4" />
                    Semanal
                  </div>
                </SelectItem>
                <SelectItem value="monthly">
                  <div className="flex items-center gap-2">
                    <Calendar className="w-4 h-4" />
                    Mensal
                  </div>
                </SelectItem>
                <SelectItem value="quarterly">
                  <div className="flex items-center gap-2">
                    <Calendar className="w-4 h-4" />
                    Trimestral
                  </div>
                </SelectItem>
              </SelectContent>
            </Select>
            <p className="text-sm text-muted-foreground">
              Próximo envio será {getScheduleLabel(formData.schedule_type).toLowerCase()}
            </p>
          </div>

          {/* Recipients */}
          <div className="space-y-2">
            <Label>Destinatários</Label>
            <div className="space-y-2">
              {formData.recipients.map((recipient, index) => (
                <div key={index} className="flex gap-2">
                  <div className="relative flex-1">
                    <Mail className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                    <Input
                      type="email"
                      placeholder="email@exemplo.com"
                      className="pl-10"
                      value={recipient}
                      onChange={(e) => updateRecipient(index, e.target.value)}
                    />
                  </div>
                  {formData.recipients.length > 1 && (
                    <Button
                      type="button"
                      variant="outline"
                      size="sm"
                      onClick={() => removeRecipient(index)}
                    >
                      <X className="w-4 h-4" />
                    </Button>
                  )}
                </div>
              ))}
            </div>
            <Button
              type="button"
              variant="outline"
              size="sm"
              onClick={addRecipient}
              className="w-full"
            >
              + Adicionar Destinatário
            </Button>
          </div>

          {/* Email Subject */}
          <div className="space-y-2">
            <Label htmlFor="email_subject">Assunto do Email</Label>
            <Input
              id="email_subject"
              placeholder={`Relatório ${template.name}`}
              value={formData.email_subject}
              onChange={(e) => setFormData(prev => ({ ...prev, email_subject: e.target.value }))}
            />
          </div>

          {/* Email Message */}
          <div className="space-y-2">
            <Label htmlFor="email_message">Mensagem (Opcional)</Label>
            <Textarea
              id="email_message"
              placeholder="Adicione uma mensagem personalizada para acompanhar o relatório..."
              value={formData.email_message}
              onChange={(e) => setFormData(prev => ({ ...prev, email_message: e.target.value }))}
              rows={3}
            />
          </div>

          {/* Summary */}
          <div className="bg-muted/50 p-4 rounded-lg">
            <h4 className="font-semibold mb-2">Resumo do Agendamento</h4>
            <div className="space-y-1 text-sm">
              <div className="flex justify-between">
                <span>Relatório:</span>
                <Badge variant="outline">{template.name}</Badge>
              </div>
              <div className="flex justify-between">
                <span>Frequência:</span>
                <span>{getScheduleLabel(formData.schedule_type)}</span>
              </div>
              <div className="flex justify-between">
                <span>Destinatários:</span>
                <span>{formData.recipients.filter(email => email.trim()).length} email(s)</span>
              </div>
            </div>
          </div>

          <div className="flex justify-end space-x-2">
            <Button
              type="button"
              variant="outline"
              onClick={() => onOpenChange(false)}
            >
              Cancelar
            </Button>
            <Button
              type="submit"
              disabled={scheduleReportMutation.isPending}
              className="min-w-[120px]"
            >
