  CheckCircle,
  Info
} from "lucide-react";

interface WordPressConfig {
  site_url: string;
  sync_enabled: boolean;
  sync_interval_hours: number;
  last_sync: string | null;
  auto_sync: boolean;
  posts_per_batch: number;
}

export function WordPressSettings() {
  const [config, setConfig] = useState<WordPressConfig>({
    site_url: 'https://memude.com.br',
    sync_enabled: true,
    sync_interval_hours: 24,
    last_sync: null,
    auto_sync: true,
    posts_per_batch: 50
  });

  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [connectionStatus, setConnectionStatus] = useState<'testing' | 'success' | 'error' | null>(null);
  const { toast } = useToast();

  useEffect(() => {
    loadConfiguration();
  }, []);

  const loadConfiguration = async () => {
    try {
      setIsLoading(true);

      // Load from system_settings table
      const { data: settings, error } = await supabase
        .from('system_settings')
        .select('key, value')
        .in('key', [
          'wp_site_url',
          'wp_sync_enabled', 
          'wp_sync_interval_hours',
          'wp_last_sync',
          'wp_auto_sync',
          'wp_posts_per_batch'
        ]);

      if (error) throw error;

      // Convert settings array to config object
      const configObj = settings?.reduce((acc: any, setting) => {
        const key = setting.key.replace('wp_', '');
        let value: any = setting.value;

        // Type conversions
        if (key === 'sync_enabled' || key === 'auto_sync') {
          value = value === 'true';
        } else if (key === 'sync_interval_hours' || key === 'posts_per_batch') {
          value = parseInt(value) || (key === 'posts_per_batch' ? 50 : 24);
        }

        acc[key] = value;
        return acc;
      }, {}) || {};

      setConfig(prev => ({ ...prev, ...configObj }));

    } catch (error) {
      console.error('Erro ao carregar configuração:', error);
      toast({
        title: "Erro",
        description: "Não foi possível carregar as configurações",
        variant: "destructive"
      });
    } finally {
      setIsLoading(false);
    }
  };

  const saveConfiguration = async () => {
    try {
      setIsSaving(true);

      // Convert config to settings format
      const settingsToUpdate = [
        { key: 'wp_site_url', value: config.site_url },
        { key: 'wp_sync_enabled', value: config.sync_enabled.toString() },
        { key: 'wp_sync_interval_hours', value: config.sync_interval_hours.toString() },
        { key: 'wp_auto_sync', value: config.auto_sync.toString() },
        { key: 'wp_posts_per_batch', value: config.posts_per_batch.toString() }
      ];

      // Upsert each setting
      for (const setting of settingsToUpdate) {
        const { error } = await supabase
          .from('system_settings')
          .upsert({
            key: setting.key,
            value: setting.value,
            description: `WordPress ${setting.key.replace('wp_', '').replace('_', ' ')}`
          }, {
            onConflict: 'key'
          });

        if (error) throw error;
      }

      toast({
        title: "Configurações salvas",
        description: "As configurações do WordPress foram atualizadas com sucesso"
      });

    } catch (error) {
      console.error('Erro ao salvar configuração:', error);
      toast({
        title: "Erro",
        description: "Não foi possível salvar as configurações",
        variant: "destructive"
      });
    } finally {
      setIsSaving(false);
    }
  };

  const testConnection = async () => {
    try {
      setConnectionStatus('testing');

      const { data, error } = await supabase.functions.invoke('sync-wordpress-properties', {
        body: { 
          manual: true,
          test_mode: true,
          limit: 3
        }
      });

      if (error) throw error;

      if (data.success) {
        setConnectionStatus('success');
        toast({
          title: "Conexão bem-sucedida",
          description: `Encontrados ${data.totalPostsFetched} posts no site`
        });
      } else {
        setConnectionStatus('error');
        toast({
          title: "Falha na conexão",
          description: data.error || "Erro desconhecido",
          variant: "destructive"
        });
      }

    } catch (error) {
      setConnectionStatus('error');
      toast({
        title: "Erro no teste",
        description: error.message || "Falha ao testar conexão",
        variant: "destructive"
      });
    }
  };

  const getConnectionBadge = () => {
    switch (connectionStatus) {
      case 'testing':
        return <Badge variant="secondary"><RefreshCw className="w-3 h-3 mr-1 animate-spin" />Testando...</Badge>;
      case 'success':
        return <Badge variant="default"><CheckCircle className="w-3 h-3 mr-1" />Conectado</Badge>;
      case 'error':
        return <Badge variant="destructive"><AlertTriangle className="w-3 h-3 mr-1" />Erro</Badge>;
      default:
        return <Badge variant="outline"><Info className="w-3 h-3 mr-1" />Não testado</Badge>;
    }
  };

  if (isLoading) {
    return (
      <Card>
        <CardContent className="flex items-center justify-center p-6">
          <RefreshCw className="w-6 h-6 animate-spin mr-2" />
          Carregando configurações...
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-6">
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Settings className="w-5 h-5" />
            Configurações do WordPress
          </CardTitle>
          <CardDescription>
            Configure a integração com o site memude.com.br
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-6">
          {/* Site URL */}
          <div className="space-y-2">
            <Label htmlFor="site_url" className="flex items-center gap-2">
              <Globe className="w-4 h-4" />
              URL do Site
            </Label>
            <div className="flex gap-2">
              <Input
                id="site_url"
                value={config.site_url}
                onChange={(e) => setConfig(prev => ({ ...prev, site_url: e.target.value }))}
                placeholder="https://memude.com.br"
              />
              <Button 
                variant="outline" 
                onClick={testConnection}
                disabled={connectionStatus === 'testing'}
              >
                Testar
              </Button>
            </div>
            <div className="flex items-center gap-2">
              <span className="text-sm text-muted-foreground">Status:</span>
              {getConnectionBadge()}
            </div>
          </div>

          {/* Sync Settings */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="sync_interval" className="flex items-center gap-2">
                <Clock className="w-4 h-4" />
                Intervalo de Sincronização (horas)
              </Label>
              <Input
                id="sync_interval"
                type="number"
                min="1"
                max="168"
                value={config.sync_interval_hours}
                onChange={(e) => setConfig(prev => ({ 
                  ...prev, 
                  sync_interval_hours: parseInt(e.target.value) || 24 
                }))}
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="posts_per_batch">Posts por Lote</Label>
              <Input
                id="posts_per_batch"
                type="number"
                min="10"
                max="100"
                value={config.posts_per_batch}
                onChange={(e) => setConfig(prev => ({ 
                  ...prev, 
                  posts_per_batch: parseInt(e.target.value) || 50 
                }))}
              />
            </div>
          </div>

          {/* Toggle Settings */}
          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <div>
                <Label htmlFor="sync_enabled">Sincronização Ativa</Label>
                <p className="text-sm text-muted-foreground">
                  Permite que o sistema sincronize dados automaticamente
                </p>
              </div>
              <Switch
                id="sync_enabled"
                checked={config.sync_enabled}
                onCheckedChange={(checked) => setConfig(prev => ({ ...prev, sync_enabled: checked }))}
              />
            </div>

            <div className="flex items-center justify-between">
              <div>
                <Label htmlFor="auto_sync">Sincronização Automática</Label>
                <p className="text-sm text-muted-foreground">
                  Executa sincronização nos horários programados
                </p>
              </div>
              <Switch
                id="auto_sync"
                checked={config.auto_sync}
                onCheckedChange={(checked) => setConfig(prev => ({ ...prev, auto_sync: checked }))}
              />
            </div>
          </div>

          {/* Status Information */}
          {config.last_sync && (
            <Alert>
              <Info className="h-4 w-4" />
              <AlertDescription>
                Última sincronização: {new Date(config.last_sync).toLocaleString('pt-BR')}
              </AlertDescription>
            </Alert>
          )}

          {/* Save Button */}
          <div className="flex justify-end">
            <Button 
              onClick={saveConfiguration}
              disabled={isSaving}
            >
              {isSaving ? (
                <>
                  <RefreshCw className="w-4 h-4 mr-2 animate-spin" />
                  Salvando...
                </>
              ) : (
                'Salvar Configurações'
              )}
            </Button>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

import React, { createContext, useContext, useEffect, useState, ReactNode } from 'react';
import { User, Session } from '@supabase/supabase-js';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';

interface Profile {
  id: string;
  user_id: string;
  role: 'admin' | 'corretor' | 'cliente';
  first_name: string;
  last_name: string;
  phone?: string;
  avatar_url?: string;
}

interface AuthContextType {
  user: User | null;
  session: Session | null;
  profile: Profile | null;
  loading: boolean;
  signIn: (email: string, password: string) => Promise<{ error?: any; success?: boolean }>;
  signUp: (email: string, password: string, firstName: string, lastName: string) => Promise<{ error?: any }>;
  signOut: () => Promise<void>;
  isAdmin: boolean;
  isCorretor: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

interface AuthProviderProps {
  children: ReactNode;
}

export function AuthProvider({ children }: AuthProviderProps): JSX.Element {
  const [user, setUser] = useState<User | null>(null);
  const [session, setSession] = useState<Session | null>(null);
  const [profile, setProfile] = useState<Profile | null>(null);
  const [loading, setLoading] = useState(true);
  const [isAuthenticating, setIsAuthenticating] = useState(false);
  const { toast } = useToast();

  const fetchProfile = async (userId: string): Promise<Profile | null> => {
    try {
      // Fetch profile data
      const { data: profileData, error: profileError } = await supabase
        .from('profiles')
        .select('*')
        .eq('user_id', userId)
        .maybeSingle();

      if (profileError) {
        console.error('Error fetching profile:', profileError);
        return null;
      }

      if (!profileData) {
        console.warn('No profile found for user:', userId);
        return null;
      }

      // Fetch user role from user_roles table
      const { data: roleData, error: roleError } = await supabase
        .from('user_roles')
        .select('role')
        .eq('user_id', userId)
        .maybeSingle();

      if (roleError) {
        console.error('Error fetching user role:', roleError);
        // Fallback to profile role if exists
        console.log('Profile loaded successfully (using fallback role):', profileData);
        return profileData;
      }

      // Combine profile and role data
      const profile = {
        ...profileData,
        role: roleData?.role || profileData.role || 'cliente'
      };

      console.log('Profile loaded successfully:', profile);
      return profile;
    } catch (error) {
      console.error('Unexpected error fetching profile:', error);
      return null;
    }
  };

  useEffect(() => {
    // Set up auth state listener
    const { data: { subscription } } = supabase.auth.onAuthStateChange(
      (event, session) => {
        console.log('Auth state changed:', event, session?.user?.email);

        // Prevent race condition with getSession on mount
        if (event === 'INITIAL_SESSION') return;

        setSession(session);
        setUser(session?.user ?? null);

        if (session?.user) {
          fetchProfile(session.user.id).then(userProfile => {
            setProfile(userProfile);
            setLoading(false);
          }).catch(error => {
            console.error('Error loading profile:', error);
            setProfile(null);
            setLoading(false);
          });
        } else {
          setProfile(null);
          setLoading(false);
        }
      }
    );

    // Check for existing session
    supabase.auth.getSession().then(({ data: { session }, error }) => {
      if (error) {
        console.error('Error getting session:', error);
        setLoading(false);
        return;
      }

      if (session?.user) {
        setSession(session);
        setUser(session.user);
        fetchProfile(session.user.id).then(userProfile => {
          setProfile(userProfile);
          setLoading(false);
        }).catch(error => {
          console.error('Error loading profile:', error);
          setProfile(null);
          setLoading(false);
        });
      } else {
        setLoading(false);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  const signIn = async (email: string, password: string) => {
    setIsAuthenticating(true);
    try {
      const { error } = await supabase.auth.signInWithPassword({
        email,
        password,
      });

      if (error) {
        setIsAuthenticating(false);
        toast({
          title: "Erro ao fazer login",
          description: error.message,
          variant: "destructive",
        });
        return { error };
      }

      toast({
        title: "Login realizado com sucesso!",
        description: "Bem-vindo ao MeMude Connect",
      });

      setIsAuthenticating(false);
      return { success: true };
    } catch (error: any) {
      setIsAuthenticating(false);
      toast({
        title: "Erro ao fazer login",
        description: error.message,
        variant: "destructive",
      });
      return { error };
    }
  };

  const signUp = async (email: string, password: string, firstName: string, lastName: string) => {
    try {
      const redirectUrl = `${window.location.origin}/`;

      const { error } = await supabase.auth.signUp({
        email,
        password,
        options: {
          emailRedirectTo: redirectUrl,
          data: {
            first_name: firstName,
            last_name: lastName,
          }
        }
      });

      if (error) {
        toast({
          title: "Erro ao criar conta",
          description: error.message,
          variant: "destructive",
        });
        return { error };
      }

      toast({
        title: "Conta criada com sucesso!",
        description: "Verifique seu email para confirmar a conta.",
      });

      return {};
    } catch (error: any) {
      toast({
        title: "Erro ao criar conta",
        description: error.message,
        variant: "destructive",
      });
      return { error };
    }
  };

  const signOut = async () => {
    await supabase.auth.signOut();
    setUser(null);
    setSession(null);
    setProfile(null);
    setIsAuthenticating(false);
    toast({
      title: "Logout realizado",
      description: "Você foi desconectado com sucesso.",
    });
  };

  const isAdmin = profile?.role === 'admin';
  const isCorretor = profile?.role === 'corretor';

  const value: AuthContextType = {
    user,
    session,
    profile,
    loading: loading || isAuthenticating,
    signIn,
    signUp,
    signOut,
    isAdmin,
    isCorretor,
  };

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  );
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';

const db = supabase; // CRM tables now in generated types

export interface CrmPipeline {
    id: string;
    nome: string;
    descricao: string | null;
    is_default: boolean;
    auto_add_visits: boolean;
    created_at: string;
}

export interface CrmStage {
    id: string;
    pipeline_id: string;
    nome: string;
    cor: string;
    posicao: number;
    is_final: boolean;
}

export interface CrmLead {
    id: string;
    lead_id: string;
    pipeline_id: string;
    stage_id: string | null;
    posicao: number;
    valor_estimado: number | null;
    notas: string | null;
    google_drive_url: string | null;
    moved_at: string;
    created_at: string;
    leads: {
        id: string;
        nome: string;
        telefone: string;
        email: string | null;
        status: string;
        origem: string;
        observacoes: string | null;
        empreendimento_id: string | null;
        corretor_designado_id: string | null;
        empreendimentos: { nome: string } | null;
        corretores: {
            profiles: { first_name: string; last_name: string };
        } | null;
    };
}

export interface CrmAutomation {
    id: string;
    pipeline_id: string;
    nome: string;
    trigger_type: string;
    trigger_value: string | null;
    action_type: string;
    target_stage_id: string | null;
    is_active: boolean;
    crm_stages?: { nome: string } | null;
}

export function useCrmPipeline(pipelineId?: string) {
    const queryClient = useQueryClient();
    const { toast } = useToast();

    const pipelines = useQuery({
        queryKey: ['crm-pipelines'],
        queryFn: async () => {
            const { data, error } = await db
                .from('crm_pipelines')
                .select('*')
                .order('is_default', { ascending: false })
                .order('created_at', { ascending: true });
            if (error) throw error;
            return data as CrmPipeline[];
        },
    });

    const stages = useQuery({
        queryKey: ['crm-stages', pipelineId],
        queryFn: async () => {
            if (!pipelineId) return [];
            const { data, error } = await db
                .from('crm_stages')
                .select('*')
                .eq('pipeline_id', pipelineId)
                .order('posicao', { ascending: true });
            if (error) throw error;
            return data as CrmStage[];
        },
        enabled: !!pipelineId,
    });

    const crmLeads = useQuery({
        queryKey: ['crm-leads', pipelineId],
        queryFn: async () => {
            if (!pipelineId) return [];
            const { data, error } = await db
                .from('crm_leads')
                .select(`
          *,
          leads (
            id, nome, telefone, email, status, origem, observacoes,
            empreendimento_id, corretor_designado_id,
            empreendimentos(nome),
            corretores(profiles(first_name, last_name))
          )
        `)
                .eq('pipeline_id', pipelineId)
                .order('posicao', { ascending: true });
            if (error) throw error;
            return data as CrmLead[];
        },
        enabled: !!pipelineId,
    });

    const automations = useQuery({
        queryKey: ['crm-automations', pipelineId],
        queryFn: async () => {
            if (!pipelineId) return [];
            const { data, error } = await db
                .from('crm_automations')
                .select('*, crm_stages(nome)')
                .eq('pipeline_id', pipelineId)
                .order('created_at', { ascending: true });
            if (error) throw error;
            return data as CrmAutomation[];
        },
        enabled: !!pipelineId,
    });

    const moveLeadToStage = useMutation({
        mutationFn: async ({
            crmLeadId,
            newStageId,
            newPosition,
        }: {
            crmLeadId: string;
            newStageId: string;
            newPosition: number;
        }) => {
            const { error } = await db
                .from('crm_leads')
                .update({
                    stage_id: newStageId,
                    posicao: newPosition,
                    moved_at: new Date().toISOString(),
                })
                .eq('id', crmLeadId);
            if (error) throw error;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['crm-leads', pipelineId] });
        },
        onError: () => {
            toast({ title: 'Erro ao mover lead', variant: 'destructive' });
        },
    });

    const addLeadToPipeline = useMutation({
        mutationFn: async ({
            leadId,
            stageId,
            valorEstimado,
            notas,
        }: {
            leadId: string;
            stageId: string;
            valorEstimado?: number;
            notas?: string;
        }) => {
            if (!pipelineId) throw new Error('Pipeline não selecionado');
            const { error } = await db.from('crm_leads').insert({
                lead_id: leadId,
                pipeline_id: pipelineId,
                stage_id: stageId,
                valor_estimado: valorEstimado || null,
                notas: notas || null,
                posicao: 0,
            });
            if (error) throw error;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['crm-leads', pipelineId] });
            toast({ title: 'Lead adicionado ao funil' });
        },
        onError: (error: any) => {
            const msg = error?.message?.includes('duplicate')
                ? 'Este lead já está no funil'
                : 'Erro ao adicionar lead';
            toast({ title: msg, variant: 'destructive' });
        },
    });

    const removeLeadFromPipeline = useMutation({
        mutationFn: async (crmLeadId: string) => {
            const { error } = await db
                .from('crm_leads')
                .delete()
                .eq('id', crmLeadId);
            if (error) throw error;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['crm-leads', pipelineId] });
            toast({ title: 'Lead removido do funil' });
        },
        onError: () => {
            toast({ title: 'Erro ao remover lead', variant: 'destructive' });
        },
    });

    const createPipeline = useMutation({
        mutationFn: async (data: {
            nome: string;
            descricao?: string;
            auto_add_visits?: boolean;
        }) => {
            const { data: result, error } = await db
                .from('crm_pipelines')
                .insert(data)
                .select()
                .single();
            if (error) throw error;
            return result;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['crm-pipelines'] });
            toast({ title: 'Pipeline criado com sucesso' });
        },
        onError: () => {
            toast({ title: 'Erro ao criar pipeline', variant: 'destructive' });
        },
    });

    const updatePipeline = useMutation({
        mutationFn: async ({
            id,
            ...data
        }: {
            id: string;
            nome?: string;
            descricao?: string;
            auto_add_visits?: boolean;
            is_default?: boolean;
        }) => {
            const { error } = await db
                .from('crm_pipelines')
                .update(data)
                .eq('id', id);
            if (error) throw error;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['crm-pipelines'] });
            toast({ title: 'Pipeline atualizado' });
        },
        onError: () => {
            toast({ title: 'Erro ao atualizar pipeline', variant: 'destructive' });
        },
    });

    const deletePipeline = useMutation({
        mutationFn: async (id: string) => {
            const { error } = await db
                .from('crm_pipelines')
                .delete()
                .eq('id', id);
            if (error) throw error;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['crm-pipelines'] });
            toast({ title: 'Pipeline excluído com sucesso' });
        },
        onError: () => {
            toast({ title: 'Erro ao excluir pipeline', variant: 'destructive' });
        },
    });

    const upsertStages = useMutation({
        mutationFn: async (
            stagesData: Array<{
                id?: string;
                pipeline_id: string;
                nome: string;
                cor: string;
                posicao: number;
                is_final?: boolean;
            }>
        ) => {
            if (!pipelineId) throw new Error('Pipeline não selecionado');

            // Delete stages not in the new list
            const existingIds = stagesData
                .filter((s) => s.id)
                .map((s) => s.id as string);

            if (existingIds.length > 0) {
                const { error: delError } = await db
                    .from('crm_stages')
                    .delete()
                    .eq('pipeline_id', pipelineId)
                    .not('id', 'in', `(${existingIds.join(',')})`);
                if (delError) throw delError;
            } else {
                const { error: delError } = await db
                    .from('crm_stages')
                    .delete()
                    .eq('pipeline_id', pipelineId);
                if (delError) throw delError;
            }

            // Upsert remaining
            for (const stage of stagesData) {
                if (stage.id) {
                    const { error } = await db
                        .from('crm_stages')
                        .update({
                            nome: stage.nome,
                            cor: stage.cor,
                            posicao: stage.posicao,
                            is_final: stage.is_final ?? false,
                        })
                        .eq('id', stage.id);
                    if (error) throw error;
                } else {
                    const { error } = await db
                        .from('crm_stages')
                        .insert({
                            pipeline_id: pipelineId,
                            nome: stage.nome,
                            cor: stage.cor,
                            posicao: stage.posicao,
                            is_final: stage.is_final ?? false,
                        });
                    if (error) throw error;
                }
            }
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['crm-stages', pipelineId] });
            queryClient.invalidateQueries({ queryKey: ['crm-leads', pipelineId] });
            toast({ title: 'Etapas atualizadas' });
        },
        onError: () => {
            toast({ title: 'Erro ao salvar etapas', variant: 'destructive' });
        },
    });

    const createAutomation = useMutation({
        mutationFn: async (data: {
            nome: string;
            trigger_type: string;
            trigger_value?: string;
            target_stage_id: string;
        }) => {
