        onSuccess: () => {
            queryClient.invalidateQueries({
                queryKey: ['crm-automations', pipelineId],
            });
        },
        onError: () => {
            toast({ title: 'Erro ao atualizar automação', variant: 'destructive' });
        },
    });

    const deleteAutomation = useMutation({
        mutationFn: async (id: string) => {
            const { error } = await db
                .from('crm_automations')
                .delete()
                .eq('id', id);
            if (error) throw error;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({
                queryKey: ['crm-automations', pipelineId],
            });
            toast({ title: 'Automação removida' });
        },
        onError: () => {
            toast({ title: 'Erro ao remover automação', variant: 'destructive' });
        },
    });

    return {
        pipelines,
        stages,
        crmLeads,
        automations,
        moveLeadToStage,
        addLeadToPipeline,
        removeLeadFromPipeline,
        createPipeline,
        updatePipeline,
        deletePipeline,
        upsertStages,
        createAutomation,
        toggleAutomation,
        deleteAutomation,
    };
}

