// Hook principal de validações
export const useValidations = () => {
  const validateLead = (data: any) => {
    try {
      return leadValidationSchema.parse(data);
    } catch (error) {
      if (error instanceof z.ZodError) {
        const firstError = error.issues[0];
        toast({
          title: "Erro de Validação",
          description: firstError.message,
          variant: "destructive"
        });
        throw new Error(firstError.message);
      }
      throw error;
    }
  };

  const validateCorretor = (data: any) => {
    try {
      return corretorValidationSchema.parse(data);
    } catch (error) {
      if (error instanceof z.ZodError) {
        const firstError = error.issues[0];
        toast({
          title: "Erro de Validação",
          description: firstError.message,
          variant: "destructive"
        });
        throw new Error(firstError.message);
      }
      throw error;
    }
  };

  const validateDistributionSettings = (data: any) => {
    try {
      return distributionSettingsSchema.parse(data);
    } catch (error) {
      if (error instanceof z.ZodError) {
        const firstError = error.issues[0];
        toast({
          title: "Erro de Validação",
          description: firstError.message,
          variant: "destructive"
        });
        throw new Error(firstError.message);
      }
      throw error;
    }
  };

  const validateWhatsappMessage = (data: any) => {
    try {
      return whatsappMessageSchema.parse(data);
    } catch (error) {
      if (error instanceof z.ZodError) {
        const firstError = error.issues[0];
        toast({
          title: "Erro de Validação",
          description: firstError.message,
          variant: "destructive"
        });
        throw new Error(firstError.message);
      }
      throw error;
    }
  };

  const sanitizePhoneNumber = (phone: string): string => {
    // Remove todos os caracteres não numéricos exceto +
    const cleaned = phone.replace(/[^\d\+]/g, "");

    // Se começa com +55, mantém
    if (cleaned.startsWith("+55")) {
      return cleaned;
    }

    // Se começa com 55 e tem mais de 11 dígitos, adiciona +
    if (cleaned.startsWith("55") && cleaned.length > 11) {
      return "+" + cleaned;
    }

    // Se tem 11 dígitos e começa com DDD brasileiro, adiciona +55
    if (cleaned.length === 11 && /^[1-9][1-9]/.test(cleaned)) {
      return "+55" + cleaned;
    }

    // Se tem 10 dígitos, adiciona 9 e +55 (celulares antigos)
    if (cleaned.length === 10 && /^[1-9][1-9]/.test(cleaned)) {
      return "+55" + cleaned.substring(0, 2) + "9" + cleaned.substring(2);
    }

    return cleaned;
  };

  const validateCPF = (cpf: string): boolean => {
    // Remove formatação
    const cleanCPF = cpf.replace(/[^\d]/g, "");

    if (cleanCPF.length !== 11) return false;

    // Verifica sequências inválidas
    if (/^(\d)\1{10}$/.test(cleanCPF)) return false;

    // Valida dígitos verificadores
    let sum = 0;
    for (let i = 0; i < 9; i++) {
      sum += parseInt(cleanCPF.charAt(i)) * (10 - i);
    }
    let remainder = 11 - (sum % 11);
    if (remainder >= 10) remainder = 0;
    if (remainder !== parseInt(cleanCPF.charAt(9))) return false;

    sum = 0;
    for (let i = 0; i < 10; i++) {
      sum += parseInt(cleanCPF.charAt(i)) * (11 - i);
    }
    remainder = 11 - (sum % 11);
    if (remainder >= 10) remainder = 0;
    if (remainder !== parseInt(cleanCPF.charAt(10))) return false;

    return true;
  };

  return {
    validateLead,
    validateCorretor,
    validateDistributionSettings,
    validateWhatsappMessage,
    sanitizePhoneNumber,
    validateCPF,
    schemas: {
      leadValidationSchema,
      corretorValidationSchema,
      distributionSettingsSchema,
      whatsappMessageSchema
    }
  };
};

export interface RetryOptions {
  maxAttempts?: number;
  baseDelay?: number;
  maxDelay?: number;
  backoffFactor?: number;
  jitter?: boolean;
  retryOn?: (error: any) => boolean;
}

export interface RetryResult<T> {
  success: boolean;
  data?: T;
  error?: any;
  attemptsMade: number;
  totalDelay: number;
}

const defaultRetryOptions: Required<RetryOptions> = {
  maxAttempts: 3,
  baseDelay: 1000, // 1 segundo
  maxDelay: 30000, // 30 segundos
  backoffFactor: 2,
  jitter: true,
  retryOn: (error: any) => {
    // Retry em erros de rede, timeouts, e erros 5xx
    if (error?.name === 'NetworkError') return true;
    if (error?.name === 'TimeoutError') return true;
    if (error?.status >= 500) return true;
    if (error?.code === 'ECONNRESET') return true;
    if (error?.code === 'ETIMEDOUT') return true;
    return false;
  }
};

export class RetryableError extends Error {
  constructor(message: string, public originalError?: any) {
    super(message);
    this.name = 'RetryableError';
  }
}

export class NonRetryableError extends Error {
  constructor(message: string, public originalError?: any) {
    super(message);
    this.name = 'NonRetryableError';
  }
}

export async function withRetry<T>(
  operation: () => Promise<T>,
  options: RetryOptions = {}
): Promise<RetryResult<T>> {
  const opts = { ...defaultRetryOptions, ...options };

  let lastError: any;
  let totalDelay = 0;

  for (let attempt = 1; attempt <= opts.maxAttempts; attempt++) {
    try {
      const data = await operation();
      return {
        success: true,
        data,
        attemptsMade: attempt,
        totalDelay
      };
    } catch (error) {
      lastError = error;

      // Se é um erro não-retryable, para imediatamente
      if (error instanceof NonRetryableError) {
        break;
      }

      // Se não deve tentar novamente, para
      if (!opts.retryOn(error)) {
        break;
      }

      // Se é a última tentativa, para
      if (attempt === opts.maxAttempts) {
        break;
      }

      // Calcula delay com backoff exponencial
      let delay = Math.min(
        opts.baseDelay * Math.pow(opts.backoffFactor, attempt - 1),
        opts.maxDelay
      );

      // Adiciona jitter para evitar thundering herd
      if (opts.jitter) {
        delay = delay * (0.5 + Math.random() * 0.5);
      }

      totalDelay += delay;

      console.log(`Retry attempt ${attempt} failed, waiting ${Math.round(delay)}ms:`, error.message);

      await new Promise(resolve => setTimeout(resolve, delay));
    }
  }

  return {
    success: false,
    error: lastError,
    attemptsMade: opts.maxAttempts,
    totalDelay
  };
}

// Wrapper específico para chamadas Supabase
export async function withSupabaseRetry<T>(
  operation: () => Promise<{ data: T; error: any }>,
  options: RetryOptions = {}
): Promise<RetryResult<T>> {
  return withRetry(async () => {
    const result = await operation();

    if (result.error) {
      // Classifica erros do Supabase
      if (result.error.code === 'PGRST116') {
        throw new NonRetryableError('Resource not found', result.error);
      }

      if (result.error.code?.startsWith('PGRST')) {
        throw new NonRetryableError('Database constraint error', result.error);
      }

      throw new RetryableError(result.error.message || 'Supabase error', result.error);
    }

    return result.data;
  }, {
    retryOn: (error) => {
      if (error instanceof NonRetryableError) return false;
      return defaultRetryOptions.retryOn(error);
    },
    ...options
  });
}

// Wrapper específico para Edge Functions
export async function withEdgeFunctionRetry<T>(
  operation: () => Promise<{ data: T; error: any }>,
  options: RetryOptions = {}
): Promise<RetryResult<T>> {
  return withRetry(async () => {
    const result = await operation();

    if (result.error) {
      // Erros 4xx geralmente não devem ser retriados
      if (result.error.status >= 400 && result.error.status < 500) {
        throw new NonRetryableError('Client error', result.error);
      }

      throw new RetryableError(result.error.message || 'Edge function error', result.error);
    }

    return result.data;
  }, {
    maxAttempts: 3,
    baseDelay: 2000, // Edge functions podem precisar de mais tempo
    ...options
  });
}

// Wrapper para operações de WhatsApp
export async function withWhatsAppRetry<T>(
  operation: () => Promise<T>,
  options: RetryOptions = {}
): Promise<RetryResult<T>> {
  return withRetry(operation, {
    maxAttempts: 5, // WhatsApp pode ser instável
    baseDelay: 3000,
    maxDelay: 60000, // Até 1 minuto para WhatsApp
    retryOn: (error) => {
      // Retry em rate limiting
      if (error?.status === 429) return true;
      // Retry em timeout do WhatsApp
      if (error?.code === 'WHATSAPP_TIMEOUT') return true;
      return defaultRetryOptions.retryOn(error);
    },
    ...options
  });
}

// Helper para criar delays
export const delay = (ms: number): Promise<void> => 
  new Promise(resolve => setTimeout(resolve, ms));

// Circuit breaker simples
export class CircuitBreaker {
  private failures = 0;
  private lastFailureTime = 0;
  private isOpen = false;

  constructor(
    private threshold = 5,
    private timeout = 60000 // 1 minuto
  ) {}

  async execute<T>(operation: () => Promise<T>): Promise<T> {
    if (this.isOpen) {
      if (Date.now() - this.lastFailureTime > this.timeout) {
        this.reset();
      } else {
        throw new Error('Circuit breaker is open');
      }
    }

    try {
      const result = await operation();
      this.onSuccess();
      return result;
    } catch (error) {
      this.onFailure();
      throw error;
    }
  }

  private onSuccess(): void {
    this.failures = 0;
    this.isOpen = false;
  }

  private onFailure(): void {
    this.failures++;
    this.lastFailureTime = Date.now();

    if (this.failures >= this.threshold) {
      this.isOpen = true;
    }
  }

  private reset(): void {
    this.failures = 0;
    this.isOpen = false;
  }

  get status() {
    return {
      isOpen: this.isOpen,
      failures: this.failures,
      lastFailureTime: this.lastFailureTime
    };
  }
}

