    persona_name: string;
    persona_role: string;
    llm_provider: 'openai' | 'gemini';
    ai_model: string;
    created_at: string;
    total_conversations?: number;
    total_leads_qualified?: number;
}

const AIAgents = () => {
    const { toast } = useToast();
    const queryClient = useQueryClient();
    const [selectedAgent, setSelectedAgent] = useState<AIAgent | null>(null);
    const [showEditor, setShowEditor] = useState(false);
    const [showMonitor, setShowMonitor] = useState(false);

    // Fetch agents
    const { data: agents, isLoading } = useQuery({
        queryKey: ['ai-agents'],
        queryFn: async () => {
            const { data, error } = await supabase
                .from('ai_agents')
                .select('*')
                .order('created_at', { ascending: false });

            if (error) throw error;
            return data as AIAgent[];
        }
    });

    // Fetch conversation stats for each agent
    const { data: stats } = useQuery({
        queryKey: ['ai-agents-stats'],
        queryFn: async () => {
            const { data, error } = await supabase
                .from('agent_conversations')
                .select('agent_id, status');

            if (error) return {};

            const statsMap: Record<string, { total: number; completed: number }> = {};
            data?.forEach(conv => {
                if (!statsMap[conv.agent_id]) {
                    statsMap[conv.agent_id] = { total: 0, completed: 0 };
                }
                statsMap[conv.agent_id].total++;
                if (conv.status === 'completed') {
                    statsMap[conv.agent_id].completed++;
                }
            });
            return statsMap;
        }
    });

    // Toggle agent active status
    const toggleMutation = useMutation({
        mutationFn: async ({ id, is_active }: { id: string; is_active: boolean }) => {
            // If activating, first deactivate all other agents
            if (is_active) {
                await supabase
                    .from('ai_agents')
                    .update({ is_active: false })
                    .neq('id', id);
            }

            const { error } = await supabase
                .from('ai_agents')
                .update({ is_active })
                .eq('id', id);

            if (error) throw error;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['ai-agents'] });
            toast({
                title: "Status atualizado",
                description: "O status do agente foi atualizado com sucesso."
            });
        },
        onError: (error: any) => {
            toast({
                title: "Erro",
                description: error.message,
                variant: "destructive"
            });
        }
    });

    // Delete agent
    const deleteMutation = useMutation({
        mutationFn: async (id: string) => {
            const { error } = await supabase
                .from('ai_agents')
                .delete()
                .eq('id', id);

            if (error) throw error;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['ai-agents'] });
            toast({
                title: "Agente excluído",
                description: "O agente foi excluído com sucesso."
            });
        },
        onError: (error: any) => {
            toast({
                title: "Erro",
                description: error.message,
                variant: "destructive"
            });
        }
    });

    const handleCreateNew = () => {
        setSelectedAgent(null);
        setShowEditor(true);
    };

    const handleEdit = (agent: AIAgent) => {
        setSelectedAgent(agent);
        setShowEditor(true);
    };

    const handleViewConversations = (agent: AIAgent) => {
        setSelectedAgent(agent);
        setShowMonitor(true);
    };

    return (
        <DashboardLayout>
            <div className="space-y-6">
                {/* Header */}
                <div className="flex justify-between items-center">
                    <div>
                        <h1 className="text-3xl font-bold flex items-center gap-2">
                            <Bot className="h-8 w-8 text-primary" />
                            Agentes de IA
                        </h1>
                        <p className="text-muted-foreground mt-1">
                            Configure agentes inteligentes para qualificação de leads via WhatsApp
                        </p>
                    </div>

                    <Button onClick={handleCreateNew}>
                        <Plus className="h-4 w-4 mr-2" />
                        Novo Agente
                    </Button>
                </div>

                {/* Stats Cards */}
                <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                    <Card>
                        <CardHeader className="pb-2">
                            <CardTitle className="text-sm font-medium text-muted-foreground">
                                Agentes Ativos
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            <div className="text-2xl font-bold">
                                {agents?.filter(a => a.is_active).length || 0}
                            </div>
                        </CardContent>
                    </Card>

                    <Card>
                        <CardHeader className="pb-2">
                            <CardTitle className="text-sm font-medium text-muted-foreground">
                                Total de Agentes
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            <div className="text-2xl font-bold">
                                {agents?.length || 0}
                            </div>
                        </CardContent>
                    </Card>

                    <Card>
                        <CardHeader className="pb-2">
                            <CardTitle className="text-sm font-medium text-muted-foreground">
                                Conversas Hoje
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            <div className="text-2xl font-bold">
                                {Object.values(stats || {}).reduce((sum, s) => sum + s.total, 0)}
                            </div>
                        </CardContent>
                    </Card>

                    <Card>
                        <CardHeader className="pb-2">
                            <CardTitle className="text-sm font-medium text-muted-foreground">
                                Taxa de Conversão
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            <div className="text-2xl font-bold">
                                {stats ? (
                                    Math.round(
                                        (Object.values(stats).reduce((sum, s) => sum + s.completed, 0) /
                                            Math.max(Object.values(stats).reduce((sum, s) => sum + s.total, 0), 1)) * 100
                                    )
                                ) : 0}%
                            </div>
                        </CardContent>
                    </Card>
                </div>

                {/* Agents List */}
                <Tabs defaultValue="agents" className="space-y-4">
                    <TabsList>
                        <TabsTrigger value="agents">
                            <Bot className="h-4 w-4 mr-2" />
                            Agentes
                        </TabsTrigger>
                        <TabsTrigger value="conversations">
                            <MessageSquare className="h-4 w-4 mr-2" />
                            Conversas
                        </TabsTrigger>
                        <TabsTrigger value="qualifications">
                            <Users className="h-4 w-4 mr-2" />
                            Qualificações
                        </TabsTrigger>
                        <TabsTrigger value="analytics">
                            <BarChart3 className="h-4 w-4 mr-2" />
                            Analytics
                        </TabsTrigger>
                    </TabsList>

                    <TabsContent value="agents">
                        {isLoading ? (
                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                                {[1, 2, 3].map(i => (
                                    <Skeleton key={i} className="h-48" />
                                ))}
                            </div>
                        ) : agents?.length === 0 ? (
                            <Card className="p-12 text-center">
                                <Bot className="h-16 w-16 mx-auto text-muted-foreground mb-4" />
                                <h3 className="text-xl font-semibold mb-2">Nenhum agente criado</h3>
                                <p className="text-muted-foreground mb-4">
                                    Crie seu primeiro agente de IA para começar a qualificar leads automaticamente.
                                </p>
                                <Button onClick={handleCreateNew}>
                                    <Plus className="h-4 w-4 mr-2" />
                                    Criar Primeiro Agente
                                </Button>
                            </Card>
                        ) : (
                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                                {agents?.map(agent => (
                                    <Card key={agent.id} className={agent.is_active ? 'border-primary' : ''}>
                                        <CardHeader>
                                            <div className="flex justify-between items-start">
                                                <div>
                                                    <CardTitle className="flex items-center gap-2">
                                                        {agent.name}
                                                        {agent.is_active && (
                                                            <Badge variant="default" className="ml-2">Ativo</Badge>
                                                        )}
                                                    </CardTitle>
                                                    <CardDescription>
                                                        {agent.persona_name} - {agent.persona_role}
                                                    </CardDescription>
                                                </div>
                                                <Switch
                                                    checked={agent.is_active}
                                                    onCheckedChange={(checked) =>
                                                        toggleMutation.mutate({ id: agent.id, is_active: checked })
                                                    }
                                                />
                                            </div>
                                        </CardHeader>
                                        <CardContent>
                                            <p className="text-sm text-muted-foreground mb-4 line-clamp-2">
                                                {agent.description || 'Sem descrição'}
                                            </p>

                                            <div className="flex items-center gap-2 text-sm text-muted-foreground mb-4">
                                                <Badge variant="outline">{agent.ai_model}</Badge>
                                                <span>•</span>
                                                <span>{stats?.[agent.id]?.total || 0} conversas</span>
                                            </div>

                                            <div className="flex gap-2">
                                                <Button
                                                    variant="outline"
                                                    size="sm"
                                                    onClick={() => handleEdit(agent)}
                                                >
                                                    <Settings className="h-4 w-4 mr-1" />
                                                    Configurar
                                                </Button>
                                                <Button
                                                    variant="outline"
                                                    size="sm"
                                                    onClick={() => handleViewConversations(agent)}
                                                >
                                                    <Eye className="h-4 w-4 mr-1" />
                                                    Conversas
                                                </Button>
                                                <Button
                                                    variant="ghost"
                                                    size="sm"
                                                    className="text-destructive"
                                                    onClick={() => {
                                                        if (confirm(`Excluir agente "${agent.name}"?`)) {
                                                            deleteMutation.mutate(agent.id);
                                                        }
                                                    }}
                                                >
                                                    <Trash2 className="h-4 w-4" />
                                                </Button>
                                            </div>
                                        </CardContent>
                                    </Card>
                                ))}
                            </div>
                        )}
                    </TabsContent>

                    <TabsContent value="conversations">
                        <ConversationMonitor agentId={selectedAgent?.id} />
                    </TabsContent>

                    <TabsContent value="qualifications">
                        <LeadQualificationView agentId={selectedAgent?.id} />
                    </TabsContent>

                    <TabsContent value="analytics">
                        <div className="grid gap-4 md:grid-cols-2">
                            <AIMetricsCard />
                            <Card>
                                <CardHeader>
                                    <CardTitle>Performance por Agente</CardTitle>
                                </CardHeader>
                                <CardContent>
                                    {agents?.map(agent => (
                                        <div key={agent.id} className="flex justify-between items-center py-2 border-b last:border-0">
                                            <span className="font-medium">{agent.name}</span>
                                            <div className="flex items-center gap-2">
                                                <Badge variant="outline">
                                                    {stats?.[agent.id]?.total || 0} conversas
                                                </Badge>
                                                <Badge variant="outline">
                                                    {stats?.[agent.id]?.completed || 0} convertidas
                                                </Badge>
                                            </div>
                                        </div>
                                    ))}
                                </CardContent>
                            </Card>
                        </div>
                    </TabsContent>
                </Tabs>

                {/* Agent Editor Dialog */}
                <Dialog open={showEditor} onOpenChange={setShowEditor}>
                    <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
                        <DialogHeader>
                            <DialogTitle>
                                {selectedAgent ? `Editar: ${selectedAgent.name}` : 'Novo Agente de IA'}
                            </DialogTitle>
                            <DialogDescription>
                                Configure o comportamento e personalidade do agente.
                            </DialogDescription>
                        </DialogHeader>
                        <AgentEditor
                            agent={selectedAgent}
                            onClose={() => {
                                setShowEditor(false);
                                queryClient.invalidateQueries({ queryKey: ['ai-agents'] });
                            }}
                        />
                    </DialogContent>
                </Dialog>

                {/* Conversation Monitor Dialog */}
                <Dialog open={showMonitor} onOpenChange={setShowMonitor}>
                    <DialogContent className="max-w-5xl max-h-[90vh] overflow-y-auto">
                        <DialogHeader>
                            <DialogTitle>
                                Conversas: {selectedAgent?.name}
                            </DialogTitle>
                            <DialogDescription>
                                Histórico de conversas do agente.
                            </DialogDescription>
                        </DialogHeader>
                        <ConversationMonitor agentId={selectedAgent?.id} />
                    </DialogContent>
                </Dialog>
            </div>
        </DashboardLayout>
    );
};

export default AIAgents;

import { useState, useMemo, useEffect } from 'react';
import DashboardLayout from '@/components/layout/DashboardLayout';
import { useAuth } from '@/hooks/useAuth';
import { useCrmPipeline } from '@/hooks/useCrmPipeline';
import KanbanBoard from '@/components/crm/KanbanBoard';
import PipelineSettingsModal from '@/components/crm/PipelineSettingsModal';
import CrmAutomationsModal from '@/components/crm/CrmAutomationsModal';
import AddLeadToPipelineModal from '@/components/crm/AddLeadToPipelineModal';
import CrmLeadDetailPanel from '@/components/crm/CrmLeadDetailPanel';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Tabs, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Skeleton } from '@/components/ui/skeleton';
import { Settings, Zap, UserPlus, PlusCircle, Users, TrendingUp, Clock, Target } from 'lucide-react';
import type { CrmLead } from '@/hooks/useCrmPipeline';
import CreatePipelineModal from '@/components/crm/CreatePipelineModal';

export default function CRM() {
    const { profile } = useAuth();
    const [selectedPipelineId, setSelectedPipelineId] = useState<string>('');
    const [showSettings, setShowSettings] = useState(false);
    const [showAutomations, setShowAutomations] = useState(false);
    const [showAddLead, setShowAddLead] = useState(false);
    const [detailLead, setDetailLead] = useState<CrmLead | null>(null);
    const [showDetail, setShowDetail] = useState(false);
    const [showCreatePipeline, setShowCreatePipeline] = useState(false);

    const {
        pipelines,
        stages,
        crmLeads,
        automations,
        moveLeadToStage,
        addLeadToPipeline,
        removeLeadFromPipeline,
        createPipeline,
        updatePipeline,
        deletePipeline,
        upsertStages,
        createAutomation,
        toggleAutomation,
        deleteAutomation,
    } = useCrmPipeline(selectedPipelineId || undefined);

    // Auto-select default pipeline
    useEffect(() => {
        if (!selectedPipelineId && pipelines.data?.length) {
            const defaultPipeline = pipelines.data.find((p) => p.is_default);
            const first = defaultPipeline ?? pipelines.data[0];
            if (first) setSelectedPipelineId(first.id);
        }
    }, [pipelines.data, selectedPipelineId]);

    const activePipelineId = selectedPipelineId || pipelines.data?.[0]?.id || '';

    const currentPipeline = pipelines.data?.find((p) => p.id === activePipelineId);
    const stagesData = stages.data ?? [];
    const leadsData = crmLeads.data ?? [];
    const automationsData = automations.data ?? [];

    // Filter leads that actually belong to one of the current stages
    const validLeadsData = useMemo(() => {
        const stageIds = new Set(stagesData.map(s => s.id));
        return leadsData.filter(l => l.stage_id && stageIds.has(l.stage_id));
    }, [leadsData, stagesData]);

    // Stats
    const totalLeads = validLeadsData.length;
    const leadsThisWeek = validLeadsData.filter((l) => {
        const d = new Date(l.created_at);
        const weekAgo = new Date();
        weekAgo.setDate(weekAgo.getDate() - 7);
        return d >= weekAgo;
    }).length;

    const avgTimeInStage = useMemo(() => {
        if (validLeadsData.length === 0) return '0d';
        const totalHours = validLeadsData.reduce((acc, l) => {
            const diff = Date.now() - new Date(l.moved_at).getTime();
            return acc + diff / (1000 * 60 * 60);
        }, 0);
        const avgHours = totalHours / validLeadsData.length;
        if (avgHours < 24) return `${Math.round(avgHours)}h`;
        return `${Math.round(avgHours / 24)}d`;
    }, [validLeadsData]);

    const totalEstimatedValue = validLeadsData.reduce(
        (acc, l) => acc + (l.valor_estimado || 0),
        0
    );

    const existingLeadIds = validLeadsData.map((l) => l.lead_id);

    const currentDetailStage = detailLead
        ? stagesData.find((s) => s.id === detailLead.stage_id) ?? null
        : null;

    if (!profile) return null;

    const isLoading = pipelines.isLoading || stages.isLoading || crmLeads.isLoading;

    return (
        <DashboardLayout>
            <div className="space-y-6">
                {/* Header First Line: Title */}
                <div className="flex items-center justify-between">
                    <div>
                        <h1 className="text-3xl font-bold">CRM</h1>
                        <p className="text-muted-foreground">
                            Gerencie seus leads no funil de vendas
                        </p>
                    </div>
                </div>

                {/* Pipeline Tabs & Actions */}
                <div className="flex flex-col sm:flex-row items-center justify-between gap-4">
                    <div className="flex-1 w-full overflow-x-auto pb-1">
                        <Tabs value={activePipelineId} onValueChange={setSelectedPipelineId} className="w-full">
                            <TabsList className="h-10">
                                {pipelines.data?.map((p) => (
                                    <TabsTrigger key={p.id} value={p.id} className="min-w-[120px]">
                                        {p.nome}
                                    </TabsTrigger>
                                ))}
                                <Button
                                    variant="ghost"
                                    size="sm"
                                    className="h-8 px-2 ml-1 text-muted-foreground"
                                    onClick={() => setShowCreatePipeline(true)}
                                >
                                    <PlusCircle className="h-4 w-4 mr-1" />
                                    Novo Funil
                                </Button>
                            </TabsList>
                        </Tabs>
                    </div>

                    <div className="flex items-center gap-2 flex-shrink-0">
                        <Button
                            variant="outline"
                            size="sm"
                            onClick={() => setShowAutomations(true)}
                            disabled={!activePipelineId}
                        >
                            <Zap className="h-4 w-4 mr-1.5" />
                            Automações
                        </Button>

                        <Button
                            variant="outline"
                            size="sm"
                            onClick={() => setShowSettings(true)}
                            disabled={!activePipelineId}
                        >
                            <Settings className="h-4 w-4 mr-1.5" />
                            Configurar
                        </Button>

                        <Button
                            size="sm"
                            onClick={() => setShowAddLead(true)}
                            disabled={!activePipelineId}
                        >
                            <UserPlus className="h-4 w-4 mr-1.5" />
                            Adicionar Lead
                        </Button>
                    </div>
                </div>

                {/* Stats */}
                <div className="grid grid-cols-1 md:grid-cols-4 gap-4 animate-fade-in">
                    <Card>
                        <CardHeader className="pb-2">
                            <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-1.5">
                                <Users className="h-4 w-4" />
                                Total no Funil
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            <div className="text-2xl font-bold">{totalLeads}</div>
                        </CardContent>
                    </Card>

                    <Card>
                        <CardHeader className="pb-2">
                            <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-1.5">
                                <PlusCircle className="h-4 w-4" />
                                Novos (7 dias)
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            <div className="text-2xl font-bold">{leadsThisWeek}</div>
                        </CardContent>
                    </Card>

                    <Card>
                        <CardHeader className="pb-2">
                            <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-1.5">
                                <Clock className="h-4 w-4" />
                                Tempo Médio na Etapa
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            <div className="text-2xl font-bold">{avgTimeInStage}</div>
                        </CardContent>
                    </Card>

                    <Card>
                        <CardHeader className="pb-2">
                            <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-1.5">
                                <Target className="h-4 w-4" />
                                Valor Estimado
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            <div className="text-2xl font-bold">
                                {totalEstimatedValue > 0
                                    ? `R$ ${totalEstimatedValue.toLocaleString('pt-BR')}`
                                    : 'R$ 0'}
                            </div>
                        </CardContent>
                    </Card>
                </div>

                {/* Kanban Board */}
                {isLoading ? (
                    <div className="flex gap-4">
                        {[1, 2, 3, 4].map((i) => (
                            <div key={i} className="min-w-[300px]">
                                <Skeleton className="h-10 w-full mb-2 rounded-lg" />
                                <Skeleton className="h-24 w-full mb-2 rounded-lg" />
                                <Skeleton className="h-24 w-full rounded-lg" />
                            </div>
                        ))}
                    </div>
                ) : stagesData.length === 0 ? (
                    <Card className="py-12">
                        <CardContent className="text-center">
                            <Settings className="h-12 w-12 mx-auto mb-4 opacity-20" />
                            <h3 className="text-lg font-medium mb-1">Nenhuma etapa configurada</h3>
                            <p className="text-sm text-muted-foreground mb-4">
                                Configure as etapas do seu funil para começar a organizar os leads
                            </p>
                            <Button onClick={() => setShowSettings(true)}>
                                <Settings className="h-4 w-4 mr-2" />
                                Configurar Pipeline
                            </Button>
                        </CardContent>
                    </Card>
                ) : (
                    <KanbanBoard
                        stages={stagesData}
                        leads={validLeadsData}
                        onMoveLead={(crmLeadId, newStageId, newPosition) => {
                            moveLeadToStage.mutate({ crmLeadId, newStageId, newPosition });
                        }}
                        onCardClick={(crmLead) => {
                            setDetailLead(crmLead);
                            setShowDetail(true);
                        }}
                        onRemoveLead={(crmLeadId) => {
                            removeLeadFromPipeline.mutate(crmLeadId);
                        }}
                        onConfigureClick={() => setShowSettings(true)}
                    />
                )}
            </div>

            {/* Modals */}
            {currentPipeline && (
                <>
                    <PipelineSettingsModal
                        open={showSettings}
                        onOpenChange={setShowSettings}
                        pipelineName={currentPipeline.nome}
                        pipelineDescription={currentPipeline.descricao ?? ''}
                        autoAddVisits={currentPipeline.auto_add_visits}
                        isDefault={currentPipeline.is_default || false}
                        stages={stagesData}
                        pipelineId={activePipelineId}
                        isSaving={upsertStages.isPending || updatePipeline.isPending}
                        onSave={async (data) => {
                            await updatePipeline.mutateAsync({
                                id: activePipelineId,
                                nome: data.nome,
                                descricao: data.descricao || undefined,
                                auto_add_visits: data.auto_add_visits,
                            });
                            await upsertStages.mutateAsync(data.stages);
                            setShowSettings(false);
                        }}
                        onDelete={() => {
                            deletePipeline.mutate(activePipelineId, {
                                onSuccess: () => {
                                    setShowSettings(false);
                                    setSelectedPipelineId('');
                                }
                            });
                        }}
                    />

                    <CreatePipelineModal
                        open={showCreatePipeline}
                        onOpenChange={setShowCreatePipeline}
                        isCreating={createPipeline.isPending}
                        onCreate={(data) => {
                            createPipeline.mutate(data, {
                                onSuccess: (newPipeline) => {
                                    setShowCreatePipeline(false);
                                    setSelectedPipelineId(newPipeline.id);
                                }
                            });
                        }}
                    />

                    <CrmAutomationsModal
                        open={showAutomations}
                        onOpenChange={setShowAutomations}
                        automations={automationsData}
                        stages={stagesData}
                        isCreating={createAutomation.isPending}
                        onCreateAutomation={(data) => createAutomation.mutate(data)}
                        onToggleAutomation={(id, is_active) =>
                            toggleAutomation.mutate({ id, is_active })
                        }
                        onDeleteAutomation={(id) => deleteAutomation.mutate(id)}
                    />

                    <AddLeadToPipelineModal
                        open={showAddLead}
                        onOpenChange={setShowAddLead}
                        pipelineId={activePipelineId}
                        stages={stagesData}
                        existingLeadIds={existingLeadIds}
                        isAdding={addLeadToPipeline.isPending}
                        onAdd={(leadId, stageId, valorEstimado) => {
                            addLeadToPipeline.mutate(
                                { leadId, stageId, valorEstimado },
                                { onSuccess: () => setShowAddLead(false) }
                            );
                        }}
                    />

                    <CrmLeadDetailPanel
                        open={showDetail}
                        onOpenChange={setShowDetail}
                        crmLead={detailLead}
                        currentStage={currentDetailStage}
                        pipelineId={activePipelineId}
                    />
                </>
            )}
        </DashboardLayout>
    );
}

import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Plus, Search, Filter, MessageSquare, Phone, Mail, Calendar, User, ArrowUpRight, ArrowDownLeft, FileText } from "lucide-react";
import DashboardLayout from "@/components/layout/DashboardLayout";
import { useAuth } from "@/hooks/useAuth";
import { TableSkeleton } from "@/components/ui/loading-skeleton";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";
import { useToast } from "@/hooks/use-toast";
import { useDebounce } from "@/hooks/use-debounce";
import { CommunicationModal } from "@/components/modals/CommunicationModal";
import { TemplateManager } from "@/components/templates/TemplateManager";
import {
  Pagination,
  PaginationContent,
  PaginationItem,
  PaginationLink,
  PaginationNext,
  PaginationPrevious,
} from "@/components/ui/pagination";

interface CommunicationLog {
  id: string;
  type: string;
  direction: string;
  status: string;
  phone_number?: string;
  content: string;
  message_id?: string;
  metadata?: any;
  created_at: string;
  leads?: {
    nome: string;
  };
  corretores?: {
    profiles: {
      first_name: string;
      last_name: string;
    };
  };
}

const typeVariants = {
  'whatsapp': 'success',
  'sms': 'secondary',
  'email': 'outline',
  'sistema': 'default'
} as const;

const typeLabels = {
  'whatsapp': 'WhatsApp',
  'sms': 'SMS',
  'email': 'Email',
  'sistema': 'Sistema'
};

const statusVariants = {
  'pending': 'secondary',
  'sent': 'outline',
  'delivered': 'success',
  'read': 'success',
  'failed': 'destructive'
} as const;

const statusLabels = {
  'pending': 'Pendente',
  'sent': 'Enviado',
  'delivered': 'Entregue',
  'read': 'Lido',
  'failed': 'Falhou'
};

export default function Comunicacoes() {
  const { profile } = useAuth();
  const { toast } = useToast();
  const [searchTerm, setSearchTerm] = useState("");
  const [filterType, setFilterType] = useState<string>("all");
  const [filterStatus, setFilterStatus] = useState<string>("all");
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [activeTab, setActiveTab] = useState("templates");
  const debouncedSearchTerm = useDebounce(searchTerm, 500);

  const [currentPage, setCurrentPage] = useState(1);
  const ITEMS_PER_PAGE = 15;

  const { data: communications = [], isLoading } = useQuery({
    queryKey: ['communications', debouncedSearchTerm, filterType, filterStatus],
    queryFn: async () => {
      let query = supabase
        .from('communication_log')
        .select(`
          *,
          leads(nome),
          corretores(
            profiles(first_name, last_name)
          )
        `)
        .order('created_at', { ascending: false });

      if (debouncedSearchTerm) {
        query = query.or(`content.ilike.%${debouncedSearchTerm}%,phone_number.ilike.%${debouncedSearchTerm}%`);
      }

      if (filterType !== 'all') {
        query = query.eq('type', filterType as any);
      }

      if (filterStatus !== 'all') {
        query = query.eq('status', filterStatus);
      }

      const { data, error } = await query;
      if (error) throw error;
      return data as CommunicationLog[];
    }
  });

  const getTypeIcon = (type: string) => {
    switch (type) {
      case 'whatsapp':
        return <MessageSquare className="w-4 h-4" />;
      case 'sms':
        return <MessageSquare className="w-4 h-4" />;
      case 'email':
        return <Mail className="w-4 h-4" />;
      case 'sistema':
        return <Phone className="w-4 h-4" />;
      default:
        return <MessageSquare className="w-4 h-4" />;
    }
  };

  const getDirectionIcon = (direction: string) => {
    return direction === 'enviado' ?
      <ArrowUpRight className="w-3 h-3" /> :
      <ArrowDownLeft className="w-3 h-3" />;
  };

  // Reset page when filters change
  useState(() => {
    setCurrentPage(1);
  });

  if (!profile) return null;

  const totalPages = Math.ceil(communications.length / ITEMS_PER_PAGE);
  const paginatedCommunications = communications.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE);

  return (
    <DashboardLayout>
      <div className="space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold">Comunicações</h1>
            <p className="text-muted-foreground">
              Gerencie comunicações e templates do sistema
            </p>
          </div>
          {activeTab === "comunicacoes" && (
            <Button
              className="flex items-center gap-2"
              onClick={() => setIsModalOpen(true)}
            >
              <Plus className="w-4 h-4" />
              Nova Comunicação
            </Button>
          )}
        </div>

        {/* Tabs */}
        <Tabs value={activeTab} onValueChange={setActiveTab} className="w-full">
          <TabsList className="grid w-full grid-cols-2 max-w-md">
            <TabsTrigger value="comunicacoes" className="flex items-center gap-2">
              <MessageSquare className="w-4 h-4" />
              Log de Comunicações
            </TabsTrigger>
            <TabsTrigger value="templates" className="flex items-center gap-2">
              <FileText className="w-4 h-4" />
              Templates
            </TabsTrigger>
          </TabsList>

          <TabsContent value="comunicacoes" className="space-y-6 mt-6">

            {/* Stats Cards */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
              <Card>
                <CardHeader className="pb-2">
                  <CardTitle className="text-sm font-medium text-muted-foreground">
                    Total de Comunicações
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="text-2xl font-bold">{communications.length}</div>
                </CardContent>
              </Card>

              <Card>
                <CardHeader className="pb-2">
                  <CardTitle className="text-sm font-medium text-muted-foreground">
                    WhatsApp
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="text-2xl font-bold">
                    {communications.filter(c => c.type === 'whatsapp').length}
                  </div>
                </CardContent>
              </Card>

              <Card>
                <CardHeader className="pb-2">
                  <CardTitle className="text-sm font-medium text-muted-foreground">
                    SMS
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="text-2xl font-bold">
                    {communications.filter(c => c.type === 'sms').length}
                  </div>
                </CardContent>
              </Card>

              <Card>
                <CardHeader className="pb-2">
                  <CardTitle className="text-sm font-medium text-muted-foreground">
                    Entregues
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="text-2xl font-bold">
                    {communications.filter(c => c.status === 'delivered' || c.status === 'read').length}
                  </div>
                </CardContent>
              </Card>
            </div>

            {/* Filters */}
            <Card>
              <CardContent className="pt-6">
                <div className="flex flex-col sm:flex-row gap-4">
                  <div className="flex-1 relative">
                    <Search className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
                    <Input
                      placeholder="Buscar comunicações..."
                      value={searchTerm}
                      onChange={(e) => setSearchTerm(e.target.value)}
                      className="pl-10"
                    />
                  </div>
                  <div className="flex gap-2">
                    <select
                      value={filterType}
                      onChange={(e) => setFilterType(e.target.value)}
                      className="px-3 py-2 border rounded-md bg-background"
                    >
                      <option value="all">Todos os Tipos</option>
                      {Object.entries(typeLabels).map(([value, label]) => (
                        <option key={value} value={value}>{label}</option>
                      ))}
                    </select>
                    <select
                      value={filterStatus}
                      onChange={(e) => setFilterStatus(e.target.value)}
                      className="px-3 py-2 border rounded-md bg-background"
                    >
                      <option value="all">Todos os Status</option>
                      {Object.entries(statusLabels).map(([value, label]) => (
                        <option key={value} value={value}>{label}</option>
                      ))}
                    </select>
                    <Button variant="outline" size="icon">
                      <Filter className="w-4 h-4" />
                    </Button>
                  </div>
                </div>
              </CardContent>
            </Card>

            {/* Communications List */}
            {isLoading ? (
              <TableSkeleton />
            ) : (
              <Card>
                <CardHeader>
                  <CardTitle>Comunicações Recentes</CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="space-y-4">
                    {paginatedCommunications.map((comm) => (
                      <div
                        key={comm.id}
                        className="flex items-start justify-between p-4 border rounded-lg hover:bg-muted/50 transition-colors"
                      >
                        <div className="flex-1 space-y-2">
                          <div className="flex items-center gap-3">
                            <div className="flex items-center gap-2">
                              {getTypeIcon(comm.type)}
                              <Badge variant={typeVariants[comm.type as keyof typeof typeVariants] || 'default'}>
                                {typeLabels[comm.type as keyof typeof typeLabels] || comm.type}
                              </Badge>
                            </div>
                            <div className="flex items-center gap-1">
                              {getDirectionIcon(comm.direction)}
                              <span className="text-sm text-muted-foreground">
                                {comm.direction === 'enviado' ? 'Enviado' : 'Recebido'}
                              </span>
                            </div>
                            <Badge variant={statusVariants[comm.status as keyof typeof statusVariants] || 'default'}>
                              {statusLabels[comm.status as keyof typeof statusLabels] || comm.status}
                            </Badge>
                          </div>

                          <div className="flex items-center gap-4 text-sm text-muted-foreground">
                            {comm.phone_number && (
                              <div className="flex items-center gap-1">
                                <Phone className="w-3 h-3" />
                                {comm.phone_number}
                              </div>
                            )}
                            <div className="flex items-center gap-1">
                              <Calendar className="w-3 h-3" />
                              {format(new Date(comm.created_at), 'dd/MM/yyyy HH:mm', { locale: ptBR })}
                            </div>
                            {comm.leads && (
                              <div className="flex items-center gap-1">
                                <User className="w-3 h-3" />
                                Lead: {comm.leads.nome}
                              </div>
                            )}
                            {comm.corretores && (
                              <div className="flex items-center gap-1">
                                <User className="w-3 h-3" />
                                Corretor: {comm.corretores.profiles.first_name} {comm.corretores.profiles.last_name}
                              </div>
                            )}
                          </div>

                          <div className="bg-muted/30 p-3 rounded-md">
                            <p className="text-sm">{comm.content}</p>
                          </div>

                          {comm.message_id && (
                            <div className="text-xs text-muted-foreground">
                              ID da mensagem: {comm.message_id}
                            </div>
                          )}
                        </div>

                        <div className="flex items-center gap-2 ml-4">
                          <Button
                            variant="outline"
                            size="sm"
                            onClick={() => toast({
                              title: "Detalhes da Mensagem",
                              description: `Log ID: ${comm.id}\nStatus: ${comm.status}`
                            })}
                          >
                            Detalhes
                          </Button>
                          {comm.type === 'whatsapp' && comm.status === 'failed' && (
                            <Button
                              variant="outline"
                              size="sm"
                              className="text-blue-600 border-blue-600 hover:bg-blue-50"
                              onClick={() => toast({
                                title: "Reenviar Mensagem",
                                description: "O fluxo de reenvio será processado em background."
                              })}
                            >
                              Reenviar
                            </Button>
                          )}
                        </div>
                      </div>
                    ))}
                    {communications.length === 0 && (
                      <div className="text-center py-8 text-muted-foreground">
                        Nenhuma comunicação encontrada
                      </div>
                    )}
                  </div>

                  {totalPages > 1 && (
                    <div className="mt-6 border-t pt-4">
                      <Pagination>
                        <PaginationContent>
                          <PaginationItem>
                            <PaginationPrevious
                              href="#"
                              onClick={(e) => {
                                e.preventDefault();
                                setCurrentPage(p => Math.max(1, p - 1));
                              }}
                              className={currentPage === 1 ? "pointer-events-none opacity-50" : ""}
                            />
                          </PaginationItem>

                          {Array.from({ length: totalPages }, (_, i) => i + 1)
                            .filter(p => p === 1 || p === totalPages || Math.abs(p - currentPage) <= 1)
                            .map((page, i, arr) => (
                              <div key={page} className="flex items-center">
                                {i > 0 && arr[i - 1] !== page - 1 && (
                                  <span className="px-2 text-muted-foreground">...</span>
                                )}
                                <PaginationItem>
                                  <PaginationLink
                                    href="#"
                                    isActive={currentPage === page}
                                    onClick={(e) => {
                                      e.preventDefault();
                                      setCurrentPage(page);
                                    }}
                                  >
                                    {page}
                                  </PaginationLink>
                                </PaginationItem>
                              </div>
                            ))}

                          <PaginationItem>
                            <PaginationNext
                              href="#"
                              onClick={(e) => {
                                e.preventDefault();
                                setCurrentPage(p => Math.min(totalPages, p + 1));
                              }}
                              className={currentPage === totalPages ? "pointer-events-none opacity-50" : ""}
                            />
                          </PaginationItem>
                        </PaginationContent>
                      </Pagination>
                    </div>
                  )}
                </CardContent>
              </Card>
            )}

            {/* Communication Modal */}
            <CommunicationModal
              isOpen={isModalOpen}
              onClose={() => setIsModalOpen(false)}
            />
          </TabsContent>

          <TabsContent value="templates" className="mt-6">
            <TemplateManager />
          </TabsContent>
        </Tabs>
      </div>
    </DashboardLayout>
  );
}

