                          <p className="text-xs text-muted-foreground">
                            Ativar distribuição automática de leads
                          </p>
                        </div>
                        <Switch
                          checked={getSetting('auto_distribution_enabled') === 'true'}
                          disabled={isSaving === 'auto_distribution_enabled'}
                          onCheckedChange={(checked) => handleSwitchChange('auto_distribution_enabled', checked)}
                        />
                      </div>
                      <div className="flex items-center justify-between">
                        <div>
                          <Label>Via WhatsApp</Label>
                          <p className="text-xs text-muted-foreground">
                            Usar WhatsApp para notificações
                          </p>
                        </div>
                        <Switch
                          checked={getSetting('whatsapp_distribution_enabled') === 'true'}
                          disabled={isSaving === 'whatsapp_distribution_enabled'}
                          onCheckedChange={(checked) => handleSwitchChange('whatsapp_distribution_enabled', checked)}
                        />
                      </div>
                    </div>
                  </div>
                </div>

                <Separator />

                {/* API Oficial do WhatsApp como Fallback */}
                <div className="space-y-4">
                  <h4 className="text-sm font-medium">WhatsApp Business API (Fallback)</h4>
                  <p className="text-sm text-muted-foreground">
                    Configurações da API Oficial para usar como backup quando a Evolution API não estiver disponível
                  </p>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label htmlFor="whatsapp_official_token">Token da API Oficial</Label>
                      <Input
                        id="whatsapp_official_token"
                        type="password"
                        placeholder="Token da Meta Business API"
                        defaultValue={getSetting('whatsapp_official_token')}
                        disabled={isSaving === 'whatsapp_official_token'}
                        onBlur={(e) => handleSaveSetting('whatsapp_official_token', e.target.value)}
                      />
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="whatsapp_phone_number_id">ID do Número</Label>
                      <Input
                        id="whatsapp_phone_number_id"
                        placeholder="ID do número do WhatsApp Business"
                        defaultValue={getSetting('whatsapp_phone_number_id')}
                        disabled={isSaving === 'whatsapp_phone_number_id'}
                        onBlur={(e) => handleSaveSetting('whatsapp_phone_number_id', e.target.value)}
                      />
                    </div>
                  </div>
                </div>

                <Separator />

                {/* Monitor de Distribuição */}
                <DistributionMonitor />
              </CardContent>
            </Card>
          </TabsContent>

          <TabsContent value="automacao-visitas" className="space-y-6">
            <div className="grid gap-6 md:grid-cols-2">
              <VisitDistributionSettings />
              <VisitDistributionMonitor />
            </div>
          </TabsContent>

          <TabsContent value="financeiro" className="space-y-6">
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <DollarSign className="w-5 h-5" />
                  Comissões e Impostos
                </CardTitle>
                <CardDescription>
                  Configure os valores padrão para cálculo de comissões de vendas.
                  Esses valores são pré-preenchidos ao criar uma nova venda, mas podem ser ajustados individualmente.
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-6">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <Label htmlFor="default_commission_percentage">Comissão Padrão (%)</Label>
                    <Input
                      id="default_commission_percentage"
                      type="number"
                      step="0.1"
                      placeholder="6.0"
                      defaultValue={getSetting('default_commission_percentage')}
                      disabled={isSaving === 'default_commission_percentage'}
                      onBlur={(e) => handleSaveSetting('default_commission_percentage', e.target.value)}
                    />
                    <p className="text-xs text-muted-foreground">
                      Percentual de comissão sobre o valor do imóvel
                    </p>
                    {isSaving === 'default_commission_percentage' && <Loader2 className="w-4 h-4 animate-spin" />}
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="tax_rate_percentage">Alíquota de Imposto (%)</Label>
                    <Input
                      id="tax_rate_percentage"
                      type="number"
                      step="0.1"
                      placeholder="20.0"
                      defaultValue={getSetting('tax_rate_percentage')}
                      disabled={isSaving === 'tax_rate_percentage'}
                      onBlur={(e) => handleSaveSetting('tax_rate_percentage', e.target.value)}
                    />
                    <p className="text-xs text-muted-foreground">
                      Imposto descontado da comissão bruta antes da divisão
                    </p>
                    {isSaving === 'tax_rate_percentage' && <Loader2 className="w-4 h-4 animate-spin" />}
                  </div>
                </div>

                <Separator />

                <Alert>
                  <Info className="h-4 w-4" />
                  <AlertDescription>
                    <strong>Como funciona o cálculo:</strong>
                    <br />
                    Valor do Imóvel × Comissão (%) = Comissão Bruta
                    <br />
                    Comissão Bruta - Imposto (%) = Comissão Líquida
                    <br />
                    Comissão Líquida ÷ 2 = Corretor (50%) + MeMude (50%)
                    <br />
                    <span className="text-xs text-muted-foreground mt-1 block">
                      Em vendas diretas, 100% da comissão líquida vai para a MeMude.
                    </span>
                  </AlertDescription>
                </Alert>
              </CardContent>
            </Card>
          </TabsContent>
        </Tabs>
      </div>
    </DashboardLayout>
  );
}

import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Plus, Search, Filter, User, Star, Calendar, Edit, Eye, Phone, Upload, Download, Trash2 } from "lucide-react";
import DashboardLayout from "@/components/layout/DashboardLayout";
import { useAuth } from "@/hooks/useAuth";
import { TableSkeleton } from "@/components/ui/loading-skeleton";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";
import CorretorModal from "@/components/modals/CorretorModal";
import CorretorActions from "@/components/actions/CorretorActions";
import ImportExportModal from "@/components/modals/ImportExportModal";
import { useDebounce } from "@/hooks/use-debounce";
import {
  Pagination,
  PaginationContent,
  PaginationItem,
  PaginationLink,
  PaginationNext,
  PaginationPrevious,
} from "@/components/ui/pagination";

interface Corretor {
  id: string;
  creci: string;
  whatsapp: string;
  email?: string;
  cpf?: string;
  status: string;
  nota_media: number;
  total_visitas: number;
  observacoes?: string;
  created_at: string;
  data_avaliacao?: string;
  deleted_at?: string | null;
  profiles: {
    first_name: string;
    last_name: string;
  };
}

const statusVariants = {
  'em_avaliacao': 'secondary',
  'ativo': 'success',
  'inativo': 'destructive',
  'bloqueado': 'outline'
} as const;

const statusLabels = {
  'em_avaliacao': 'Em Avaliação',
  'ativo': 'Aprovado',
  'inativo': 'Reprovado',
  'bloqueado': 'Suspenso'
};

export default function Corretores() {
  const { profile } = useAuth();
  const [searchTerm, setSearchTerm] = useState("");
  const [filterStatus, setFilterStatus] = useState<string>("all");
  const [viewMode, setViewMode] = useState<'active' | 'trash'>('active');
  const [showCorretorModal, setShowCorretorModal] = useState(false);
  const [selectedCorretor, setSelectedCorretor] = useState<any>(null);
  const [showImportModal, setShowImportModal] = useState(false);
  const [showExportModal, setShowExportModal] = useState(false);
  const debouncedSearchTerm = useDebounce(searchTerm, 500);

  const [currentPage, setCurrentPage] = useState(1);
  const ITEMS_PER_PAGE = 15;

  const { data: corretores = [], isLoading } = useQuery({
    queryKey: ['corretores', debouncedSearchTerm, filterStatus, viewMode],
    queryFn: async () => {
      let query = supabase
        .from('corretores')
        .select(`
          *,
          profiles(first_name, last_name),
          corretor_bairros(bairro_id),
          corretor_construtoras(construtora_id)
        `)
        .order('created_at', { ascending: false });

      // Filtrar por modo de visualização (ativos ou lixeira)
      if (viewMode === 'active') {
        query = query.is('deleted_at', null);
      } else {
        query = query.not('deleted_at', 'is', null);
      }

      if (debouncedSearchTerm) {
        query = query.or(`creci.ilike.%${debouncedSearchTerm}%,whatsapp.ilike.%${debouncedSearchTerm}%,profiles.first_name.ilike.%${debouncedSearchTerm}%,profiles.last_name.ilike.%${debouncedSearchTerm}%`);
      }

      if (filterStatus !== 'all') {
        query = query.eq('status', filterStatus as any);
      }

      const { data, error } = await query;
      if (error) throw error;
      return data as Corretor[];
    }
  });

  const getRatingStars = (rating: number) => {
    const stars = [];
    const fullStars = Math.floor(rating);
    const hasHalfStar = rating % 1 !== 0;

    for (let i = 0; i < 5; i++) {
      if (i < fullStars) {
        stars.push(<Star key={i} className="w-3 h-3 fill-yellow-400 text-yellow-400" />);
      } else if (i === fullStars && hasHalfStar) {
        stars.push(<Star key={i} className="w-3 h-3 fill-yellow-400/50 text-yellow-400" />);
      } else {
        stars.push(<Star key={i} className="w-3 h-3 text-muted-foreground" />);
      }
    }
    return stars;
  };

  // Reset page when filters change
  useState(() => {
    setCurrentPage(1);
  });

  if (!profile) return null;

  const totalPages = Math.ceil(corretores.length / ITEMS_PER_PAGE);
  const paginatedCorretores = corretores.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE);

  return (
    <DashboardLayout>
      <div className="space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold">Gerenciamento de Corretores</h1>
            <p className="text-muted-foreground">
              Gerencie corretores, aprovar cadastros e acompanhar performance
            </p>
          </div>
          <div className="flex gap-2">
            <Button
              variant={viewMode === 'trash' ? 'default' : 'outline'}
              onClick={() => setViewMode(viewMode === 'active' ? 'trash' : 'active')}
            >
              <Trash2 className="w-4 h-4 mr-2" />
              {viewMode === 'active' ? 'Ver Lixeira' : 'Ver Ativos'}
            </Button>
            {viewMode === 'active' && (
              <>
                <Button variant="outline" onClick={() => setShowImportModal(true)}>
                  <Upload className="w-4 h-4 mr-2" />
                  Importar
                </Button>
                <Button variant="outline" onClick={() => setShowExportModal(true)}>
                  <Download className="w-4 h-4 mr-2" />
                  Exportar
                </Button>
                <Button className="flex items-center gap-2" onClick={() => {
                  setSelectedCorretor(null);
                  setShowCorretorModal(true);
                }}>
                  <Plus className="w-4 h-4" />
                  Novo Corretor
                </Button>
              </>
            )}
          </div>
        </div>

        {/* Stats Cards */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium text-muted-foreground">
                Total de Corretores
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{corretores.length}</div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium text-muted-foreground">
                Em Avaliação
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">
                {corretores.filter(c => c.status === 'em_avaliacao').length}
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium text-muted-foreground">
                Aprovados
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">
                {corretores.filter(c => c.status === 'ativo').length}
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium text-muted-foreground">
                Nota Média
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">
                {corretores.length > 0 ?
                  (corretores.reduce((acc, c) => acc + c.nota_media, 0) / corretores.length).toFixed(1) :
                  '0.0'
                }
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Filters */}
        <Card>
          <CardContent className="pt-6">
            <div className="flex flex-col sm:flex-row gap-4">
              <div className="flex-1 relative">
                <Search className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
                <Input
                  placeholder="Buscar corretores..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="pl-10"
                />
              </div>
              <div className="flex gap-2">
                <select
                  value={filterStatus}
                  onChange={(e) => setFilterStatus(e.target.value)}
                  className="px-3 py-2 border rounded-md bg-background"
                >
                  <option value="all">Todos os Status</option>
                  {Object.entries(statusLabels).map(([value, label]) => (
                    <option key={value} value={value}>{label}</option>
                  ))}
                </select>
                <Button variant="outline" size="icon">
                  <Filter className="w-4 h-4" />
                </Button>
              </div>
            </div>
          </CardContent>
        </Card>

        {/* Corretores List */}
        {isLoading ? (
          <TableSkeleton />
        ) : (
          <Card>
            <CardHeader>
              <CardTitle>
                {viewMode === 'active' ? 'Corretores Cadastrados' : 'Corretores na Lixeira'}
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-4">
                {corretores.length === 0 ? (
                  <div className="text-center py-8 text-muted-foreground">
                    {viewMode === 'active'
                      ? 'Nenhum corretor encontrado'
                      : 'A lixeira está vazia'}
                  </div>
                ) : (
                  paginatedCorretores.map((corretor) => (
                    <div
                      key={corretor.id}
                      className="flex items-center justify-between p-4 border rounded-lg hover:bg-muted/50 transition-colors"
                    >
                      <div className="flex-1 space-y-1">
                        <div className="flex items-center gap-3">
                          <h3 className="font-semibold">
                            {corretor.profiles.first_name} {corretor.profiles.last_name}
                          </h3>
                          <Badge variant={statusVariants[corretor.status as keyof typeof statusVariants] || 'default'}>
                            {statusLabels[corretor.status as keyof typeof statusLabels] || corretor.status}
                          </Badge>
                          {corretor.deleted_at && (
                            <Badge variant="destructive">
                              <Trash2 className="w-3 h-3 mr-1" />
                              Excluído
                            </Badge>
                          )}
                        </div>
                        <div className="flex items-center gap-4 text-sm text-muted-foreground">
                          <div className="flex items-center gap-1">
                            <User className="w-3 h-3" />
                            CRECI: {corretor.creci}
                          </div>
                          <div className="flex items-center gap-1">
                            <Phone className="w-3 h-3" />
                            {corretor.whatsapp}
                          </div>
                          {corretor.email && (
                            <div className="flex items-center gap-1">
                              <span className="w-3 h-3">📧</span>
                              {corretor.email}
                            </div>
                          )}
                          <div className="flex items-center gap-1">
                            <Calendar className="w-3 h-3" />
                            {corretor.total_visitas} visitas
                          </div>
                        </div>
                        <div className="flex items-center gap-2">
                          <span className="text-sm text-muted-foreground">Avaliação:</span>
                          <div className="flex items-center gap-1">
                            {getRatingStars(corretor.nota_media)}
                            <span className="text-sm font-medium ml-1">
                              {corretor.nota_media.toFixed(1)}
                            </span>
                            {corretor.nota_media === 0 && (
                              <Badge variant="secondary" className="ml-2">
                                Não avaliado
                              </Badge>
                            )}
                          </div>
                        </div>
                        {corretor.data_avaliacao && (
                          <div className="text-sm text-muted-foreground">
                            Avaliado em: {format(new Date(corretor.data_avaliacao), 'dd/MM/yyyy', { locale: ptBR })}
                          </div>
                        )}
                        {corretor.deleted_at && (
                          <div className="text-sm text-destructive">
                            Excluído em: {format(new Date(corretor.deleted_at), 'dd/MM/yyyy HH:mm', { locale: ptBR })}
                          </div>
                        )}
                      </div>
                      <div className="flex items-center gap-2">
                        {viewMode === 'active' && (
                          <>
                            <Button
                              variant="ghost"
                              size="sm"
                              onClick={() => {
                                setSelectedCorretor(corretor);
                                setShowCorretorModal(true);
                              }}
                            >
                              <Eye className="w-4 h-4 mr-1" />
                              Ver
                            </Button>
                            <Button
                              variant="outline"
                              size="sm"
                              onClick={() => {
                                setSelectedCorretor(corretor);
                                setShowCorretorModal(true);
                              }}
                            >
                              <Edit className="w-4 h-4 mr-1" />
                              Editar
                            </Button>
                          </>
                        )}
                        <CorretorActions corretor={corretor} />
                      </div>
                    </div>
                  ))
                )}
              </div>

              {totalPages > 1 && (
                <div className="mt-6 border-t pt-4">
                  <Pagination>
                    <PaginationContent>
                      <PaginationItem>
                        <PaginationPrevious
                          href="#"
                          onClick={(e) => {
                            e.preventDefault();
                            setCurrentPage(p => Math.max(1, p - 1));
                          }}
                          className={currentPage === 1 ? "pointer-events-none opacity-50" : ""}
                        />
                      </PaginationItem>

                      {Array.from({ length: totalPages }, (_, i) => i + 1)
                        .filter(p => p === 1 || p === totalPages || Math.abs(p - currentPage) <= 1)
                        .map((page, i, arr) => (
                          <div key={page} className="flex items-center">
                            {i > 0 && arr[i - 1] !== page - 1 && (
                              <span className="px-2 text-muted-foreground">...</span>
                            )}
                            <PaginationItem>
                              <PaginationLink
                                href="#"
                                isActive={currentPage === page}
                                onClick={(e) => {
                                  e.preventDefault();
                                  setCurrentPage(page);
                                }}
                              >
                                {page}
                              </PaginationLink>
                            </PaginationItem>
                          </div>
                        ))}

                      <PaginationItem>
                        <PaginationNext
                          href="#"
                          onClick={(e) => {
                            e.preventDefault();
                            setCurrentPage(p => Math.min(totalPages, p + 1));
                          }}
                          className={currentPage === totalPages ? "pointer-events-none opacity-50" : ""}
                        />
                      </PaginationItem>
                    </PaginationContent>
                  </Pagination>
                </div>
              )}
            </CardContent>
          </Card>
        )}
      </div>

      <CorretorModal
        open={showCorretorModal}
        onOpenChange={setShowCorretorModal}
        initialData={selectedCorretor}
        title={selectedCorretor ? "Editar Corretor" : "Novo Corretor"}
      />

      <ImportExportModal
        open={showImportModal}
        onOpenChange={setShowImportModal}
        type="import"
      />

      <ImportExportModal
        open={showExportModal}
        onOpenChange={setShowExportModal}
        type="export"
      />
    </DashboardLayout>
  );
}

import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Plus, Search, Filter, MapPin, Building, DollarSign, Edit, Eye } from "lucide-react";
import DashboardLayout from "@/components/layout/DashboardLayout";
import { useAuth } from "@/hooks/useAuth";
import { TableSkeleton } from "@/components/ui/loading-skeleton";
import EmpreendimentoModal from "@/components/modals/EmpreendimentoModal";
import { formatCurrency } from "@/utils/formatters";
import { useToast } from "@/hooks/use-toast";
import { useDebounce } from "@/hooks/use-debounce";

interface Empreendimento {
  id: string;
  nome: string;
  endereco?: string;
  descricao?: string;
  valor_min?: number;
  valor_max?: number;
  ativo: boolean;
  created_at: string;
  construtoras?: {
    nome: string;
  };
  bairros?: {
    nome: string;
    cidade: string;
  };
}

export default function Empreendimentos() {
  const { profile } = useAuth();
  const queryClient = useQueryClient();
  const [searchTerm, setSearchTerm] = useState("");
  const [filterAtivo, setFilterAtivo] = useState<string>("all");
  const [showEmpreendimentoModal, setShowEmpreendimentoModal] = useState(false);
  const [selectedEmpreendimento, setSelectedEmpreendimento] = useState<any>(null);
  const debouncedSearchTerm = useDebounce(searchTerm, 500);

  const { data: empreendimentos = [], isLoading } = useQuery({
    queryKey: ['empreendimentos', debouncedSearchTerm, filterAtivo],
    queryFn: async () => {
      let query = supabase
        .from('empreendimentos')
        .select(`
          *,
          construtoras(nome),
          bairros(nome, cidade)
        `)
        .order('created_at', { ascending: false });

      if (debouncedSearchTerm) {
        query = query.or(`nome.ilike.%${debouncedSearchTerm}%,endereco.ilike.%${debouncedSearchTerm}%,descricao.ilike.%${debouncedSearchTerm}%`);
      }

      if (filterAtivo !== 'all') {
        query = query.eq('ativo', filterAtivo === 'true');
      }

      const { data, error } = await query;
      if (error) throw error;
      return data as Empreendimento[];
    }
  });



  if (!profile) return null;

  return (
    <DashboardLayout>
      <div className="space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold">Gerenciamento de Empreendimentos</h1>
            <p className="text-muted-foreground">
              Gerencie empreendimentos, preços e detalhes
            </p>
          </div>
          <Button className="flex items-center gap-2" onClick={() => {
            setSelectedEmpreendimento(null);
            setShowEmpreendimentoModal(true);
          }}>
            <Plus className="w-4 h-4" />
            Novo Empreendimento
          </Button>
        </div>

        {/* Stats Cards */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium text-muted-foreground">
                Total de Empreendimentos
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{empreendimentos.length}</div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium text-muted-foreground">
                Ativos
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">
                {empreendimentos.filter(e => e.ativo).length}
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium text-muted-foreground">
                Inativos
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">
                {empreendimentos.filter(e => !e.ativo).length}
