              <div className="text-2xl font-bold">
                {empreendimentos.length > 0 && empreendimentos.some(e => e.valor_min && e.valor_max) ?
                  formatCurrency(
                    empreendimentos
                      .filter(e => e.valor_min && e.valor_max)
                      .reduce((acc, e) => acc + ((e.valor_min! + e.valor_max!) / 2), 0) /
                    empreendimentos.filter(e => e.valor_min && e.valor_max).length
                  ) : 'N/A'
                }
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Filters */}
        <Card>
          <CardContent className="pt-6">
            <div className="flex flex-col sm:flex-row gap-4">
              <div className="flex-1 relative">
                <Search className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
                <Input
                  placeholder="Buscar empreendimentos..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="pl-10"
                />
              </div>
              <div className="flex gap-2">
                <select
                  value={filterAtivo}
                  onChange={(e) => setFilterAtivo(e.target.value)}
                  className="px-3 py-2 border rounded-md bg-background"
                >
                  <option value="all">Todos</option>
                  <option value="true">Ativos</option>
                  <option value="false">Inativos</option>
                </select>
                <Button variant="outline" size="icon">
                  <Filter className="w-4 h-4" />
                </Button>
              </div>
            </div>
          </CardContent>
        </Card>

        {/* Empreendimentos List */}
        {isLoading ? (
          <TableSkeleton />
        ) : (
          <Card>
            <CardHeader>
              <CardTitle>Empreendimentos Cadastrados</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-4">
                {empreendimentos.map((empreendimento) => (
                  <div
                    key={empreendimento.id}
                    className="flex items-center justify-between p-4 border rounded-lg hover:bg-muted/50 transition-colors"
                  >
                    <div className="flex-1 space-y-1">
                      <div className="flex items-center gap-3">
                        <h3 className="font-semibold">{empreendimento.nome}</h3>
                        <Badge variant={empreendimento.ativo ? 'success' : 'secondary'}>
                          {empreendimento.ativo ? 'Ativo' : 'Inativo'}
                        </Badge>
                      </div>
                      <div className="flex items-center gap-4 text-sm text-muted-foreground">
                        {empreendimento.construtoras && (
                          <div className="flex items-center gap-1">
                            <Building className="w-3 h-3" />
                            {empreendimento.construtoras.nome}
                          </div>
                        )}
                        {empreendimento.bairros && (
                          <div className="flex items-center gap-1">
                            <MapPin className="w-3 h-3" />
                            {empreendimento.bairros.nome}, {empreendimento.bairros.cidade}
                          </div>
                        )}
                        {(empreendimento.valor_min || empreendimento.valor_max) && (
                          <div className="flex items-center gap-1">
                            <DollarSign className="w-3 h-3" />
                            {empreendimento.valor_min && empreendimento.valor_max ? (
                              `${formatCurrency(empreendimento.valor_min)} - ${formatCurrency(empreendimento.valor_max)}`
                            ) : empreendimento.valor_min ? (
                              `A partir de ${formatCurrency(empreendimento.valor_min)}`
                            ) : empreendimento.valor_max ? (
                              `Até ${formatCurrency(empreendimento.valor_max)}`
                            ) : null}
                          </div>
                        )}
                      </div>
                      {empreendimento.endereco && (
                        <div className="text-sm text-muted-foreground">
                          Endereço: {empreendimento.endereco}
                        </div>
                      )}
                      {empreendimento.descricao && (
                        <div className="text-sm text-muted-foreground line-clamp-2">
                          {empreendimento.descricao}
                        </div>
                      )}
                    </div>
                    <div className="flex items-center gap-2">
                      <Button variant="outline" size="sm" onClick={() => {
                        setSelectedEmpreendimento(empreendimento);
                        setShowEmpreendimentoModal(true);
                      }}>
                        <Eye className="w-3 h-3 mr-1" />
                        Visualizar
                      </Button>
                      <Button variant="outline" size="sm" onClick={() => {
                        setSelectedEmpreendimento(empreendimento);
                        setShowEmpreendimentoModal(true);
                      }}>
                        <Edit className="w-3 h-3 mr-1" />
                        Editar
                      </Button>
                      <Button
                        variant="outline"
                        size="sm"
                        className={empreendimento.ativo ? "text-red-600 border-red-600 hover:bg-red-50" : "text-green-600 border-green-600 hover:bg-green-50"}
                        onClick={async () => {
                          const { error } = await supabase
                            .from('empreendimentos')
                            .update({ ativo: !empreendimento.ativo })
                            .eq('id', empreendimento.id);
                          if (!error) {
                            queryClient.invalidateQueries({ queryKey: ['empreendimentos'] });
                          }
                        }}
                      >
                        {empreendimento.ativo ? 'Desativar' : 'Ativar'}
                      </Button>
                    </div>
                  </div>
                ))}
                {empreendimentos.length === 0 && (
                  <div className="text-center py-8 text-muted-foreground">
                    Nenhum empreendimento encontrado
                  </div>
                )}
              </div>
            </CardContent>
          </Card>
        )}
      </div>

      <EmpreendimentoModal
        open={showEmpreendimentoModal}
        onOpenChange={setShowEmpreendimentoModal}
        initialData={selectedEmpreendimento}
        title={selectedEmpreendimento ? "Editar Empreendimento" : "Novo Empreendimento"}
      />
    </DashboardLayout>
  );
}

import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Plus, Search, Filter, Phone, Mail, Calendar, MapPin, Eye, Edit, Trash2, RotateCcw } from "lucide-react";
import DashboardLayout from "@/components/layout/DashboardLayout";
import { useAuth } from "@/hooks/useAuth";
import { TableSkeleton } from "@/components/ui/loading-skeleton";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";
import LeadModal from "@/components/modals/LeadModal";
import LeadStatusActions from "@/components/actions/LeadStatusActions";
import LeadActions from "@/components/actions/LeadActions";
import { useDebounce } from "@/hooks/use-debounce";
import {
  Pagination,
  PaginationContent,
  PaginationItem,
  PaginationLink,
  PaginationNext,
  PaginationPrevious,
} from "@/components/ui/pagination";

interface Lead {
  id: string;
  nome: string;
  telefone: string;
  email?: string;
  status: string;
  origem: string;
  data_visita_solicitada: string;
  horario_visita_solicitada: string;
  created_at: string;
  deleted_at?: string | null;
  empreendimento_id?: string;
  corretor_designado_id?: string;
  observacoes?: string;
  empreendimentos?: {
    nome: string;
  };
  corretores?: {
    profiles: {
      first_name: string;
      last_name: string;
    };
  };
}

const statusVariants = {
  'novo': 'default',
  'buscando_corretor': 'secondary',
  'visita_agendada': 'outline',
  'visita_realizada': 'success',
  'cancelado': 'destructive',
  'follow_up': 'outline'
} as const;

const statusLabels = {
  'novo': 'Novo',
  'buscando_corretor': 'Em Contato',
  'visita_agendada': 'Agendado',
  'visita_realizada': 'Visitou',
  'cancelado': 'Perdido',
  'follow_up': 'Follow-up'
};

export default function Leads() {
  const { profile } = useAuth();
  const [searchTerm, setSearchTerm] = useState("");
  const [filterStatus, setFilterStatus] = useState<string>("all");
  const [viewMode, setViewMode] = useState<'active' | 'trash'>('active');
  const [showLeadModal, setShowLeadModal] = useState(false);
  const [selectedLead, setSelectedLead] = useState<any>(null);
  const debouncedSearchTerm = useDebounce(searchTerm, 500);

  const [currentPage, setCurrentPage] = useState(1);
  const ITEMS_PER_PAGE = 15;

  const { data: leads = [], isLoading } = useQuery({
    queryKey: ['leads', debouncedSearchTerm, filterStatus, viewMode],
    queryFn: async () => {
      try {
        // TENTATIVA 1: Query com filtro de Lixeira (Padrão)
        let query = supabase
          .from('leads')
          .select(`
            *,
            empreendimentos(nome),
            corretores(
              profiles(first_name, last_name)
            )
          `)
          .order('created_at', { ascending: false });

        if (debouncedSearchTerm) {
          query = query.or(`nome.ilike.%${debouncedSearchTerm}%,telefone.ilike.%${debouncedSearchTerm}%,email.ilike.%${debouncedSearchTerm}%`);
        }

        if (filterStatus !== 'all') {
          query = query.eq('status', filterStatus as any);
        }

        // Tentar aplicar filtro de soft delete
        let queryWithFilter = query;
        if (viewMode === 'active') {
          queryWithFilter = query.is('deleted_at', null);
        } else {
          queryWithFilter = query.not('deleted_at', 'is', null);
        }

        const { data, error } = await queryWithFilter;

        if (error) {
          // Se o erro for de coluna inexistente (PGRST204 ou similar), tentar sem o filtro
          console.warn("Erro ao filtrar por deleted_at, tentando query sem filtro de lixeira:", error.message);
          throw error; // Lançar para o catch
        }

        return data as Lead[];

      } catch (err: any) {
        // TENTATIVA 2: Fallback (Modo de Compatibilidade - Banco Desatualizado)
        // Se falhar (ex: coluna deleted_at não existe), carrega tudo sem filtrar lixeira
        if (err.message?.includes('deleted_at') || err.code === 'PGRST204' || err.code === '42703') {
          console.log("Ativando modo de compatibilidade (sem lixeira)...");

          let fallbackQuery = supabase
            .from('leads')
            .select(`
              *,
              empreendimentos(nome),
              corretores(
                profiles(first_name, last_name)
              )
            `)
            .order('created_at', { ascending: false });

          if (searchTerm) {
            fallbackQuery = fallbackQuery.or(`nome.ilike.%${searchTerm}%,telefone.ilike.%${searchTerm}%,email.ilike.%${searchTerm}%`);
          }

          if (filterStatus !== 'all') {
            fallbackQuery = fallbackQuery.eq('status', filterStatus as any);
          }

          const { data: fallbackData, error: fallbackError } = await fallbackQuery;

          if (fallbackError) throw fallbackError;
          return fallbackData as Lead[];
        }

        throw err;
      }
    }
  });

  // Reset page when filters change
  useState(() => {
    setCurrentPage(1);
  });

  if (!profile) return null;

  const totalPages = Math.ceil(leads.length / ITEMS_PER_PAGE);
  const paginatedLeads = leads.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE);

  return (
    <DashboardLayout>
      <div className="space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold">Gerenciamento de Leads</h1>
            <p className="text-muted-foreground">
              Gerencie e acompanhe todos os leads do sistema
            </p>
          </div>
          <div className="flex gap-2">
            <Button
              variant={viewMode === 'trash' ? 'default' : 'outline'}
              onClick={() => setViewMode(viewMode === 'active' ? 'trash' : 'active')}
            >
              {viewMode === 'active' ? (
                <>
                  <Trash2 className="w-4 h-4 mr-2" />
                  Ver Lixeira
                </>
              ) : (
                <>
                  <RotateCcw className="w-4 h-4 mr-2" />
                  Ver Ativos
                </>
              )}
            </Button>
            {viewMode === 'active' && (
              <Button className="flex items-center gap-2" onClick={() => {
                setSelectedLead(null);
                setShowLeadModal(true);
              }}>
                <Plus className="w-4 h-4" />
                Novo Lead
              </Button>
            )}
          </div>
        </div>

        {/* Stats Cards - Só mostrar no modo ativo */}
        {viewMode === 'active' && (
          <div className="grid grid-cols-1 md:grid-cols-4 gap-6 animate-fade-in">
            <Card>
              <CardHeader className="pb-2">
                <CardTitle className="text-sm font-medium text-muted-foreground">
                  Total de Leads
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold">{leads.length}</div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="pb-2">
                <CardTitle className="text-sm font-medium text-muted-foreground">
                  Novos Hoje
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold">
                  {leads.filter(lead =>
                    new Date(lead.created_at).toDateString() === new Date().toDateString()
                  ).length}
                </div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="pb-2">
                <CardTitle className="text-sm font-medium text-muted-foreground">
                  Em Contato
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold">
                  {leads.filter(lead => lead.status === 'buscando_corretor').length}
                </div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="pb-2">
                <CardTitle className="text-sm font-medium text-muted-foreground">
                  Convertidos
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold">
                  {leads.filter(lead => lead.status === 'visita_realizada').length}
                </div>
              </CardContent>
            </Card>
          </div>
        )}

        {/* Filters */}
        <Card>
          <CardContent className="pt-6">
            <div className="flex flex-col sm:flex-row gap-4">
              <div className="flex-1 relative">
                <Search className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
                <Input
                  placeholder={viewMode === 'active' ? "Buscar leads ativos..." : "Buscar leads na lixeira..."}
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="pl-10"
                />
              </div>
              <div className="flex gap-2">
                <select
                  value={filterStatus}
                  onChange={(e) => setFilterStatus(e.target.value)}
                  className="px-3 py-2 border rounded-md bg-background"
                >
                  <option value="all">Todos os Status</option>
                  {Object.entries(statusLabels).map(([value, label]) => (
                    <option key={value} value={value}>{label}</option>
                  ))}
                </select>
                <Button variant="outline" size="icon">
                  <Filter className="w-4 h-4" />
                </Button>
              </div>
            </div>
          </CardContent>
        </Card>

        {/* Leads List */}
        {isLoading ? (
          <TableSkeleton />
        ) : (
          <Card className={viewMode === 'trash' ? "border-red-200 bg-red-50/10" : ""}>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                {viewMode === 'active' ? (
                  "Leads Recentes"
                ) : (
                  <>
                    <Trash2 className="w-5 h-5 text-destructive" />
                    Lixeira de Leads
                  </>
                )}
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-4">
                {paginatedLeads.map((lead) => (
                  <div
                    key={lead.id}
                    className="flex items-center justify-between p-4 border rounded-lg hover:bg-muted/50 transition-colors bg-white/50"
                  >
                    <div className="flex-1 space-y-1">
                      <div className="flex items-center gap-3">
                        <h3 className="font-semibold">{lead.nome}</h3>
                        <Badge variant={statusVariants[lead.status as keyof typeof statusVariants] || 'default'}>
                          {statusLabels[lead.status as keyof typeof statusLabels] || lead.status}
                        </Badge>
                        {lead.deleted_at && (
                          <Badge variant="destructive" className="flex items-center gap-1">
                            <Trash2 className="w-3 h-3" />
                            Excluído
                          </Badge>
                        )}
                      </div>
                      <div className="flex items-center gap-4 text-sm text-muted-foreground">
                        <div className="flex items-center gap-1">
                          <Phone className="w-3 h-3" />
                          {lead.telefone}
                        </div>
                        {lead.email && (
                          <div className="flex items-center gap-1">
                            <Mail className="w-3 h-3" />
                            {lead.email}
                          </div>
                        )}
                        <div className="flex items-center gap-1">
                          <Calendar className="w-3 h-3" />
                          {format(new Date(lead.data_visita_solicitada), 'dd/MM/yyyy', { locale: ptBR })} às {lead.horario_visita_solicitada}
                        </div>
                        {lead.empreendimentos && (
                          <div className="flex items-center gap-1">
                            <MapPin className="w-3 h-3" />
                            {lead.empreendimentos.nome}
                          </div>
                        )}
                      </div>
                      {lead.corretores && (
                        <div className="text-sm text-muted-foreground">
                          Corretor: {lead.corretores.profiles.first_name} {lead.corretores.profiles.last_name}
                        </div>
                      )}
                      {lead.deleted_at && (
                        <div className="text-xs text-destructive mt-1">
                          Excluído em: {format(new Date(lead.deleted_at), "dd/MM/yyyy 'às' HH:mm", { locale: ptBR })}
                        </div>
                      )}
                    </div>

                    <div className="flex items-center gap-2">
                      {/* Ações específicas da Lixeira ou Ativos */}
                      {viewMode === 'active' && (
                        <>
                          <LeadStatusActions lead={lead} />
                          <Button variant="ghost" size="sm" onClick={() => {
                            setSelectedLead(lead);
                            setShowLeadModal(true);
                          }}>
                            <Eye className="w-4 h-4 text-gray-500" />
                            <span className="sr-only">Visualizar</span>
                          </Button>
                          <Button variant="ghost" size="sm" onClick={() => {
                            setSelectedLead(lead);
                            setShowLeadModal(true);
                          }}>
                            <Edit className="w-4 h-4 text-blue-500" />
                            <span className="sr-only">Editar</span>
                          </Button>
                        </>
                      )}

                      {/* Botão de Excluir/Restaurar (LeadActions lida com ambos os estados) */}
                      <LeadActions lead={lead} />
                    </div>
                  </div>
                ))}
                {leads.length === 0 && (
                  <div className="text-center py-12 text-muted-foreground">
                    <div className="flex justify-center mb-4">
                      {viewMode === 'active' ? (
                        <Search className="h-12 w-12 opacity-20" />
                      ) : (
                        <Trash2 className="h-12 w-12 opacity-20" />
                      )}
                    </div>
                    <p className="text-lg font-medium">
                      {viewMode === 'active' ? 'Nenhum lead encontrado' : 'A lixeira está vazia'}
                    </p>
                    {searchTerm && (
                      <p className="text-sm">Tente ajustar seus termos de busca</p>
                    )}
                  </div>
                )}
              </div>

              {totalPages > 1 && (
                <div className="mt-6 border-t pt-4">
                  <Pagination>
                    <PaginationContent>
                      <PaginationItem>
                        <PaginationPrevious
                          href="#"
                          onClick={(e) => {
                            e.preventDefault();
                            setCurrentPage(p => Math.max(1, p - 1));
                          }}
                          className={currentPage === 1 ? "pointer-events-none opacity-50" : ""}
                        />
                      </PaginationItem>

                      {Array.from({ length: totalPages }, (_, i) => i + 1)
                        .filter(p => p === 1 || p === totalPages || Math.abs(p - currentPage) <= 1)
                        .map((page, i, arr) => (
                          <div key={page} className="flex items-center">
                            {i > 0 && arr[i - 1] !== page - 1 && (
                              <span className="px-2 text-muted-foreground">...</span>
                            )}
                            <PaginationItem>
                              <PaginationLink
                                href="#"
                                isActive={currentPage === page}
                                onClick={(e) => {
                                  e.preventDefault();
                                  setCurrentPage(page);
                                }}
                              >
                                {page}
                              </PaginationLink>
                            </PaginationItem>
                          </div>
                        ))}

                      <PaginationItem>
                        <PaginationNext
                          href="#"
                          onClick={(e) => {
                            e.preventDefault();
                            setCurrentPage(p => Math.min(totalPages, p + 1));
                          }}
                          className={currentPage === totalPages ? "pointer-events-none opacity-50" : ""}
                        />
                      </PaginationItem>
                    </PaginationContent>
                  </Pagination>
                </div>
              )}
            </CardContent>
          </Card>
        )}
      </div>

      <LeadModal
        open={showLeadModal}
        onOpenChange={setShowLeadModal}
        initialData={selectedLead}
        title={selectedLead ? "Editar Lead" : "Novo Lead"}
      />
    </DashboardLayout>
  );
}

import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import DashboardLayout from "@/components/layout/DashboardLayout";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { AlertTriangle, CheckCircle, Clock, XCircle } from "lucide-react";
import { formatDistanceToNow } from "date-fns";
import { ptBR } from "date-fns/locale";

// Type definitions para melhor type safety
interface RateLimit {
  key: string;
  count: number;
  expires_at: string;
  created_at: string;
}

interface RateLimitWithStatus extends RateLimit {
  time_remaining: number;
  status: 'ok' | 'warning' | 'blocked';
}

interface ApplicationLog {
  timestamp: string;
  level: 'info' | 'warn' | 'error' | 'critical';
  function_name: string;
  event: string;
  message: string | null;
  metadata: Record<string, any> | null;
  user_id: string | null;
  corretor_id: string | null;
  lead_id: string | null;
}

export default function Monitoring() {
  // Rate limits ativos - Query com type safety
  const { data: rateLimits } = useQuery<RateLimitWithStatus[]>({
    queryKey: ['active-rate-limits'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('rate_limits')
        .select('key, count, expires_at, created_at')
        .gt('expires_at', new Date().toISOString())
        .order('count', { ascending: false })
        .limit(20);

      if (error) throw error;

      // Calcular status e tempo restante
      const rawData = data as unknown as RateLimit[];
      return (rawData || []).map((limit): RateLimitWithStatus => ({
        ...limit,
        time_remaining: new Date(limit.expires_at).getTime() - Date.now(),
        status: limit.count >= 10 ? 'blocked' : limit.count >= 7 ? 'warning' : 'ok'
      }));
    },
    refetchInterval: 5000
  });

  // Logs de erro recentes - Query com type safety
  const { data: recentErrors } = useQuery<ApplicationLog[]>({
    queryKey: ['recent-errors'],
    queryFn: async () => {
      const yesterday = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();

      const { data, error } = await supabase
        .from('application_logs')
        .select('timestamp, level, function_name, event, message, metadata, user_id, corretor_id, lead_id')
        .in('level', ['error', 'critical'])
        .gte('timestamp', yesterday)
        .order('timestamp', { ascending: false })
        .limit(10);

      if (error) throw error;
      return (data || []) as unknown as ApplicationLog[];
    },
    refetchInterval: 10000
  });

  // Estatísticas de comunicação (últimas 24h)
  const { data: commStats } = useQuery({
    queryKey: ['communication-stats-24h'],
    queryFn: async () => {
      const yesterday = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();

      const { data, error } = await supabase
        .from('communication_log')
        .select('status')
        .gte('created_at', yesterday);

      if (error) throw error;

      const total = data.length;
      const success = data.filter(d => d.status === 'sent' || d.status === 'delivered').length;
      const pending = data.filter(d => d.status === 'pending').length;
      const failed = data.filter(d => d.status === 'failed' || d.status === 'error').length;

      return {
        total,
        success,
        pending,
        failed,
        successRate: total > 0 ? ((success / total) * 100).toFixed(1) : '0.0'
      };
    },
    refetchInterval: 30000 // Atualiza a cada 30s
  });

  // Estatísticas de distribuição (últimas 24h)
  const { data: distStats } = useQuery({
    queryKey: ['distribution-stats-24h'],
    queryFn: async () => {
      const yesterday = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();

      const { data, error } = await supabase
        .from('distribution_attempts')
        .select('response_type')
        .gte('created_at', yesterday);

      if (error) throw error;

      const total = data.length;
      const accepted = data.filter(d => d.response_type === 'accept').length;
      const rejected = data.filter(d => d.response_type === 'reject').length;
      const timeout = data.filter(d => d.response_type === 'timeout').length;

      return {
        total,
        accepted,
        rejected,
        timeout,
        acceptanceRate: total > 0 ? ((accepted / total) * 100).toFixed(1) : '0.0'
      };
    },
    refetchInterval: 30000
  });

  const getStatusBadge = (status: string) => {
    const config: Record<string, { variant: any; icon: any }> = {
      ok: { variant: 'default', icon: CheckCircle },
      warning: { variant: 'secondary', icon: AlertTriangle },
      blocked: { variant: 'destructive', icon: XCircle }
    };

    const { variant, icon: Icon } = config[status] || config.ok;

    return (
      <Badge variant={variant} className="gap-1">
        <Icon className="h-3 w-3" />
        {status.toUpperCase()}
      </Badge>
    );
  };

  const getLevelBadge = (level: string) => {
    const variants: Record<string, any> = {
      error: 'destructive',
      critical: 'destructive',
      warn: 'secondary',
      info: 'default'
    };

    return (
      <Badge variant={variants[level] || 'default'}>
        {level.toUpperCase()}
      </Badge>
    );
  };

  return (
    <DashboardLayout>
      <div className="space-y-6">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Monitoramento do Sistema</h1>
          <p className="text-muted-foreground">
            Acompanhe métricas, rate limits e logs do sistema em tempo real
          </p>
        </div>

        {/* Métricas Gerais */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <Card>
          <CardHeader className="pb-3">
            <CardDescription>WhatsApp - Últimas 24h</CardDescription>
            <CardTitle className="text-3xl">{commStats?.successRate}%</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-sm text-muted-foreground">
              {commStats?.success}/{commStats?.total} enviadas
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-3">
            <CardDescription>Taxa de Aceitação</CardDescription>
            <CardTitle className="text-3xl">{distStats?.acceptanceRate}%</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-sm text-muted-foreground">
              {distStats?.accepted}/{distStats?.total} tentativas
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-3">
            <CardDescription>Mensagens Pendentes</CardDescription>
            <CardTitle className="text-3xl">{commStats?.pending || 0}</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-sm text-muted-foreground">
              Aguardando envio
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-3">
            <CardDescription>Erros (24h)</CardDescription>
            <CardTitle className="text-3xl text-destructive">
              {(commStats?.failed || 0) + (recentErrors?.length || 0)}
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-sm text-muted-foreground">
              Requerem atenção
            </div>
          </CardContent>
        </Card>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Rate Limits Ativos */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Clock className="h-5 w-5" />
              Rate Limits Ativos
            </CardTitle>
            <CardDescription>
              Controle de limite de requisições em tempo real
            </CardDescription>
          </CardHeader>
          <CardContent>
            {!rateLimits || rateLimits.length === 0 ? (
              <div className="text-sm text-muted-foreground text-center py-8">
                <CheckCircle className="h-12 w-12 mx-auto mb-2 text-green-500" />
                Nenhum rate limit ativo no momento
              </div>
            ) : (
              <div className="space-y-3">
                {rateLimits.map((limit: any, idx: number) => (
                  <div key={idx} className="flex items-center justify-between p-3 border rounded-lg">
                    <div className="flex-1">
                      <div className="font-medium text-sm">{limit.key}</div>
                      <div className="text-xs text-muted-foreground">
                        Expira {formatDistanceToNow(new Date(limit.expires_at), { 
                          addSuffix: true, 
                          locale: ptBR 
                        })}
                      </div>
                    </div>
                    <div className="flex items-center gap-3">
                      <div className="text-right">
                        <div className="font-bold">{limit.count}</div>
                        <div className="text-xs text-muted-foreground">requisições</div>
                      </div>
                      {getStatusBadge(limit.status)}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>

        {/* Erros Recentes */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <AlertTriangle className="h-5 w-5" />
              Erros Recentes
            </CardTitle>
            <CardDescription>
              Últimos erros e alertas críticos do sistema
            </CardDescription>
          </CardHeader>
          <CardContent>
            {!recentErrors || recentErrors.length === 0 ? (
              <div className="text-sm text-muted-foreground text-center py-8">
                <CheckCircle className="h-12 w-12 mx-auto mb-2 text-green-500" />
                Nenhum erro nas últimas 24 horas
              </div>
            ) : (
              <div className="space-y-3 max-h-[400px] overflow-y-auto">
                {recentErrors.map((error: any, idx: number) => (
                  <div key={idx} className="p-3 border rounded-lg space-y-2">
                    <div className="flex items-start justify-between gap-2">
                      <div className="flex-1 min-w-0">
                        <div className="font-medium text-sm truncate">
                          {error.function_name}:{error.event}
                        </div>
                        <div className="text-xs text-muted-foreground">
                          {formatDistanceToNow(new Date(error.timestamp), { 
                            addSuffix: true, 
                            locale: ptBR 
                          })}
                        </div>
                      </div>
                      {getLevelBadge(error.level)}
                    </div>
                    {error.message && (
                      <div className="text-sm text-muted-foreground line-clamp-2">
                        {error.message}
                      </div>
                    )}
                    {error.metadata && Object.keys(error.metadata).length > 0 && (
                      <div className="text-xs bg-muted p-2 rounded">
                        <code className="text-xs">
                          {JSON.stringify(error.metadata, null, 2)}
                        </code>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>
      </div>
      </div>
    </DashboardLayout>
  );
}

import { useState } from 'react';
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, LineChart, Line, PieChart, Pie, Cell } from 'recharts';
import {
  Download,
  TrendingUp,
  Users,
  Calendar,
  Target,
  ArrowUpRight,
  ArrowDownRight,
  FileText,
  Settings,
  Clock,
  BarChart3
} from "lucide-react";
import DashboardLayout from "@/components/layout/DashboardLayout";
import { useAuth } from "@/hooks/useAuth";
import { DashboardSkeleton } from "@/components/ui/loading-skeleton";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";
import { useToast } from "@/hooks/use-toast";
import { subDays, startOfMonth, endOfMonth } from "@/utils/dateHelpers";
import { AdvancedCharts } from "@/components/charts/AdvancedCharts";
import { ReportTemplateManager } from "@/components/reports/ReportTemplateManager";
import { ReportBuilder } from "@/components/reports/ReportBuilder";
import { ScheduleReportModal } from "@/components/reports/ScheduleReportModal";

const COLORS = ['hsl(var(--primary))', 'hsl(var(--secondary))', 'hsl(var(--accent))', '#8884d8', '#82ca9d'];

export default function Relatorios() {
  const { profile } = useAuth();
  const { toast } = useToast();
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedTemplate, setSelectedTemplate] = useState<any>(null);
  const [scheduleModalOpen, setScheduleModalOpen] = useState(false);

  // Dados de leads por período
  const { data: leadsData = [], isLoading: isLoadingLeads } = useQuery({
    queryKey: ['reports-leads'],
    queryFn: async () => {
      const startDate = subDays(new Date(), 30);
      const { data, error } = await supabase
        .from('leads')
        .select('created_at, status')
        .gte('created_at', startDate.toISOString())
        .order('created_at', { ascending: true });

      if (error) throw error;
      return data;
    }
  });

  // Dados de corretores
  const { data: corretoresData = [], isLoading: isLoadingCorretores } = useQuery({
    queryKey: ['reports-corretores'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('corretores')
        .select('status, nota_media, total_visitas, profiles(first_name, last_name)')
        .order('total_visitas', { ascending: false })
        .limit(10);

      if (error) throw error;
      return data;
    }
  });

  // Dados de visitas
  const { data: visitasData = [], isLoading: isLoadingVisitas } = useQuery({
    queryKey: ['reports-visitas'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('visitas')
        .select('data_visita, status, avaliacao_lead')
        .order('data_visita', { ascending: false });

      if (error) throw error;
      return data;
    }
  });

  // Processamento dos dados para gráficos
  // Process data for advanced charts
  const processLeadsData = () => {
    const last7Days = Array.from({ length: 7 }, (_, i) => {
      const date = subDays(new Date(), i);
      return {
        date: format(date, 'dd/MM', { locale: ptBR }),
        leads: leadsData.filter(lead =>
          format(new Date(lead.created_at), 'yyyy-MM-dd') === format(date, 'yyyy-MM-dd')
        ).length
      };
    }).reverse();
    return last7Days;
  };

  const processStatusData = () => {
    const statusCounts = leadsData.reduce((acc: Record<string, number>, lead) => {
      acc[lead.status] = (acc[lead.status] || 0) + 1;
      return acc;
    }, {});

    return Object.entries(statusCounts).map(([status, count]) => ({
      name: status.replace('_', ' '),
      value: count
    }));
  };

  const processedData = {
    leadsOverTime: processLeadsData(),
    leadsByStatus: processStatusData(),
    conversionFunnel: [
      { name: 'Leads Recebidos', value: leadsData.length, fill: 'hsl(var(--primary))' },
      { name: 'Visitas Agendadas', value: leadsData.filter(l => l.status === 'visita_agendada').length, fill: 'hsl(var(--secondary))' },
      { name: 'Visitas Realizadas', value: leadsData.filter(l => l.status === 'visita_realizada').length, fill: 'hsl(var(--accent))' },
      { name: 'Convertidos', value: leadsData.filter(l => l.status === 'visita_realizada').length, fill: 'hsl(var(--primary))' },
    ],
    corretorPerformance: corretoresData.slice(0, 5).map(c => ({
      name: `${c.profiles.first_name} ${c.profiles.last_name}`,
      visitas: c.total_visitas || 0,
      nota: c.nota_media || 0,
    })),
    visitsByMonth: visitasData.reduce((acc: any[], visita) => {
      const month = format(new Date(visita.data_visita), 'MMM', { locale: ptBR });
      const existing = acc.find(item => item.month === month);

      if (existing) {
        if (visita.status === 'realizada') existing.realizadas++;
        else existing.agendadas++;
      } else {
        acc.push({
          month,
          realizadas: visita.status === 'realizada' ? 1 : 0,
          agendadas: visita.status !== 'realizada' ? 1 : 0,
        });
      }

      return acc;
    }, []),
    leadSources: leadsData.reduce((acc: { name: string; value: number }[], lead) => {
      const key = lead.status?.replace('_', ' ') || 'Outro';
      const existing = acc.find(s => s.name === key);
      if (existing) existing.value++;
      else acc.push({ name: key, value: 1 });
      return acc;
    }, [])
  };

  const processConversionData = () => {
    const thisMonth = leadsData.filter(lead => {
      const leadDate = new Date(lead.created_at);
      return leadDate >= startOfMonth(new Date()) && leadDate <= endOfMonth(new Date());
    });

    const converted = thisMonth.filter(lead => lead.status === 'visita_realizada').length;
    const total = thisMonth.length;
    const rate = total > 0 ? (converted / total) * 100 : 0;

    return { converted, total, rate };
  };

  if (!profile) return null;
  if (isLoadingLeads || isLoadingCorretores || isLoadingVisitas) return <DashboardSkeleton />;

  const chartData = processLeadsData();
  const statusData = processStatusData();
  const conversionMetrics = processConversionData();
  const avgRating = corretoresData.length > 0
    ? (corretoresData.reduce((acc, c) => acc + c.nota_media, 0) / corretoresData.length).toFixed(1)
    : '0.0';

  const handleSelectTemplate = (template: any) => {
    setSelectedTemplate(template);
    setActiveTab('builder');
  };

  const handleSaveTemplate = (template: any) => {
    // Implementation for saving template
    console.log('Saving template:', template);
  };

  const handleGenerateReport = (config: any) => {
    // Implementation for generating report
    console.log('Generating report with config:', config);
  };

  return (
    <DashboardLayout>
      <div className="space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold">Relatórios e Analytics</h1>
            <p className="text-muted-foreground">
              Sistema completo de relatórios e insights
            </p>
          </div>
          <div className="flex gap-2">
            <Button
              variant="outline"
              className="flex items-center gap-2"
              onClick={() => setScheduleModalOpen(true)}
            >
              <Clock className="w-4 h-4" />
              Agendar Relatório
            </Button>
            <Button
              className="flex items-center gap-2"
              onClick={() => toast({
                title: "Exportar Dados",
                description: "A exportação para Excel/CSV será implementada em breve.",
              })}
            >
              <Download className="w-4 h-4" />
              Exportar Dados
            </Button>
          </div>
        </div>

        {/* Tabs Navigation */}
        <Tabs value={activeTab} onValueChange={setActiveTab}>
          <TabsList className="grid w-full grid-cols-4">
            <TabsTrigger value="dashboard" className="flex items-center gap-2">
              <BarChart3 className="w-4 h-4" />
              Dashboard
            </TabsTrigger>
            <TabsTrigger value="templates" className="flex items-center gap-2">
              <FileText className="w-4 h-4" />
              Templates
            </TabsTrigger>
            <TabsTrigger value="builder" className="flex items-center gap-2">
              <Settings className="w-4 h-4" />
              Construtor
            </TabsTrigger>
            <TabsTrigger value="scheduled" className="flex items-center gap-2">
              <Clock className="w-4 h-4" />
              Agendados
            </TabsTrigger>
          </TabsList>

          {/* Dashboard Tab */}
          <TabsContent value="dashboard" className="space-y-6">

            {/* KPIs */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
              <Card>
                <CardHeader className="pb-2">
                  <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-2">
                    <Users className="w-4 h-4" />
                    Leads Este Mês
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="text-2xl font-bold">{conversionMetrics.total}</div>
                  <div className="text-xs text-muted-foreground flex items-center gap-1 mt-1">
                    <TrendingUp className="w-3 h-3" />
                    total no período
                  </div>
                </CardContent>
              </Card>

              <Card>
                <CardHeader className="pb-2">
                  <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-2">
                    <Target className="w-4 h-4" />
                    Taxa de Conversão
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="text-2xl font-bold">{conversionMetrics.rate.toFixed(1)}%</div>
                  <div className="text-xs text-muted-foreground flex items-center gap-1 mt-1">
                    <ArrowUpRight className="w-3 h-3 text-green-500" />
                    média atual
                  </div>
                </CardContent>
              </Card>

              <Card>
                <CardHeader className="pb-2">
                  <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-2">
                    <Calendar className="w-4 h-4" />
                    Visitas Realizadas
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="text-2xl font-bold">
                    {visitasData.filter(v => v.status === 'realizada').length}
                  </div>
                  <div className="text-xs text-muted-foreground flex items-center gap-1 mt-1">
                    <ArrowUpRight className="w-3 h-3 text-green-500" />
                    total acumulado
                  </div>
                </CardContent>
              </Card>

              <Card>
                <CardHeader className="pb-2">
                  <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-2">
                    <TrendingUp className="w-4 h-4" />
                    Nota Média Corretores
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="text-2xl font-bold">{avgRating}</div>
                  <div className="text-xs text-muted-foreground flex items-center gap-1 mt-1">
                    <span className="opacity-70">avaliação geral</span>
                  </div>
                </CardContent>
              </Card>
            </div>

            {/* Charts */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              {/* Leads por Dia */}
              <Card>
                <CardHeader>
                  <CardTitle>Leads por Dia (Últimos 7 dias)</CardTitle>
                </CardHeader>
                <CardContent>
                  <ResponsiveContainer width="100%" height={300}>
                    <BarChart data={chartData}>
                      <CartesianGrid strokeDasharray="3 3" />
                      <XAxis dataKey="date" />
                      <YAxis />
                      <Tooltip />
                      <Bar dataKey="leads" fill="hsl(var(--primary))" />
                    </BarChart>
                  </ResponsiveContainer>
                </CardContent>
              </Card>

              {/* Status dos Leads */}
              <Card>
                <CardHeader>
                  <CardTitle>Distribuição por Status</CardTitle>
                </CardHeader>
                <CardContent>
                  <ResponsiveContainer width="100%" height={300}>
                    <PieChart>
                      <Pie
                        data={statusData}
                        cx="50%"
                        cy="50%"
                        outerRadius={100}
                        fill="#8884d8"
                        dataKey="value"
                        label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}
                      >
                        {statusData.map((_, index) => (
                          <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                        ))}
                      </Pie>
                      <Tooltip />
                    </PieChart>
                  </ResponsiveContainer>
                </CardContent>
              </Card>
            </div>

            {/* Top Corretores */}
            <Card>
              <CardHeader>
                <CardTitle>Top 10 Corretores por Performance</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-4">
                  {corretoresData.map((corretor, index) => (
                    <div
                      key={index}
                      className="flex items-center justify-between p-4 border rounded-lg"
                    >
                      <div className="flex items-center gap-3">
                        <div className="w-8 h-8 rounded-full bg-primary/10 flex items-center justify-center text-sm font-semibold">
                          {index + 1}
                        </div>
                        <div>
                          <h4 className="font-semibold">
                            {corretor.profiles.first_name} {corretor.profiles.last_name}
                          </h4>
                          <div className="flex items-center gap-2 text-sm text-muted-foreground">
                            <Badge variant={corretor.status === 'ativo' ? 'success' : 'secondary'}>
                              {corretor.status}
                            </Badge>
                            <span>•</span>
                            <span>{corretor.total_visitas} visitas</span>
                          </div>
                        </div>
                      </div>
                      <div className="text-right">
                        <div className="font-semibold">{corretor.nota_media.toFixed(1)}/5.0</div>
                        <div className="text-sm text-muted-foreground">Avaliação</div>
                      </div>
                    </div>
                  ))}
                </div>
              </CardContent>
            </Card>
          </TabsContent>

          {/* Templates Tab */}
          <TabsContent value="templates">
            <ReportTemplateManager onSelectTemplate={handleSelectTemplate} />
          </TabsContent>

          {/* Builder Tab */}
          <TabsContent value="builder">
            <ReportBuilder
              template={selectedTemplate}
              onSave={handleSaveTemplate}
              onGenerate={handleGenerateReport}
            />
          </TabsContent>

          {/* Scheduled Reports Tab */}
          <TabsContent value="scheduled">
            <Card>
              <CardHeader>
                <CardTitle>Relatórios Agendados</CardTitle>
                <CardDescription>
                  Gerencie seus relatórios programados
                </CardDescription>
              </CardHeader>
              <CardContent>
                <div className="text-center py-8 text-muted-foreground">
                  <Clock className="w-12 h-12 mx-auto mb-4" />
                  <h3 className="text-lg font-semibold mb-2">Nenhum relatório agendado</h3>
                  <p>Configure relatórios automáticos para receber insights regulares.</p>
                  <Button className="mt-4" onClick={() => setScheduleModalOpen(true)}>
                    <Clock className="w-4 h-4 mr-2" />
                    Agendar Primeiro Relatório
                  </Button>
                </div>
              </CardContent>
            </Card>
          </TabsContent>
        </Tabs>

        {/* Schedule Report Modal */}
        <ScheduleReportModal
          open={scheduleModalOpen}
          onOpenChange={setScheduleModalOpen}
          template={selectedTemplate}
        />
      </div>
    </DashboardLayout>
  );
}

import { useState, useEffect } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { Progress } from "@/components/ui/progress";
import { supabase } from "@/integrations/supabase/client";
import { useToast } from "@/hooks/use-toast";
import { useAuth } from "@/hooks/useAuth";
import DashboardLayout from "@/components/layout/DashboardLayout";
import { 
  RefreshCw, 
  Play, 
  CheckCircle, 
  AlertCircle, 
  Clock, 
  TrendingUp,
  Database,
  Zap
} from "lucide-react";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";
import { WordPressSettings } from "@/components/wordpress/WordPressSettings";
import { SyncStatusIndicator } from "@/components/wordpress/SyncStatusIndicator";

interface SyncLog {
  id: string;
  sync_date: string;
  total_posts_fetched: number;
  new_empreendimentos: number;
  updated_empreendimentos: number;
  errors_count: number;
  sync_duration_ms: number;
  last_wp_post_id: number;
  status: 'success' | 'partial' | 'error';
  error_details?: { errors: string[] };
  created_at: string;
}

interface PerformanceMetric {
  id: string;
  operation_type: string;
  duration_ms: number;
  success: boolean;
  error_message?: string;
  created_at: string;
}

export default function SincronizacaoWordpress() {
  const { isAdmin } = useAuth();
  const [syncLogs, setSyncLogs] = useState<SyncLog[]>([]);
  const [performanceMetrics, setPerformanceMetrics] = useState<PerformanceMetric[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [selectedLogId, setSelectedLogId] = useState<string | null>(null);
  const { toast } = useToast();

  // Redirect non-admin users
  if (!isAdmin) {
    return (
      <DashboardLayout>
        <div className="flex items-center justify-center h-64">
          <p className="text-muted-foreground">Acesso negado. Apenas administradores podem acessar esta página.</p>
        </div>
      </DashboardLayout>
    );
  }

  useEffect(() => {
    loadSyncData();
  }, []);

  const loadSyncData = async () => {
    try {
      setIsLoading(true);

      // Load sync logs
      const { data: logs, error: logsError } = await supabase
        .from('wp_sync_log')
        .select('*')
        .order('created_at', { ascending: false })
        .limit(20);

      if (logsError) throw logsError;
      setSyncLogs((logs || []) as SyncLog[]);

      // Load recent performance metrics
      const { data: metrics, error: metricsError } = await supabase
        .from('wp_sync_performance')
        .select('*')
        .order('created_at', { ascending: false })
        .limit(100);

      if (metricsError) throw metricsError;
      setPerformanceMetrics(metrics || []);

    } catch (error) {
      console.error('Erro ao carregar dados:', error);
      toast({
        title: "Erro",
        description: "Não foi possível carregar os dados de sincronização",
        variant: "destructive"
      });
    } finally {
      setIsLoading(false);
    }
  };

  const executeSyncNow = async () => {
    try {
      setIsSyncing(true);

      toast({
        title: "Sincronização iniciada",
        description: "Buscando dados do WordPress...",
      });

      const { data, error } = await supabase.functions.invoke('sync-wordpress-properties', {
        body: { 
          manual: true,
          test_mode: false 
        }
      });

      if (error) throw error;

      toast({
        title: "Sincronização concluída",
        description: `Processados: ${data?.totalPostsFetched || 0} posts, Novos: ${data?.newEmpreendimentos || 0}, Atualizados: ${data?.updatedEmpreendimentos || 0}`,
      });

      // Reload data after sync with proper delay
      setTimeout(() => {
        loadSyncData();
      }, 1500);

    } catch (error) {
      console.error('Erro na sincronização:', error);
      toast({
        title: "Erro na sincronização",
        description: error.message || "Erro desconhecido ao executar sincronização",
        variant: "destructive"
      });
    } finally {
      setTimeout(() => {
        setIsSyncing(false);
      }, 3000);
    }
  };

  const executeTestSync = async () => {
    try {
      setIsSyncing(true);

      toast({
        title: "Teste de sincronização iniciado",
        description: "Verificando conexão com WordPress...",
      });

      const { data, error } = await supabase.functions.invoke('sync-wordpress-properties', {
        body: { 
          manual: true,
          test_mode: true,
          limit: 5 
        }
      });

      if (error) throw error;

      toast({
        title: "Teste concluído",
        description: `Conexão OK. Encontrados ${data?.totalPostsFetched || 0} posts de teste.`,
      });

    } catch (error) {
      console.error('Erro no teste:', error);
      toast({
        title: "Erro no teste",
        description: error.message || "Falha na conexão com WordPress",
        variant: "destructive"
      });
    } finally {
      setTimeout(() => {
        setIsSyncing(false);
      }, 2000);
    }
  };

  const getStatusBadge = (status: string) => {
    const variants = {
      success: { variant: "default" as const, icon: CheckCircle, text: "Sucesso" },
      partial: { variant: "secondary" as const, icon: AlertCircle, text: "Parcial" },
      error: { variant: "destructive" as const, icon: AlertCircle, text: "Erro" }
    };

    const config = variants[status as keyof typeof variants];
    if (!config) return null;

    const Icon = config.icon;

    return (
      <Badge variant={config.variant} className="flex items-center gap-1">
        <Icon className="w-3 h-3" />
        {config.text}
      </Badge>
    );
  };

  const formatDuration = (ms: number) => {
    if (ms < 1000) return `${ms}ms`;
    if (ms < 60000) return `${(ms / 1000).toFixed(1)}s`;
    return `${(ms / 60000).toFixed(1)}min`;
  };

  const getPerformanceStats = () => {
    if (performanceMetrics.length === 0) return null;

    const avgDuration = performanceMetrics
      .filter(m => m.duration_ms)
      .reduce((acc, m) => acc + m.duration_ms, 0) / performanceMetrics.length;

    const successRate = (performanceMetrics.filter(m => m.success).length / performanceMetrics.length) * 100;

    const operationTypes = performanceMetrics.reduce((acc, m) => {
      acc[m.operation_type] = (acc[m.operation_type] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    return {
      avgDuration,
      successRate,
      operationTypes
    };
  };

  const stats = getPerformanceStats();

  if (isLoading) {
    return (
      <DashboardLayout>
        <div className="flex items-center justify-center h-64">
          <RefreshCw className="w-8 h-8 animate-spin" />
        </div>
      </DashboardLayout>
    );
  }

  return (
    <DashboardLayout>
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Sincronização WordPress</h1>
          <p className="text-muted-foreground">
            Monitore e gerencie a sincronização com memude.com.br
          </p>
        </div>

        <div className="flex items-center gap-2">
          <Button 
            variant="outline" 
            onClick={loadSyncData}
            disabled={isLoading || isSyncing}
          >
            <RefreshCw className={`w-4 h-4 mr-2 ${isLoading ? 'animate-spin' : ''}`} />
            Atualizar
          </Button>

          <Button 
            variant="secondary"
            onClick={executeTestSync}
            disabled={isSyncing}
          >
            {isSyncing ? (
              <>
                <RefreshCw className="w-4 h-4 mr-2 animate-spin" />
                Testando...
              </>
            ) : (
              <>
                <CheckCircle className="w-4 h-4 mr-2" />
                Testar Conexão
              </>
            )}
          </Button>

          <Button 
            onClick={executeSyncNow}
            disabled={isSyncing}
          >
            {isSyncing ? (
              <>
                <RefreshCw className="w-4 h-4 mr-2 animate-spin" />
                Sincronizando...
              </>
            ) : (
              <>
                <Play className="w-4 h-4 mr-2" />
                Sincronização Completa
              </>
            )}
          </Button>
        </div>
      </div>

      {/* Real-time Status Indicator */}
      <SyncStatusIndicator />

      {/* Status Cards */}
      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Status do Sistema</CardTitle>
            <CheckCircle className={`h-4 w-4 ${syncLogs.length > 0 ? 'text-green-500' : 'text-gray-400'}`} />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">
              {syncLogs.length > 0 ? 'Ativo' : 'Aguardando'}
            </div>
            <p className="text-xs text-muted-foreground">
              {syncLogs.length > 0 ? 'Sistema funcionando' : 'Primeira sincronização pendente'}
            </p>
          </CardContent>
        </Card>

        {stats && (
          <>
            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">Tempo Médio</CardTitle>
                <Clock className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold">{formatDuration(stats.avgDuration)}</div>
                <p className="text-xs text-muted-foreground">
                  Por operação
                </p>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">Taxa de Sucesso</CardTitle>
                <TrendingUp className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold">{stats.successRate.toFixed(1)}%</div>
                <p className="text-xs text-muted-foreground">
                  {performanceMetrics.filter(m => m.success).length} de {performanceMetrics.length}
                </p>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">Sincronizações</CardTitle>
                <Database className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold">{syncLogs.length}</div>
                <p className="text-xs text-muted-foreground">
                  Total executadas
                </p>
              </CardContent>
            </Card>
          </>
        )}

        {!stats && (
          <>
            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">Próxima Sincronização</CardTitle>
                <Clock className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold">00:00</div>
                <p className="text-xs text-muted-foreground">
                  Diariamente (automática)
                </p>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">Site WordPress</CardTitle>
                <TrendingUp className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-sm font-bold">memude.com.br</div>
                <p className="text-xs text-muted-foreground">
                  Fonte dos dados
                </p>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">Ação</CardTitle>
                <Database className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-sm font-bold">Execute o primeiro teste</div>
                <p className="text-xs text-muted-foreground">
                  Para verificar a conexão
                </p>
              </CardContent>
            </Card>
          </>
        )}
      </div>

        {/* Tabs */}
        <Tabs defaultValue="logs" className="space-y-4">
          <TabsList>
            <TabsTrigger value="logs">Logs de Sincronização</TabsTrigger>
            <TabsTrigger value="performance">Performance</TabsTrigger>
            <TabsTrigger value="settings">Configurações</TabsTrigger>
          </TabsList>

        {/* Sync Logs Tab */}
        <TabsContent value="logs" className="space-y-4">
          <Card>
            <CardHeader>
              <CardTitle>Histórico de Sincronizações</CardTitle>
              <CardDescription>
                Últimas 20 sincronizações executadas
              </CardDescription>
            </CardHeader>
            <CardContent>
              {syncLogs.length === 0 ? (
                <div className="text-center py-8 text-muted-foreground">
                  Nenhuma sincronização encontrada
                </div>
              ) : (
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Data</TableHead>
                      <TableHead>Status</TableHead>
                      <TableHead>Posts</TableHead>
                      <TableHead>Novos</TableHead>
                      <TableHead>Atualizados</TableHead>
                      <TableHead>Erros</TableHead>
                      <TableHead>Duração</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {syncLogs.map((log) => (
                      <TableRow 
                        key={log.id}
                        className="cursor-pointer hover:bg-muted/50"
                        onClick={() => setSelectedLogId(selectedLogId === log.id ? null : log.id)}
                      >
                        <TableCell>
                          {format(new Date(log.sync_date), 'dd/MM/yyyy HH:mm', { locale: ptBR })}
                        </TableCell>
                        <TableCell>{getStatusBadge(log.status)}</TableCell>
                        <TableCell>{log.total_posts_fetched}</TableCell>
                        <TableCell>
                          <Badge variant="outline" className="text-green-600">
                            +{log.new_empreendimentos}
                          </Badge>
                        </TableCell>
                        <TableCell>
                          <Badge variant="outline" className="text-blue-600">
                            ~{log.updated_empreendimentos}
                          </Badge>
                        </TableCell>
                        <TableCell>
                          {log.errors_count > 0 && (
                            <Badge variant="destructive">
                              {log.errors_count}
                            </Badge>
                          )}
                        </TableCell>
                        <TableCell>{formatDuration(log.sync_duration_ms)}</TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              )}
            </CardContent>
          </Card>

          {/* Error Details */}
          {selectedLogId && (
            <Card>
              <CardHeader>
                <CardTitle>Detalhes da Sincronização</CardTitle>
              </CardHeader>
              <CardContent>
                {(() => {
                  const selectedLog = syncLogs.find(log => log.id === selectedLogId);
                  if (!selectedLog) return null;

                  return (
                    <div className="space-y-4">
                      <div className="grid grid-cols-2 gap-4 text-sm">
                        <div>
                          <span className="font-medium">ID:</span> {selectedLog.id}
                        </div>
                        <div>
                          <span className="font-medium">Último Post ID:</span> {selectedLog.last_wp_post_id}
                        </div>
                      </div>

                      {selectedLog.error_details?.errors && (
                        <Alert>
                          <AlertCircle className="h-4 w-4" />
                          <AlertDescription>
                            <div className="space-y-2">
                              <p className="font-medium">Erros encontrados:</p>
                              <ul className="list-disc pl-4 space-y-1">
                                {selectedLog.error_details.errors.map((error, index) => (
                                  <li key={index} className="text-sm">{error}</li>
                                ))}
                              </ul>
                            </div>
                          </AlertDescription>
                        </Alert>
                      )}
                    </div>
                  );
                })()}
              </CardContent>
            </Card>
          )}
        </TabsContent>

        {/* Performance Tab */}
        <TabsContent value="performance" className="space-y-4">
          <Card>
            <CardHeader>
              <CardTitle>Métricas de Performance</CardTitle>
              <CardDescription>
                Análise detalhada das operações de sincronização
              </CardDescription>
            </CardHeader>
            <CardContent>
              {stats && (
                <div className="space-y-6">
                  {/* Operation Types Chart */}
                  <div>
                    <h4 className="text-sm font-medium mb-3">Tipos de Operação</h4>
                    <div className="space-y-2">
                      {Object.entries(stats.operationTypes).map(([type, count]) => {
                        const percentage = (count / performanceMetrics.length) * 100;
                        return (
                          <div key={type} className="flex items-center gap-2">
                            <div className="w-24 text-sm capitalize">
                              {type.replace('_', ' ')}
                            </div>
                            <Progress value={percentage} className="flex-1" />
                            <div className="w-12 text-sm text-right">{count}</div>
                          </div>
                        );
                      })}
                    </div>
                  </div>

                  {/* Recent Operations */}
                  <div>
                    <h4 className="text-sm font-medium mb-3">Operações Recentes</h4>
                    <Table>
                      <TableHeader>
                        <TableRow>
                          <TableHead>Tipo</TableHead>
                          <TableHead>Duração</TableHead>
                          <TableHead>Status</TableHead>
                          <TableHead>Data</TableHead>
                        </TableRow>
                      </TableHeader>
                      <TableBody>
                        {performanceMetrics.slice(0, 10).map((metric) => (
                          <TableRow key={metric.id}>
                            <TableCell className="capitalize">
                              {metric.operation_type.replace('_', ' ')}
                            </TableCell>
                            <TableCell>{formatDuration(metric.duration_ms)}</TableCell>
                            <TableCell>
                              {metric.success ? (
                                <Badge variant="default">Sucesso</Badge>
                              ) : (
                                <Badge variant="destructive">Erro</Badge>
                              )}
                            </TableCell>
                            <TableCell>
                              {format(new Date(metric.created_at), 'dd/MM HH:mm', { locale: ptBR })}
                            </TableCell>
                          </TableRow>
                        ))}
                      </TableBody>
                    </Table>
                  </div>
                </div>
              )}
            </CardContent>
          </Card>
        </TabsContent>

        {/* Settings Tab */}
        <TabsContent value="settings" className="space-y-4">
          <WordPressSettings />
        </TabsContent>
      </Tabs>
      </div>
    </DashboardLayout>
  );
}

import { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { useAuth } from '@/hooks/useAuth';
import { supabase } from '@/integrations/supabase/client';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Input } from '@/components/ui/input';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Plus, Search, Edit, Trash2, UserCheck, UserX, Shield, Clock, Users, Loader2, Power } from 'lucide-react';
import { useToast } from '@/hooks/use-toast';
import { DashboardSkeleton } from '@/components/ui/loading-skeleton';
import { CreateUserModal } from '@/components/modals/CreateUserModal';
import { EditUserModal } from '@/components/modals/EditUserModal';
import DashboardLayout from '@/components/layout/DashboardLayout';

export interface ManagedUser {
  id: string;
  first_name: string;
  last_name: string;
  role: 'admin' | 'corretor' | 'cliente';
  email: string;
  phone?: string;
  is_active: boolean;
  created_at: string;
  user_id: string;
}

const UserManagement = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [createModalOpen, setCreateModalOpen] = useState(false);
  const [editModalOpen, setEditModalOpen] = useState(false);
  const [selectedUser, setSelectedUser] = useState<ManagedUser | null>(null);
  const { isAdmin } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();

  // Fetch users via Edge Function (includes email from auth.users)
  const { data: users = [], isLoading } = useQuery({
    queryKey: ['managed-users'],
    queryFn: async () => {
      const { data, error } = await supabase.functions.invoke('manage-user', {
        body: { action: 'list' }
      });

      if (error) throw error;
      if (!data.success) throw new Error(data.error);
      return data.users as ManagedUser[];
    },
    enabled: isAdmin
  });

  // Toggle user active status
  const toggleActiveStatusMutation = useMutation({
    mutationFn: async (userId: string) => {
      const { data, error } = await supabase.functions.invoke('manage-user', {
        body: { action: 'toggle_active', user_id: userId }
      });
      if (error) throw error;
      if (!data.success) throw new Error(data.error);
      return data;
    },
    onSuccess: (data) => {
      queryClient.invalidateQueries({ queryKey: ['managed-users'] });
      toast({
        title: data.is_active ? '✅ Usuário ativado' : '⛔ Usuário desativado',
        description: data.is_active
          ? 'O usuário agora pode acessar o sistema.'
          : 'O usuário foi bloqueado e não poderá fazer login.',
      });
    },
    onError: (error: any) => {
      toast({
        title: 'Erro ao alterar status',
        description: error.message,
        variant: 'destructive',
      });
    }
  });

  // Delete user
  const deleteUserMutation = useMutation({
    mutationFn: async (userId: string) => {
      const { data, error } = await supabase.functions.invoke('manage-user', {
        body: { action: 'delete', user_id: userId }
      });
      if (error) throw error;
      if (!data.success) throw new Error(data.error);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['managed-users'] });
      toast({
        title: 'Usuário removido',
        description: 'O usuário e todos os seus dados foram removidos do sistema.',
      });
    },
    onError: (error: any) => {
      toast({
        title: 'Erro ao remover usuário',
        description: error.message,
        variant: 'destructive',
      });
    }
  });

  const filteredUsers = users.filter(user =>
    user.first_name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    user.last_name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    user.email?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    user.role?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const getRoleBadgeVariant = (role: string) => {
    switch (role) {
      case 'admin': return 'destructive' as const;
      case 'corretor': return 'default' as const;
      case 'cliente': return 'secondary' as const;
      default: return 'outline' as const;
    }
  };

  const getRoleLabel = (role: string) => {
    switch (role) {
      case 'admin': return 'Administrador';
      case 'corretor': return 'Corretor';
      case 'cliente': return 'Cliente';
      default: return role;
    }
  };

  if (!isAdmin) {
    return (
      <DashboardLayout>
        <Card>
          <CardHeader>
            <CardTitle>Acesso Negado</CardTitle>
            <CardDescription>
              Você não tem permissão para acessar esta página.
            </CardDescription>
          </CardHeader>
        </Card>
      </DashboardLayout>
    );
  }

  if (isLoading) {
    return (
      <DashboardLayout>
        <DashboardSkeleton />
      </DashboardLayout>
    );
  }

  return (
    <DashboardLayout>
      <div className="space-y-6">
        {/* Header */}
        <div className="flex flex-col space-y-4 md:flex-row md:items-center md:justify-between md:space-y-0">
          <div>
            <h1 className="text-3xl font-bold tracking-tight">Gestão de Usuários</h1>
            <p className="text-muted-foreground">
