import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Search, Filter, Phone, Mail, Calendar, MapPin, MessageSquare, Star } from "lucide-react";
import DashboardLayout from "@/components/layout/DashboardLayout";
import { useAuth } from "@/hooks/useAuth";
import { TableSkeleton } from "@/components/ui/loading-skeleton";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";
import { useToast } from "@/hooks/use-toast";
import { useDebounce } from "@/hooks/use-debounce";

interface Lead {
  id: string;
  nome: string;
  telefone: string;
  email?: string;
  status: string;
  origem: string;
  data_visita_solicitada: string;
  horario_visita_solicitada: string;
  created_at: string;
  observacoes?: string;
  empreendimentos?: {
    nome: string;
  };
}

const statusVariants = {
  'novo': 'default',
  'buscando_corretor': 'secondary',
  'visita_agendada': 'outline',
  'visita_realizada': 'success',
  'cancelado': 'destructive',
  'follow_up': 'outline'
} as const;

const statusLabels = {
  'novo': 'Novo',
  'buscando_corretor': 'Em Contato',
  'visita_agendada': 'Agendado',
  'visita_realizada': 'Visitou',
  'cancelado': 'Perdido',
  'follow_up': 'Follow-up'
};

export default function MeusLeads() {
  const { profile } = useAuth();
  const { toast } = useToast();
  const [searchTerm, setSearchTerm] = useState("");
  const [filterStatus, setFilterStatus] = useState<string>("all");
  const debouncedSearchTerm = useDebounce(searchTerm, 500);

  const { data: corretor } = useQuery({
    queryKey: ['my-corretor-profile'],
    queryFn: async () => {
      if (!profile?.id) return null;

      const { data, error } = await supabase
        .from('corretores')
        .select('id')
        .eq('profile_id', profile.id)
        .single();

      if (error) throw error;
      return data;
    },
    enabled: !!profile?.id
  });

  const { data: leads = [], isLoading } = useQuery({
    queryKey: ['my-leads', debouncedSearchTerm, filterStatus, corretor?.id],
    queryFn: async () => {
      if (!corretor?.id) return [];

      let query = supabase
        .from('leads')
        .select(`
          *,
          empreendimentos(nome)
        `)
        .eq('corretor_designado_id', corretor.id)
        .order('created_at', { ascending: false });

      if (debouncedSearchTerm) {
        query = query.or(`nome.ilike.%${debouncedSearchTerm}%,telefone.ilike.%${debouncedSearchTerm}%,email.ilike.%${debouncedSearchTerm}%`);
      }

      if (filterStatus !== 'all') {
        query = query.eq('status', filterStatus as any);
      }

      const { data, error } = await query;
      if (error) throw error;
      return data as Lead[];
    },
    enabled: !!corretor?.id
  });

  if (!profile || !corretor) return (
    <DashboardLayout>
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary" />
      </div>
    </DashboardLayout>
  );

  return (
    <DashboardLayout>
      <div className="space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold">Meus Leads</h1>
            <p className="text-muted-foreground">
              Gerencie seus leads designados
            </p>
          </div>
        </div>

        {/* Stats Cards */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium text-muted-foreground">
                Total de Leads
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{leads.length}</div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium text-muted-foreground">
                Novos
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">
                {leads.filter(lead => lead.status === 'novo').length}
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium text-muted-foreground">
                Em Contato
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">
                {leads.filter(lead => lead.status === 'buscando_corretor').length}
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium text-muted-foreground">
                Convertidos
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">
                {leads.filter(lead => lead.status === 'visita_realizada').length}
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Filters */}
        <Card>
          <CardContent className="pt-6">
            <div className="flex flex-col sm:flex-row gap-4">
              <div className="flex-1 relative">
                <Search className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
                <Input
                  placeholder="Buscar leads..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="pl-10"
                />
              </div>
              <div className="flex gap-2">
                <select
                  value={filterStatus}
                  onChange={(e) => setFilterStatus(e.target.value)}
                  className="px-3 py-2 border rounded-md bg-background"
                >
                  <option value="all">Todos os Status</option>
                  {Object.entries(statusLabels).map(([value, label]) => (
                    <option key={value} value={value}>{label}</option>
                  ))}
                </select>
                <Button variant="outline" size="icon">
                  <Filter className="w-4 h-4" />
                </Button>
              </div>
            </div>
          </CardContent>
        </Card>

        {/* Leads List */}
        {isLoading ? (
          <TableSkeleton />
        ) : (
          <Card>
            <CardHeader>
              <CardTitle>Meus Leads Ativos</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-4">
                {leads.map((lead) => (
                  <div
                    key={lead.id}
                    className="flex items-center justify-between p-4 border rounded-lg hover:bg-muted/50 transition-colors"
                  >
                    <div className="flex-1 space-y-1">
                      <div className="flex items-center gap-3">
                        <h3 className="font-semibold">{lead.nome}</h3>
                        <Badge variant={statusVariants[lead.status as keyof typeof statusVariants] || 'default'}>
                          {statusLabels[lead.status as keyof typeof statusLabels] || lead.status}
                        </Badge>
                        {lead.status === 'novo' && (
                          <Badge variant="outline" className="bg-red-50 text-red-700 border-red-200">
                            Urgente
                          </Badge>
                        )}
                      </div>
                      <div className="flex items-center gap-4 text-sm text-muted-foreground">
                        <div className="flex items-center gap-1">
                          <Phone className="w-3 h-3" />
                          {lead.telefone}
                        </div>
                        {lead.email && (
                          <div className="flex items-center gap-1">
                            <Mail className="w-3 h-3" />
                            {lead.email}
                          </div>
                        )}
                        <div className="flex items-center gap-1">
                          <Calendar className="w-3 h-3" />
                          Visita: {format(new Date(lead.data_visita_solicitada), 'dd/MM/yyyy', { locale: ptBR })} às {lead.horario_visita_solicitada}
                        </div>
                        {lead.empreendimentos && (
                          <div className="flex items-center gap-1">
                            <MapPin className="w-3 h-3" />
                            {lead.empreendimentos.nome}
                          </div>
                        )}
                      </div>
                      {lead.observacoes && (
                        <div className="text-sm text-muted-foreground">
                          <strong>Observações:</strong> {lead.observacoes}
                        </div>
                      )}
                      <div className="text-xs text-muted-foreground">
                        Lead recebido em {format(new Date(lead.created_at), 'dd/MM/yyyy HH:mm', { locale: ptBR })}
                      </div>
                    </div>
                    <div className="flex items-center gap-2">
                      <Button
                        variant="outline"
                        size="sm"
                        className="flex items-center gap-2 text-green-600 border-green-600 hover:bg-green-50"
                        onClick={() => {
                          const phone = lead.telefone.replace(/\D/g, '');
                          window.open(`tel:+55${phone}`, '_self');
                        }}
                      >
                        <Phone className="w-3 h-3" />
                        Ligar
                      </Button>
                      <Button
                        variant="outline"
                        size="sm"
                        className="flex items-center gap-2 text-blue-600 border-blue-600 hover:bg-blue-50"
                        onClick={() => {
                          const phone = lead.telefone.replace(/\D/g, '');
                          window.open(`https://wa.me/55${phone}`, '_blank');
                        }}
                      >
                        <MessageSquare className="w-3 h-3" />
                        WhatsApp
                      </Button>
                      <Button
                        variant="outline"
                        size="sm"
                        onClick={() => {
                          toast({
                            title: lead.nome,
                            description: `Status: ${lead.status} | Origem: ${lead.origem} | Tel: ${lead.telefone}`,
                          });
                        }}
                      >
                        Detalhes
                      </Button>
                      <Button
                        variant="outline"
                        size="sm"
                        className="flex items-center gap-2"
                        onClick={() => {
                          toast({
                            title: "Avaliar Lead",
                            description: "Funcionalidade de avaliação será implementada em breve.",
                          });
                        }}
                      >
                        <Star className="w-3 h-3" />
                        Avaliar
                      </Button>
                    </div>
                  </div>
                ))}
                {leads.length === 0 && (
                  <div className="text-center py-8 text-muted-foreground">
                    Nenhum lead encontrado. Aguarde a designação de novos leads.
                  </div>
                )}
              </div>
            </CardContent>
          </Card>
        )}
      </div>
    </DashboardLayout>
  );
}

/**
 * Audit Logger Module
 * Provides comprehensive audit logging for compliance and security
 * Part of Phase 5: Enterprise Scale
 */

import { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';

// ============================================================
// TYPES
// ============================================================

export type AuditAction =
    | 'conversation_started'
    | 'conversation_ended'
    | 'message_sent'
    | 'message_received'
    | 'lead_qualified'
    | 'lead_transferred'
    | 'visit_scheduled'
    | 'property_searched'
    | 'agent_config_changed'
    | 'prompt_modified'
    | 'user_login'
    | 'user_logout'
    | 'data_exported'
    | 'data_deleted'
    | 'error_occurred'
    | 'rate_limited'
    | 'api_called';

export type EntityType =
    | 'conversation'
    | 'lead'
    | 'agent'
    | 'message'
    | 'property'
    | 'visit'
    | 'user'
    | 'config'
    | 'system';

export interface AuditLogEntry {
    action: AuditAction;
    entity_type: EntityType;
    entity_id?: string;
    user_id?: string;
    agent_id?: string;
    conversation_id?: string;
    previous_value?: Record<string, any>;
    new_value?: Record<string, any>;
    metadata?: Record<string, any>;
    is_sensitive?: boolean;
}

export interface AuditQuery {
    user_id?: string;
    agent_id?: string;
    conversation_id?: string;
    action?: AuditAction;
    entity_type?: EntityType;
    from_date?: string;
    to_date?: string;
    limit?: number;
}

// ============================================================
// MAIN FUNCTIONS
// ============================================================

/**
 * Write audit log entry
 */
export async function writeAuditLog(
    supabase: SupabaseClient,
    entry: AuditLogEntry
): Promise<string | null> {
    try {
        const { data, error } = await supabase.rpc('write_audit_log', {
            p_action: entry.action,
            p_entity_type: entry.entity_type,
            p_entity_id: entry.entity_id || null,
            p_user_id: entry.user_id || null,
            p_agent_id: entry.agent_id || null,
            p_conversation_id: entry.conversation_id || null,
            p_previous_value: entry.previous_value || null,
            p_new_value: entry.new_value || null,
            p_metadata: entry.metadata || {}
        });

        if (error) {
            console.warn('Audit log write error:', error);
            return null;
        }

        return data as string;
    } catch (e) {
        console.warn('Audit log error:', e);
        return null;
    }
}

/**
 * Write audit log without awaiting (fire and forget)
 */
export function writeAuditLogAsync(
    supabase: SupabaseClient,
    entry: AuditLogEntry
): void {
    writeAuditLog(supabase, entry).catch(e =>
        console.warn('Async audit log error:', e)
    );
}

/**
 * Query audit logs
 */
export async function queryAuditLogs(
    supabase: SupabaseClient,
    query: AuditQuery
): Promise<any[]> {
    let builder = supabase
        .from('audit_logs')
        .select('*')
        .order('created_at', { ascending: false })
        .limit(query.limit || 100);

    if (query.user_id) {
        builder = builder.eq('user_id', query.user_id);
    }
    if (query.agent_id) {
        builder = builder.eq('agent_id', query.agent_id);
    }
    if (query.conversation_id) {
        builder = builder.eq('conversation_id', query.conversation_id);
    }
    if (query.action) {
        builder = builder.eq('action', query.action);
    }
    if (query.entity_type) {
        builder = builder.eq('entity_type', query.entity_type);
    }
    if (query.from_date) {
        builder = builder.gte('created_at', query.from_date);
    }
    if (query.to_date) {
        builder = builder.lte('created_at', query.to_date);
    }

    const { data, error } = await builder;

    if (error) {
        console.warn('Audit log query error:', error);
        return [];
    }

    return data || [];
}

/**
 * Log conversation event
 */
export function logConversationEvent(
    supabase: SupabaseClient,
    conversationId: string,
    agentId: string,
    action: 'conversation_started' | 'conversation_ended' | 'lead_transferred',
    metadata?: Record<string, any>
): void {
    writeAuditLogAsync(supabase, {
        action,
        entity_type: 'conversation',
        entity_id: conversationId,
        agent_id: agentId,
        conversation_id: conversationId,
        metadata
    });
}

/**
 * Log message event
 */
export function logMessageEvent(
    supabase: SupabaseClient,
    messageId: string,
    conversationId: string,
    agentId: string,
    action: 'message_sent' | 'message_received',
    metadata?: Record<string, any>
): void {
    writeAuditLogAsync(supabase, {
        action,
        entity_type: 'message',
        entity_id: messageId,
        agent_id: agentId,
        conversation_id: conversationId,
        metadata
    });
}

/**
 * Log lead qualification event
 */
export function logLeadEvent(
    supabase: SupabaseClient,
    leadId: string,
    conversationId: string,
    agentId: string,
    action: 'lead_qualified' | 'lead_transferred',
    previousValue?: Record<string, any>,
    newValue?: Record<string, any>
): void {
    writeAuditLogAsync(supabase, {
        action,
        entity_type: 'lead',
        entity_id: leadId,
        agent_id: agentId,
        conversation_id: conversationId,
        previous_value: previousValue,
        new_value: newValue
    });
}

/**
 * Log configuration change
 */
export async function logConfigChange(
    supabase: SupabaseClient,
    userId: string,
    entityType: 'agent' | 'config',
    entityId: string,
    previousValue: Record<string, any>,
    newValue: Record<string, any>
): Promise<void> {
    await writeAuditLog(supabase, {
        action: 'agent_config_changed',
        entity_type: entityType,
        entity_id: entityId,
        user_id: userId,
        previous_value: previousValue,
        new_value: newValue,
        is_sensitive: true
    });
}

/**
 * Log error event
 */
export function logError(
    supabase: SupabaseClient,
    error: Error,
    context: {
        agent_id?: string;
        conversation_id?: string;
        action?: string;
        metadata?: Record<string, any>;
    }
): void {
    writeAuditLogAsync(supabase, {
        action: 'error_occurred',
        entity_type: 'system',
        agent_id: context.agent_id,
        conversation_id: context.conversation_id,
        metadata: {
            error_name: error.name,
            error_message: error.message,
            error_stack: error.stack?.substring(0, 500),
            action: context.action,
            ...context.metadata
        }
    });
}

