function detectProvider(modelName: string): 'openai' | 'gemini' {
  if (modelName.startsWith('gemini')) return 'gemini';
  return 'openai';
}

// ARQ-04: Conversation stage progression logic
function determineConversationStage(conversation: ConversationData | null, messageCount: number): string {
  const qualData = conversation?.qualification_data || {};
  const presentedCount = conversation?.presented_properties?.length || 0;
  const leadScore = conversation?.lead_score || 0;

  // Count how many BANT fields are filled
  let bantFieldsFilled = 0;
  if (qualData.property_type) bantFieldsFilled++;
  if (qualData.max_price || qualData.price_max) bantFieldsFilled++;
  if (qualData.min_bedrooms || qualData.bedrooms) bantFieldsFilled++;
  if (qualData.urgency || qualData.timeline) bantFieldsFilled++;
  if (qualData.preferred_neighborhoods || qualData.neighborhood) bantFieldsFilled++;
  if (qualData.financing_needed !== undefined) bantFieldsFilled++;

  // Stage determination based on conversation progress
  if (messageCount <= 2) return 'greeting';
  if (bantFieldsFilled < 2) return 'qualifying';
  if (bantFieldsFilled >= 2 && presentedCount === 0) return 'searching';
  if (presentedCount > 0 && leadScore < 60) return 'presenting';
  if (leadScore >= 60 && leadScore < 80) return 'negotiating';
  if (leadScore >= 80) return 'closing';

  return 'qualifying';
}

async function callOpenAI(
  supabase: any,
  agent: any,
  systemPrompt: string,
  history: any[],
  currentMessage: string,
  conversation: any
): Promise<{ response: string; tokensUsed: number }> {
  // P3: Use cached API key
  const apiKey = await getApiKey(supabase, 'openai_api_key');

  if (!apiKey) {
    throw new Error('OpenAI API key não configurada');
  }

  const openai = new OpenAI({ apiKey: apiKey });

  const messages: any[] = [
    { role: 'system', content: systemPrompt }
  ];

  if (conversation?.total_messages === 0 && agent.greeting_message) {
    messages.push({ role: 'assistant', content: agent.greeting_message });
  }

  if (history) {
    for (const msg of history) {
      messages.push({ role: msg.role, content: msg.content });
    }
  }

  messages.push({ role: 'user', content: currentMessage });

  const completion = await openai.chat.completions.create({
    model: agent.ai_model,
    messages: messages,
    max_tokens: agent.max_tokens,
    temperature: Number(agent.temperature),
  });

  return {
    response: completion.choices[0]?.message?.content || 'Desculpe, não consegui processar sua mensagem.',
    tokensUsed: completion.usage?.total_tokens || 0
  };
}

async function callGemini(
  supabase: any,
  agent: any,
  systemPrompt: string,
  history: any[],
  currentMessage: string,
  conversation: any
): Promise<{ response: string; tokensUsed: number }> {
  // P3: Use cached API key
  const apiKey = await getApiKey(supabase, 'gemini_api_key');

  if (!apiKey) {
    throw new Error('Gemini API key não configurada');
  }

  const genAI = new GoogleGenerativeAI(apiKey);
  const model = genAI.getGenerativeModel({
    model: agent.ai_model,
    systemInstruction: systemPrompt
  });

  const chatHistory: any[] = [];

  if (conversation?.total_messages === 0 && agent.greeting_message) {
    chatHistory.push({
      role: 'model',
      parts: [{ text: agent.greeting_message }]
    });
  }

  if (history) {
    for (const msg of history) {
      chatHistory.push({
        role: msg.role === 'assistant' ? 'model' : 'user',
        parts: [{ text: msg.content }]
      });
    }
  }

  const chat = model.startChat({
    history: chatHistory,
    generationConfig: {
      maxOutputTokens: agent.max_tokens,
      temperature: Number(agent.temperature),
    }
  });

  const result = await chat.sendMessage(currentMessage);
  const response = result.response;

  // AI-03: Use actual token count from Gemini API response metadata when available
  const actualTokens = response.usageMetadata?.totalTokenCount;
  const estimatedTokens = actualTokens || Math.ceil((systemPrompt.length + currentMessage.length + (response.text()?.length || 0)) / 4);

  return {
    response: response.text() || 'Desculpe, não consegui processar sua mensagem.',
    tokensUsed: estimatedTokens
  };
}

function parseAIResponse(response: string): {
  cleanResponse: string;
  action: string | null;
  actionData: any;
  intent: string
} {
  let cleanResponse = response;
  let action: string | null = null;
  let actionData: any = {};
  let intent = 'conversation';

  if (response.includes('[BUSCAR_IMOVEIS]')) {
    action = 'property_search';
    intent = 'property_search';
    cleanResponse = response.replace(/\[BUSCAR_IMOVEIS\]/g, '').trim();
  }

  if (response.includes('[AGENDAR_VISITA]')) {
    action = 'schedule_visit';
    intent = 'schedule_visit';
    cleanResponse = response.replace(/\[AGENDAR_VISITA\]/g, '').trim();
  }

  if (response.includes('[TRANSFERIR_HUMANO]')) {
    action = 'transfer_human';
    intent = 'transfer_human';
    cleanResponse = response.replace(/\[TRANSFERIR_HUMANO\]/g, '').trim();
  }

  // ARQ-05 FIX: Removed qualification pattern extraction from AI response.
  // Qualification data must be extracted from USER messages (via extractEntities),
  // not from the AI response which may echo or rephrase user data incorrectly.

  return { cleanResponse, action, actionData, intent };
}

async function searchProperties(
  supabase: any,
  provider: string,
  query: string,
  conversation: any
): Promise<any[]> {
  try {
    const { data: openaiSetting } = await supabase
      .from('system_settings')
      .select('value')
      .eq('key', 'openai_api_key')
      .single();

    if (!openaiSetting?.value) return [];

    const openai = new OpenAI({ apiKey: openaiSetting.value });
    const embeddingResponse = await openai.embeddings.create({
      model: 'text-embedding-3-small',
      input: query
    });

    const embedding = embeddingResponse.data[0].embedding;
    const filters = conversation?.qualification_data || {};

    const { data: properties } = await supabase.rpc('match_properties', {
      query_embedding: embedding,
      match_threshold: 0.6,
      match_count: 5,
      filter_min_price: filters.min_price || null,
      filter_max_price: filters.max_price || null,
      filter_bairro_id: filters.bairro_id || null
    });

    return properties || [];

  } catch (error) {
    console.error('Erro ao buscar imóveis:', error);
    return [];
  }
}

async function updateQualification(
  supabase: any,
  conversationId: string,
  leadId: string | null,
  data: any
) {
  const { data: current } = await supabase
    .from('agent_conversations')
    .select('qualification_data')
    .eq('id', conversationId)
    .single();

  const merged = { ...current?.qualification_data, ...data };

  await supabase
    .from('agent_conversations')
    .update({ qualification_data: merged })
    .eq('id', conversationId);

  await supabase
    .from('ai_lead_qualification')
    .upsert({
      conversation_id: conversationId,
      lead_id: leadId,
      ...data,
      updated_at: new Date().toISOString()
    }, {
      onConflict: 'conversation_id'
    });
}

async function notifyAdmin(supabase: any, conversation: any, reason: string) {
  const { data: adminSettings } = await supabase
    .from('system_settings')
    .select('value')
    .eq('key', 'admin_whatsapp')
    .single();

  if (adminSettings?.value) {
    await supabase.functions.invoke('evolution-send-whatsapp-v2', {
      body: {
        phone_number: adminSettings.value,
        message: `🚨 *ATENÇÃO: Transferência de Atendimento*\n\nTelefone: ${conversation?.phone_number}\nMotivo: ${reason}\n\nPor favor, assuma o atendimento.`
      }
    });
  }
}

import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

// ============================================================
// AI FOLLOWUP CHECKER
// Cron job que verifica conversas inativas e envia follow-ups
// Executar a cada 5 minutos via pg_cron ou webhook externo
// ============================================================

serve(async (req) => {
    if (req.method === 'OPTIONS') {
        return new Response(null, { headers: corsHeaders });
    }

    const startTime = Date.now();

    // ============================================================
    // CRON AUTHENTICATION
    // Permite autenticação via CRON_SECRET, SERVICE_ROLE, ou INTERNAL_DB_SECRET
    // ============================================================
    const authHeader = req.headers.get('Authorization');
    const cronSecret = Deno.env.get('CRON_SECRET');
    const serviceRoleKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY');

    // Inicializa Supabase Client (necessário para buscar segredo interno do banco)
    const supabase = createClient(
        Deno.env.get('SUPABASE_URL') ?? '',
        serviceRoleKey ?? ''
    );

    // Aceita: Bearer CRON_SECRET ou Bearer SERVICE_ROLE_KEY
    const token = authHeader?.replace('Bearer ', '');
    const isValidCronAuth = token === cronSecret;
    const isValidServiceAuth = token === serviceRoleKey;

    let isValidInternalAuth = false;

    // Se as auths padrão falharem, tentar validar com segredo do banco (para pg_cron)
    if (!isValidCronAuth && !isValidServiceAuth && token) {
        try {
            const { data: internalSecret } = await supabase
                .from('system_settings')
                .select('value')
                .eq('key', 'cron_secret')
                .single();

            if (internalSecret && internalSecret.value === token) {
                isValidInternalAuth = true;
            }
        } catch (e) {
            console.warn('Erro ao verificar internal cron secret:', e);
        }
    }

    if (!isValidCronAuth && !isValidServiceAuth && !isValidInternalAuth) {
        console.warn('⚠️ Tentativa de acesso não autorizada ao ai-followup-checker');
        return new Response(
            JSON.stringify({ error: 'Unauthorized', message: 'Valid CRON_SECRET, SERVICE_ROLE_KEY or INTERNAL_DB_SECRET required' }),
            { status: 401, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
        );
    }

    console.log(`🔐 Auth válida: ${isValidCronAuth ? 'CRON_SECRET' : isValidServiceAuth ? 'SERVICE_ROLE_KEY' : 'INTERNAL_DB_SECRET'}`);

    try {
        const currentHour = new Date().getHours();
        const now = new Date();

        console.log(`🔄 Follow-up Checker executando às ${now.toISOString()}, hora local: ${currentHour}h`);

        // 1. Buscar conversas ativas que estão inativas há pelo menos 1 hora
        const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000).toISOString();

        const { data: inactiveConversations, error: convError } = await supabase
            .from('agent_conversations')
            .select(`
        id,
        phone_number,
        agent_id,
        last_message_at,
        current_stage,
        qualification_data,
        lead_score,
        customer_name,
        total_messages,
        ai_agents!inner ( evolution_instance_id )
      `)
            .eq('status', 'active')
            .lt('last_message_at', oneHourAgo)
            .order('last_message_at', { ascending: true })
            .limit(50);

        // Also fetch qualifications for temperature checking
        const conversationIds = inactiveConversations?.map(c => c.id) || [];
        let qualificationsMap: Record<string, any> = {};

        if (conversationIds.length > 0) {
            const { data: quals } = await supabase
                .from('ai_lead_qualification')
                .select('conversation_id, lead_temperature, bant_total_score')
                .in('conversation_id', conversationIds);

            if (quals) {
                for (const q of quals) {
                    qualificationsMap[q.conversation_id] = q;
                }
            }
        }

        if (convError) {
            throw new Error(`Erro ao buscar conversas: ${convError.message}`);
        }

        console.log(`📋 Encontradas ${inactiveConversations?.length || 0} conversas inativas`);

        const results = {
            checked: inactiveConversations?.length || 0,
            followupsSent: 0,
            skipped: 0,
            errors: 0
        };

        for (const conv of inactiveConversations || []) {
            try {
                // 2. Buscar follow-ups já enviados para esta conversa
                const { data: sentFollowups } = await supabase
                    .from('agent_followup_log')
                    .select('sequence_order')
                    .eq('conversation_id', conv.id)
                    .order('sequence_order', { ascending: false })
                    .limit(1);

                const lastSentSequence = sentFollowups?.[0]?.sequence_order || 0;

                // 3. Buscar próximo follow-up na sequência
                const { data: nextFollowup } = await supabase
                    .from('agent_followups')
                    .select('*')
                    .eq('agent_id', conv.agent_id)
                    .eq('sequence_order', lastSentSequence + 1)
                    .eq('is_active', true)
                    .single();

                if (!nextFollowup) {
                    console.log(`  ⏭️ ${conv.phone_number}: Sem mais follow-ups configurados`);
                    results.skipped++;
                    continue;
                }

                // 4. Calcular tempo desde última mensagem
                const lastMessageTime = new Date(conv.last_message_at).getTime();
                const hoursSinceLastMessage = (Date.now() - lastMessageTime) / (1000 * 60 * 60);

                if (hoursSinceLastMessage < nextFollowup.delay_hours) {
                    console.log(`  ⏰ ${conv.phone_number}: Aguardando (${hoursSinceLastMessage.toFixed(1)}h < ${nextFollowup.delay_hours}h)`);
                    results.skipped++;
                    continue;
                }

                // 5. Verificar horário comercial
                if (currentHour < nextFollowup.send_after_hour || currentHour >= nextFollowup.send_before_hour) {
                    console.log(`  🌙 ${conv.phone_number}: Fora do horário (${currentHour}h, permitido: ${nextFollowup.send_after_hour}-${nextFollowup.send_before_hour}h)`);
                    results.skipped++;
                    continue;
                }

                // 6. Verificar condições especiais
                if (nextFollowup.skip_if_qualified && conv.lead_score && conv.lead_score >= 70) {
                    console.log(`  ✅ ${conv.phone_number}: Lead já qualificado, pulando`);
                    results.skipped++;
                    continue;
                }

                if (nextFollowup.only_if_stages && nextFollowup.only_if_stages.length > 0) {
                    if (!nextFollowup.only_if_stages.includes(conv.current_stage)) {
                        console.log(`  📍 ${conv.phone_number}: Estágio ${conv.current_stage} não elegível`);
                        results.skipped++;
                        continue;
                    }
                }

                // 6.5 Check temperature filtering (Phase 3 enhancement)
                const leadQual = qualificationsMap[conv.id];
                const leadTemperature = leadQual?.lead_temperature || 'cold';

                if (nextFollowup.use_for_temperature && nextFollowup.use_for_temperature.length > 0) {
                    if (!nextFollowup.use_for_temperature.includes(leadTemperature)) {
                        console.log(`  🌡️ ${conv.phone_number}: Temperatura ${leadTemperature} não elegível para este followup`);
                        results.skipped++;
                        continue;
                    }
                }

                // 6.6 Check objection-based filtering
                const lastObjection = conv.qualification_data?.last_objection;
                if (nextFollowup.use_after_objection && lastObjection) {
                    if (nextFollowup.use_after_objection !== lastObjection) {
                        console.log(`  ⚠️ ${conv.phone_number}: Objeção ${lastObjection} não match`);
                        results.skipped++;
                        continue;
                    }
                }

                // 7. Personalizar mensagem
                const personalizedMessage = await personalizeMessage(
                    supabase,
                    nextFollowup.message_template,
                    conv,
                    nextFollowup.include_property_reminder
                );

                // 8. Enviar follow-up
                console.log(`  📤 ${conv.phone_number}: Enviando follow-up #${nextFollowup.sequence_order}`);

                const { error: sendError } = await supabase.functions.invoke('evolution-send-whatsapp-v2', {
                    body: {
                        phone_number: conv.phone_number,
                        message: personalizedMessage,
                        typing_delay_ms: 2000 + Math.random() * 2000, // 2-4s delay humanizado
                        instance_id: (conv.ai_agents as any)?.evolution_instance_id
                    }
                });

                if (sendError) {
                    console.error(`  ❌ Erro ao enviar: ${sendError.message}`);
                    results.errors++;
                    continue;
                }

                // 9. Registrar no log
                await supabase.from('agent_followup_log').insert({
                    conversation_id: conv.id,
                    followup_id: nextFollowup.id,
                    sequence_order: nextFollowup.sequence_order,
                    message_sent: personalizedMessage
                });

                // 10. Salvar mensagem no histórico
                await supabase.from('agent_messages').insert({
                    conversation_id: conv.id,
                    role: 'assistant',
                    content: personalizedMessage,
                    intent_detected: 'followup',
                    action_taken: 'followup_sent'
                });

                // 11. Atualizar last_message_at
                await supabase
                    .from('agent_conversations')
                    .update({
                        last_message_at: new Date().toISOString(),
                        total_messages: (conv.total_messages || 0) + 1
                    })
                    .eq('id', conv.id);

                results.followupsSent++;
                console.log(`  ✅ Follow-up #${nextFollowup.sequence_order} enviado para ${conv.phone_number}`);

            } catch (convError: any) {
                console.error(`  ❌ Erro ao processar ${conv.phone_number}: ${convError.message}`);
                results.errors++;
            }
        }

        console.log(`\n📊 Resultado: ${results.followupsSent} enviados, ${results.skipped} pulados, ${results.errors} erros`);

        return new Response(
            JSON.stringify({
                success: true,
                ...results,
                duration: Date.now() - startTime
            }),
            { headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
        );

    } catch (error: any) {
        console.error('❌ Erro no Follow-up Checker:', error);

        return new Response(
            JSON.stringify({
                success: false,
                error: error.message,
                duration: Date.now() - startTime
            }),
            {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 500
            }
        );
    }
});

// ============================================================
// HELPER FUNCTIONS
// ============================================================

function personalizeMessage(
    supabase: any,
    template: string,
    conversation: any,
    includePropertyReminder: boolean = false
): Promise<string> {
    return (async () => {
        let message = template;

        // Substituir variáveis
        const replacements: Record<string, string> = {
            '{{nome}}': conversation.customer_name || 'amigo(a)',
            '{{telefone}}': conversation.phone_number || '',
            '{{estagio}}': conversation.current_stage || 'conversa',
            '{{mensagens}}': String(conversation.total_messages || 0)
        };

        // Extrair dados de qualificação se disponíveis
        const qualData = conversation.qualification_data || {};
        if (qualData.preferred_neighborhood) {
            replacements['{{bairro}}'] = qualData.preferred_neighborhood;
        }
        if (qualData.property_type) {
            replacements['{{tipo_imovel}}'] = qualData.property_type;
        }
        if (qualData.max_price) {
            const priceK = Math.round(qualData.max_price / 1000);
            replacements['{{orcamento}}'] = `${priceK}k`;
        }

        // Add property reminder if enabled (Phase 3)
        if (includePropertyReminder && conversation.presented_properties?.length > 0) {
            try {
                const lastPropertyId = conversation.presented_properties.slice(-1)[0];
                const { data: property } = await supabase
                    .from('empreendimentos')
                    .select('nome, bairro, valor_min, valor_max')
                    .eq('id', lastPropertyId)
                    .single();

                if (property) {
                    const formatPrice = (v: number) => v >= 1000000 ? `R$ ${(v / 1000000).toFixed(1)}M` : `R$ ${(v / 1000).toFixed(0)}k`;
                    const priceRange = property.valor_min && property.valor_max
                        ? `${formatPrice(property.valor_min)} - ${formatPrice(property.valor_max)}`
                        : property.valor_max ? formatPrice(property.valor_max) : '';

                    replacements['{{ultimo_imovel}}'] = property.nome;
                    replacements['{{bairro_imovel}}'] = property.bairro || '';
                    replacements['{{preco_imovel}}'] = priceRange;

                    // Add a reminder suffix if template doesn't use the variable
                    if (!template.includes('{{ultimo_imovel}}')) {
                        message += `\n\nLembrei aqui do ${property.nome}${property.bairro ? ` no ${property.bairro}` : ''}... Ainda tem interesse? 🏠`;
                    }
                }
            } catch (e) {
                console.warn('Property reminder error:', e);
            }
        }

        for (const [variable, value] of Object.entries(replacements)) {
            message = message.replace(new RegExp(variable.replace(/[{}]/g, '\\$&'), 'g'), value);
        }

        // Remover variáveis não substituídas
        message = message.replace(/\{\{[^}]+\}\}/g, '');

        return message.trim();
    })();
}

import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';
import OpenAI from 'https://esm.sh/openai@4.28.0';

const corsHeaders = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

interface GenerateEmbeddingsRequest {
    empreendimento_id?: string;
    regenerate_all?: boolean;
}

serve(async (req) => {
    if (req.method === 'OPTIONS') {
        return new Response(null, { headers: corsHeaders });
    }

    const startTime = Date.now();

    try {
        const supabase = createClient(
            Deno.env.get('SUPABASE_URL') ?? '',
            Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? ''
        );

        const { empreendimento_id, regenerate_all }: GenerateEmbeddingsRequest = await req.json().catch(() => ({}));

        console.log('🧮 Gerando embeddings...', { empreendimento_id, regenerate_all });

        // Get OpenAI API key
        const { data: openaiSetting } = await supabase
            .from('system_settings')
            .select('value')
            .eq('key', 'openai_api_key')
            .single();

        if (!openaiSetting?.value) {
            throw new Error('OpenAI API key não configurada');
        }

        const openai = new OpenAI({ apiKey: openaiSetting.value });

        let empreendimentos: any[] = [];

        if (empreendimento_id) {
            // Single empreendimento
            const { data, error } = await supabase
                .from('empreendimentos')
                .select(`
          id,
          nome,
          descricao,
          valor_min,
          valor_max,
          endereco,
          tipo_imovel,
          bairro:bairros(nome, cidade),
          construtora:construtoras(nome)
        `)
                .eq('id', empreendimento_id)
                .eq('ativo', true)
                .single();

            if (error) {
                throw new Error(`Empreendimento não encontrado: ${error.message}`);
            }

            empreendimentos = [data];
        } else if (regenerate_all) {
            // All active empreendimentos
            const { data, error } = await supabase
                .from('empreendimentos')
                .select(`
          id,
          nome,
          descricao,
          valor_min,
          valor_max,
          endereco,
          tipo_imovel,
          bairro:bairros(nome, cidade),
          construtora:construtoras(nome)
        `)
                .eq('ativo', true);

            if (error) {
                throw new Error(`Erro ao buscar empreendimentos: ${error.message}`);
            }

            empreendimentos = data || [];
        } else {
            // Only empreendimentos without embeddings
            const { data: existing } = await supabase
                .from('property_embeddings')
                .select('empreendimento_id');

            const existingIds = new Set((existing || []).map(e => e.empreendimento_id));

            const { data, error } = await supabase
                .from('empreendimentos')
                .select(`
          id,
          nome,
          descricao,
          valor_min,
          valor_max,
          endereco,
          tipo_imovel,
          bairro:bairros(nome, cidade),
          construtora:construtoras(nome)
        `)
                .eq('ativo', true);

            if (error) {
                throw new Error(`Erro ao buscar empreendimentos: ${error.message}`);
            }

            empreendimentos = (data || []).filter(e => !existingIds.has(e.id));
        }

        console.log(`📊 ${empreendimentos.length} empreendimentos para processar`);

        if (empreendimentos.length === 0) {
            return new Response(
                JSON.stringify({
                    success: true,
                    processed: 0,
                    message: 'Nenhum empreendimento para processar',
                    duration: Date.now() - startTime
                }),
                { headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
            );
        }

        let processed = 0;
        let errors: string[] = [];

        // Process in batches of 10
        const batchSize = 10;

        for (let i = 0; i < empreendimentos.length; i += batchSize) {
            const batch = empreendimentos.slice(i, i + batchSize);

            const results = await Promise.allSettled(
                batch.map(async (emp) => {
                    try {
                        // Build content text for embedding
                        const contentText = buildContentText(emp);

                        // Generate embedding
                        const embeddingResponse = await openai.embeddings.create({
                            model: 'text-embedding-3-small',
                            input: contentText
                        });

                        const embedding = embeddingResponse.data[0].embedding;

                        // Upsert to database
                        const { error: upsertError } = await supabase
                            .from('property_embeddings')
                            .upsert({
                                empreendimento_id: emp.id,
                                embedding: embedding,
                                content_text: contentText,
                                updated_at: new Date().toISOString()
                            }, {
                                onConflict: 'empreendimento_id'
                            });

                        if (upsertError) {
                            throw new Error(upsertError.message);
                        }

                        processed++;
                        console.log(`✅ Embedding gerado: ${emp.nome}`);
                    } catch (error) {
                        const msg = `Erro em ${emp.nome}: ${error.message}`;
                        console.error(msg);
                        errors.push(msg);
                    }
                })
            );

            // Rate limiting between batches
            if (i + batchSize < empreendimentos.length) {
                await new Promise(resolve => setTimeout(resolve, 500));
            }
        }

        console.log(`🏁 Processamento concluído: ${processed}/${empreendimentos.length}`);

        return new Response(
            JSON.stringify({
                success: true,
                processed,
                total: empreendimentos.length,
                errors: errors.length > 0 ? errors : undefined,
                duration: Date.now() - startTime
            }),
            { headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
        );

    } catch (error) {
        console.error('❌ Erro ao gerar embeddings:', error);

        return new Response(
            JSON.stringify({
                success: false,
                error: error.message,
                duration: Date.now() - startTime
            }),
            {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 500
            }
        );
    }
});

function buildContentText(emp: any): string {
    const parts: string[] = [];

    // Name (most important)
    parts.push(`Empreendimento: ${emp.nome}`);

    // Description
    if (emp.descricao) {
        // Limit description to 500 chars
        const desc = emp.descricao.length > 500
            ? emp.descricao.substring(0, 500) + '...'
            : emp.descricao;
        parts.push(`Descrição: ${desc}`);
    }

    // Property type
    if (emp.tipo_imovel) {
        parts.push(`Tipo: ${emp.tipo_imovel}`);
    }

    // Price range
    if (emp.valor_min || emp.valor_max) {
        const min = emp.valor_min ? formatPrice(emp.valor_min) : '';
        const max = emp.valor_max ? formatPrice(emp.valor_max) : '';
        if (min && max) {
            parts.push(`Preço: de ${min} até ${max}`);
        } else if (min) {
            parts.push(`Preço a partir de: ${min}`);
        } else if (max) {
            parts.push(`Preço até: ${max}`);
        }
    }

    // Location
    if (emp.bairro) {
        parts.push(`Bairro: ${emp.bairro.nome}`);
        if (emp.bairro.cidade) {
            parts.push(`Cidade: ${emp.bairro.cidade}`);
        }
    }

    if (emp.endereco) {
        parts.push(`Endereço: ${emp.endereco}`);
    }

    // Builder
    if (emp.construtora) {
        parts.push(`Construtora: ${emp.construtora.nome}`);
    }

    return parts.join('. ');
}

function formatPrice(value: number): string {
    if (value >= 1000000) {
        return `R$ ${(value / 1000000).toFixed(1)} milhões`;
    }
    if (value >= 1000) {
        return `R$ ${(value / 1000).toFixed(0)} mil`;
    }
    return `R$ ${value.toFixed(0)}`;
}

import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';
import OpenAI from 'https://esm.sh/openai@4.28.0';

const corsHeaders = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

interface PropertySearchRequest {
    query: string;
    filters?: {
        min_price?: number;
        max_price?: number;
        bairro_id?: string;
        tipo_imovel?: string;
    };
    max_results?: number;
    threshold?: number;
}

serve(async (req) => {
    if (req.method === 'OPTIONS') {
        return new Response(null, { headers: corsHeaders });
    }

    const startTime = Date.now();

    try {
        const supabase = createClient(
            Deno.env.get('SUPABASE_URL') ?? '',
            Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? ''
        );

        const { query, filters, max_results = 5, threshold = 0.6 }: PropertySearchRequest = await req.json();

        if (!query) {
            throw new Error('Query é obrigatória');
        }

        console.log(`🔍 Buscando imóveis: "${query.substring(0, 50)}..."`);

        // Get OpenAI API key
        const { data: openaiSetting } = await supabase
            .from('system_settings')
            .select('value')
            .eq('key', 'openai_api_key')
            .single();

        if (!openaiSetting?.value) {
            throw new Error('OpenAI API key não configurada');
        }

        const openai = new OpenAI({ apiKey: openaiSetting.value });

        // Generate embedding for query
        console.log('🧮 Gerando embedding da query...');
        const embeddingResponse = await openai.embeddings.create({
            model: 'text-embedding-3-small',
            input: query
        });

        const queryEmbedding = embeddingResponse.data[0].embedding;

        // Search using vector similarity
        console.log('🔎 Buscando por similaridade vetorial...');
        const { data: matchedProperties, error: searchError } = await supabase.rpc('match_properties', {
            query_embedding: queryEmbedding,
            match_threshold: threshold,
            match_count: max_results,
            filter_min_price: filters?.min_price || null,
            filter_max_price: filters?.max_price || null,
            filter_bairro_id: filters?.bairro_id || null
        });

        if (searchError) {
            console.error('Erro na busca vetorial:', searchError);
            throw new Error(`Erro na busca: ${searchError.message}`);
        }

        console.log(`✅ Encontrados ${matchedProperties?.length || 0} imóveis`);

        // Enrich results with full empreendimento data
        let enrichedResults: any[] = [];

        if (matchedProperties && matchedProperties.length > 0) {
            const empreendimentoIds = matchedProperties.map((p: any) => p.empreendimento_id);

            const { data: fullData } = await supabase
                .from('empreendimentos')
                .select(`
          id,
          nome,
          descricao,
          valor_min,
          valor_max,
          endereco,
          tipo_imovel,
          bairro:bairros(id, nome, cidade),
          construtora:construtoras(id, nome)
        `)
                .in('id', empreendimentoIds)
                .eq('ativo', true);

            // Merge with similarity scores
            enrichedResults = (fullData || []).map(emp => {
                const match = matchedProperties.find((m: any) => m.empreendimento_id === emp.id);
                return {
                    ...emp,
                    similarity: match?.similarity || 0
                };
            }).sort((a, b) => b.similarity - a.similarity);
        }

        // Format for AI/WhatsApp
        const formattedForAI = enrichedResults.map((emp, index) => ({
            position: index + 1,
            id: emp.id,
            nome: emp.nome,
            tipo: emp.tipo_imovel,
            preco: formatPriceRange(emp.valor_min, emp.valor_max),
            localizacao: emp.bairro?.nome || 'Não informado',
            construtora: emp.construtora?.nome || 'Não informada',
            similarity: (emp.similarity * 100).toFixed(1) + '%'
        }));

        // Generate text summary for WhatsApp
        let textSummary = '';
        if (enrichedResults.length > 0) {
            textSummary = '🏠 *Imóveis encontrados para você:*\n\n';
            enrichedResults.forEach((emp, i) => {
                textSummary += `*${i + 1}. ${emp.nome}*\n`;
                textSummary += `📍 ${emp.bairro?.nome || 'Localização não informada'}\n`;
                textSummary += `💰 ${formatPriceRange(emp.valor_min, emp.valor_max)}\n`;
                if (emp.construtora) {
                    textSummary += `🏗️ ${emp.construtora.nome}\n`;
                }
                textSummary += '\n';
            });
            textSummary += '_Posso te dar mais detalhes sobre algum deles?_';
        } else {
            textSummary = 'Não encontrei imóveis compatíveis com sua busca. Pode me contar mais sobre o que você procura?';
        }

        return new Response(
            JSON.stringify({
                success: true,
                count: enrichedResults.length,
                properties: enrichedResults,
                formatted: formattedForAI,
                text_summary: textSummary,
                query_used: query,
                duration: Date.now() - startTime
            }),
            { headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
        );

    } catch (error) {
        console.error('❌ Erro na busca de imóveis:', error);

        return new Response(
            JSON.stringify({
                success: false,
                error: error.message,
                count: 0,
                properties: [],
                duration: Date.now() - startTime
            }),
            {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 500
            }
        );
    }
});

function formatPriceRange(min: number | null, max: number | null): string {
    const formatValue = (value: number): string => {
        if (value >= 1000000) {
            return `R$ ${(value / 1000000).toFixed(1)} mi`;
        }
        if (value >= 1000) {
            return `R$ ${(value / 1000).toFixed(0)} mil`;
        }
        return `R$ ${value.toFixed(0)}`;
    };

    if (min && max) {
        if (min === max) {
            return formatValue(min);
        }
        return `${formatValue(min)} a ${formatValue(max)}`;
    }

    if (min) {
        return `A partir de ${formatValue(min)}`;
    }

    if (max) {
        return `Até ${formatValue(max)}`;
    }

    return 'Consulte';
}

