      let errorDetail = responseText;
      try {
        const parsed = JSON.parse(responseText);
        errorDetail = parsed.message || parsed.error || responseText;
      } catch { /* keep raw text */ }

      throw new Error(`Evolution API retornou erro (${response.status}): ${errorDetail}`);
    }

    let result;
