import { createClient } from 'https://esm.sh/@supabase/supabase-js@2.39.3';
import { logIntegration } from '../_shared/integration-logger.ts';
import { DbEvolutionInstance } from '../_shared/types/evolution.ts';


const corsHeaders = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

interface ManagerRequest {
    action: 'create' | 'connect' | 'items' | 'restart' | 'logout' | 'delete' | 'fetch' | 'connectionState';
    instance_id?: string;
    payload?: any;
}

Deno.serve(async (req) => {
    // Handle CORS preflight requests
    if (req.method === 'OPTIONS') {
        return new Response(null, { headers: corsHeaders });
    }

    try {
        const supabaseUrl = Deno.env.get('SUPABASE_URL');
        const supabaseKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY');

        if (!supabaseUrl || !supabaseKey) {
            throw new Error('Missing Supabase environment variables');
        }

        const supabase = createClient(supabaseUrl, supabaseKey);

        let body;
        try {
            body = await req.json();
        } catch (e) {
            throw new Error('Invalid JSON payload');
        }

        const { action, instance_id, payload } = body as ManagerRequest;

        console.log(`🤖 Evolution Manager: ${action}`, { instance_id });

        // Helper to get instance data
        const getInstance = async (id: string) => {
            const { data, error } = await supabase
                .from('evolution_instances')
                .select('*')
                .eq('id', id)
                .single();

            if (error || !data) throw new Error(`Instance not found: ${id}`);
            return data;
        };

        // Helper to make Evolution API calls

        const evoCall = async (instance: DbEvolutionInstance, endpoint: string, method: string = 'GET', body?: any) => {
            const url = `${instance.api_url.replace(/\/$/, '')}${endpoint}`;
            console.log(`📡 Evo Call: ${method} ${url}`);

            const startTime = Date.now();
            let responseStatus = 0;
            let responseData: any = null;

            try {
                const response = await fetch(url, {
                    method,
                    headers: {
                        'Content-Type': 'application/json',
                        'apikey': instance.api_token
                    },
                    body: body ? JSON.stringify(body) : undefined,
                    signal: AbortSignal.timeout(15000) // 15s timeout
                });

                responseStatus = response.status;
                const text = await response.text();

                try {
                    responseData = text ? JSON.parse(text) : {};
                } catch (e) {
                    responseData = { raw: text };
                }

                if (!response.ok) {
                    const errorMessage = responseData.message || responseData.error || (responseData.response?.message) || `Error ${response.status}: ${text}`;
                    throw new Error(errorMessage);
                }
                return responseData;
            } catch (err: any) {
                if (err.name === 'AbortError' || err.name === 'TimeoutError') {
                    responseData = { error: 'Timeout' };
                    throw new Error(`Evolution API timed out after 15s`);
                }
                responseData = { error: err.message };
                throw err;
            } finally {
                // Log the integration event
                await logIntegration(supabase, {
                    service: 'evolution-api',
                    endpoint: endpoint,
                    method: method,
                    status_code: responseStatus,
                    request_payload: body,
                    response_body: responseData,
                    duration_ms: Date.now() - startTime,
                    metadata: { instance_name: instance.instance_name }
                });
            }
        };

        let result;

        switch (action) {
            case 'create':
                const { instanceName, raw_url, raw_apikey } = payload;
                if (!instanceName || !raw_url || !raw_apikey) {
                    throw new Error("Missing required fields: instanceName, raw_url, raw_apikey");
                }
                const apiUrl = raw_url.replace(/\/$/, '');

                // 1. Try to create in Evolution API
                try {
                    const createResponse = await fetch(`${apiUrl}/instance/create`, {
                        method: 'POST',
                        headers: {
                            'Content-Type': 'application/json',
                            'apikey': raw_apikey
                        },
                        body: JSON.stringify({
                            instanceName: instanceName,
                            token: payload.token,
                            qrcode: true
                        }),
                        signal: AbortSignal.timeout(10000)
                    });

                    const text = await createResponse.text();
                    let createData;
                    try {
                        createData = JSON.parse(text);
                    } catch (e) {
                        createData = { message: text };
                    }

                    if (!createResponse.ok) {
                        const strData = JSON.stringify(createData).toLowerCase();
                        if (strData.includes('already exists')) {
                            console.log(`Instance ${instanceName} already exists in Evolution. Proceeding to register in DB.`);
                        } else {
                            const errMsg = createData.message || createData.error || 'Failed to create instance in Evolution API';
                            throw new Error(errMsg);
                        }
                    }
                } catch (error: any) {
                    if (error.message?.toLowerCase().includes('already exists')) {
                        console.log(`Instance ${instanceName} already exists (caught error). Proceeding to register in DB.`);
                    } else {
                        // Throw unless it's a fetch error that we want to bypass? No, creation failure is usually fatal.
                        // But if we can't reach the API, we definitely shouldn't create in DB? 
                        // Actually, user might want to register valid instance even if currently offline? 
                        // Let's stick to throwing error for safety.
                        throw error;
                    }
                }

                // 2. Register in DB
                // EVO-05: Deactivate all other instances before creating a new active one
                await supabase
                    .from('evolution_instances')
                    .update({ is_active: false })
                    .neq('id', 'new'); // Updates all existing rows

                const { data: newInstance, error: dbError } = await supabase
                    .from('evolution_instances')
                    .insert({
                        name: payload.name || instanceName,
                        instance_name: instanceName,
                        api_url: apiUrl,
                        api_token: raw_apikey,
                        is_active: true
                    })
                    .select()
                    .single();

                if (dbError) throw dbError;
                result = newInstance;
                break;

            case 'connect':
                const instConnect = await getInstance(instance_id!);
                const connectData = await evoCall(instConnect, `/instance/connect/${instConnect.instance_name}`);
                result = connectData;
                break;

            case 'connectionState':
                const instState = await getInstance(instance_id!);
                const stateData = await evoCall(instState, `/instance/connectionState/${instState.instance_name}`);
                result = stateData;
                break;

            case 'fetch':
                const instFetch = await getInstance(instance_id!);
                const fetchData = await evoCall(instFetch, `/instance/fetchInstances?instanceName=${instFetch.instance_name}`);
                if (Array.isArray(fetchData)) {
                    result = fetchData.find((i: any) => i.instance?.instanceName === instFetch.instance_name || i.instanceName === instFetch.instance_name) || fetchData[0];
                } else {
                    result = fetchData;
                }
                break;

            case 'restart':
                const instRestart = await getInstance(instance_id!);
                result = await evoCall(instRestart, `/instance/restart/${instRestart.instance_name}`, 'PUT');
                break;

            case 'logout':
                const instLogout = await getInstance(instance_id!);
                result = await evoCall(instLogout, `/instance/logout/${instLogout.instance_name}`, 'DELETE');
                break;

            case 'delete':
                const instDelete = await getInstance(instance_id!);
                // EVO-09: Surface Evolution API delete errors as warnings instead of swallowing
                let evoDeleteWarning: string | null = null;
                try {
                    await evoCall(instDelete, `/instance/delete/${instDelete.instance_name}`, 'DELETE');
                } catch (e: any) {
                    evoDeleteWarning = e.message || 'Failed to delete from Evolution API';
                    console.warn('Evolution API delete warning:', evoDeleteWarning);
                }

                const { error: delError } = await supabase
                    .from('evolution_instances')
                    .delete()
                    .eq('id', instance_id);

                if (delError) throw delError;
                result = {
                    success: true,
                    ...(evoDeleteWarning ? { warning: `Instance removed from DB. Evolution API note: ${evoDeleteWarning}` } : {})
                };
                break;

            default:
                throw new Error(`Unknown action: ${action}`);
        }

        return new Response(
            JSON.stringify({ success: true, data: result }),
            { headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
        );

    } catch (error: any) {
        console.error(`❌ Manager Error:`, error);
        return new Response(
            JSON.stringify({ success: false, error: error.message }),
            {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 400
            }
        );
    }
});

import { createClient } from 'https://esm.sh/@supabase/supabase-js@2.39.3';
import { logIntegration } from '../_shared/integration-logger.ts';
import { DbEvolutionInstance } from '../_shared/types/evolution.ts';

const corsHeaders = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

Deno.serve(async (req) => {
    // Basic CORS
    if (req.method === 'OPTIONS') {
        return new Response(null, { headers: corsHeaders });
    }

    try {
        const supabaseUrl = Deno.env.get('SUPABASE_URL')!;
        const supabaseKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;
        const supabase = createClient(supabaseUrl, supabaseKey);

        console.log('👷 Evolution Queue Worker started');

        // 1. Fetch pending messages (limit 10 per run to avoid timeouts)
        // Ideally use RPC for atomic lock, but simple update loop works for low volume

        // Fetch pending items
        const { data: pendingItems, error: fetchError } = await supabase
            .from('message_queue')
            .select('*')
            .eq('status', 'pending')
            .order('priority', { ascending: false })
            .order('created_at', { ascending: true })
            .limit(10);

        if (fetchError) throw fetchError;

        if (!pendingItems || pendingItems.length === 0) {
            console.log('📭 Queue is empty');
            return new Response(JSON.stringify({ message: 'Queue empty' }), { headers: { ...corsHeaders, 'Content-Type': 'application/json' } });
        }

        console.log(`Processing ${pendingItems.length} messages...`);
        const results = [];

        for (const item of pendingItems) {
            const startTime = Date.now();
            let processStatus = 'failed';
            let errorMsg = null;
            let responseData = null;

            try {
                // Lock item
                await supabase.from('message_queue').update({ status: 'processing', last_attempt: new Date().toISOString() }).eq('id', item.id);

                // Get instance
                let instance: DbEvolutionInstance | null = null;
                if (item.instance_id) {
                    const { data } = await supabase.from('evolution_instances').select('*').eq('id', item.instance_id).single();
                    instance = data;
                } else {
                    // Get active
                    const { data } = await supabase.from('evolution_instances').select('*').eq('is_active', true).maybeSingle();
                    instance = data;
                }

                if (!instance) throw new Error('No active Evolution instance found');

                // Determine payload from message_queue.message_body
                const payload = item.message_body;

                // Construct URL
                // We assume payload has 'type' ('text', 'media', 'list') to know endpoint, or just direct pass if we standardized before queueing.
                // Let's standardise the queue payload to match `evolution-send-whatsapp-v2` logic or just map it here.
                // Better: The queue payload should have `type`, `endpoint` (suffix), and `body`.

                let endpoint = '';
                let apiBody = {};

                if (payload.type === 'text') {
                    endpoint = `/message/sendText/${instance.instance_name}`;
                    apiBody = {
                        number: item.phone_number,
                        text: payload.text || payload.message
                    };
                } else if (payload.type === 'media') {
                    endpoint = `/message/sendMedia/${instance.instance_name}`;
                    apiBody = {
                        number: item.phone_number,
                        mediatype: payload.media?.type || 'image',
                        media: payload.media?.url,
                        caption: payload.media?.caption,
                        fileName: payload.media?.filename
                    };
                } else if (payload.type === 'list') {
                    endpoint = `/message/sendList/${instance.instance_name}`;
                    apiBody = {
                        number: item.phone_number,
                        title: payload.list?.title,
                        description: payload.list?.description,
                        buttonText: payload.list?.buttonText,
                        sections: payload.list?.sections
                    };
                } else if (payload.type === 'buttons') {
                    endpoint = `/message/sendButtons/${instance.instance_name}`;
                    apiBody = {
                        number: item.phone_number,
                        title: 'Opções',
                        description: payload.message || '',
                        buttons: payload.buttons.map((b: any) => ({
                            id: b.id,
                            displayText: b.text || b.displayText
                        }))
                    };
                } else {
                    // Fallback generic
                    endpoint = `/message/sendText/${instance.instance_name}`;
                    apiBody = { number: item.phone_number, text: JSON.stringify(payload) };
                }

                const url = `${instance.api_url.replace(/\/$/, '')}${endpoint}`;

                // Send
                const response = await fetch(url, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json', 'apikey': instance.api_token },
                    body: JSON.stringify(apiBody),
                    signal: AbortSignal.timeout(15000)
                });

                const text = await response.text();
                try { responseData = JSON.parse(text); } catch { responseData = { raw: text }; }

                if (!response.ok) {
                    throw new Error(responseData?.message || `API Error ${response.status}`);
                }

                processStatus = 'completed';
                results.push({ id: item.id, status: 'success', data: responseData });

            } catch (err: any) {
                console.error(`Failed to process message ${item.id}:`, err);
                errorMsg = err.message;
                processStatus = 'failed';
                results.push({ id: item.id, status: 'error', error: err.message });
            } finally {
                // Update queue
                const updateData: any = {
                    status: processStatus,
                    processed_at: new Date().toISOString(),
                    attempts: (item.attempts || 0) + 1
                };

                if (processStatus === 'failed') {
                    updateData.error_message = errorMsg;
                    if ((item.attempts || 0) < 3) {
                        updateData.status = 'pending'; // Retry later
                    } else {
                        // EVO-06: Dead-letter alerting — log permanently failed messages
                        await supabase.from('agent_activity_log').insert({
                            activity_type: 'dead_letter',
                            activity_data: {
                                queue_id: item.id,
                                phone_number: item.phone_number,
                                error: errorMsg,
                                attempts: (item.attempts || 0) + 1,
                                message_type: item.message_type || 'text',
                                alert: 'Message permanently failed after max retries'
                            }
                        }).catch((e: any) => console.warn('Dead-letter log error:', e));
                    }
                }

                await supabase.from('message_queue').update(updateData).eq('id', item.id);

                // Log integration
                if (item.instance_id || item.phone_number) { // Only if we have some context
                    await logIntegration(supabase, {
                        service: 'evolution-api-queue',
                        endpoint: 'worker',
                        method: 'PROCESS',
                        status_code: processStatus === 'completed' ? 200 : 500,
                        duration_ms: Date.now() - startTime,
                        metadata: { queue_id: item.id, error: errorMsg }
                    });
                }
            }
        }

        return new Response(JSON.stringify({ success: true, processed: results.length, details: results }), { headers: { ...corsHeaders, 'Content-Type': 'application/json' } });

    } catch (error: any) {
        return new Response(JSON.stringify({ error: error.message }), { status: 500, headers: { ...corsHeaders, 'Content-Type': 'application/json' } });
    }
});

import { createClient } from 'https://esm.sh/@supabase/supabase-js@2.39.3';
import { normalizePhoneNumber, isValidBrazilianPhone } from '../_shared/phoneHelpers.ts';
import { logIntegration } from '../_shared/integration-logger.ts';

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

interface WhatsAppMessage {
  phone_number: string;
  message?: string;
  media?: {
    type: 'image' | 'video' | 'document' | 'audio';
    url: string;
    caption?: string;
    filename?: string;
  };
  buttons?: Array<{
    id: string;
    text: string;
  }>;
  list?: {
    title: string;
    description?: string;
    buttonText: string;
    sections: Array<{
      title: string;
      rows: Array<{
        id: string;
        title: string;
        description?: string;
      }>;
    }>;
  };
  lead_id?: string;
  corretor_id?: string;
  instance_id?: string;
  async?: boolean;
}

Deno.serve(async (req) => {
  // Handle CORS preflight requests
  if (req.method === 'OPTIONS') {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    console.log('=== EVOLUTION API V2 - SEND WHATSAPP MESSAGE ===');

    const supabaseUrl = Deno.env.get('SUPABASE_URL');
    const supabaseKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY');

    if (!supabaseUrl || !supabaseKey) {
      throw new Error('Missing Supabase environment variables');
    }

    const supabase = createClient(supabaseUrl, supabaseKey);

    let body: WhatsAppMessage;
    try {
      body = await req.json();
    } catch (e) {
      throw new Error('Invalid JSON payload');
    }

    const { phone_number, message, media, buttons, list, lead_id, corretor_id, async } = body;

    if (!phone_number) {
      throw new Error('Número de telefone é obrigatório');
    }

    // Normalizar número
    const normalizedPhone = normalizePhoneNumber(phone_number);

    console.log('Sending to:', normalizedPhone);

    if (!isValidBrazilianPhone(normalizedPhone)) {
      throw new Error('Número de telefone inválido');
    }

    // 0. Async Queue Handling
    if (async) {
      console.log('🔄 Async mode: Enqueuing message for', normalizedPhone);

      // Determine message body for queue
      const queuePayload = {
        type: media ? 'media' : list ? 'list' : (buttons && buttons.length > 0) ? 'buttons' : 'text',
        message: message,
        media: media,
        list: list,
        buttons: buttons // Stored for worker
      };

      const { data: queueItem, error: queueError } = await supabase
        .from('message_queue')
        .insert({
          instance_id: body.instance_id || null, // If null, worker picks active
          phone_number: normalizedPhone,
          message_body: queuePayload,
          status: 'pending',
          priority: 0
        })
        .select('id')
        .single();

      if (queueError) throw queueError;

      // Log in communication_log as 'queued'
      await supabase.from('communication_log').insert({
        type: 'whatsapp',
        direction: 'enviado',
        phone_number: normalizedPhone,
        content: message || (media ? 'Media (Queued)' : 'List (Queued)'),
        status: 'queued',
        corretor_id: corretor_id || null,
        lead_id: lead_id || null,
        metadata: {
          queue_id: queueItem.id,
          async: true
        }
      });

      return new Response(
        JSON.stringify({
          success: true,
          queued: true,
          queue_id: queueItem.id,
          message: 'Message queued for async delivery'
        }),
        { headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
      );
    }

    // 1. Get instance configuration
    let apiUrl = '';
    let apiKey = '';
    let instanceName = '';

    const { instance_id } = body;

    if (instance_id) {
      // Fetch specific instance
      const { data: instance, error } = await supabase
        .from('evolution_instances')
        .select('*')
        .eq('id', instance_id)
        .single();

      if (error || !instance) {
        throw new Error(`Instance not found: ${instance_id}`);
      }

      apiUrl = instance.api_url;
      apiKey = instance.api_token;
      instanceName = instance.instance_name;
      console.log(`Using specific Evolution Instance: ${instance.name} (${instanceName})`);

    } else {
      // No instance_id provided. Try to find an ACTIVE instance first.
      const { data: activeInstance } = await supabase
        .from('evolution_instances')
        .select('*')
        .eq('is_active', true)
        .limit(1)
        .maybeSingle();

      if (activeInstance) {
        apiUrl = activeInstance.api_url;
        apiKey = activeInstance.api_token;
        instanceName = activeInstance.instance_name;
        console.log(`Using ACTIVE Evolution Instance: ${activeInstance.name} (${instanceName})`);
      } else {
        // Fallback: Fetch from system_settings (Legacy)
        console.log('No active instance found in DB. Falling back to system_settings.');
        const { data: settings } = await supabase
          .from('system_settings')
          .select('key, value')
          .in('key', ['evolution_api_url', 'evolution_api_key', 'evolution_instance_name']);

        const settingsMap = new Map(settings?.map((s: any) => [s.key, s.value]) || []);

        apiUrl = settingsMap.get('evolution_api_url');
        apiKey = settingsMap.get('evolution_api_key');
        instanceName = settingsMap.get('evolution_instance_name');
      }
    }

    if (!apiUrl || !apiKey || !instanceName) {
      throw new Error('Configurações da Evolution API não encontradas');
    }

    // Trim trailing slash from API URL to prevent double slashes
    apiUrl = apiUrl.trim().replace(/\/$/, '');
    instanceName = instanceName.trim();

    let endpoint = '';
    let payload: any = {};

    // Evolution API v2: Suporte para diferentes tipos de mensagem
    if (media) {
      // Enviar mídia
      endpoint = `/message/sendMedia/${instanceName}`;
      payload = {
        number: normalizedPhone,
        mediatype: media.type,
        media: media.url,
        ...(media.caption && { caption: media.caption }),
        ...(media.filename && { fileName: media.filename }),
      };
    } else if (list) {
      // Enviar mensagem com lista
      endpoint = `/message/sendList/${instanceName}`;
      payload = {
        number: normalizedPhone,
        title: list.title,
        description: list.description || '',
        buttonText: list.buttonText,
        sections: list.sections,
      };
    } else if (buttons && buttons.length > 0) {
      // Enviar botões
      endpoint = `/message/sendButtons/${instanceName}`;
      payload = {
        number: normalizedPhone,
        title: 'Opções', // Title is often required
        description: message || '',
        buttons: buttons.map(b => ({
          id: b.id,
          displayText: b.text // Evolution usually expects "displayText" for Baileys, or "text" depending on version. Using "displayText" is safer for buttons.
        }))
      };
      // Note: Some Evolution versions use "text" instead of "displayText" inside button object. 
      // Evolution V2 often uses { id, displayText } for reply buttons.
    } else {
      // Enviar mensagem de texto simples
      // IMPORTANTE: Evolution API V2 aceita APENAS "number" e "text" nas rotas /message/sendText
      endpoint = `/message/sendText/${instanceName}`;
      payload = {
        number: normalizedPhone,
        text: message || '',
      };
    }

    // Log detalhado do request
    console.log('📤 Request para Evolution API v2:', {
      url: `${apiUrl}${endpoint}`,
      method: 'POST',
      payload: payload,
      headers: { 'Content-Type': 'application/json', 'apikey': '***' }
    });

    const startTime = Date.now();
    let responseStatus = 0;
    let responseBody: any = null;

    try {
      const response = await fetch(`${apiUrl}${endpoint}`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'apikey': apiKey,
        },
        body: JSON.stringify(payload),
        signal: AbortSignal.timeout(15000)
      });

      responseStatus = response.status;
      console.log('📥 Response status:', response.status);
      const responseText = await response.text();
      console.log('📥 Response body:', responseText);

      try {
        responseBody = responseText ? JSON.parse(responseText) : { raw: responseText };
      } catch {
        responseBody = { raw: responseText };
      }

      if (!response.ok) {
        console.error('❌ Evolution API error:', responseText);

        // Log failure in communication_log for debugging
        await supabase.from('communication_log').insert({
          type: 'whatsapp',
          direction: 'enviado',
          phone_number: normalizedPhone,
          content: message || `Mídia/Lista falhou`,
          status: 'failed',
          corretor_id: corretor_id || null,
          lead_id: lead_id || null,
          metadata: {
            error: responseText,
            status_code: response.status,
            endpoint: endpoint,
            api_version: 'v2'
          }
        });

        throw new Error(`Erro ao enviar mensagem (status ${response.status}): ${responseText}`);
      }

      console.log('✅ Message sent successfully:', responseBody);

      // === LID-to-Phone Mapping ===
      // Evolution API V2 returns remoteJid in the response.
      // We capture this mapping so the webhook handler can resolve LIDs to real phones later.
      if (responseBody?.key?.remoteJid) {
        try {
          const remoteJid = responseBody.key.remoteJid as string;
          const jidPhone = remoteJid.replace('@s.whatsapp.net', '').replace('@lid', '');

          // Only map if remoteJid contains a real phone (not already a LID)
          if (remoteJid.includes('@s.whatsapp.net') && /^\d{10,15}$/.test(jidPhone)) {
            await supabase.from('lid_phone_map').upsert({
              lid: jidPhone,
              phone: normalizedPhone,
              instance_name: instanceName,
              updated_at: new Date().toISOString()
            }, { onConflict: 'lid' });
            console.log(`🗺️ LID mapping saved: ${jidPhone} → ${normalizedPhone}`);
          }
        } catch (mapErr) {
          console.warn('⚠️ Failed to save LID mapping (non-critical):', mapErr);
        }
      }

      // Registrar no communication_log
      const logContent = media
        ? `Mídia (${media.type}): ${media.caption || media.url}`
        : list
          ? `Lista: ${list.title}`
          : message || '';

      await supabase.from('communication_log').insert({
        type: 'whatsapp',
        direction: 'enviado',
        phone_number: normalizedPhone,
        content: logContent,
        message_id: responseBody?.key?.id || responseBody?.messageId || null,
        status: 'sent',
        corretor_id: corretor_id || null,
        lead_id: lead_id || null,
        metadata: {
          media_type: media?.type,
          has_list: !!list,
          api_version: 'v2',
          endpoint: endpoint,
          response: responseBody,
        }
      });

      return new Response(
        JSON.stringify({
          success: true,
          message_id: responseBody?.key?.id || responseBody?.messageId,
          phone_number: normalizedPhone,
          result: responseBody
        }),
        { headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
      );

    } catch (error: any) {
      responseBody = { error: error.message };
      throw error;
    } finally {
      await logIntegration(supabase, {
        service: 'evolution-api',
        endpoint: endpoint,
        method: 'POST',
        status_code: responseStatus,
        request_payload: payload,
        response_body: responseBody,
        duration_ms: Date.now() - startTime,
        metadata: {
          instance_name: instanceName,
          phone: normalizedPhone
        }
      });
    }


  } catch (error: any) {
    if (error.name === 'AbortError' || error.name === 'TimeoutError') {
      console.error('❌ Evolution API Timeout');
      return new Response(
        JSON.stringify({ success: false, error: 'Evolution API Timeout' }),
        { headers: { ...corsHeaders, 'Content-Type': 'application/json' }, status: 504 }
      );
    }
    console.error('❌ Erro ao enviar mensagem:', error);

    return new Response(
      JSON.stringify({
        success: false,
        error: error.message
      }),
      {
        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
        status: 400
      }
    );
  }
});

import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

serve(async (req) => {
  // Handle CORS preflight requests
  if (req.method === 'OPTIONS') {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    const supabase = createClient(
      Deno.env.get('SUPABASE_URL') ?? '',
      Deno.env.get('SUPABASE_ANON_KEY') ?? ''
    );

    // Get Evolution API settings
    const { data: settings, error: settingsError } = await supabase
      .from('system_settings')
      .select('key, value')
      .in('key', ['evolution_api_url', 'evolution_api_key', 'evolution_instance_name']);

    if (settingsError) throw settingsError;

    const settingsMap = settings.reduce((acc: any, setting) => {
      acc[setting.key] = setting.value;
      return acc;
    }, {});

    const { phone_number, message, lead_id, corretor_id } = await req.json();

    console.log('Sending WhatsApp message to:', phone_number);

    if (!settingsMap.evolution_api_url || !settingsMap.evolution_api_key || !settingsMap.evolution_instance_name) {
      throw new Error('Evolution API não configurada');
    }

    // Send message via Evolution API V2
    const apiUrl = settingsMap.evolution_api_url.replace(/\/$/, '');
