async function processReminders(supabase: any, dateStr: string, type: 'reminder_24h' | 'reminder_today') {
  console.log(`Processando ${type} para data ${dateStr}`);

  // Buscar visitas confirmadas para a data
  const { data: visitas, error } = await supabase
    .from('visitas')
    .select(`
      id,
      data_visita,
      horario_visita,
      lead:leads!inner (id, nome, telefone),
      corretor:corretores!inner (id, whatsapp, profiles(first_name)),
      empreendimento:empreendimentos!inner (nome)
    `)
    .eq('data_visita', dateStr)
    .eq('status', 'agendada'); // Apenas agendadas

  if (error) {
    console.error(`Erro ao buscar visitas para ${type}:`, error);
    return 0;
  }

  let count = 0;

  for (const visita of visitas) {
    // Verificar se já enviamos este lembrete
    const alreadySent = await checkCommunicationLog(supabase, visita.id, type);
    if (alreadySent) continue;

    // Enviar para Corretor e Cliente
    await sendReminderMessages(supabase, visita, type);
    count++;
  }

  return count;
}

async function processPostVisitFeedback(supabase: any) {
  console.log('Processando feedbacks pós-visita...');

  // Buscar visitas 'agendada' ou 'realizada' que já passaram do horário
  // Nota: Idealmente o status muda para 'realizada' manualmente, mas vamos pegar pelo horário também
  // para garantir automação.

  const now = new Date();
  const threeHoursAgo = new Date(now.getTime() - 3 * 60 * 60 * 1000); // 3h atrás

  // Vamos buscar visitas de hoje e ontem (para cobrir o caso de "dia seguinte 8h")
  const todayStr = now.toISOString().split('T')[0];
  const yesterday = new Date();
  yesterday.setDate(yesterday.getDate() - 1);
  const yesterdayStr = yesterday.toISOString().split('T')[0];

  const { data: visitas, error } = await supabase
    .from('visitas')
    .select(`
      id,
      data_visita,
      horario_visita,
      status,
      lead:leads!inner (id, nome, telefone),
      corretor:corretores!inner (id, whatsapp, profiles(first_name)),
      empreendimento:empreendimentos!inner (nome)
    `)
    .in('data_visita', [todayStr, yesterdayStr])
    .neq('status', 'cancelada');

  if (error) return 0;

  let count = 0;

  for (const visita of visitas) {
    // Construir data/hora da visita
    // horario_visita é string "HH:MM" ou "HH:MM:SS"
    const [hours, minutes] = visita.horario_visita.split(':');
    const visitDateTime = new Date(visita.data_visita);
    visitDateTime.setHours(parseInt(hours), parseInt(minutes), 0);

    // Calcular tempo decorrido
    const diffMs = now.getTime() - visitDateTime.getTime();
    const diffHours = diffMs / (1000 * 60 * 60);

    // Regra: Enviar 3h depois. Se 3h depois for > 19h, enviar 8h do dia seguinte.
    if (diffHours < 3) continue; // Ainda não passou 3h

    // Verificar horário atual
    const currentHour = now.getHours();

    // Se a visita foi hoje e 3h depois cai após as 19h, só enviamos se agora for amanhã > 8h
    // Simplificação: Se agora é > 19h e < 8h, não enviamos (janela de silêncio)
    if (currentHour >= 19 || currentHour < 8) {
      continue; // Esperar horário comercial
    }

    // Verificar se já enviamos
    const alreadySent = await checkCommunicationLog(supabase, visita.id, 'post_visit_feedback');
    if (alreadySent) continue;

    // Enviar Feedback
    await sendFeedbackRequest(supabase, visita);
    count++;
  }

  return count;
}

async function checkCommunicationLog(supabase: any, visitaId: string, type: string) {
  const { data } = await supabase
    .from('communication_log')
    .select('id')
    .eq('metadata->visita_id', visitaId) // Assumindo que salvamos visita_id no metadata
    .eq('metadata->type', type)
    .limit(1);

  return data && data.length > 0;
}

async function sendReminderMessages(supabase: any, visita: any, type: 'reminder_24h' | 'reminder_today') {
  const isToday = type === 'reminder_today';
  const timeText = isToday ? "é HOJE" : "é AMANHÃ";

  // Mensagem para Cliente — Pede confirmação SIM/NÃO
  const msgClient = `⏰ *LEMBRETE DE VISITA*

Olá ${visita.lead.nome}, sua visita ao *${visita.empreendimento.nome}* ${timeText}.

🕒 Horário: ${visita.horario_visita}
📍 Corretor: ${visita.corretor.profiles.first_name}

⚠️ *Precisamos confirmar sua presença.*
Responda *SIM* para confirmar ou *NÃO* para cancelar.`;

  // Mensagem para Corretor — Agora também pede confirmação SIM/NÃO
  const msgCorretor = `⏰ *LEMBRETE DE VISITA*

Corretor(a) ${visita.corretor.profiles.first_name}, sua visita com o cliente *${visita.lead.nome}* ${timeText}.

🏢 Empreendimento: ${visita.empreendimento.nome}
🕒 Horário: ${visita.horario_visita}

⚠️ *Precisamos confirmar sua presença.*
Responda *SIM* para confirmar ou *NÃO* se não puder comparecer.`;

  // Enviar com contexto de "visit_reminder" para que o webhook saiba rotear as respostas
  await sendWhatsapp(supabase, visita.lead.telefone, msgClient, visita, type, 'client');
  await sendWhatsapp(supabase, visita.corretor.whatsapp, msgCorretor, visita, type, 'corretor');
}

async function sendFeedbackRequest(supabase: any, visita: any) {
  // Feedback Cliente
  const msgClient = `👋 Olá ${visita.lead.nome}!

Esperamos que sua visita ao *${visita.empreendimento.nome}* tenha sido ótima.

Poderia nos responder rapidinho?
1. O que achou do empreendimento? (Gostou?)
2. De 0 a 10, qual sua nota para o atendimento do corretor ${visita.corretor.profiles.first_name}?

Sua opinião é muito importante pra gente! 💙`;

  // Feedback Corretor
  const msgCorretor = `👋 Olá ${visita.corretor.profiles.first_name}, como foi a visita com *${visita.lead.nome}*?

Por favor, nos envie um breve feedback (texto ou áudio) sobre:
- O cliente demonstrou interesse real?
- Qual a probabilidade de fechamento?
- Próximos passos agendados?

Isso ajuda a calibrar nossos leads! 🚀`;

  await sendWhatsapp(supabase, visita.lead.telefone, msgClient, visita, 'post_visit_feedback', 'client');
  await sendWhatsapp(supabase, visita.corretor.whatsapp, msgCorretor, visita, 'post_visit_feedback', 'corretor');
}

async function sendWhatsapp(supabase: any, phone: string, message: string, visita: any, type: string, target: string) {
  try {
    const isReminder = type === 'reminder_24h' || type === 'reminder_today';

    await supabase.functions.invoke('evolution-send-whatsapp-v2', {
      body: {
        phone_number: phone,
        message: message,
        metadata: {
          visita_id: visita.id,
          lead_id: visita.lead.id,
          type: type,
          target: target,
          context: isReminder ? 'visit_reminder' : 'post_visit_feedback'
        }
      }
    });

    // Log local para o checkCommunicationLog funcionar
    await supabase.from('communication_log').insert({
      type: 'whatsapp',
      direction: 'outbound',
      phone_number: phone,
      content: message,
      status: 'sent',
      metadata: {
        visita_id: visita.id,
        type: type,
        target: target,
        context: isReminder ? 'visit_reminder' : 'post_visit_feedback'
      }
    });

  } catch (error) {
    console.error(`Erro ao enviar ${type} para ${target}:`, error);
  }
}

import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

// ============================================================
// HELPERS
// ============================================================

async function sendWhatsAppWithRetry(supabase: any, phone: string, message: string, maxRetries = 3): Promise<boolean> {
    let attempt = 0;
    while (attempt < maxRetries) {
        try {
            const { error } = await supabase.functions.invoke('evolution-send-whatsapp-v2', {
                body: {
                    phone_number: phone,
                    message: message
                }
            });

            if (error) throw error;
            return true;
        } catch (error) {
            attempt++;
            console.warn(`WhatsApp attempt ${attempt}/${maxRetries} failed:`, error);
            if (attempt < maxRetries) {
                // Exponential backoff: 1s, 2s, 4s
                await new Promise(resolve => setTimeout(resolve, 1000 * Math.pow(2, attempt - 1)));
            }
        }
    }
    return false;
}

// ============================================================
// PAYMENT REMINDER CHECKER
// Cron job diário que verifica vendas com pagamento próximo
// e envia lembretes internos + WhatsApp para o admin
// ============================================================

serve(async (req) => {
    if (req.method === 'OPTIONS') {
        return new Response(null, { headers: corsHeaders });
    }

    const startTime = Date.now();

    const authHeader = req.headers.get('Authorization');
    const cronSecret = Deno.env.get('CRON_SECRET');
    const serviceRoleKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY');

    const supabase = createClient(
        Deno.env.get('SUPABASE_URL') ?? '',
        serviceRoleKey ?? ''
    );

    const token = authHeader?.replace('Bearer ', '');
    const isValidCronAuth = token === cronSecret;
    const isValidServiceAuth = token === serviceRoleKey;

    let isValidInternalAuth = false;
    if (!isValidCronAuth && !isValidServiceAuth && token) {
        try {
            const { data: internalSecret } = await supabase
                .from('system_settings')
                .select('value')
                .eq('key', 'cron_secret')
                .single();
            if (internalSecret && internalSecret.value === token) {
                isValidInternalAuth = true;
            }
        } catch (e) {
            console.warn('Erro ao verificar internal cron secret:', e);
        }
    }

    if (!isValidCronAuth && !isValidServiceAuth && !isValidInternalAuth) {
        return new Response(
            JSON.stringify({ error: 'Unauthorized' }),
            { status: 401, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
        );
    }

    try {
        console.log('🔔 Payment Reminder Checker iniciando...');

        const tomorrow = new Date();
        tomorrow.setDate(tomorrow.getDate() + 1);
        const tomorrowStr = tomorrow.toISOString().split('T')[0];

        const { data: vendas, error: vendasError } = await supabase
            .from('vendas')
            .select(`
                id,
                valor_imovel,
                valor_corretor,
                valor_memude,
                valor_comissao_liquida,
                data_pagamento,
                status,
                is_venda_direta,
                leads!inner ( nome, telefone ),
                empreendimentos!inner ( nome ),
                corretores ( nome )
            `)
            .eq('data_pagamento', tomorrowStr)
            .eq('lembrete_enviado', false)
            .in('status', ['pendente', 'aprovada']);

        if (vendasError) {
            throw new Error(`Erro ao buscar vendas: ${vendasError.message}`);
        }

        console.log(`📋 Encontradas ${vendas?.length || 0} vendas com pagamento amanhã`);

        const results = { checked: vendas?.length || 0, reminders: 0, errors: 0 };

        const { data: admins } = await supabase
            .from('profiles')
            .select('id, full_name, phone')
            .eq('role', 'admin');

        for (const venda of vendas || []) {
            try {
                const leadNome = (venda.leads as any)?.nome || 'Lead';
                const empNome = (venda.empreendimentos as any)?.nome || 'Empreendimento';
                const corretorNome = venda.is_venda_direta ? 'Venda Direta' : ((venda.corretores as any)?.nome || 'Corretor');

                const valorFormatado = new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(Number(venda.valor_comissao_liquida));

                // 1. Send Internal Notifications
                for (const admin of admins || []) {
                    await supabase.from('notifications').insert({
                        user_id: admin.id,
                        type: 'payment_reminder',
                        title: '💰 Lembrete de Pagamento',
                        message: `Pagamento de ${valorFormatado} para venda de ${leadNome} (${empNome}) vence amanhã. Corretor: ${corretorNome}.`,
                        data: { venda_id: venda.id }
                    });
                }

                // 2. Send WhatsApp with Retry
                for (const admin of admins || []) {
                    if (admin.phone) {
                        const whatsappMessage = `💰 *Lembrete de Pagamento*\n\n` +
                            `📋 Venda: ${leadNome} - ${empNome}\n` +
                            `👤 Corretor: ${corretorNome}\n` +
                            `💵 Valor Líquido: ${valorFormatado}\n` +
                            `📅 Vencimento: ${new Date(venda.data_pagamento + 'T12:00:00').toLocaleDateString('pt-BR')}\n\n` +
                            `⚠️ Este pagamento vence *amanhã*!`;

                        await sendWhatsAppWithRetry(supabase, admin.phone, whatsappMessage);
                    }
                }

                await supabase
                    .from('vendas')
                    .update({ lembrete_enviado: true })
                    .eq('id', venda.id);

                results.reminders++;
                console.log(`✅ Lembrete enviado para venda ${venda.id} (${leadNome})`);

            } catch (vendaError: any) {
                console.error(`❌ Erro ao processar venda ${venda.id}:`, vendaError.message);
                results.errors++;
            }
        }

        console.log(`📊 Resultado: ${results.reminders} lembretes enviados, ${results.errors} erros`);

        return new Response(
            JSON.stringify({ success: true, ...results, duration: Date.now() - startTime }),
            { headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
        );

    } catch (error: any) {
        console.error('❌ Erro no Payment Reminder Checker:', error);
        return new Response(
            JSON.stringify({ success: false, error: error.message, duration: Date.now() - startTime }),
            { headers: { ...corsHeaders, 'Content-Type': 'application/json' }, status: 500 }
        );
    }
});

