async function savePerformanceMetrics(
  supabase: any,
  performanceMetrics: PerformanceMetric[],
  syncLogId: string
) {
  try {
    const metricsData = performanceMetrics.map(metric => ({
      sync_log_id: syncLogId,
      operation_type: metric.operationType,
      operation_start: metric.operationStart,
      operation_end: new Date().toISOString(),
      duration_ms: metric.metadata?.duration || null,
      post_id: metric.postId || null,
      empreendimento_id: metric.empreendimentoId || null,
      success: metric.metadata?.success !== false,
      error_message: metric.metadata?.error || null,
      metadata: metric.metadata
    }));

    const { error } = await supabase
      .from('wp_sync_performance')
      .insert(metricsData);

    if (error) {
      console.error('❌ Erro ao salvar métricas de performance:', error);
    } else {
      console.log(`📈 Salvado ${metricsData.length} métricas de performance`);
    }
  } catch (error) {
    console.error('❌ Erro ao processar métricas:', error);
  }
}

async function logSyncResults(
  supabase: any,
  stats: SyncStats,
  syncDuration: number,
  errors: string[],
  syncLogId: string | null,
  status: 'success' | 'partial' | 'error' = 'success'
) {
  if (errors.length > 0 && status === 'success') {
    status = 'partial';
  }

  const logData = {
    total_posts_fetched: stats.totalPostsFetched,
    new_empreendimentos: stats.newEmpreendimentos,
    updated_empreendimentos: stats.updatedEmpreendimentos,
    errors_count: stats.errorsCount,
    sync_duration_ms: syncDuration,
    last_wp_post_id: stats.lastWpPostId,
    status,
    error_details: errors.length > 0 ? { errors } : null
  };

  try {
    if (syncLogId) {
      // Update existing log
      const { error } = await supabase
        .from('wp_sync_log')
        .update(logData)
        .eq('id', syncLogId);

      if (error) {
        console.error('❌ Erro ao atualizar log da sincronização:', error);
      } else {
        console.log('📝 Log da sincronização atualizado com sucesso');
      }
    } else {
      // Create new log
      const { error } = await supabase
        .from('wp_sync_log')
        .insert(logData);

      if (error) {
        console.error('❌ Erro ao criar log da sincronização:', error);
      } else {
        console.log('📝 Log da sincronização criado com sucesso');
      }
    }
  } catch (error) {
    console.error('❌ Erro ao processar log:', error);
  }
}

import { serve } from "https://deno.land/std@0.190.0/http/server.ts";
import { createClient } from "https://esm.sh/@supabase/supabase-js@2.57.4";

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

interface TemplateRequest {
  action: 'create' | 'update' | 'delete' | 'list' | 'duplicate';
  templateId?: string;
  templateData?: {
    name: string;
    category: string;
    type: string;
    subject?: string;
    content: string;
    variables?: string[];
    is_active?: boolean;
  };
  filters?: {
    category?: string;
    type?: string;
    is_system?: boolean;
    search?: string;
  };
}

const handler = async (req: Request): Promise<Response> => {
  if (req.method === 'OPTIONS') {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    const supabaseUrl = Deno.env.get('SUPABASE_URL')!;
    const supabaseServiceKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;

    const supabase = createClient(supabaseUrl, supabaseServiceKey);

    // Verificar autenticação
    const authHeader = req.headers.get('Authorization');
    if (!authHeader) {
      return new Response(JSON.stringify({ error: 'Token de autorização obrigatório' }), {
        status: 401,
        headers: { ...corsHeaders, 'Content-Type': 'application/json' }
      });
    }

    const token = authHeader.replace('Bearer ', '');
    const { data: { user }, error: authError } = await supabase.auth.getUser(token);

    if (authError || !user) {
      return new Response(JSON.stringify({ error: 'Token inválido' }), {
        status: 401,
        headers: { ...corsHeaders, 'Content-Type': 'application/json' }
      });
    }

    // Buscar perfil do usuário
    const { data: profile } = await supabase
      .from('profiles')
      .select('id, role')
      .eq('user_id', user.id)
      .single();

    if (!profile) {
      return new Response(JSON.stringify({ error: 'Perfil não encontrado' }), {
        status: 404,
        headers: { ...corsHeaders, 'Content-Type': 'application/json' }
      });
    }

    const { action, templateId, templateData, filters }: TemplateRequest = await req.json();

    switch (action) {
      case 'list': {
        let query = supabase
          .from('message_templates')
          .select(`
            id,
            name,
            category,
            type,
            subject,
            content,
            variables,
            is_active,
            is_system,
            created_at,
            updated_at,
            created_by,
            profiles:created_by(first_name, last_name)
          `)
          .order('created_at', { ascending: false });

        if (filters?.category) {
          query = query.eq('category', filters.category);
        }
        if (filters?.type) {
          query = query.eq('type', filters.type);
        }
        if (filters?.is_system !== undefined) {
          query = query.eq('is_system', filters.is_system);
        }
        if (filters?.search) {
          query = query.or(`name.ilike.%${filters.search}%,content.ilike.%${filters.search}%`);
        }

        const { data: templates, error } = await query;

        if (error) throw error;

        return new Response(JSON.stringify({ templates }), {
          headers: { ...corsHeaders, 'Content-Type': 'application/json' }
        });
      }

      case 'create': {
        if (!templateData) {
          return new Response(JSON.stringify({ error: 'Dados do template obrigatórios' }), {
            status: 400,
            headers: { ...corsHeaders, 'Content-Type': 'application/json' }
          });
        }

        const { data: newTemplate, error } = await supabase
          .from('message_templates')
          .insert({
            ...templateData,
            created_by: profile.id,
            is_system: false,
            variables: templateData.variables || []
          })
          .select()
          .single();

        if (error) throw error;

        console.log('Template criado:', newTemplate);

        return new Response(JSON.stringify({ template: newTemplate }), {
          headers: { ...corsHeaders, 'Content-Type': 'application/json' }
        });
      }

      case 'update': {
        if (!templateId || !templateData) {
          return new Response(JSON.stringify({ error: 'ID e dados do template obrigatórios' }), {
            status: 400,
            headers: { ...corsHeaders, 'Content-Type': 'application/json' }
          });
        }

        // Verificar se o usuário pode editar este template
        const { data: existingTemplate } = await supabase
          .from('message_templates')
          .select('created_by, is_system')
          .eq('id', templateId)
          .single();

        if (existingTemplate?.is_system && profile.role !== 'admin') {
          return new Response(JSON.stringify({ error: 'Apenas administradores podem editar templates do sistema' }), {
            status: 403,
            headers: { ...corsHeaders, 'Content-Type': 'application/json' }
          });
        }

        const { data: updatedTemplate, error } = await supabase
          .from('message_templates')
          .update({
            ...templateData,
            variables: templateData.variables || []
          })
          .eq('id', templateId)
          .select()
          .single();

        if (error) throw error;

        console.log('Template atualizado:', updatedTemplate);

        return new Response(JSON.stringify({ template: updatedTemplate }), {
          headers: { ...corsHeaders, 'Content-Type': 'application/json' }
        });
      }

      case 'duplicate': {
        if (!templateId) {
          return new Response(JSON.stringify({ error: 'ID do template obrigatório' }), {
            status: 400,
            headers: { ...corsHeaders, 'Content-Type': 'application/json' }
          });
        }

        const { data: originalTemplate } = await supabase
          .from('message_templates')
          .select('*')
          .eq('id', templateId)
          .single();

        if (!originalTemplate) {
          return new Response(JSON.stringify({ error: 'Template não encontrado' }), {
            status: 404,
            headers: { ...corsHeaders, 'Content-Type': 'application/json' }
          });
        }

        const { data: duplicatedTemplate, error } = await supabase
          .from('message_templates')
          .insert({
            name: `${originalTemplate.name} (Cópia)`,
            category: originalTemplate.category,
            type: originalTemplate.type,
            subject: originalTemplate.subject,
            content: originalTemplate.content,
            variables: originalTemplate.variables,
            is_active: true,
            is_system: false,
            created_by: profile.id
          })
          .select()
          .single();

        if (error) throw error;

        return new Response(JSON.stringify({ template: duplicatedTemplate }), {
          headers: { ...corsHeaders, 'Content-Type': 'application/json' }
        });
      }

      case 'delete': {
        if (!templateId) {
          return new Response(JSON.stringify({ error: 'ID do template obrigatório' }), {
            status: 400,
            headers: { ...corsHeaders, 'Content-Type': 'application/json' }
          });
        }

        // Verificar se é um template do sistema
        const { data: existingTemplate } = await supabase
          .from('message_templates')
          .select('is_system')
          .eq('id', templateId)
          .single();

        if (existingTemplate?.is_system) {
          return new Response(JSON.stringify({ error: 'Templates do sistema não podem ser excluídos' }), {
            status: 403,
            headers: { ...corsHeaders, 'Content-Type': 'application/json' }
          });
        }

        const { error } = await supabase
          .from('message_templates')
          .delete()
          .eq('id', templateId);

        if (error) throw error;

        console.log('Template excluído:', templateId);

        return new Response(JSON.stringify({ success: true }), {
          headers: { ...corsHeaders, 'Content-Type': 'application/json' }
        });
      }

      default:
        return new Response(JSON.stringify({ error: 'Ação não suportada' }), {
          status: 400,
          headers: { ...corsHeaders, 'Content-Type': 'application/json' }
        });
    }

  } catch (error: any) {
    console.error('Erro no template-manager:', error);
    return new Response(JSON.stringify({ error: error.message }), {
      status: 500,
      headers: { ...corsHeaders, 'Content-Type': 'application/json' }
    });
  }
};

serve(handler);

import { createClient } from "https://esm.sh/@supabase/supabase-js@2.39.3";

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

interface TemplateRenderRequest {
  templateId?: string;
  category?: string;
  type?: string;
  variables: Record<string, any>;
  previewMode?: boolean;
}

Deno.serve(async (req) => {
  // Handle CORS preflight requests
  if (req.method === 'OPTIONS') {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    const supabaseUrl = Deno.env.get('SUPABASE_URL');
    const supabaseServiceKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY');

    if (!supabaseUrl || !supabaseServiceKey) {
      throw new Error('Missing Supabase environment variables');
    }

    const supabase = createClient(supabaseUrl, supabaseServiceKey);

    let body: TemplateRenderRequest;
    try {
      body = await req.json();
    } catch (e) {
      throw new Error('Invalid JSON payload');
    }

    const {
      templateId,
      category,
      type,
      variables,
      previewMode = false
    } = body;

    let template;

    // Buscar template por ID ou por categoria/tipo
    if (templateId) {
      const { data } = await supabase
        .from('message_templates')
        .select('*')
        .eq('id', templateId)
        .eq('is_active', true)
        .single();
      template = data;
    } else if (category && type) {
      const { data } = await supabase
        .from('message_templates')
        .select('*')
        .eq('category', category)
        .eq('type', type)
        .eq('is_active', true)
        .eq('is_system', true)
        .order('created_at', { ascending: true })
        .limit(1);
      template = data?.[0];
    }

    if (!template) {
      return new Response(JSON.stringify({
        error: 'Template não encontrado',
        rendered_content: null
      }), {
        status: 404,
        headers: { ...corsHeaders, 'Content-Type': 'application/json' }
      });
    }

    // Renderizar template com variáveis
    let renderedContent = template.content;

    // Adicionar variáveis do sistema
    const systemVariables = {
      data_atual: new Date().toLocaleDateString('pt-BR'),
      hora_atual: new Date().toLocaleTimeString('pt-BR', {
        hour: '2-digit',
        minute: '2-digit'
      }),
      empresa: 'Memude Imóveis'
    };

    const allVariables = { ...systemVariables, ...variables };

    // Substituir variáveis no template
    for (const [key, value] of Object.entries(allVariables)) {
      const variablePattern = new RegExp(`{${key}}`, 'g');
      renderedContent = renderedContent.replace(variablePattern, String(value || ''));
    }

    // Verificar variáveis não substituídas (opcional para debug)
    const unresolvedVariables = renderedContent.match(/{[^}]+}/g) || [];

    console.log('Template renderizado:', {
      templateId: template.id,
      templateName: template.name,
      category: template.category,
      type: template.type,
      variablesUsed: Object.keys(allVariables),
      unresolvedVariables,
      previewMode
    });

    return new Response(JSON.stringify({
      template_id: template.id,
      template_name: template.name,
      category: template.category,
      type: template.type,
      subject: template.subject,
      rendered_content: renderedContent,
      original_content: template.content,
      variables_used: Object.keys(allVariables),
      unresolved_variables: unresolvedVariables,
      preview_mode: previewMode
    }), {
      status: 200,
      headers: { ...corsHeaders, 'Content-Type': 'application/json' }
    });

  } catch (error: any) {
    console.error('Erro no template-renderer:', error);
    return new Response(JSON.stringify({
      error: error.message,
      rendered_content: null
    }), {
      status: 500,
      headers: { ...corsHeaders, 'Content-Type': 'application/json' }
    });
  }
});

import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

serve(async (req) => {
  if (req.method === 'OPTIONS') {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    const supabase = createClient(
      Deno.env.get('SUPABASE_URL') ?? '',
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? ''
    );

    const { phone, message } = await req.json();

    if (!phone || !message) {
      throw new Error('Telefone e mensagem são obrigatórios');
    }

    // 1. Obter configurações
    const { data: settings } = await supabase
      .from('system_settings')
      .select('key, value')
      .in('key', [
        'whatsapp_provider', 
        'evolution_api_url', 'evolution_api_key', 'evolution_instance_name',
        'waha_api_url', 'waha_api_key'
      ]);

    const config = new Map(settings?.map(s => [s.key, s.value]) || []);
    const provider = config.get('whatsapp_provider') || 'evolution'; // Default Evolution

    console.log(`📨 Enviando via ${provider.toUpperCase()} para ${phone}`);

    let result;

    if (provider === 'waha') {
        result = await sendViaWAHA(config, phone, message);
    } else {
        result = await sendViaEvolution(config, phone, message);
    }

    // Log comunicação
    await supabase.from('communication_log').insert({
        type: 'whatsapp',
        direction: 'outbound',
        phone_number: phone,
        content: message,
        status: result.success ? 'sent' : 'failed',
        metadata: { provider, result }
    });

    return new Response(JSON.stringify(result), { headers: { ...corsHeaders, 'Content-Type': 'application/json' } });

  } catch (error) {
    return new Response(JSON.stringify({ error: error.message }), { status: 500, headers: { ...corsHeaders, 'Content-Type': 'application/json' } });
  }
});

async function sendViaEvolution(config: Map<string, string>, phone: string, message: string) {
    const url = config.get('evolution_api_url');
    const key = config.get('evolution_api_key');
    const instance = config.get('evolution_instance_name');

    if (!url || !key || !instance) throw new Error("Configuração Evolution incompleta");

    const endpoint = `${url}/message/sendText/${instance}`;
    const body = {
        number: phone, // Evolution V2 usa 'number'
        text: message,
        options: { delay: 1200, presence: 'composing' }
    };

    const response = await fetch(endpoint, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'apikey': key },
        body: JSON.stringify(body)
    });

    const data = await response.json();
    return { success: response.ok, provider: 'evolution', data };
}

async function sendViaWAHA(config: Map<string, string>, phone: string, message: string) {
    const url = config.get('waha_api_url');
    const key = config.get('waha_api_key'); // Opcional se usar sessão padrão sem auth

    if (!url) throw new Error("URL do WAHA não configurada");

    // WAHA usa chatId formato 558599999999@c.us
    // Remover + e caracteres especiais
    const cleanPhone = phone.replace(/\D/g, '');
    const chatId = `${cleanPhone}@c.us`;

    const endpoint = `${url}/api/send/text`;
    const body = {
        chatId: chatId,
        text: message,
        session: 'default' 
    };

    const headers: any = { 'Content-Type': 'application/json' };
    if (key) headers['X-Api-Key'] = key;

    const response = await fetch(endpoint, {
        method: 'POST',
        headers,
        body: JSON.stringify(body)
    });

    const data = await response.json();
    return { success: response.ok, provider: 'waha', data };
}

import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';
import { normalizePhoneNumber } from '../_shared/phoneHelpers.ts';

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

serve(async (req) => {
  if (req.method === 'OPTIONS') {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    const supabase = createClient(
      Deno.env.get('SUPABASE_URL') ?? '',
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? ''
    );

    console.log('Verificando timeouts de distribuição de visitas...');

    // Buscar tentativas pendentes que expiraram
    // Usando queue_id como FK explícita (adicionada na Fase 1 do Sprint 5)
    const { data: expiredAttempts, error } = await supabase
      .from('visit_distribution_attempts')
      .select(`
        *,
        visit_distribution_queue!queue_id (
          id,
          status,
          current_attempt,
          visita_id
        ),
        visita:visitas!visita_id (
          id,
          data_visita,
          horario_visita,
          lead:leads!lead_id (
            id,
            nome,
            telefone,
            email
          ),
          empreendimento:empreendimentos!empreendimento_id (
            nome
          )
        ),
        corretor:corretores!corretor_id (
          id,
          whatsapp,
          profiles!profile_id (
            first_name,
            last_name
          )
        )
      `)
      .eq('status', 'pending')
      .lt('timeout_at', new Date().toISOString());

    if (error) {
      throw new Error(`Erro ao buscar tentativas expiradas: ${error.message}`);
    }

    if (!expiredAttempts || expiredAttempts.length === 0) {
      console.log('Nenhuma tentativa expirada encontrada');
      return new Response(
        JSON.stringify({ message: 'Nenhuma tentativa expirada' }),
        { headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
      );
    }

    console.log(`Processando ${expiredAttempts.length} tentativas expiradas`);

    const processedResults = [];

    for (const attempt of expiredAttempts) {
      try {
        const result = await processExpiredAttempt(supabase, attempt);
        processedResults.push(result);
      } catch (error) {
        console.error(`Erro ao processar tentativa ${attempt.id}:`, error);
        processedResults.push({
          attempt_id: attempt.id,
          error: error.message
        });
      }
    }

    return new Response(
      JSON.stringify({ 
        success: true, 
        processed: expiredAttempts.length,
        results: processedResults
      }),
      { headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
    );

  } catch (error) {
    console.error('Erro no checker de timeout de visitas:', error);
    return new Response(
      JSON.stringify({ error: error.message }),
      { headers: { ...corsHeaders, 'Content-Type': 'application/json' }, status: 500 }
    );
  }
});

async function processExpiredAttempt(supabase: any, attempt: any) {
  console.log(`Processando timeout para tentativa ${attempt.id}`);

  // Marcar tentativa como timeout
  await supabase
    .from('visit_distribution_attempts')
    .update({ 
      status: 'timeout',
      response_type: 'timeout',
      response_received_at: new Date().toISOString()
    })
    .eq('id', attempt.id);

  // Buscar configurações
  const { data: settings } = await supabase
    .from('distribution_settings')
    .select('*')
    .single();

  const maxAttempts = settings?.max_attempts || 5;
  const currentAttempt = attempt.visit_distribution_queue.current_attempt;

  console.log(`Tentativa ${currentAttempt} de ${maxAttempts} expirou`);

  if (currentAttempt >= maxAttempts) {
    // Todas as tentativas esgotadas
    console.log(`Máximo de tentativas atingido para visita ${attempt.visita.id}`);

    await supabase
      .from('visit_distribution_queue')
      .update({ 
        status: 'failed',
        failure_reason: 'Todas as tentativas esgotadas - nenhum corretor aceitou',
        completed_at: new Date().toISOString()
      })
      .eq('id', attempt.visit_distribution_queue.id);

    // Notificar admin
    await notifyAdminFailure(
      supabase, 
      attempt.visita, 
      'Todas as tentativas esgotadas - nenhum corretor aceitou a visita'
    );

    return {
      attempt_id: attempt.id,
      action: 'failed',
      reason: 'Máximo de tentativas atingido'
    };

  } else {
    // Tentar próximo corretor
    console.log(`Tentando próximo corretor para visita ${attempt.visita.id}`);

    await supabase
      .from('visit_distribution_queue')
      .update({ 
        current_attempt: currentAttempt + 1
      })
      .eq('id', attempt.visit_distribution_queue.id);

    // Buscar próximo corretor elegível
    const nextResult = await distributeToNextCorretor(
      supabase, 
      attempt.visita_id, 
      currentAttempt + 1
    );

    return {
      attempt_id: attempt.id,
      action: 'retry',
      next_attempt: currentAttempt + 1,
      next_corretor: nextResult
    };
  }
}

async function distributeToNextCorretor(
  supabase: any, 
  visitaId: string, 
  attemptNumber: number
) {
  console.log(`Distribuindo para próximo corretor, tentativa ${attemptNumber}`);

  // Buscar corretores que já receberam esta oportunidade
  const { data: usedAttempts } = await supabase
    .from('visit_distribution_attempts')
    .select('corretor_id')
    .eq('visita_id', visitaId);

  const usedCorretorIds = usedAttempts?.map((a: any) => a.corretor_id) || [];

  // Buscar visita com todos os dados
  const { data: visita } = await supabase
    .from('visitas')
    .select(`
      *,
      lead:leads!inner (
        id,
        nome,
        telefone,
        email
      ),
      empreendimento:empreendimentos (
        id,
        nome,
        bairro_id,
        construtora_id,
        tipo_imovel
      )
    `)
    .eq('id', visitaId)
    .is('deleted_at', null)
    .single();

  if (!visita) {
    console.error('Visita não encontrada:', visitaId);
    throw new Error('Visita não encontrada');
  }

  // Buscar próximo corretor elegível (excluindo os já tentados)
  const nextCorretor = await getNextEligibleCorretor(supabase, visita, usedCorretorIds);

  if (!nextCorretor) {
    console.log('Nenhum corretor elegível restante');

    await supabase
      .from('visit_distribution_queue')
      .update({ 
        status: 'failed',
        failure_reason: 'Nenhum corretor elegível disponível',
        completed_at: new Date().toISOString()
      })
      .eq('visita_id', visitaId);

    await notifyAdminFailure(
      supabase, 
      visita, 
      'Nenhum corretor elegível disponível para esta visita'
    );

    return null;
  }

  // Enviar mensagem para próximo corretor
  const { data: settings } = await supabase
    .from('distribution_settings')
    .select('*')
    .single();

  await sendDistributionMessage(
    supabase, 
    visitaId, 
    nextCorretor, 
    visita, 
    settings, 
    attemptNumber
  );

  return {
    corretor_id: nextCorretor.id,
    corretor_name: `${nextCorretor.profiles.first_name} ${nextCorretor.profiles.last_name}`,
    score: nextCorretor.score
  };
}

async function getNextEligibleCorretor(
  supabase: any, 
  visita: any, 
  excludeIds: string[]
) {
  console.log(`Buscando próximo corretor (excluindo ${excludeIds.length} já tentados)`);

  // Buscar corretores ativos
  let query = supabase
    .from('corretores')
    .select(`
      id,
      profile_id,
      whatsapp,
      telefone,
      nota_media,
      total_visitas,
      tipo_imovel,
      corretor_bairros (bairro_id),
      corretor_construtoras (construtora_id),
      profiles!inner (
        first_name,
        last_name
      )
    `)
    .eq('status', 'ativo')
    .is('deleted_at', null);

  if (excludeIds.length > 0) {
    query = query.not('id', 'in', `(${excludeIds.join(',')})`);
  }

  const { data: corretores } = await query;

  if (!corretores || corretores.length === 0) {
    console.log('Nenhum corretor elegível encontrado após exclusões');
    return null;
  }

  console.log(`Avaliando ${corretores.length} corretores restantes`);

  // Filtrar apenas com WhatsApp/telefone
  const corretoresComContato = corretores.filter(c => c.whatsapp || c.telefone);

  if (corretoresComContato.length === 0) {
    console.log('Nenhum corretor com WhatsApp/telefone disponível');
    return null;
  }

  // Aplicar algoritmo de scoring
  const corretoresWithScore = [];

  for (const corretor of corretoresComContato) {
    let score = 0;

    // Prioridade 1: Compatibilidade (Bairro ou Construtora)
    let hasMatch = false;

    // Construtora
    if (visita.empreendimento?.construtora_id) {
      const hasConstrutorMatch = corretor.corretor_construtoras?.some(
        (cc: any) => cc.construtora_id === visita.empreendimento.construtora_id
      );
      if (hasConstrutorMatch) {
        score += 10000;
        hasMatch = true;
      }
    }

    // Bairro (Se não deu match na construtora, tenta bairro, ou soma se for o caso de priorizar ambos)
    // A regra diz: "Corretores que atendem a cidade e o bairro... OU construtora"
    // Vamos garantir que se já tem match de construtora, não duplique absurdamente, mas se tiver ambos é melhor ainda?
    // O requisito diz "Prioridade 1: Compatibilidade geográfica... ou construtora".
    // Vamos manter simples: Se tem um dos dois, ganha o bonus de compatibilidade.

    if (!hasMatch && visita.empreendimento?.bairro_id) {
      const hasBairroMatch = corretor.corretor_bairros?.some(
        (cb: any) => cb.bairro_id === visita.empreendimento.bairro_id
      );
      if (hasBairroMatch) {
        score += 10000;
        hasMatch = true;
      }
    } else if (hasMatch && visita.empreendimento?.bairro_id) {
       // Se já tem construtora e também tem bairro, damos um pequeno bonus de desempate
       const hasBairroMatch = corretor.corretor_bairros?.some(
        (cb: any) => cb.bairro_id === visita.empreendimento.bairro_id
      );
      if (hasBairroMatch) score += 500; // Bonus por "Combo"
    }

    // Prioridade 2: Reputação (Nota Média)
    score += Math.round((corretor.nota_media || 0) * 100);

    // Prioridade 3: Equilíbrio (Menos visitas)
    const visitasPenalty = (corretor.total_visitas || 0) * 10;
    score += (1000 - Math.min(visitasPenalty, 1000));

    corretoresWithScore.push({ ...corretor, score });
  }

  // Retornar o de maior score
  const bestCorretor = corretoresWithScore.sort((a, b) => b.score - a.score)[0];

  if (bestCorretor) {
    console.log(`Próximo corretor selecionado: ${bestCorretor.profiles.first_name} ${bestCorretor.profiles.last_name} (Score: ${bestCorretor.score})`);
  }

  return bestCorretor || null;
}

async function sendDistributionMessage(
  supabase: any,
  visitaId: string,
  corretor: any,
  visita: any,
  settings: any,
  attemptOrder: number
) {
  console.log(`Enviando mensagem para corretor ${corretor.id}, tentativa ${attemptOrder}`);

  const timeoutAt = new Date();
  timeoutAt.setMinutes(timeoutAt.getMinutes() + (settings?.timeout_minutes || 15));

  const dataVisita = new Date(visita.data_visita).toLocaleDateString('pt-BR');

  // Registrar nova tentativa
  const { data: attempt, error: attemptError } = await supabase
    .from('visit_distribution_attempts')
    .insert({
      visita_id: visitaId,
      corretor_id: corretor.id,
      attempt_order: attemptOrder,
      timeout_at: timeoutAt.toISOString(),
      status: 'pending'
    })
    .select()
    .single();

  if (attemptError) {
    console.error('Erro ao registrar tentativa:', attemptError);
    throw attemptError;
  }

  const message = `🏠 *NOVA OPORTUNIDADE DE VISITA*

*Cliente:* ${visita.lead.nome}
*Telefone:* ${visita.lead.telefone}
${visita.lead.email ? `*E-mail:* ${visita.lead.email}` : ''}
*Empreendimento:* ${visita.empreendimento?.nome || 'Não especificado'}
*Data:* ${dataVisita}
*Horário:* ${visita.horario_visita}

✅ Para aceitar, responda: *SIM*
❌ Para recusar, responda: *NÃO*

⏰ Você tem ${settings?.timeout_minutes || 15} minutos para responder.`;

  // Usar whatsapp ou telefone como fallback - normalizar para Evolution API
  const rawPhoneNumber = corretor.whatsapp || corretor.telefone;
  const phoneNumber = normalizePhoneNumber(rawPhoneNumber);

  console.log(`Enviando retry WhatsApp para: ${phoneNumber} (original: ${rawPhoneNumber}) (tentativa ${attemptOrder})`);

  try {
    // SPRINT 5 - FASE 4a: Migrado para evolution-send-whatsapp-v2
    const { data: whatsappResult, error: whatsappError } = await supabase.functions.invoke(
      'evolution-send-whatsapp-v2',
      {
        body: {
          phone: phoneNumber,
          message: message,
          metadata: {
            lead_id: visita.lead.id,
            corretor_id: corretor.id,
            visita_id: visita.id,
            type: 'visit_distribution_retry'
          }
        }
      }
    );

    if (whatsappError) {
      throw whatsappError;
    }

    await supabase
      .from('visit_distribution_attempts')
      .update({ 
        whatsapp_message_id: whatsappResult.messageId 
      })
      .eq('id', attempt.id);

    console.log(`Mensagem enviada com sucesso para tentativa ${attemptOrder}`);

  } catch (error) {
    console.error('Erro ao enviar mensagem:', error);

    await supabase
      .from('visit_distribution_attempts')
      .update({ 
        status: 'error',
        response_message: `Erro no envio: ${error.message}`
      })
      .eq('id', attempt.id);

    throw error;
  }
}

async function notifyAdminFailure(supabase: any, visita: any, reason: string) {
  console.log('Notificando admin sobre falha:', reason);

  try {
    const { data: adminSettings } = await supabase
      .from('system_settings')
      .select('value')
      .eq('key', 'admin_whatsapp')
      .single();

    if (!adminSettings?.value) {
      console.log('WhatsApp do administrador não configurado');
      return;
    }

    const dataVisita = new Date(visita.data_visita).toLocaleDateString('pt-BR');

    const adminMessage = `🚨 *FALHA NA DISTRIBUIÇÃO AUTOMÁTICA DE VISITA*

*Visita ID:* ${visita.id}
*Cliente:* ${visita.lead.nome}
*Telefone:* ${visita.lead.telefone}
*Empreendimento:* ${visita.empreendimento?.nome || 'Não especificado'}
*Data:* ${dataVisita}
*Horário:* ${visita.horario_visita}

*Motivo:* ${reason}

⚠️ *É necessário atribuir manualmente um corretor para esta visita.*`;

    // SPRINT 5 - FASE 4a: Migrado para evolution-send-whatsapp-v2
    await supabase.functions.invoke('evolution-send-whatsapp-v2', {
      body: {
        phone: adminSettings.value,
        message: adminMessage,
        metadata: {
          lead_id: visita.lead.id,
          visita_id: visita.id,
          type: 'admin_notification_visit_failure'
        }
      }
    });

    console.log('Administrador notificado com sucesso');

  } catch (error) {
    console.error('Erro ao notificar administrador:', error);
  }
}

import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import { createClient } from "https://esm.sh/@supabase/supabase-js@2";

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

interface WhatsAppWebhookPayload {
  messageId?: string;
  status?: 'sent' | 'delivered' | 'read' | 'failed';
  timestamp?: string;
  error?: {
    code: number;
    message: string;
  };
  phone?: string;
  metadata?: any;
}

serve(async (req) => {
  // Handle CORS preflight requests
  if (req.method === 'OPTIONS') {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    const supabase = createClient(
      Deno.env.get('SUPABASE_URL') ?? '',
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? ''
    );

    const payload: WhatsAppWebhookPayload = await req.json();
    console.log('WhatsApp webhook received:', payload);

    const { messageId, status, timestamp, error, phone, metadata } = payload;

    if (!messageId) {
      console.error('MessageId não fornecido no webhook');
      return new Response(
        JSON.stringify({ error: 'MessageId is required' }),
        { 
          status: 400, 
          headers: { ...corsHeaders, 'Content-Type': 'application/json' } 
        }
      );
    }

    // Atualizar status na tabela communication_log
    const { error: updateError } = await supabase
      .from('communication_log')
      .update({
        status: status || 'failed',
        metadata: {
          ...(metadata || {}),
          webhook_timestamp: timestamp || new Date().toISOString(),
          error_details: error,
          phone_number: phone
        }
      })
      .eq('message_id', messageId);

    if (updateError) {
      console.error('Erro ao atualizar communication_log:', updateError);
      throw updateError;
    }

    // Se o status é 'failed', atualizar também distribution_attempts
    if (status === 'failed') {
      const { error: attemptUpdateError } = await supabase
        .from('distribution_attempts')
        .update({
          status: 'timeout',
          response_message: `WhatsApp delivery failed: ${error?.message || 'Unknown error'}`
        })
        .eq('whatsapp_message_id', messageId);

      if (attemptUpdateError) {
        console.error('Erro ao atualizar distribution_attempts:', attemptUpdateError);
      }

      // Buscar o lead associado e tentar redistribuir
      const { data: attempt } = await supabase
        .from('distribution_attempts')
        .select(`
          lead_id,
          corretor_id,
          attempt_order
        `)
        .eq('whatsapp_message_id', messageId)
        .single();

      if (attempt) {
        console.log('Tentando redistribuir lead devido a falha no WhatsApp:', attempt.lead_id);

        // Chamar distribution-timeout-checker para processar essa falha
        try {
          await supabase.functions.invoke('distribution-timeout-checker', {
            body: { 
              force_process_lead: attempt.lead_id,
              reason: 'whatsapp_delivery_failed'
            }
          });
        } catch (redistributeError) {
          console.error('Erro ao redistribuir lead:', redistributeError);
        }
      }
    }

    // Se o status é 'delivered' ou 'read', marcar como enviado com sucesso
    if (status === 'delivered' || status === 'read') {
      const { error: successUpdateError } = await supabase
        .from('distribution_attempts')
        .update({
          status: 'pending' // Mantém pending até resposta do corretor
        })
        .eq('whatsapp_message_id', messageId);

      if (successUpdateError) {
        console.error('Erro ao atualizar status de entrega:', successUpdateError);
      }
    }

    // Log da atividade para auditoria
    const { error: auditError } = await supabase
      .from('audit_logs')
      .insert({
        table_name: 'whatsapp_webhook',
        action: 'webhook_received',
        new_values: {
          message_id: messageId,
          status: status,
          timestamp: timestamp,
          error: error,
          phone: phone
        },
        ip_address: req.headers.get('x-forwarded-for') || 'unknown'
      });

    if (auditError) {
      console.error('Erro ao registrar auditoria:', auditError);
    }

    console.log(`WhatsApp webhook processado com sucesso - MessageId: ${messageId}, Status: ${status}`);

    return new Response(
      JSON.stringify({ 
        success: true,
        message: 'Webhook processed successfully',
        messageId: messageId,
        status: status
      }),
      {
        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
        status: 200,
      }
    );

  } catch (error) {
    console.error('Error in whatsapp-webhook function:', error);

    return new Response(
      JSON.stringify({ 
        error: error.message,
        timestamp: new Date().toISOString()
      }),
      {
        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
        status: 500,
      }
    );
  }
});

